<?php
// Emergency session clearance hook (Runs even if database is offline or missing)
if (isset($_GET['action']) && $_GET['action'] === 'clear_session_emergency') {
  if (session_status() === PHP_SESSION_NONE) {
    session_start();
  }
  session_destroy();
  setcookie('admin_session_token', '', time() - 3600, '/');
  setcookie('admin_email', '', time() - 3600, '/');
  header('Location: ./');
  exit;
}

// Bypass Gzip compression for heavy files, streaming, and uploads to prevent memory exhaustion and play crashes
$raw_uri_gzip = $_SERVER['REQUEST_URI'] ?? '';
// FIXED: Added all scanning endpoints to bypass GZIP to prevent blank white screens from corrupted buffers
$is_gzip_bypass = preg_match('/action=(stream|thumb|get_stream|download_song|upload|batch|full_scan|force_rescan|rescan_covers|rescan_charts|vacuum_database|reset_rhythm_charts)/i', $raw_uri_gzip) || isset($_GET['download']) || isset($_GET['batch']);

if (!$is_gzip_bypass && isset($_SERVER['HTTP_ACCEPT_ENCODING']) && substr_count($_SERVER['HTTP_ACCEPT_ENCODING'], 'gzip')) {
  ob_start('ob_gzhandler');
}
error_reporting(E_ALL & ~E_DEPRECATED);

// AUTOMATIC SECURITY FIREWALL: Generate strict .htaccess to block direct file and DB access
$htaccess_path = __DIR__ . '/.htaccess';
$needs_htaccess_update = false;

if (file_exists($htaccess_path)) {
  // If the old overly-strict FilesMatch is present, force an update to fix X-Sendfile audio playback
  if (strpos(file_get_contents($htaccess_path), 'mp3|m4a') !== false) {
    $needs_htaccess_update = true;
  }
} else {
  $needs_htaccess_update = true;
}

if ($needs_htaccess_update) {
  $htaccess_content = <<<HTACCESS
# ==========================================
# PHP MUSIC - STRICT SECURITY FIREWALL
# ==========================================

# 1. Disable directory listing globally
Options -Indexes

# 2. Block direct web access to database and config files unconditionally
<FilesMatch "\.(db|sqlite|sqlite3|bak|log|ini|sh)$">
  <IfModule mod_authz_core.c>
    Require all denied
  </IfModule>
  <IfModule !mod_authz_core.c>
    Order Allow,Deny
    Deny from all
  </IfModule>
</FilesMatch>

# 3. Prevent raw folder browsing & redirect direct media downloads into the secure Drive Manager
<IfModule mod_rewrite.c>
  RewriteEngine On

  # Exclude loop matches
  RewriteCond %{REQUEST_URI} !^/index\.php$
  RewriteCond %{ENV:REDIRECT_STATUS} ^$
  RewriteRule ^(uploads/.*|getid3/.*|.*\.(mp3|m4a|flac|ogg|wav|jpg|jpeg|png|webp|gif))$ index.php?access=admin&page=drive&path=$1 [R=302,L,QSA]
</IfModule>
HTACCESS;
  @file_put_contents($htaccess_path, $htaccess_content);
}

