define('MUSIC_DIR', __DIR__);
define('DB_FILE', __DIR__ . '/music.db');
define('APP_VERSION', '6.9');
define('PAGE_SIZE', 25);
define('ADMIN_PAGE_SIZE', 20);
define('DAILY_UPLOAD_LIMIT', 10);

function get_db() {
  static $db = null;
  if ($db !== null) return $db; 
  
  try {
    // Removed ATTR_PERSISTENT as it causes permanent database locking bugs in SQLite
    $db = new PDO('sqlite:' . DB_FILE, null, null, [
      PDO::ATTR_TIMEOUT => 15
    ]);
    $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    $db->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE, PDO::FETCH_ASSOC);
      
    // Optimized PRAGMAs for fast concurrent reads without locking the browser
    $db->exec("
      PRAGMA journal_mode=WAL; 
      PRAGMA synchronous=NORMAL; 
      PRAGMA cache_size=-50000; /* 50MB of RAM for caching */
      PRAGMA temp_store=MEMORY; 
      PRAGMA foreign_keys=ON;
      PRAGMA busy_timeout=5000;
    ");
    
    $db->sqliteCreateFunction('match_artist', function($artist_field, $search_name) {
      if ($artist_field === null || $search_name === null) return 0;
      $db_parts = @preg_split('/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+|\s*,\s*(?!(?:the|a|an|jr|sr)\b))\s*/i', $artist_field);
      $search_parts = @preg_split('/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+|\s*,\s*(?!(?:the|a|an|jr|sr)\b))\s*/i', $search_name);
      if (!is_array($db_parts)) $db_parts = [$artist_field];
      if (!is_array($search_parts)) $search_parts = [$search_name];
      foreach ($db_parts as $db_part) {
        foreach ($search_parts as $search_part) {
          if (strcasecmp(trim($db_part), trim($search_part)) === 0) return 1;
          if (romanize_string(trim($db_part)) === romanize_string(trim($search_part))) return 1;
        }
      }
      return 0;
    }, 2);

    $db->sqliteCreateFunction('match_text', function($db_field, $search_string) {
      if ($db_field === null || $search_string === null) return 0;
      if (mb_stripos($db_field, $search_string, 0, 'UTF-8') !== false) return 1;
      
      $db_rom = romanize_string($db_field);
      $search_rom = romanize_string($search_string);
      
      if ($search_rom !== 'unknown' && $search_rom !== '' && strpos($db_rom, $search_rom) !== false) return 1;
      return 0;
    }, 2);

    return $db;
  } catch (PDOException $e) {
    // Elegant, styled emergency modal fallback if connection fails or database file is missing/locked
    header('HTTP/1.1 500 Internal Server Error');
    ?>
    <!DOCTYPE html>
    <html lang="en" data-bs-theme="dark">
      <head>
        <meta charset="UTF-8">
        <title>Emergency Recovery - PHP Music</title>
        <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet">
        <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css">
        <style>
          body { background-color: #030303; color: #fff; height: 100vh; display: flex; align-items: center; justify-content: center; font-family: sans-serif; }
          .recovery-card { background: #121212; border: 1px solid #333; border-radius: 16px; padding: 32px; max-width: 450px; text-align: center; box-shadow: 0 10px 30px rgba(0,0,0,0.8); }
        </style>
      </head>
      <body>
        <div class="recovery-card">
          <i class="bi bi-exclamation-triangle-fill text-danger" style="font-size: 4rem;"></i>
          <h4 class="fw-bold mt-3 mb-2">Connection Failure</h4>
          <p class="text-secondary small mb-4">The database is either missing, corrupted, or locked. If you recently reset the server, please clear your session cookies to recover.</p>
          <a href="?action=clear_session_emergency" class="btn btn-danger w-100 fw-bold py-2 rounded-pill mb-2">Clear Session & Recover</a>
          <a href="./" class="btn btn-outline-light w-100 fw-bold py-2 rounded-pill">Retry Connection</a>
        </div>
      </body>
    </html>
    <?php
    exit;
  }
}

// Auto-logout if session exists but database record is missing
if (isset($_SESSION['user_id'])) {
  try {
    $db_check = get_db();
    $stmt_check = $db_check->prepare("SELECT id FROM users WHERE id = ?");
    $stmt_check->execute([$_SESSION['user_id']]);
    if (!$stmt_check->fetch()) {
      session_destroy();
      $_SESSION = [];
    }
  } catch (Exception $e) {}
}

if (isset($_GET['access']) && $_GET['access'] === 'admin') {
  if (empty($_SESSION['admin_csrf_token'])) {
    $_SESSION['admin_csrf_token'] = bin2hex(random_bytes(32));
  }

  // Ensure DB schema is initialized so default admin exists immediately
  if (function_exists('init_db')) { init_db(get_db()); }

  // Sync main site login with Admin session
  if (!isset($_SESSION['admin_logged_in']) && isset($_SESSION['user_id'])) {
    $db = get_db();
    $stmt = $db->prepare("SELECT email, is_admin FROM users WHERE id = ?");
    $stmt->execute([$_SESSION['user_id']]);
    $u = $stmt->fetch();
    if ($u && ($u['is_admin'] == 1 || strtolower(trim($u['email'])) === 'musiclibrary@mail.com')) {
      $_SESSION['admin_logged_in'] = true;
      $_SESSION['admin_email'] = $u['email'];
      $_SESSION['admin_id'] = $_SESSION['user_id'];
    }
  }

  // 1-Year Admin Session Persistence Check
  if (!isset($_SESSION['admin_logged_in']) && isset($_COOKIE['admin_session_token']) && isset($_COOKIE['admin_email'])) {
    $db = get_db();
    $stmt = $db->prepare("SELECT id, password_hash, is_admin, artist FROM users WHERE email = ?");
    $stmt->execute([$_COOKIE['admin_email']]);
    $user = $stmt->fetch();
    if ($user && ($user['is_admin'] == 1 || $_COOKIE['admin_email'] === 'musiclibrary@mail.com')) {
      if (hash_equals(hash('sha256', $user['password_hash'] . ($_SERVER['HTTP_USER_AGENT'] ?? '')), $_COOKIE['admin_session_token'])) {
        $_SESSION['admin_logged_in'] = true;
        $_SESSION['admin_email'] = $_COOKIE['admin_email'];
        $_SESSION['admin_id'] = $user['id'];
        $_SESSION['user_artist'] = $user['artist'];
      }
    }
  }

  $is_admin_logged_in = isset($_SESSION['admin_logged_in']) && $_SESSION['admin_logged_in'] === true;

  // Release the PHP session write-lock early for non-auth Drive actions.
  // This allows parallel uploads and chunked streams to run concurrently without freezing.
  if (isset($_GET['page']) && $_GET['page'] === 'drive') {
    $driveAction = $_GET['action'] ?? '';
    if ($driveAction !== 'login' && $driveAction !== 'toggle_auth' && $driveAction !== 'logout') {
      session_write_close();
    }
  }

  // ==========================================
  // PHP DRIVE BACKEND CONTROLLER
  // ==========================================
  if (isset($_GET['page']) && $_GET['page'] === 'drive') {
    if (!$is_admin_logged_in && (isset($_GET['api']) || isset($_GET['download']) || isset($_GET['batch']))) {
      header('Content-Type: application/json');
      http_response_code(401);
      echo json_encode(['success' => false, 'error' => 'auth_required']);
      exit;
    }

    $baseDir = __DIR__;

    function isAllowedExtension($filename) {
      return true; // All file extensions allowed
    }

    function save_file_version($filepath) {
      global $baseDir;
      if (!file_exists($filepath) || is_dir($filepath)) return;
      $filename = basename($filepath);
      $verDir = $baseDir . '/.file_version/' . $filename;
      if (!is_dir($verDir)) @mkdir($verDir, 0755, true);
      $date = date('Y-m-d_H-i-s');
      @copy($filepath, $verDir . '/' . $filename . '_' . $date);
    }

    function generateUniqueFileName($dir, $filename) {
      $baseName = pathinfo($filename, PATHINFO_FILENAME);
      $extension = pathinfo($filename, PATHINFO_EXTENSION);
      $counter = 1;
      while (file_exists($dir . '/' . $baseName . '_' . $counter . '.' . $extension)) {
        $counter++;
      }
      return $baseName . '_' . $counter . '.' . $extension;
    }

    function generateUniqueFolderName($dir, $foldername) {
      $counter = 1;
      while (is_dir($dir . '/' . $foldername . '_' . $counter)) {
        $counter++;
      }
      return $foldername . '_' . $counter;
    }

    function recursiveCopy($src, $dst) {
      if (is_dir($src)) {
        @mkdir($dst);
        $items = scandir($src);
        foreach ($items as $item) {
          if ($item === '.' || $item === '..') continue;
          recursiveCopy($src . '/' . $item, $dst . '/' . $item);
        }
      } else if (file_exists($src)) {
        copy($src, $dst);
      }
    }

    function isValidPath($base, $path) {
      $realBase = realpath($base);
      $realPath = realpath($path);
      if ($realPath === false) return false;
      return strpos($realPath, $realBase) === 0;
    }

    function recursiveDelete($dir) {
      global $baseDir;
      if (!isValidPath($baseDir, $dir)) return false;
      if (is_file($dir)) return unlink($dir);
      if (!is_dir($dir)) return false;
      $items = array_diff(scandir($dir), ['.', '..']);
      foreach ($items as $item) {
        $path = $dir . '/' . $item;
        is_dir($path) ? recursiveDelete($path) : unlink($path);
      }
      return rmdir($dir);
    }

    function formatBytes($bytes, $precision = 2) {
      $units = ['B', 'KB', 'MB', 'GB', 'TB'];
      $bytes = max($bytes, 0);
      $pow = floor(($bytes ? log($bytes) : 0) / log(1024));
      $pow = min($pow, count($units) - 1);
      $bytes /= (1 << (10 * $pow));
      return round($bytes, $precision) . ' ' . $units[$pow];
    }

    function logDriveActivity($fileName, $filePath, $action) {
      try {
        $db = get_db();
        $stmt = $db->prepare("INSERT INTO drive_activity (file_name, file_path, action, timestamp) VALUES (?, ?, ?, ?)");
        $stmt->execute([$fileName, $filePath, $action, time()]);
      } catch (Exception $e) {}
    }

    $db = get_db();
    $db->exec("
      CREATE TABLE IF NOT EXISTS drive_starred (
        path TEXT PRIMARY KEY
      );
      CREATE TABLE IF NOT EXISTS drive_trash (
        uniq TEXT PRIMARY KEY,
        original_name TEXT,
        original_parent TEXT,
        deleted_at INTEGER
      );
      CREATE TABLE IF NOT EXISTS drive_shares (
        token TEXT PRIMARY KEY,
        path TEXT
      );
      CREATE TABLE IF NOT EXISTS drive_activity (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        file_name TEXT,
        file_path TEXT,
        action TEXT,
        timestamp INTEGER
      );
    ");

    function cleanupExpiredTrash() {
      global $baseDir;
      $db = get_db();
      $thirtyDays = 30 * 24 * 60 * 60;
      $now = time();
      $trashBin = $baseDir . '/.drive_trash_bin';

      $stmt = $db->prepare("SELECT uniq FROM drive_trash WHERE (? - deleted_at) > ?");
      $stmt->execute([$now, $thirtyDays]);
      $expired = $stmt->fetchAll(PDO::FETCH_COLUMN);

      $delStmt = $db->prepare("DELETE FROM drive_trash WHERE uniq = ?");
      foreach ($expired as $uniq) {
        $full = $trashBin . '/' . $uniq;
        if (file_exists($full)) {
          recursiveDelete($full);
        }
        $delStmt->execute([$uniq]);
      }
    }

    function streamFileRange($filePath) {
      $size = filesize($filePath);
      $length = $size;
      $start = 0;
      $end = $size - 1;
      $ext = strtolower(pathinfo($filePath, PATHINFO_EXTENSION));
      $mimeTypes = [
        'mp3' => 'audio/mpeg', 'wav' => 'audio/wav', 'ogg' => 'audio/ogg',
        'mp4' => 'video/mp4', 'webm' => 'video/webm', 'pdf' => 'application/pdf',
        'png' => 'image/png', 'jpg' => 'image/jpeg', 'jpeg' => 'image/jpeg', 'gif' => 'image/gif',
        'txt' => 'text/plain', 'html' => 'text/plain', 'css' => 'text/plain',
        'js' => 'text/plain', 'json' => 'text/plain', 'xml' => 'text/plain',
        'php' => 'text/plain'
      ];
      $mime = $mimeTypes[$ext] ?? 'application/octet-stream';
      
      header("Content-Disposition: inline; filename=\"" . basename($filePath) . "\"");
      header("Accept-Ranges: bytes");
      if (isset($_SERVER['HTTP_RANGE'])) {
        $c_start = $start;
        $c_end = $end;
        list(, $range) = explode('=', $_SERVER['HTTP_RANGE'], 2);
        if (strpos($range, ',') !== false) {
          header('HTTP/1.1 416 Requested Range Not Satisfiable');
          header("Content-Range: bytes $start-$end/$size");
          exit;
        }
        if ($range == '-') {
          $c_start = $size - substr($range, 1);
        } else {
          $range = explode('-', $range);
          $c_start = $range[0];
          $c_end = (isset($range[1]) && is_numeric($range[1])) ? $range[1] : $size - 1;
        }
        $c_end = ($c_end > $end) ? $end : $c_end;
        if ($c_start > $c_end || $c_start > $size - 1 || $c_end >= $size) {
          header('HTTP/1.1 416 Requested Range Not Satisfiable');
          header("Content-Range: bytes $start-$end/$size");
          exit;
        }
        $start = $c_start;
        $end = $c_end;
        $length = $end - $start + 1;
        header('HTTP/1.1 206 Partial Content');
        header("Content-Range: bytes $start-$end/$size");
      }
      header("Content-Length: " . $length);
      header("Content-Type: " . $mime);
      
      $fp = fopen($filePath, 'rb');
      fseek($fp, $start);
      $bytesLeft = $length;
      $bufferSize = 1024 * 8;
      while (!feof($fp) && $bytesLeft > 0) {
        if (connection_aborted()) break;
        $readSize = min($bufferSize, $bytesLeft);
        $data = fread($fp, $readSize);
        if ($data === false || strlen($data) === 0) break;
        echo $data;
        flush();
        $bytesLeft -= strlen($data);
      }
      fclose($fp);
    }

    if (isset($_GET['share'])) {
      $token = $_GET['share'];
      $db = get_db();
      $stmt = $db->prepare("SELECT path FROM drive_shares WHERE token = ?");
      $stmt->execute([$token]);
      $relFile = $stmt->fetchColumn();
      if ($relFile) {
        $fullFile = $baseDir . '/' . $relFile;
        if (file_exists($fullFile) && isAllowedExtension($fullFile)) {
          streamFileRange($fullFile);
          exit;
        }
      }
      http_response_code(404);
      echo "<h1>Link Expired or Invalid</h1>";
      exit;
    }

    $api = $_GET['api'] ?? null;
    $action = $_GET['action'] ?? null;
    $reqPath = $_GET['path'] ?? '';
    $absPath = $baseDir;

    if ($reqPath) {
      $propPath = $baseDir . '/' . $reqPath;
      if (isValidPath($baseDir, $propPath)) {
        $absPath = $propPath;
      } else {
        if ($api) {
          header('Content-Type: application/json');
          echo json_encode(['success' => false, 'error' => 'Invalid path access']);
          exit;
        }
      }
    }

    if ($api) {
      cleanupExpiredTrash();

      if ($action === 'thumb') {
        while (ob_get_level()) ob_end_clean();
        $file = $_GET['file'] ?? '';
        $full = $baseDir . '/' . $file;
        if (!isValidPath($baseDir, $full) || !is_file($full) || !isAllowedExtension($file)) {
          http_response_code(404);
          exit;
        }
        
        $ext = strtolower(pathinfo($file, PATHINFO_EXTENSION));
        $isImage = in_array($ext, ['png', 'jpg', 'jpeg', 'gif']);
        
        if ($ext === 'svg') {
          header('Content-Type: image/svg+xml');
          readfile($full);
          exit;
        }
        
        if ($isImage) {
          $thumbDir = $baseDir . '/.drive_thumbnails';
          if (!is_dir($thumbDir)) @mkdir($thumbDir, 0755, true);
          $hash = md5($full . filemtime($full));
          $thumbPath = $thumbDir . '/' . $hash . '.webp';
          
          if (!file_exists($thumbPath)) {
            if (function_exists('imagecreatefromstring')) {
              @ini_set('memory_limit', '256M');
              $content = @file_get_contents($full);
              if ($content) {
                $img = @imagecreatefromstring($content);
                if ($img) {
                  $width = imagesx($img);
                  $height = imagesy($img);
                  $newWidth = 320;
                  $newHeight = floor($height * ($newWidth / $width));
                  $tmp = imagecreatetruecolor($newWidth, $newHeight);
                  if ($ext === 'png' || $ext === 'gif') {
                    imagealphablending($tmp, false);
                    imagesavealpha($tmp, true);
                    $transparent = imagecolorallocatealpha($tmp, 255, 255, 255, 127);
                    imagefilledrectangle($tmp, 0, 0, $newWidth, $newHeight, $transparent);
                  }
                  imagecopyresampled($tmp, $img, 0, 0, 0, 0, $newWidth, $newHeight, $width, $height);
                  @imagewebp($tmp, $thumbPath, 50);
                  imagedestroy($img);
                  imagedestroy($tmp);
                }
              }
            }
          }
          
          if (file_exists($thumbPath)) {
            header('Content-Type: image/webp');
            header('Content-Length: ' . filesize($thumbPath));
            readfile($thumbPath);
            exit;
          }
        }
        
        streamFileRange($full);
        exit;
      }

      if ($action === 'stream') {
        while (ob_get_level()) ob_end_clean();
        $file = $_GET['file'] ?? '';
        $full = $baseDir . '/' . $file;
        if (!isValidPath($baseDir, $full) || !is_file($full) || !isAllowedExtension($file)) {
          http_response_code(404);
          exit;
        }
        streamFileRange($full);
        exit;
      }

      header('Content-Type: application/json');
      ob_start();

      try {
        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
          $input = json_decode(file_get_contents('php://input'), true) ?? $_POST;
          $postAction = $input['action'] ?? $_POST['action'] ?? '';

          switch ($postAction) {
            case 'add_file':
              $name = $input['name'] ?? '';
              $full = $absPath . '/' . $name;
              if (file_exists($full)) throw new Exception('CONFLICT|' . basename($full));
              file_put_contents($full, '');
              logDriveActivity($name, ltrim(str_replace($baseDir, '', $full), '/'), 'created');
              echo json_encode(['success' => true]);
              break;

            case 'add_folder':
              $name = $input['name'] ?? '';
              $full = $absPath . '/' . $name;
              if (file_exists($full)) throw new Exception('CONFLICT|' . basename($full));
              mkdir($full);
              logDriveActivity($name, ltrim(str_replace($baseDir, '', $full), '/'), 'created');
              echo json_encode(['success' => true]);
              break;

            case 'upload':
              if (!isset($_FILES['files'])) throw new Exception('No files uploaded');
              $uploaded = 0;
              $paths = $_POST['paths'] ?? [];
              $chunk = isset($_POST['chunk']) ? (int)$_POST['chunk'] : 0;
              $chunks = isset($_POST['chunks']) ? (int)$_POST['chunks'] : 1;
              $fileId = $_POST['file_id'] ?? 'unknown';
              $override = !empty($_POST['override']);

              foreach ($_FILES['files']['name'] as $i => $name) {
                $relPathClean = !empty($paths[$i]) ? ltrim(str_replace(['..', '\\'], ['', '/'], $paths[$i]), '/') : $name;
                $dest = $absPath . '/' . $relPathClean;
                $targetDir = dirname($dest);
                if (!is_dir($targetDir)) mkdir($targetDir, 0755, true);

                if ($chunk === 0 && file_exists($dest) && !$override) {
                  echo json_encode(['success' => false, 'error' => 'CONFLICT|' . basename($dest)]);
                  exit;
                }
                if ($chunk === 0 && file_exists($dest) && $override) {
                  save_file_version($dest);
                }

                if ($chunks > 1) {
                  $tempDest = $targetDir . '/.temp_upload_' . md5($fileId . $name);
                  $out = @fopen($tempDest, $chunk === 0 ? 'wb' : 'ab');
                  if ($out) {
                    $in = @fopen($_FILES['files']['tmp_name'][$i], 'rb');
                    if ($in) { stream_copy_to_stream($in, $out); fclose($in); }
                    fclose($out);
                  }
                  if ($chunk == $chunks - 1) {
                    rename($tempDest, $dest);
                    $uploaded++;
                    logDriveActivity(basename($dest), ltrim(str_replace($baseDir, '', $dest), '/'), 'uploaded');
                  }
                } else {
                  if (move_uploaded_file($_FILES['files']['tmp_name'][$i], $dest)) {
                    $uploaded++;
                    logDriveActivity(basename($dest), ltrim(str_replace($baseDir, '', $dest), '/'), 'uploaded');
                  }
                }
              }
              echo json_encode(['success' => true, 'uploaded' => $uploaded]);
              break;

            case 'upload_url':
              $url = $input['url'] ?? '';
              $override = !empty($input['override']);
              $name = basename(parse_url($url, PHP_URL_PATH));
              if (!$name) $name = 'downloaded_file_' . time();
              $target = $absPath . '/' . $name;
              if (file_exists($target) && !$override) throw new Exception('CONFLICT|' . $name);
              if (file_exists($target) && $override) save_file_version($target);
              file_put_contents($target, file_get_contents($url));
              logDriveActivity($name, ltrim(str_replace($baseDir, '', $target), '/'), 'uploaded via url');
              echo json_encode(['success' => true]);
              break;

            case 'zip_items':
              $items = $input['items'] ?? [];
              if (empty($items)) throw new Exception('No items selected');
              $zipName = (count($items) === 1) ? basename($items[0]) . '.zip' : 'Archive_' . date('Ymd_His') . '.zip';
              $target = $absPath . '/' . $zipName;
              if (file_exists($target) && empty($input['override'])) throw new Exception('CONFLICT|' . $zipName);
              if (file_exists($target)) save_file_version($target);
              
              $zip = new ZipArchive();
              if ($zip->open($target, ZipArchive::CREATE | ZipArchive::OVERWRITE)) {
                foreach ($items as $item) {
                  $src = $baseDir . '/' . $item;
                  if (is_file($src)) $zip->addFile($src, basename($src));
                  elseif (is_dir($src)) {
                    $iter = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($src, FilesystemIterator::SKIP_DOTS));
                    foreach ($iter as $f) {
                      if ($f->isFile()) $zip->addFile($f->getPathname(), basename($src) . '/' . str_replace($src . '/', '', $f->getPathname()));
                    }
                  }
                }
                $zip->close();
              }
              logDriveActivity($zipName, ltrim(str_replace($baseDir, '', $target), '/'), 'archived');
              echo json_encode(['success' => true]);
              break;

            case 'encrypt_file':
            case 'decrypt_file':
              $file = $input['file'] ?? '';
              $src = $baseDir . '/' . $file;
              if (!file_exists($src) || is_dir($src)) throw new Exception('Invalid file');
              
              $admin_stmt = get_db()->query("SELECT password_hash FROM users WHERE email = 'musiclibrary@mail.com'");
              $admin_hash = $admin_stmt->fetchColumn() ?: 'fallback_secure_key_123!';
              $secret_key = substr(hash('sha256', $admin_hash), 0, 32);
              $content = file_get_contents($src);
              
              if ($postAction === 'encrypt_file') {
                $target = $src . '.enc';
                if (file_exists($target) && empty($input['override'])) throw new Exception('CONFLICT|' . basename($target));
                $iv = random_bytes(16);
                $encrypted = openssl_encrypt($content, 'aes-256-cbc', $secret_key, 0, $iv);
                file_put_contents($target, base64_encode($iv) . ':' . $encrypted);
                unlink($src);
              } else {
                if (substr($src, -4) !== '.enc') throw new Exception('Not an encrypted file');
                $target = substr($src, 0, -4);
                if (file_exists($target) && empty($input['override'])) throw new Exception('CONFLICT|' . basename($target));
                $parts = explode(':', $content, 2);
                $iv = base64_decode($parts[0]);
                $decrypted = openssl_decrypt($parts[1], 'aes-256-cbc', $secret_key, 0, $iv);
                if ($decrypted === false) throw new Exception('Decryption failed. Incorrect key or corrupted file.');
                file_put_contents($target, $decrypted);
                unlink($src);
              }
              logDriveActivity(basename($target), ltrim(str_replace($baseDir, '', $target), '/'), $postAction === 'encrypt_file' ? 'encrypted' : 'decrypted');
              echo json_encode(['success' => true]);
              break;

            case 'get_versions':
              $file = $input['file'] ?? '';
              $verDir = $baseDir . '/.file_version/' . basename($file);
              $versions = [];
              if (is_dir($verDir)) {
                foreach (array_diff(scandir($verDir), ['.', '..']) as $v) {
                  $versions[] = ['name' => $v, 'mtime' => filemtime($verDir . '/' . $v), 'size' => formatBytes(filesize($verDir . '/' . $v))];
                }
                usort($versions, function($a, $b) { return $b['mtime'] - $a['mtime']; });
              }
              echo json_encode(['success' => true, 'versions' => $versions]);
              break;

            case 'restore_version':
              $file = $input['file'] ?? '';
              $version_name = $input['version_name'] ?? '';
              $src = $baseDir . '/.file_version/' . basename($file) . '/' . $version_name;
              $dest = $baseDir . '/' . $file;
              if (!file_exists($src)) throw new Exception('Version not found');
              save_file_version($dest); // Backup current state before restoring
              copy($src, $dest);
              logDriveActivity(basename($dest), $file, 'restored version');
              echo json_encode(['success' => true]);
              break;

            case 'trash':
              $items = $input['items'] ?? [];
              $db = get_db();
              $trashBin = $baseDir . '/.drive_trash_bin';
              if (!is_dir($trashBin)) mkdir($trashBin, 0755, true);
              
              $insStmt = $db->prepare("INSERT INTO drive_trash (uniq, original_name, original_parent, deleted_at) VALUES (?, ?, ?, ?)");
              foreach ($items as $itemPath) {
                $full = $baseDir . '/' . $itemPath;
                if (isValidPath($baseDir, $full) && file_exists($full)) {
                  $itemName = basename($itemPath);
                  $uniq = uniqid() . '_' . $itemName;
                  $trashPath = $trashBin . '/' . $uniq;
                  if (rename($full, $trashPath)) {
                    $insStmt->execute([$uniq, $itemName, ltrim(str_replace($baseDir, '', dirname($full)), '/'), time()]);
                    logDriveActivity($itemName, $itemPath, 'deleted');
                  }
                }
              }
              echo json_encode(['success' => true]);
              break;

            case 'restore_trash':
              $items = $input['items'] ?? [];
              $db = get_db();
              $trashBin = $baseDir . '/.drive_trash_bin';
              
              $selectStmt = $db->prepare("SELECT original_name, original_parent FROM drive_trash WHERE uniq = ?");
              $delStmt = $db->prepare("DELETE FROM drive_trash WHERE uniq = ?");
              foreach ($items as $uniq) {
                $selectStmt->execute([$uniq]);
                $info = $selectStmt->fetch(PDO::FETCH_ASSOC);
                if ($info) {
                  $targetDir = $baseDir . '/' . $info['original_parent'];
                  if (!is_dir($targetDir)) $targetDir = $baseDir;
                  $dest = $targetDir . '/' . $info['original_name'];
                  if (file_exists($dest) && empty($input['override'])) throw new Exception('CONFLICT|' . $info['original_name']);
                  if (file_exists($dest) && !empty($input['override'])) save_file_version($dest);
                  if (rename($trashBin . '/' . $uniq, $dest)) {
                    $delStmt->execute([$uniq]);
                    logDriveActivity(basename($dest), ltrim(str_replace($baseDir, '', $dest), '/'), 'restored');
                  }
                }
              }
              echo json_encode(['success' => true]);
              break;

            case 'delete_perm':
              $items = $input['items'] ?? [];
              $db = get_db();
              $trashBin = $baseDir . '/.drive_trash_bin';
              $delStmt = $db->prepare("DELETE FROM drive_trash WHERE uniq = ?");
              foreach ($items as $uniq) {
                $full = $trashBin . '/' . $uniq;
                if (file_exists($full)) {
                  recursiveDelete($full);
                  $delStmt->execute([$uniq]);
                }
              }
              echo json_encode(['success' => true]);
              break;

            case 'empty_trash':
              $trashBin = $baseDir . '/.drive_trash_bin';
              recursiveDelete($trashBin);
              mkdir($trashBin, 0755, true);
              get_db()->exec("DELETE FROM drive_trash");
              echo json_encode(['success' => true]);
              break;

            case 'rename':
              $old = $input['old'] ?? '';
              $new = $input['new'] ?? '';
              $oldFull = $baseDir . '/' . $old;
              $newFull = dirname($oldFull) . '/' . $new;
              if (!isValidPath($baseDir, $oldFull) || !file_exists($oldFull)) throw new Exception('Invalid source');
              if (file_exists($newFull) && empty($input['override'])) throw new Exception('CONFLICT|' . $new);
              if (file_exists($newFull) && !empty($input['override'])) save_file_version($newFull);
              rename($oldFull, $newFull);
              logDriveActivity($new, ltrim(str_replace($baseDir, '', $newFull), '/'), 'renamed');
              echo json_encode(['success' => true]);
              break;

            case 'write':
              $file = $input['file'] ?? '';
              $content = $input['content'] ?? '';
              $full = $baseDir . '/' . $file;
              if (!isValidPath($baseDir, $full)) throw new Exception('Invalid file');
              save_file_version($full); // Track file version before writing
              file_put_contents($full, $content);
              logDriveActivity(basename($file), $file, 'modified');
              echo json_encode(['success' => true]);
              break;

            case 'toggle_star':
              $item = $input['item'] ?? '';
              $db = get_db();
              $stmt = $db->prepare("SELECT path FROM drive_starred WHERE path = ?");
              $stmt->execute([$item]);
              if ($stmt->fetch()) {
                $db->prepare("DELETE FROM drive_starred WHERE path = ?")->execute([$item]);
                $starred = false;
              } else {
                $db->prepare("INSERT OR IGNORE INTO drive_starred (path) VALUES (?)")->execute([$item]);
                $starred = true;
              }
              echo json_encode(['success' => true, 'starred' => $starred]);
              break;

            case 'copy_items':
            case 'move_items':
              $items = $input['items'] ?? [];
              $target = $input['target'] ?? '';
              $override = !empty($input['override']);
              $targetDir = rtrim($baseDir . '/' . $target, '/');
              if (!isValidPath($baseDir, $targetDir)) throw new Exception('Invalid target');
              
              foreach ($items as $item) {
                $src = $baseDir . '/' . $item;
                if (!isValidPath($baseDir, $src) || !file_exists($src)) continue;
                $dest = $targetDir . '/' . basename($item);
                
                if (file_exists($dest) && !$override) {
                  throw new Exception('CONFLICT|' . basename($item));
                }
                if (file_exists($dest) && $override) {
                  save_file_version($dest);
                }
                
                if ($postAction === 'move_items') {
                  if ($src !== $dest) rename($src, $dest);
                } else {
                  recursiveCopy($src, $dest);
                }
              }
              echo json_encode(['success' => true]);
              break;

            case 'create_share':
              $item = $input['item'] ?? '';
              $token = md5($item . time());
              get_db()->prepare("INSERT INTO drive_shares (token, path) VALUES (?, ?)")->execute([$token, $item]);
              echo json_encode(['success' => true, 'token' => $token]);
              break;

            case 'unzip':
              $item = $input['item'] ?? '';
              $src = $baseDir . '/' . $item;
              if (!isValidPath($baseDir, $src) || !file_exists($src) || strtolower(pathinfo($src, PATHINFO_EXTENSION)) !== 'zip') {
                throw new Exception('Invalid zip file');
              }
              $zip = new ZipArchive;
              if ($zip->open($src) === TRUE) {
                $folderName = pathinfo($src, PATHINFO_FILENAME);
                $parentDir = dirname($src);
                $extractTarget = $parentDir . '/' . $folderName;
                if (file_exists($extractTarget) && empty($input['override'])) throw new Exception('CONFLICT|' . $folderName);
                if (!file_exists($extractTarget)) mkdir($extractTarget, 0755, true);
                $zip->extractTo($extractTarget);
                $zip->close();
                logDriveActivity(basename($extractTarget), ltrim(str_replace($baseDir, '', $extractTarget), '/'), 'extracted');
                echo json_encode(['success' => true]);
              } else {
                throw new Exception('Failed to extract ZIP');
              }
              break;

            default:
              throw new Exception('Unknown POST action');
          }
        } else {
          switch ($action) {
            case 'search_drive':
              $q = strtolower($_GET['q'] ?? '');
              $db = get_db();
              $starredPaths = $db->query("SELECT path FROM drive_starred")->fetchAll(PDO::FETCH_COLUMN);
              $folders = [];
              $files = [];
              if ($q !== '') {
                $iter = new RecursiveIteratorIterator(
                  new RecursiveDirectoryIterator($baseDir, FilesystemIterator::SKIP_DOTS),
                  RecursiveIteratorIterator::SELF_FIRST
                );
                foreach ($iter as $item) {
                  $pathName = $item->getPathname();
                  if (strpos($pathName, '.drive_trash_bin') !== false || strpos($pathName, '.drive_thumbnails') !== false || strpos($pathName, '.file_version') !== false) {
                    continue;
                  }
                  $filename = $item->getFilename();
                  if (stripos($filename, $q) !== false) {
                    $rel = ltrim(str_replace($baseDir, '', $pathName), '/');
                    $rel = str_replace('\\', '/', $rel);
                    $stat = stat($pathName);
                    $starred = in_array($rel, $starredPaths);
                    if ($item->isDir()) {
                      $folders[] = [
                        'name' => $filename,
                        'path' => $rel,
                        'mtime' => $stat['mtime'],
                        'size' => 0,
                        'formatSize' => '-',
                        'ext' => '',
                        'isImage' => false,
                        'starred' => $starred
                      ];
                    } elseif ($item->isFile() && isAllowedExtension($filename)) {
                      $ext = strtolower(pathinfo($filename, PATHINFO_EXTENSION));
                      $files[] = [
                        'name' => $filename,
                        'path' => $rel,
                        'mtime' => $stat['mtime'],
                        'size' => $stat['size'],
                        'formatSize' => formatBytes($stat['size']),
                        'ext' => $ext,
                        'isImage' => in_array($ext, ['png', 'jpg', 'jpeg', 'gif', 'svg']),
                        'starred' => $starred
                      ];
                    }
                  }
                }
              }
              echo json_encode(['success' => true, 'folders' => array_slice($folders, 0, 50), 'files' => array_slice($files, 0, 100)]);
              break;

            case 'list':
              $db = get_db();
              $starredPaths = $db->query("SELECT path FROM drive_starred")->fetchAll(PDO::FETCH_COLUMN);
              $files = [];
              $folders = [];
              $items = array_diff(scandir($absPath), ['.', '..', '.drive_trash_bin', '.drive_thumbnails']);
              foreach ($items as $item) {
                $path = $absPath . '/' . $item;
                $stat = stat($path);
                $ext = strtolower(pathinfo($item, PATHINFO_EXTENSION));
                $rel = ltrim(str_replace($baseDir, '', $path), '/');
                $starred = in_array($rel, $starredPaths);
                
                $itemMeta = [
                  'name' => $item,
                  'path' => $rel,
                  'mtime' => $stat['mtime'],
                  'size' => $stat['size'],
                  'formatSize' => formatBytes($stat['size']),
                  'ext' => $ext,
                  'isImage' => in_array($ext, ['png', 'jpg', 'jpeg', 'gif', 'svg']),
                  'starred' => $starred
                ];
                if (is_dir($path)) {
                  $folders[] = $itemMeta;
                } elseif (is_file($path) && isAllowedExtension($item)) {
                  $files[] = $itemMeta;
                }
              }
              
              $pathDisplay = ltrim(str_replace($baseDir, '', $absPath), '/');
              $breadcrumbs = [];
              if (!empty($pathDisplay)) {
                $segments = explode('/', $pathDisplay);
                $curr = '';
                foreach ($segments as $seg) {
                  if (empty($seg)) continue;
                  $curr .= $seg . '/';
                  $breadcrumbs[] = ['name' => $seg, 'path' => rtrim($curr, '/')];
                }
              }
              
              echo json_encode([
                'success' => true, 
                'folders' => $folders, 
                'files' => $files, 
                'breadcrumbs' => $breadcrumbs
              ]);
              break;

            case 'list_trash':
              $db = get_db();
              $trashList = [];
              $rows = $db->query("SELECT uniq, original_name, original_parent, deleted_at FROM drive_trash ORDER BY deleted_at DESC")->fetchAll(PDO::FETCH_ASSOC);
              foreach ($rows as $info) {
                $trashList[] = [
                  'uniq' => $info['uniq'],
                  'name' => $info['original_name'],
                  'original_parent' => $info['original_parent'],
                  'deleted_at' => date("Y-m-d H:i:s", $info['deleted_at'])
                ];
              }
              echo json_encode(['success' => true, 'trash' => $trashList]);
              break;

            case 'list_file_versions':
              $historyList = [];
              $verDir = $baseDir . '/.file_version';
              if (is_dir($verDir)) {
                $iter = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($verDir, FilesystemIterator::SKIP_DOTS));
                foreach ($iter as $file) {
                  if ($file->isFile()) {
                    $origName = basename(dirname($file->getPathname()));
                    $historyList[] = [
                      'name' => $file->getFilename(),
                      'path' => ltrim(str_replace($baseDir, '', $file->getPathname()), '/'),
                      'mtime' => $file->getMTime(),
                      'size' => $file->getSize(),
                      'formatSize' => formatBytes($file->getSize()),
                      'ext' => strtolower($file->getExtension()),
                      'isImage' => in_array(strtolower($file->getExtension()), ['png', 'jpg', 'jpeg', 'gif', 'svg']),
                      'starred' => false,
                      'original_file' => $origName
                    ];
                  }
                }
                usort($historyList, function($a, $b) { return $b['mtime'] - $a['mtime']; });
              }
              echo json_encode(['success' => true, 'history_files' => $historyList]);
              break;

            case 'list_history':
              $historyFiles = [];
              $verDir = $baseDir . '/.file_version';
              if (is_dir($verDir)) {
                $iter = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($verDir, FilesystemIterator::SKIP_DOTS));
                foreach ($iter as $file) {
                  if ($file->isFile()) {
                    $origName = basename(dirname($file->getPathname()));
                    $ext = strtolower(pathinfo($origName, PATHINFO_EXTENSION));
                    $historyFiles[] = [
                      'name' => $file->getFilename() . ' (Version of ' . $origName . ')',
                      'path' => ltrim(str_replace($baseDir, '', $file->getPathname()), '/'),
                      'mtime' => $file->getMTime(),
                      'size' => $file->getSize(),
                      'formatSize' => formatBytes($file->getSize()),
                      'ext' => $ext,
                      'isImage' => in_array($ext, ['png', 'jpg', 'jpeg', 'gif', 'svg']),
                      'starred' => false,
                      'is_version' => true,
                      'original_file' => $origName,
                      'version_name' => $file->getFilename()
                    ];
                  }
                }
                usort($historyFiles, function($a, $b) { return $b['mtime'] - $a['mtime']; });
              }
              echo json_encode(['success' => true, 'history' => $historyFiles]);
              break;

            case 'list_starred':
              $db = get_db();
              $starredPaths = $db->query("SELECT path FROM drive_starred")->fetchAll(PDO::FETCH_COLUMN);
              $starredList = [];
              foreach ($starredPaths as $rel) {
                $full = $baseDir . '/' . $rel;
                if (file_exists($full)) {
                  $stat = stat($full);
                  $ext = strtolower(pathinfo($rel, PATHINFO_EXTENSION));
                  $starredList[] = [
                    'name' => basename($rel),
                    'path' => $rel,
                    'parent' => dirname($rel) === '.' ? '' : dirname($rel),
                    'isDir' => is_dir($full),
                    'mtime' => $stat['mtime'],
                    'size' => $stat['size'],
                    'formatSize' => formatBytes($stat['size']),
                    'ext' => $ext,
                    'isImage' => in_array($ext, ['png', 'jpg', 'jpeg', 'gif', 'svg'])
                  ];
                }
              }
              echo json_encode(['success' => true, 'starred' => $starredList]);
              break;

            case 'activity':
              $db = get_db();
              // Housekeeping: purge activity records older than 90 days to keep the database fast
              $ninetyDaysAgo = time() - (90 * 24 * 60 * 60);
              $db->prepare("DELETE FROM drive_activity WHERE timestamp < ?")->execute([$ninetyDaysAgo]);

              $stmt = $db->prepare("SELECT file_name, file_path, action, timestamp FROM drive_activity ORDER BY timestamp DESC LIMIT 50");
              $stmt->execute();
              $rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
              
              $grouped = [];
              $today = strtotime("today");
              $yesterday = strtotime("yesterday");
              $week = strtotime("-1 week");
              
              foreach ($rows as $row) {
                if ($row['timestamp'] >= $today) $group = 'Today';
                elseif ($row['timestamp'] >= $yesterday) $group = 'Yesterday';
                elseif ($row['timestamp'] >= $week) $group = 'Previous 7 Days';
                else $group = date('F Y', $row['timestamp']);
                
                $grouped[$group][] = [
                  'name' => $row['file_name'],
                  'path' => $row['file_path'],
                  'action' => $row['action'],
                  'mtime' => $row['timestamp']
                ];
              }
              echo json_encode(['success' => true, 'activity' => $grouped]);
              break;

            case 'recents':
              $db = get_db();
              $limit = isset($_GET['all']) ? 100 : 15;
              $recentFiles = [];
              
              // Optimized Directory Scanner: Skip scanning massive or irrelevant system directories
              $dir = new RecursiveDirectoryIterator($baseDir, FilesystemIterator::SKIP_DOTS);
              $filter = new RecursiveCallbackFilterIterator($dir, function ($current) {
                $exclude = ['getid3', '.drive_trash_bin', '.drive_thumbnails', '.git', 'uploads', 'covers', 'brain'];
                if ($current->isDir() && in_array($current->getFilename(), $exclude)) {
                  return false;
                }
                return true;
              });
              
              $iter = new RecursiveIteratorIterator($filter);
              foreach ($iter as $file) {
                if ($file->isFile() && isAllowedExtension($file->getFilename())) {
                  $path = $file->getPathname();
                  $recentFiles[] = [
                    'name' => $file->getFilename(),
                    'path' => ltrim(str_replace($baseDir, '', $path), '/'),
                    'mtime' => $file->getMTime(),
                    'size' => $file->getSize(),
                    'formatSize' => formatBytes($file->getSize()),
                    'ext' => strtolower($file->getExtension()),
                    'isImage' => in_array(strtolower($file->getExtension()), ['png', 'jpg', 'jpeg', 'gif', 'svg'])
                  ];
                }
              }
              usort($recentFiles, function($a, $b) { return $b['mtime'] - $a['mtime']; });
              echo json_encode(['success' => true, 'recents' => array_slice($recentFiles, 0, $limit)]);
              break;

            case 'read':
              $file = $_GET['file'] ?? '';
              $full = $baseDir . '/' . $file;
              if (!isValidPath($baseDir, $full) || !is_file($full) || !isAllowedExtension($file)) throw new Exception('Invalid file');
              echo json_encode(['success' => true, 'content' => file_get_contents($full)]);
              break;

            case 'properties':
              $file = $_GET['file'] ?? '';
              $full = $baseDir . '/' . $file;
              if (!isValidPath($baseDir, $full) || !file_exists($full)) throw new Exception('Invalid item');
              $stat = stat($full);
              $is_dir = is_dir($full);
              $size = $stat['size'];
              $typeStr = $is_dir ? 'Folder' : 'File (' . strtoupper(pathinfo($file, PATHINFO_EXTENSION)) . ')';
              $contentStr = '';
              
              if ($is_dir) {
                $total_files = 0;
                $total_folders = 0;
                $total_size = 0;
                // Calculate folder bulk size and recursive contents
                $iter = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($full, FilesystemIterator::SKIP_DOTS), RecursiveIteratorIterator::SELF_FIRST);
                foreach ($iter as $f) {
                  if ($f->isDir()) {
                    $total_folders++;
                  } else {
                    $total_files++;
                    $total_size += $f->getSize();
                  }
                }
                $size = $total_size;
                $contentStr = $total_files . ' files, ' . $total_folders . ' folders';
              }

              echo json_encode([
                'success' => true,
                'data' => [
                  'name' => basename($file),
                  'type' => $typeStr,
                  'size' => formatBytes($size),
                  'contents' => $contentStr,
                  'modified' => date("Y-m-d H:i:s", $stat['mtime']),
                  'created' => date("Y-m-d H:i:s", $stat['ctime']),
                  'permissions' => substr(sprintf('%o', fileperms($full)), -4)
                ]
              ]);
              break;

            default:
              throw new Exception('Unknown GET action');
          }
        }
      } catch (Exception $e) {
        echo json_encode(['success' => false, 'error' => $e->getMessage()]);
      }
      ob_end_flush();
      exit;
    }

    if (isset($_GET['download'])) {
      $file = $_GET['download'];
      $full = $baseDir . '/' . $file;
      if (isValidPath($baseDir, $full) && is_file($full) && isAllowedExtension($file)) {
        header('Content-Type: application/octet-stream');
        header('Content-Disposition: attachment; filename="' . basename($full) . '"');
        header('Content-Length: ' . filesize($full));
        readfile($full);
      }
      exit;
    }

    if (isset($_GET['batch'])) {
      $type = $_GET['batch'];
      $zip = new ZipArchive();
      $zipName = 'download_' . date('Ymd_His') . '.zip';
      
      if ($zip->open($zipName, ZipArchive::CREATE) === TRUE) {
        if ($type === 'context') {
          $iter = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($absPath, FilesystemIterator::SKIP_DOTS));
          foreach ($iter as $file) {
            if ($file->isFile() && isAllowedExtension($file->getFilename())) {
              $localPath = ltrim(str_replace($absPath, '', $file->getPathname()), '/');
              $zip->addFile($file->getPathname(), $localPath);
            }
          }
        } elseif ($type === 'selected' && isset($_GET['items'])) {
          $items = explode(',', $_GET['items']);
          foreach ($items as $item) {
            $full = $baseDir . '/' . $item;
            if (isValidPath($baseDir, $full) && file_exists($full)) {
              if (is_file($full) && isAllowedExtension($item)) {
                $zip->addFile($full, basename($item));
              } elseif (is_dir($full)) {
                $iter = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($full, FilesystemIterator::SKIP_DOTS));
                foreach ($iter as $f) {
                  if ($f->isFile() && isAllowedExtension($f->getFilename())) {
                    $localPath = ltrim(str_replace($baseDir, '', $f->getPathname()), '/');
                    $zip->addFile($f->getPathname(), $localPath);
                  }
                }
              }
            }
          }
        }
        $zip->close();
        header('Content-Type: application/zip');
        header('Content-Disposition: attachment; filename=' . $zipName);
        header('Content-Length: ' . filesize($zipName));
        readfile($zipName);
        unlink($zipName);
      }
      exit;
    }
  }

  if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_SESSION['admin_logged_in']) && $_SESSION['admin_logged_in'] === true) {
    if (!isset($_POST['csrf_token']) || !hash_equals($_SESSION['admin_csrf_token'], $_POST['csrf_token'])) {
      die("Security violation: CSRF token mismatch.");
    }

    function log_admin_activity($db, $admin_email, $action, $target_user_id) {
      $stmt = $db->prepare("SELECT email FROM users WHERE id = ?");
      $stmt->execute([$target_user_id]);
      $target_email = $stmt->fetchColumn() ?: 'Unknown';
      $db->prepare("INSERT INTO admin_logs (admin_email, action, target_user_id, target_email) VALUES (?, ?, ?, ?)")->execute([$admin_email, $action, $target_user_id, $target_email]);
    }

    if (isset($_POST['generate_reset_link']) && isset($_POST['user_id'])) {
      $db = get_db();
      $user_id = (int)$_POST['user_id'];
      $token = bin2hex(random_bytes(16));
      $db->prepare("INSERT INTO password_resets (token, user_id, expires_at) VALUES (?, ?, datetime('now', '+1 day'))")->execute([$token, $user_id]);
      $db->prepare("UPDATE users SET reset_requested = 0 WHERE id = ?")->execute([$user_id]);
      log_admin_activity($db, $_SESSION['admin_email'], 'Generated Password Reset Link', $user_id);
      
      $reset_link = (isset($_SERVER['HTTPS']) && $_SERVER['HTTPS'] === 'on' ? "https" : "http") . "://" . $_SERVER['HTTP_HOST'] . strtok($_SERVER["REQUEST_URI"], '?') . "?reset_token=" . $token;
      $_SESSION['admin_flash_msg'] = "Reset link generated for User ID $user_id. Copy & send this link to the user: $reset_link";
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['toggle_admin']) && isset($_POST['user_id'])) {
      $db = get_db();
      $user_id = (int)$_POST['user_id'];
      $stmt = $db->prepare("SELECT email FROM users WHERE id = ?");
      $stmt->execute([$user_id]);
      $target_email = $stmt->fetchColumn();
      if (strtolower(trim($target_email)) !== 'musiclibrary@mail.com') {
        $db->prepare("UPDATE users SET is_admin = CASE WHEN is_admin = 1 THEN 0 ELSE 1 END WHERE id = ?")->execute([$user_id]);
        log_admin_activity($db, $_SESSION['admin_email'], 'Toggled Admin Status', $user_id);
      }
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['toggle_verify']) && isset($_POST['user_id'])) {
      $db = get_db();
      $user_id = (int)$_POST['user_id'];
      $stmt = $db->prepare("SELECT verified FROM users WHERE id = ?");
      $stmt->execute([$user_id]);
      $current_status = $stmt->fetchColumn();
      if ($current_status) {
        $new_status = ($current_status === 'yes') ? 'no' : 'yes';
        $update_stmt = $db->prepare("UPDATE users SET verified = ? WHERE id = ?");
        $update_stmt->execute([$new_status, $user_id]);
        log_admin_activity($db, $_SESSION['admin_email'], 'Toggled Verification', $user_id);
      }
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }
    
    if (isset($_POST['toggle_ban']) && isset($_POST['user_id'])) {
      $db = get_db();
      $user_id = (int)$_POST['user_id'];
      $db->prepare("UPDATE users SET banned = CASE WHEN banned = 1 THEN 0 ELSE 1 END WHERE id = ?")->execute([$user_id]);
      log_admin_activity($db, $_SESSION['admin_email'], 'Toggled Ban Status', $user_id);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['toggle_rhythm_ban']) && isset($_POST['user_id'])) {
      $db = get_db();
      $user_id = (int)$_POST['user_id'];
      
      $stmt = $db->prepare("SELECT rhythm_strikes FROM users WHERE id = ?");
      $stmt->execute([$user_id]);
      $strikes = (int)$stmt->fetchColumn();

      if ($strikes > 0) {
        // Currently banned. Unban them but preserve their strike count as a negative history integer
        $new_strikes = -$strikes;
        $db->prepare("UPDATE users SET rhythm_strikes = ? WHERE id = ?")->execute([$new_strikes, $user_id]);
        log_admin_activity($db, $_SESSION['admin_email'], 'Unbanned from Rhythm Game (History Preserved)', $user_id);
      } else {
        // Currently allowed to play. Ban them and increment their historical strike count
        $abs_strikes = abs($strikes);
        $new_strikes = $abs_strikes + 1;
        if ($new_strikes >= 3) {
          // 3/3 reached: Trigger Full Account Ban
          $db->prepare("UPDATE users SET rhythm_strikes = 3, banned = 1 WHERE id = ?")->execute([$user_id]);
          log_admin_activity($db, $_SESSION['admin_email'], 'Rhythm Game Ban 3/3: Full Account Ban Triggered', $user_id);
        } else {
          $db->prepare("UPDATE users SET rhythm_strikes = ? WHERE id = ?")->execute([$new_strikes, $user_id]);
          log_admin_activity($db, $_SESSION['admin_email'], 'Banned from Rhythm Game (Strike ' . $new_strikes . '/3)', $user_id);
        }
      }
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['reset_rhythm_history']) && isset($_POST['user_id'])) {
      $db = get_db();
      $user_id = (int)$_POST['user_id'];
      $db->prepare("UPDATE users SET rhythm_strikes = 0, banned = 0 WHERE id = ?")->execute([$user_id]);
      log_admin_activity($db, $_SESSION['admin_email'], 'Reset Rhythm Ban History and Unbanned Account', $user_id);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['resolve_report']) && isset($_POST['report_id'])) {
      $db = get_db();
      $report_id = (int)$_POST['report_id'];
      $db->prepare("UPDATE user_reports SET status = 'resolved' WHERE id = ?")->execute([$report_id]);
      log_admin_activity($db, $_SESSION['admin_email'], 'Resolved User Report ID: ' . $report_id, 0);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['approve_appeal']) && isset($_POST['appeal_id']) && isset($_POST['user_id'])) {
      $db = get_db();
      $appeal_id = (int)$_POST['appeal_id'];
      $user_id = (int)$_POST['user_id'];
      
      $db->prepare("UPDATE ban_appeals SET status = 'approved' WHERE id = ?")->execute([$appeal_id]);
      $db->prepare("UPDATE users SET banned = 0, rhythm_strikes = 0 WHERE id = ?")->execute([$user_id]);
      
      log_admin_activity($db, $_SESSION['admin_email'], 'Approved Ban Appeal (Unbanned & Strikes Reset)', $user_id);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['reject_appeal']) && isset($_POST['appeal_id']) && isset($_POST['user_id'])) {
      $db = get_db();
      $appeal_id = (int)$_POST['appeal_id'];
      $user_id = (int)$_POST['user_id'];
      
      $db->prepare("UPDATE ban_appeals SET status = 'rejected' WHERE id = ?")->execute([$appeal_id]);
      
      log_admin_activity($db, $_SESSION['admin_email'], 'Rejected Ban Appeal', $user_id);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }
    
    if (isset($_POST['soft_delete_user']) && isset($_POST['user_id'])) {
      $db = get_db();
      $del_uid = (int)$_POST['user_id'];
      
      $db->prepare("DELETE FROM personal_notes WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM tasks WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM history WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM favorites WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM offline_songs WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM listen_later WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM messages WHERE sender_id = ? OR receiver_id = ?")->execute([$del_uid, $del_uid]);
      $db->prepare("DELETE FROM starred_messages WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM user_statuses WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM rhythm_scores WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM rhythm_favorites WHERE user_id = ?")->execute([$del_uid]);
      
      $new_email = 'deleted_' . $del_uid . '_' . time() . '@mail.com';
      $db->prepare("UPDATE users SET email = ?, artist = 'Deleted User', bio = NULL, password_hash = NULL, backup_key = NULL, profile_picture = NULL, profile_background = NULL, profile_background_type = NULL, banned = 1 WHERE id = ?")->execute([$new_email, $del_uid]);

      log_admin_activity($db, $_SESSION['admin_email'], 'Soft Deleted User', $del_uid);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['delete_rhythm_score_ajax']) && isset($_POST['score_id'])) {
      header('Content-Type: application/json');
      $score_id = (int)$_POST['score_id'];
      get_db()->prepare("DELETE FROM rhythm_scores WHERE id = ?")->execute([$score_id]);
      log_admin_activity(get_db(), $_SESSION['admin_email'], 'Deleted Rhythm Score ID: ' . $score_id, 0);
      echo json_encode(['status' => 'success']);
      exit;
    }

    if (isset($_POST['permanent_delete_user']) && isset($_POST['user_id'])) {
      $db = get_db();
      $del_uid = (int)$_POST['user_id'];
      $stmt = $db->prepare("SELECT file FROM music WHERE user_id = ?");
      $stmt->execute([$del_uid]);
      while ($row = $stmt->fetch()) {
        if ($row['file'] && file_exists($row['file'])) @unlink($row['file']);
      }
      $db->prepare("DELETE FROM starred_messages WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM user_statuses WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM rhythm_scores WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM rhythm_favorites WHERE user_id = ?")->execute([$del_uid]);
      $db->prepare("DELETE FROM users WHERE id = ?")->execute([$del_uid]);
      log_admin_activity($db, $_SESSION['admin_email'], 'Permanently Deleted User', $del_uid);
      header('Location: ' . $_SERVER['REQUEST_URI']);
      exit;
    }

    if (isset($_POST['generate_api_key'])) {
       $name = htmlspecialchars(trim($_POST['key_name'] ?? 'Unnamed App'));
       $token = 'pk_' . bin2hex(random_bytes(16));
       $expires_at = date('Y-m-d H:i:s', strtotime('+1 month'));
       get_db()->prepare("INSERT INTO api_keys (name, token, reset_month, user_id, status, expires_at) VALUES (?, ?, ?, ?, 'active', ?)")->execute([$name, $token, date('Y-m'), $_SESSION['admin_id'] ?? 0, $expires_at]);
       log_admin_activity(get_db(), $_SESSION['admin_email'], "Generated API Key: $name", 0);
       $_SESSION['admin_flash_msg'] = "Custom API Key generated successfully! Expires in 1 month.";
       header("Location: ?access=admin&page=api"); exit;
    }
    if (isset($_POST['verify_api_key'])) {
      $expires_at = date('Y-m-d H:i:s', strtotime('+1 month'));
      $token = 'pk_' . bin2hex(random_bytes(16));
      get_db()->prepare("UPDATE api_keys SET status = 'active', token = ?, expires_at = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?")->execute([$token, $expires_at, (int)$_POST['key_id']]);
      log_admin_activity(get_db(), $_SESSION['admin_email'], "Verified User API Key", 0);
      $_SESSION['admin_flash_msg'] = "API Key verified! Valid for 1 month.";
      header("Location: ?access=admin&page=api"); exit;
    }
    if (isset($_POST['ban_api_key'])) {
      get_db()->prepare("UPDATE api_keys SET status = 'banned', updated_at = CURRENT_TIMESTAMP WHERE id = ?")->execute([(int)$_POST['key_id']]);
      log_admin_activity(get_db(), $_SESSION['admin_email'], "Banned API Key", 0);
      $_SESSION['admin_flash_msg'] = "API Key banned!";
      header("Location: ?access=admin&page=api"); exit;
    }
    if (isset($_POST['unban_api_key'])) {
      get_db()->prepare("UPDATE api_keys SET status = 'active', updated_at = CURRENT_TIMESTAMP WHERE id = ?")->execute([(int)$_POST['key_id']]);
      log_admin_activity(get_db(), $_SESSION['admin_email'], "Unbanned API Key", 0);
      $_SESSION['admin_flash_msg'] = "API Key unbanned!";
      header("Location: ?access=admin&page=api"); exit;
    }
    if (isset($_POST['delete_api_key'])) {
      get_db()->prepare("DELETE FROM api_keys WHERE id = ?")->execute([(int)$_POST['key_id']]);
      log_admin_activity(get_db(), $_SESSION['admin_email'], "Revoked an API Key", 0);
      $_SESSION['admin_flash_msg'] = "API Key removed permanently!";
      header("Location: ?access=admin&page=api"); exit;
    }
        
    if (isset($_POST['reset_opcache'])) {
      if (function_exists('opcache_reset')) {
        opcache_reset();
      }
      header('Location: ?access=admin');
      exit;
    }
  }

  $admin_login_error = '';
  if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['admin_email']) && isset($_POST['admin_password'])) {
    $db = get_db();
    $stmt = $db->prepare("SELECT id, artist, password_hash, is_admin FROM users WHERE email = ?");
    $stmt->execute([$_POST['admin_email']]);
    $user = $stmt->fetch();
    
    if ($user && password_verify($_POST['admin_password'], $user['password_hash'])) {
      if ($user['is_admin'] == 1 || strtolower(trim($_POST['admin_email'])) === 'musiclibrary@mail.com') {
        $_SESSION['admin_logged_in'] = true;
        $_SESSION['admin_email'] = $_POST['admin_email'];
        $_SESSION['admin_id'] = $user['id'];
        
        // Auto-login to Main Site simultaneously
        $_SESSION['user_id'] = $user['id'];
        $_SESSION['user_artist'] = $user['artist'];
        
        setcookie('admin_session_token', hash('sha256', $user['password_hash'] . ($_SERVER['HTTP_USER_AGENT'] ?? '')), time() + 31536000, '/');
        setcookie('admin_email', $_POST['admin_email'], time() + 31536000, '/');
        header('Location: ?access=admin');
        exit;
      } else {
        $admin_login_error = "Access denied: Account is not an administrator.";
      }
    } else {
      $admin_login_error = "Invalid email or password.";
    }
  }

  if (isset($_GET['logout'])) {
    // Hard destroy the entire session to safely logout everywhere
    session_destroy();
    setcookie('admin_session_token', '', time() - 3600, '/');
    setcookie('admin_email', '', time() - 3600, '/');
    header('Location: ?access=admin');
    exit;
  }
  
  $is_admin_logged_in = isset($_SESSION['admin_logged_in']) && $_SESSION['admin_logged_in'] === true;
?>
