                      ORDER BY r.created_at DESC LIMIT ? OFFSET ?
                    ");
                    $stmt_reps->bindValue(1, (int)$rep_limit, PDO::PARAM_INT);
                    $stmt_reps->bindValue(2, (int)$rep_offset, PDO::PARAM_INT);
