                // Revert URL Bar
                const newUrl = `?access=admin&page=drive` + (this.currentPath ? `&path=${encodeURIComponent(this.currentPath).replace(/%2F/g, '/')}` : '');
                window.history.pushState({ path: this.currentPath }, '', newUrl);
