function romanize_string($string) {
  if (class_exists('Transliterator')) {
    // Uses the external ICU library to flawlessly romanize Kanji, Katakana, and Hiragana to Romaji
    $transliterator = Transliterator::create('Any-Latin; Latin-ASCII; Lower()');
    if ($transliterator) {
      $string = $transliterator->transliterate($string);
    }
  }
  $string = mb_strtolower($string, 'UTF-8');
  $string = preg_replace('/[^a-z0-9]/', '', $string);
  return empty($string) ? 'unknown' : $string;
}

function generatePhpChart($song_id, $duration, $difficulty, $density_multiplier = 1.0) {
  // 1. Highly sophisticated deterministic seed generator based on song ID and duration
  $seed_string = $song_id . '_' . $difficulty . '_' . $duration;
  $seed = crc32($seed_string) + hexdec(substr(md5($seed_string), 0, 8));
  
  // 2. Xorshift RNG for superior distribution compared to standard LCG
  $rng = function() use (&$seed) {
    $seed ^= $seed << 13;
    $seed ^= $seed >> 17;
    $seed ^= $seed << 5;
    // Keep within 32-bit unsigned bounds and return float 0.0 to 1.0
    return abs($seed % 1000000) / 1000000;
  };

  $lanesCount = ($difficulty === 'easy' || $difficulty === 'medium') ? 4 : ($difficulty === 'demon' ? 10 : 6);
  
  // 3. Dynamic base spacing calculation
  $base_spacing = 0.500;
  if ($difficulty === 'easy') $base_spacing = 0.850;
  elseif ($difficulty === 'medium') $base_spacing = 0.500;
  elseif ($difficulty === 'hard') $base_spacing = 0.320;
  elseif ($difficulty === 'expert') $base_spacing = 0.200;
  elseif ($difficulty === 'master') $base_spacing = 0.140;
  elseif ($difficulty === 'demon') $base_spacing = 0.025; // 3x extreme density for 10-lane demon

  $spacing = $base_spacing / max(0.1, min(10.0, $density_multiplier));

  $notes = [];
  $totalTime = $duration ?: 180;
  
  // 4. Advanced mechanic probabilities per difficulty tier
  $chordChance = 0.0;
  $tripleChordChance = 0.0;
  
  if ($difficulty === 'hard') { $chordChance = 0.18; }
  elseif ($difficulty === 'expert') { $chordChance = 0.35; $tripleChordChance = 0.05; }
  elseif ($difficulty === 'master') { $chordChance = 0.55; $tripleChordChance = 0.15; }
  elseif ($difficulty === 'demon') { $chordChance = 0.75; $tripleChordChance = 0.30; }
  
  $swipeChance = ($difficulty === 'easy') ? 0.0 : (($difficulty === 'medium') ? 0.08 : 0.25);
  $longChance = ($difficulty === 'demon') ? 0.10 : 0.20; // Less holds in demon, more tap stamina drain

  $lane_busy_until = array_fill(0, $lanesCount, 0.0);
  $restrict_holds = in_array($difficulty, ['easy', 'medium', 'hard']);
  $any_hold_until = 0.0;

  $is_drop = false;
  $current_step = $spacing;
  
  // 5. Chart Generation Loop with Musical Phrasing Simulation
  for ($t = 1.0; $t < $totalTime - 2.0; $t += $current_step) {
    
    // Simulate musical phrasing/drops (increases density by 20% during 'chorus' sections)
    if ($t % 20 < 1) {
      $is_drop = ($rng() > 0.5);
    }
    $current_step = $is_drop ? ($spacing * 0.8) : $spacing;

    // Add micro-stutters and syncopation to high difficulties
    if ($difficulty === 'demon' || $difficulty === 'master') {
      if ($rng() > 0.85) $current_step *= 0.5; // Double time burst
      if ($rng() > 0.96) $current_step *= 1.5; // Rest/syncopation break
    }

    if ($restrict_holds && $t < $any_hold_until) {
      continue;
    }

    $noteCount = 1;
    if ($rng() < $chordChance) $noteCount = 2;
    if ($rng() < $tripleChordChance && $lanesCount === 6) $noteCount = 3;

    $allowLong = !($restrict_holds && $noteCount > 1);
    $usedLanes = [];
    
    for ($i = 0; $i < $noteCount; $i++) {
      $lane = floor($rng() * $lanesCount) % $lanesCount;
      $attempts = 0;
      
      // Semi-random lane searching to create stairs/trills instead of vertical stacks
      while ((in_array($lane, $usedLanes) || $t < $lane_busy_until[$lane]) && $attempts < $lanesCount * 2) {
        $lane = ($lane + ($rng() > 0.5 ? 1 : -1) + $lanesCount) % $lanesCount;
        $attempts++;
      }
      if ($attempts >= $lanesCount * 2) continue;
      
      $usedLanes[] = $lane;
      
      $isLong = $allowLong && ($rng() < $longChance);
      $isSwipe = !$isLong && ($rng() < $swipeChance);
      $hitEndSwipe = $isLong && ($rng() < $swipeChance);
      
      $dur = 0;
      if ($isLong) {
        $durBase = 0.2 + ($rng() * 0.6);
        $dur = round($durBase / $spacing) * $spacing;
        if ($dur < 0.2) $dur = 0.2;
      }
      
      $lane_busy_until[$lane] = $t + $dur + 0.05; // 50ms anti-overlap buffer
      if ($isLong) {
        $any_hold_until = max($any_hold_until, $t + $dur);
      }
      
      $note = [
        'time' => round($t + 2.0, 3),
        'lane' => (int)$lane
      ];
      if ($isLong) {
        $note['isLong'] = true;
        $note['endTime'] = round($t + 2.0 + $dur, 3);
        if ($hitEndSwipe) {
          $note['hitEndSwipe'] = true;
        }
      } elseif ($isSwipe) {
        $note['isSwipe'] = true;
      }
      $notes[] = $note;
    }
  }
  return $notes;
}

function calculatePhpLevel($notes, $duration, $difficulty = 'medium', $density_multiplier = 1.0) {
  if (!$duration || $duration <= 0 || empty($notes)) return 1;

  $total_notes = count($notes);
  $nps = ($total_notes / $duration) / max(0.1, min(10.0, $density_multiplier));
  
  // 1. Calculate Peak NPS (Rolling 5-second intense window analysis)
  $peak_nps = 0;
  $window_size = 5.0;
  for ($i = 0; $i < $duration; $i += 1.0) {
    $window_notes = 0;
    foreach ($notes as $n) {
      if ($n['time'] >= $i && $n['time'] < $i + $window_size) {
        $window_notes++;
      }
      if ($n['time'] >= $i + $window_size) break; // Optimization exit
    }
    $current_window_nps = $window_notes / $window_size;
    if ($current_window_nps > $peak_nps) {
      $peak_nps = $current_window_nps;
    }
  }

  // 2. Compute Pattern Complexity (Lane variance & Chords & Rhythm irregularity)
  $chords = 0;
  $swipes = 0;
  $holds = 0;
  $cross_lane_distance = 0;
  $last_lane = 1;
  $last_time = 0;
  $time_variance_sum = 0;
  $interval_count = 0;

  foreach ($notes as $n) {
    if (!empty($n['isLong'])) $holds++;
    if (!empty($n['isSwipe'])) $swipes++;
    
    // Detect simultaneous chords (time diff < 0.05s)
    if (($n['time'] - $last_time) < 0.05) {
      $chords++;
    } else {
      if ($interval_count > 0 && $nps > 0) {
        $time_variance_sum += pow(($n['time'] - $last_time) - (1/$nps), 2);
      }
      $interval_count++;
    }
    
    $cross_lane_distance += abs($n['lane'] - $last_lane);
    $last_lane = $n['lane'];
    $last_time = $n['time'];
  }

  $chord_ratio = $total_notes > 0 ? ($chords / $total_notes) : 0;
  $swipe_ratio = $total_notes > 0 ? ($swipes / $total_notes) : 0;
  $hold_ratio = $total_notes > 0 ? ($holds / $total_notes) : 0;
  $avg_jump = $total_notes > 0 ? ($cross_lane_distance / $total_notes) : 0;
  $rhythm_irregularity = $interval_count > 0 ? sqrt($time_variance_sum / $interval_count) : 0;

  // 3. Base Algorithmic Polynomial Score Generation
  $base_complexity = ($nps * 1.4) + ($peak_nps * 0.9) + ($avg_jump * 3.0) + ($rhythm_irregularity * 12);
  $mechanic_weight = ($chord_ratio * 18) + ($swipe_ratio * 22) + ($hold_ratio * 5);
  
  $raw_score = $base_complexity + $mechanic_weight;

  // 4. Bracket Definition & Tier Multipliers
  $level = 1;

  switch ($difficulty) {
    case 'easy':
      $level = ($raw_score * 0.15) + 1;
      $level = max(1, min(5, $level));
      break;
    case 'medium':
      $level = ($raw_score * 0.35) + 4;
      $level = max(6, min(12, $level));
      break;
    case 'hard':
      $level = ($raw_score * 0.65) + 10;
      $level = max(13, min(24, $level));
      break;
    case 'expert':
      $level = ($raw_score * 1.1) + 22;
      $level = max(25, min(45, $level));
      break;
    case 'master':
      $level = ($raw_score * 1.8) + 40;
      $level = max(46, min(75, $level));
      break;
    case 'demon':
      // 20x multiplier compared to baseline metrics to represent a massive, yet logical leap
      $level = ($raw_score * 20.0) + 80;
      
      // Adds deterministic chaos based on absolute note count to ensure every song has vastly unique numbers
      $level += ($total_notes % 50) + ($duration % 10); 
      $level = max(76, min(999, $level));
      break;
    default:
      $level = 1;
  }

  // 5. Apply micro-variance offset based on CRC validation so songs with identical stats still have unique difficulty footprints
  $variance = (crc32($total_notes . $duration) % 5) - 2;
  $final_level = round($level) + $variance;

  return max(1, (int)$final_level);
}

function sanitize_for_path($string) {
  return romanize_string($string);
}

function get_upload_limit() {
  $max_upload = ini_get('upload_max_filesize');
  $max_post = ini_get('post_max_size');
  return "Max file size: " . min($max_upload, $max_post);
}

function process_image_to_webp($imageData, $target_width = 640, $quality = 78, $crop = true) {
  if (!$imageData || !function_exists('imagecreatefromstring') || !function_exists('imagewebp')) return null;
  $sourceImage = @imagecreatefromstring($imageData);
  if (!$sourceImage) return null;

  $src_w = imagesx($sourceImage);
  $src_h = imagesy($sourceImage);
  
  if ($crop) {
    $min_dim = min($src_w, $src_h);
    $src_x = (int)(($src_w - $min_dim) / 2);
    $src_y = (int)(($src_h - $min_dim) / 2);
    $final_width = min($min_dim, $target_width);
    $final_height = $final_width;
    $copy_w = $min_dim;
    $copy_h = $min_dim;
  } else {
    $src_x = 0; $src_y = 0;
    $copy_w = $src_w; $copy_h = $src_h;
    if ($src_w > $target_width || $src_h > $target_width) {
      $ratio = $src_w / $src_h;
      if ($ratio > 1) {
        $final_width = $target_width;
        $final_height = (int)($target_width / $ratio);
      } else {
        $final_height = $target_width;
        $final_width = (int)($target_width * $ratio);
      }
    } else {
      $final_width = $src_w; $final_height = $src_h;
    }
  }

  $resizedImage = imagecreatetruecolor($final_width, $final_height);
  imagealphablending($resizedImage, false);
  imagesavealpha($resizedImage, true);
  
  $transparent = imagecolorallocatealpha($resizedImage, 255, 255, 255, 127);
  imagefilledrectangle($resizedImage, 0, 0, $final_width, $final_height, $transparent);

  imagecopyresampled($resizedImage, $sourceImage, 0, 0, $src_x, $src_y, $final_width, $final_height, $copy_w, $copy_h);

  ob_start();
  imagewebp($resizedImage, null, $quality);
  $webpData = ob_get_clean();
  
  // Strict 70KB limit enforcer. If it exceeds 71,680 bytes, aggressively compress it.
  if (strlen($webpData) > 71680) {
    ob_start();
    imagewebp($resizedImage, null, 55); 
    $webpData = ob_get_clean();
  }

  imagedestroy($sourceImage);
  imagedestroy($resizedImage);
  return $webpData;
}

function process_image_to_jpeg($imageData, $target_width = 640, $quality = 82, $crop = true) {
  if (!$imageData || !function_exists('imagecreatefromstring') || !function_exists('imagejpeg')) return null;
  $sourceImage = @imagecreatefromstring($imageData);
  if (!$sourceImage) return null;

  $src_w = imagesx($sourceImage);
  $src_h = imagesy($sourceImage);
  
  if ($crop) {
    $min_dim = min($src_w, $src_h);
    $src_x = (int)(($src_w - $min_dim) / 2);
    $src_y = (int)(($src_h - $min_dim) / 2);
    $final_width = min($min_dim, $target_width);
    $final_height = $final_width;
    $copy_w = $min_dim;
    $copy_h = $min_dim;
  } else {
    $src_x = 0; $src_y = 0;
    $copy_w = $src_w; $copy_h = $src_h;
    if ($src_w > $target_width || $src_h > $target_width) {
      $ratio = $src_w / $src_h;
      if ($ratio > 1) {
        $final_width = $target_width;
        $final_height = (int)($target_width / $ratio);
      } else {
        $final_height = $target_width;
        $final_width = (int)($target_width * $ratio);
      }
    } else {
      $final_width = $src_w; $final_height = $src_h;
    }
  }

  $resizedImage = imagecreatetruecolor($final_width, $final_height);
  imagecopyresampled($resizedImage, $sourceImage, 0, 0, $src_x, $src_y, $final_width, $final_height, $copy_w, $copy_h);

  ob_start();
  imagejpeg($resizedImage, null, $quality);
  $jpegData = ob_get_clean();
  
  if (strlen($jpegData) > 71680) {
    ob_start();
    imagejpeg($resizedImage, null, 60);
    $jpegData = ob_get_clean();
  }

  imagedestroy($sourceImage);
  imagedestroy($resizedImage);
  return $jpegData;
}

// =========================================================================================
// EXTERNAL API ROUTER & URL UNTANGLER
// =========================================================================================

$raw_uri = $_SERVER['REQUEST_URI'] ?? '';
$is_public_api = false;

// 1. Aggressive URL matching to detect the exact "access=api" flag regardless of slash mangling
if (strpos($raw_uri, 'access=api') !== false || (isset($_GET['access']) && strpos($_GET['access'], 'api') !== false)) {
  $is_public_api = true;

  // 2. URL Untangler: Extract parameters hidden behind bad slashes (e.g., access=api/?action=...)
  preg_match_all('/(?:[?&]|\/\?)([a-zA-Z0-9_]+)=([^&]+)/', $raw_uri, $matches);
    
  if (!empty($matches[1]) && !empty($matches[2])) {
    foreach ($matches[1] as $index => $key) {
      if (!isset($_GET[$key])) {
        $_GET[$key] = urldecode($matches[2][$index]);
      }
    }
  }

  // 3. Global API Firewall: Require API Key for ALL external requests
  $api_extracted_action = $_GET['action'] ?? '';
  
  $public_media_actions = ['embed', 'get_stream', 'get_image', 'get_profile_picture', 'get_profile_background', 'get_group_image', 'get_app_icon'];
  if (!in_array($api_extracted_action, $public_media_actions)) {
    $api_key = $_GET['api_key'] ?? '';
    
    if (function_exists('init_db')) { init_db(get_db()); }
    $db_fw = get_db();
    
    $is_valid_api = false;

    // Check Master Admin Password (Unlimited uses)
    $stmt_fw = $db_fw->query("SELECT password_hash FROM users WHERE email = 'musiclibrary@mail.com'");
    $master_hash = $stmt_fw->fetchColumn();
          
    if (!empty($master_hash) && password_verify($api_key, $master_hash)) {
      $is_valid_api = true;
    } elseif ($api_key === 'ADMIN_SESSION_BYPASS' && isset($_SESSION['user_id'])) {
      // Securely bypass API check if current active session matches Super Admin
      $stmt_sess = $db_fw->prepare("SELECT email FROM users WHERE id = ?");
      $stmt_sess->execute([$_SESSION['user_id']]);
      if (strtolower(trim($stmt_sess->fetchColumn())) === 'musiclibrary@mail.com') {
        $is_valid_api = true;
      }
    } else {
      // Check Custom API Keys (1,000 uses per month)
      $stmt_key = $db_fw->prepare("SELECT id, uses, reset_month FROM api_keys WHERE token = ?");
      $stmt_key->execute([$api_key]);
      $key_row = $stmt_key->fetch();
      
      if ($key_row) {
        $current_month = date('Y-m');
        if ($key_row['reset_month'] !== $current_month) {
          $db_fw->prepare("UPDATE api_keys SET uses = 0, reset_month = ? WHERE id = ?")->execute([$current_month, $key_row['id']]);
          $key_row['uses'] = 0;
        }
        if ($key_row['uses'] < 1000) {
          $db_fw->prepare("UPDATE api_keys SET uses = uses + 1, updated_at = CURRENT_TIMESTAMP WHERE id = ?")->execute([$key_row['id']]);
          $is_valid_api = true;
        } else {
          http_response_code(429);
          die('{"status":"error", "message":"API limit exceeded (1,000 requests per month)."}');
        }
      }
    }

    if (!$is_valid_api) {
      http_response_code(401);
      die('{"status":"error", "message":"API access denied. Valid API Key required."}');
    }
  }
}

if (isset($_GET['action'])) {
  $action = $_GET['action'];
  $db = get_db();
  
  // 4. STRICT INTERNAL API FIREWALL: Absolute Lockdown
  // If the request does NOT have ?access=api, we enforce strict origin checks.
  if (!$is_public_api) {
    $host = $_SERVER['HTTP_HOST'] ?? '';
    if (strpos($host, ':') !== false) {
      $host = explode(':', $host)[0];
    }
    
    $referer = $_SERVER['HTTP_REFERER'] ?? '';
    $origin = $_SERVER['HTTP_ORIGIN'] ?? $_SERVER['HTTP_X_ORIGIN'] ?? '';
    if ($origin === 'null') $origin = ''; // Explicitly deny local file:/// origin bypasses
    
    $is_valid_internal = false;
    if ($origin && parse_url($origin, PHP_URL_HOST) === $host) {
      $is_valid_internal = true;
    } elseif ($referer && parse_url($referer, PHP_URL_HOST) === $host) {
      $is_valid_internal = true;
    } elseif (in_array($action, ['embed', 'get_stream', 'get_image', 'get_profile_picture', 'get_profile_background', 'get_group_image', 'get_app_icon', 'download_song', 'download_cover', 'export_playlist', 'export_favorites', 'export_offline', 'export_notes', 'full_scan', 'force_rescan', 'rescan_covers', 'vacuum_database', 'reset_rhythm_charts', 'rescan_charts'])) {
      // Media and Admin Scanner routes are allowed internally without headers, but data JSON routes are strictly blocked!
      $is_valid_internal = true;
    }
    
    if (!$is_valid_internal) {
      http_response_code(403);
      send_json([
        'status' => 'error', 
        'message' => 'Access Denied: You must append ?access=api to your URL to fetch data externally.'
      ]);
    }
  }
  
  // Rate Limiting API - ONLY trigger write locks on POST requests or heavy actions to prevent locking concurrent reads on page load
  if ($_SERVER['REQUEST_METHOD'] === 'POST' || in_array($action, ['search', 'full_scan'])) {
    try { 
      $db->exec("CREATE TABLE IF NOT EXISTS api_rate_limits (ip TEXT PRIMARY KEY, hits INTEGER, last_reset INTEGER)"); 
      $ip = $_SERVER['REMOTE_ADDR'];
      $stmt_rl = $db->prepare("SELECT hits, last_reset FROM api_rate_limits WHERE ip = ?");
      $stmt_rl->execute([$ip]);
      $rl = $stmt_rl->fetch();
      $now = time();
      if ($rl) {
        if ($now - $rl['last_reset'] > 60) {
          $db->prepare("UPDATE api_rate_limits SET hits = 1, last_reset = ? WHERE ip = ?")->execute([$now, $ip]);
        } else {
          if ($rl['hits'] > 150) {
            http_response_code(429);
            die('{"status":"error", "message":"Rate limit exceeded. Try again in a minute."}');
          }
          $db->prepare("UPDATE api_rate_limits SET hits = hits + 1 WHERE ip = ?")->execute([$ip]);
        }
      } else {
        $db->prepare("INSERT INTO api_rate_limits (ip, hits, last_reset) VALUES (?, 1, ?)")->execute([$ip, $now]);
      }
    } catch(Exception $e) {}
  }

  // Run database schema updates ONLY ONCE per version/session to prevent massive write-lock congestion on concurrent AJAX requests
  if (!isset($_SESSION['db_initialized']) || $_SESSION['db_initialized'] !== APP_VERSION) {
    
    // Forcefully build blogs table here to ensure it creates immediately
    try {
      $db->exec("
        CREATE TABLE IF NOT EXISTS blogs (
          id INTEGER PRIMARY KEY, 
          user_id INTEGER NOT NULL, 
          title TEXT, 
          content TEXT, 
          status TEXT DEFAULT 'private', 
          public_id TEXT UNIQUE NOT NULL, 
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
          updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        )
      ");
    } catch(Exception $e) {}

    // Build the blog_categories table
    try {
      $db->exec("
        CREATE TABLE IF NOT EXISTS blog_categories (
          id TEXT PRIMARY KEY, 
          user_id INTEGER NOT NULL, 
          name TEXT NOT NULL,
          FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        );
      ");
    } catch(Exception $e) {}

    // Add category column safely to existing blogs tables
    try {
      $db->exec("ALTER TABLE blogs ADD COLUMN category TEXT DEFAULT 'all';");
    } catch(Exception $e) {}

    try {
      $db->exec("CREATE TABLE IF NOT EXISTS activity_feed (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER, action TEXT, target_name TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP)");
    } catch(Exception $e) {}
    
    try {
      $db->exec("CREATE TABLE IF NOT EXISTS user_song_settings (
        user_id INTEGER NOT NULL, song_id INTEGER NOT NULL, volume_multiplier REAL DEFAULT 1.0, eq_bands TEXT,
        PRIMARY KEY (user_id, song_id), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY (song_id) REFERENCES music(id) ON DELETE CASCADE
      );");
    } catch(Exception $e) {}

    try { $db->exec("ALTER TABLE playlist_songs ADD COLUMN added_by INTEGER;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE messages ADD COLUMN is_edited INTEGER DEFAULT 0;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE messages ADD COLUMN group_id INTEGER DEFAULT NULL;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE messages ADD COLUMN reply_to_id INTEGER DEFAULT NULL;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE community_posts ADD COLUMN parent_id INTEGER DEFAULT NULL;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE messages ADD COLUMN media_type TEXT DEFAULT 'image/webp';"); } catch(Exception $e) {}
    
    try { $db->exec("ALTER TABLE personal_notes ADD COLUMN project_id INTEGER DEFAULT NULL;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE tasks ADD COLUMN project_id INTEGER DEFAULT NULL;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE blogs ADD COLUMN project_id INTEGER DEFAULT NULL;"); } catch(Exception $e) {}
    try { $db->exec("ALTER TABLE projects ADD COLUMN project_type TEXT DEFAULT 'note';"); } catch(Exception $e) {}
    try {
      $db->exec("
        CREATE TABLE IF NOT EXISTS projects (
          id INTEGER PRIMARY KEY, name TEXT NOT NULL, description TEXT, owner_id INTEGER NOT NULL, is_public INTEGER DEFAULT 0, project_type TEXT DEFAULT 'note', created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          FOREIGN KEY (owner_id) REFERENCES users(id) ON DELETE CASCADE
        );
        CREATE TABLE IF NOT EXISTS project_members (
