      }
      if ($filter === 'starred') {
        $where .= " AND starred = 1";
      } elseif ($filter === 'tasks') {
        $where .= " AND note_type = 'task'";
      } elseif ($filter !== 'all' && strpos($filter, 'proj_') !== 0) {
        $where .= " AND category = ?";
        $params[] = $filter;
