        FROM blog_comments c JOIN users u ON c.user_id = u.id 
        WHERE c.blog_id = ? AND c.parent_id IS NULL $order_by LIMIT 25 OFFSET ?
      ");
      $root_stmt->execute([$user_id ?? 0, $blog_id, $offset]);
