          $where = "WHERE b.project_id = ? AND (b.project_id IN (SELECT project_id FROM project_members WHERE user_id = ?) OR b.project_id IN (SELECT id FROM projects WHERE is_public = 1))";
          $params = [$pid, $user_id];
        } else {
          $where = "WHERE b.user_id = ?";
          $params = [$user_id];
        }

        if ($search !== '') {
          $where .= " AND (b.title LIKE ? OR b.content LIKE ?)";
          $params[] = "%$search%";
          $params[] = "%$search%";
        }
        if ($filter === 'public') { 
          $where .= " AND b.status = 'public'"; 
        } elseif ($filter === 'private') { 
          $where .= " AND b.status = 'private'"; 
        } elseif ($filter !== 'all' && strpos($filter, 'proj_') !== 0) {
          $where .= " AND b.category = ?";
          $params[] = $filter;
        }
        
        $stmt = $db->prepare("SELECT b.id, b.user_id, b.title, b.content, b.status, b.public_id, b.created_at, b.updated_at, b.category, (SELECT name FROM blog_categories WHERE id = b.category AND user_id = b.user_id) as category_name, u.artist as author FROM blogs b JOIN users u ON b.user_id = u.id $where $order_by $limit_clause");
