    case 'get_message_image':
      header('Cache-Control: public, max-age=31536000, immutable');
      $msg_id = intval($_GET['id'] ?? 0);
      $is_thumb = isset($_GET['thumb']) && $_GET['thumb'] == '1';
      
      try {
        $stmt = $db->prepare("SELECT image, sender_id, receiver_id, media_type FROM messages WHERE id = ?");
      } catch (Exception $e) {
        $stmt = $db->prepare("SELECT image, sender_id, receiver_id, 'image/webp' as media_type FROM messages WHERE id = ?");
      }
      $stmt->execute([$msg_id]);
      $msg = $stmt->fetch();
      
      if ($msg && $msg['image']) {
        $stmt_grp = $db->prepare("SELECT group_id FROM messages WHERE id = ?");
        $stmt_grp->execute([$msg_id]);
        $grp_id = $stmt_grp->fetchColumn();
        
        $has_access = false;
        if ($grp_id) {
          $stmt_mem = $db->prepare("SELECT 1 FROM chat_group_members WHERE group_id = ? AND user_id = ?");
          $stmt_mem->execute([$grp_id, $user_id]);
          if ($stmt_mem->fetch() || $is_super_admin) $has_access = true;
        } else {
          if ($msg['sender_id'] == $user_id || $msg['receiver_id'] == $user_id || $is_super_admin) $has_access = true;
        }
        
        if ($has_access) {
          $mime = $msg['media_type'] ?? 'image/webp';
          $is_filepath = (strpos($msg['image'], 'uploads/media/') === 0);

          if ($is_filepath) {
            $file_path = MUSIC_DIR . '/' . $msg['image'];
            
            if ($is_thumb && strpos($mime, 'image/') === 0) {
              $thumb_path = str_replace('uploads/media/', 'thumbnails/', $file_path) . '.webp';
              if (file_exists($thumb_path)) {
                $file_path = $thumb_path;
                $mime = 'image/webp';
              }
            }

            if (!file_exists($file_path)) {
              http_response_code(404); exit;
            }

            header('Content-Type: ' . $mime);
            header('Accept-Ranges: bytes');
            
            $filesize = filesize($file_path);
            $start = 0;
            $end = $filesize - 1;
            $length = $filesize;

            if (isset($_SERVER['HTTP_RANGE'])) {
              $range = str_replace('bytes=', '', $_SERVER['HTTP_RANGE']);
              $parts = explode('-', $range, 2);
              $start = intval($parts[0]);
              if (isset($parts[1]) && $parts[1] !== '') {
                $end = intval($parts[1]);
              }
              if ($start > $end || $start >= $filesize) {
                header('HTTP/1.1 416 Range Not Satisfiable');
                header("Content-Range: bytes */$filesize");
                exit;
              }
              $length = $end - $start + 1;
              header('HTTP/1.1 206 Partial Content');
              header("Content-Range: bytes $start-$end/$filesize");
            } else {
              header('HTTP/1.1 200 OK');
            }
            header('Content-Length: ' . $length);

            $f = @fopen($file_path, 'rb');
            if ($f) {
              fseek($f, $start);
              $chunk_size = 1024 * 8;
              $bytes_left = $length;
              while ($bytes_left > 0 && !feof($f)) {
                if (connection_aborted()) break;
                $read_size = min($chunk_size, $bytes_left);
                $data = fread($f, $read_size);
                if ($data === false) break;
                echo $data;
                @flush();
                $bytes_left -= strlen($data);
              }
              fclose($f);
            }
            exit;
          } else {
            // Legacy BLOB handler
            header('Content-Type: ' . $mime);
            if (strpos($mime, 'video/') === 0 || strpos($mime, 'audio/') === 0) {
              header('Accept-Ranges: bytes');
              $filesize = strlen($msg['image']);
              $start = 0;
              $end = $filesize - 1;
              $length = $filesize;

              if (isset($_SERVER['HTTP_RANGE'])) {
                $range = str_replace('bytes=', '', $_SERVER['HTTP_RANGE']);
                $parts = explode('-', $range, 2);
                $start = intval($parts[0]);
                if (isset($parts[1]) && $parts[1] !== '') {
                  $end = intval($parts[1]);
                }
                if ($start > $end || $start >= $filesize) {
                  header('HTTP/1.1 416 Range Not Satisfiable');
                  header("Content-Range: bytes */$filesize");
                  exit;
                }
                $length = $end - $start + 1;
                header('HTTP/1.1 206 Partial Content');
                header("Content-Range: bytes $start-$end/$filesize");
              } else {
                header('HTTP/1.1 200 OK');
              }
              header('Content-Length: ' . $length);
              echo substr($msg['image'], $start, $length);
            } else {
              echo $msg['image'];
            }
            exit;
          }
        }
      }
      http_response_code(404); exit;

    case 'toggle_follow':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $following_id = intval($data['following_id']);
      if ($following_id === $user_id) {
        send_json(['status' => 'error', 'message' => 'Cannot follow yourself.']);
      }
      $stmt = $db->prepare("SELECT 1 FROM follows WHERE follower_id = ? AND following_id = ?");
      $stmt->execute([$user_id, $following_id]);
      if ($stmt->fetch()) {
        $db->prepare("DELETE FROM follows WHERE follower_id = ? AND following_id = ?")->execute([$user_id, $following_id]);
        send_json(['status' => 'unfollowed']);
      } else {
        $db->prepare("INSERT INTO follows (follower_id, following_id) VALUES (?, ?)")->execute([$user_id, $following_id]);
        
        try { 
          $db->prepare("INSERT INTO activity_feed (user_id, action, target_name) VALUES (?, 'started following', (SELECT artist FROM users WHERE id = ?))")->execute([$user_id, $following_id]); 
        } catch(Exception $e) {}
        
        send_json(['status' => 'followed']);
      }
      break;

    case 'update_favorite_order':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $ordered_ids = $data['ids'];
      $db->beginTransaction();
      try {
        foreach ($ordered_ids as $index => $song_id) {
          $db->prepare("UPDATE favorites SET sort_order = ? WHERE user_id = ? AND song_id = ?")
             ->execute([$index, $user_id, $song_id]);
        }
        $db->commit();
        send_json(['status' => 'success']);
      } catch (Exception $e) {
        $db->rollBack();
        http_response_code(500);
        send_json(['status' => 'error', 'message' => 'Failed to update order.']);
      }
      break;

    case 'get_view_ids':
      $post_data = json_decode(file_get_contents('php://input'), true);
      $view_type = $post_data['view_type'] ?? '';
      $param = $post_data['param'] ?? '';
      $sort = $post_data['sort'] ?? '';
      $filter_user_id = $post_data['filter_user_id'] ?? '';
      $artist_name = $post_data['artist_name'] ?? '';

      $sql = "SELECT m.id FROM music m ";
      $conditions = "";
      $group_by = "";
      $params = [];
      $default_sort = 'artist_asc';

      switch ($view_type) {
        case 'get_songs':
          $default_sort = 'id_desc';
          break;
        case 'get_profile_songs':
          if (!$user_id) { send_json([]); }
          $conditions = "WHERE m.user_id = ?";
          $params[] = $user_id;
          $default_sort = 'title_asc';
          break;
        case 'get_favorites':
          if (!$user_id) { send_json([]); }
          $sql = "SELECT m.id FROM music m JOIN favorites f ON m.id = f.song_id ";
          $conditions = "WHERE f.user_id = ?";
          $params[] = $user_id;
          $default_sort = 'manual_order';
          break;
        case 'get_listen_later':
          if (!$user_id) { send_json([]); }
          $sql = "SELECT m.id FROM music m JOIN listen_later ll ON m.id = ll.song_id ";
          $conditions = "WHERE ll.user_id = ?";
          $params[] = $user_id;
          $default_sort = 'manual_order';
          break;
        case 'get_offline_songs':
          if (!$user_id) { send_json([]); }
          $sql = "SELECT m.id FROM music m JOIN offline_songs os ON m.id = os.song_id ";
          $conditions = "WHERE os.user_id = ?";
          $params[] = $user_id;
          $default_sort = 'manual_order';
          break;
        case 'get_history':
          if (!$user_id) { send_json([]); }
          $sql = "SELECT m.id FROM music m JOIN history h ON m.id = h.song_id ";
          $conditions = "WHERE h.user_id = ?";
          $group_by = "GROUP BY m.id";
          $params[] = $user_id;
          $default_sort = 'history_desc';
          break;
        case 'get_trending':
          $sql = "SELECT m.id FROM music m LEFT JOIN (SELECT song_id, SUM(play_count) as total_plays FROM play_counts GROUP BY song_id) pc ON m.id = pc.song_id ";
          $conditions = "WHERE 1=1";
          $default_sort = 'trending';
          break;
        case 'artist_songs':
          if ($filter_user_id !== '') {
            $conditions = "WHERE (match_artist(m.artist, ?) = 1 OR m.user_id = ? OR m.id IN (SELECT song_id FROM song_collaborators WHERE user_id = ?)) AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR m.id IN (SELECT song_id FROM song_collaborators WHERE user_id = ?) OR {$is_super_admin} = 1)";
            $params[] = $param;
            $params[] = $filter_user_id;
            $params[] = $filter_user_id;
            $params[] = $user_id;
            $params[] = $user_id;
            $params[] = $user_id;
            $filter_user_id = ''; // Processed here, prevent global append
          } else {
            $conditions = "WHERE match_artist(m.artist, ?) = 1 AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR m.id IN (SELECT song_id FROM song_collaborators WHERE user_id = ?) OR {$is_super_admin} = 1)";
            $params[] = $param;
            $params[] = $user_id;
            $params[] = $user_id;
            $params[] = $user_id;
          }
          break;
        case 'album_songs':
          $conditions = "WHERE m.album = ? AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1)";
          $params[] = $param;
          $params[] = $user_id;
          $params[] = $user_id;
          if ($artist_name !== '') {
            $conditions .= " AND match_artist(m.artist, ?) = 1";
            $params[] = $artist_name;
          }
          $default_sort = 'title_asc';
          break;
        case 'year_songs':
          $conditions = "WHERE m.year = ? AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1)";
          $params[] = $param;
          $params[] = $user_id;
          $params[] = $user_id;
          $default_sort = 'artist_asc';
          break;
        case 'genre_songs':
          $conditions = "WHERE m.genre = ? AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1)";
          $params[] = $param;
          $params[] = $user_id;
          $params[] = $user_id;
          $default_sort = 'artist_asc';
          break;
        case 'playlist_songs':
          $sql = "SELECT m.id FROM music m JOIN playlist_songs ps ON m.id = ps.song_id JOIN playlists p ON ps.playlist_id = p.id ";
          $conditions = "WHERE p.public_id = ? AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1)";
          $params[] = $param;
          $params[] = $user_id;
          $params[] = $user_id;
          $default_sort = 'manual_order';
          break;
        case 'mix_songs':
          $sql = "SELECT m.id FROM mix_songs ms JOIN mixes mx ON ms.mix_id = mx.id JOIN music m ON ms.song_id = m.id ";
          $conditions = "WHERE mx.public_id = ? AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1)";
          $params[] = $param;
          $params[] = $user_id;
          $params[] = $user_id;
          $default_sort = 'manual_order';
          break;
        case 'search':
          $conditions = "WHERE (match_text(m.title, ?) = 1 OR match_text(m.artist, ?) = 1 OR match_text(m.album, ?) = 1) AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1)";
          $query_param = $param;
          $params = [$query_param, $query_param, $query_param, $user_id, $user_id];
          break;
        case 'get_recommendations':
          send_json([]);
        default:
          send_json([]);
      }
      
      if ($filter_user_id !== '') {
        if (empty($conditions)) {
          $conditions = "WHERE m.user_id = ?";
        } else {
          $conditions .= " AND m.user_id = ?";
        }
        $params[] = $filter_user_id;
      }

      $sort_map = [
        'id_desc' => 'ORDER BY m.id DESC',
        'id_asc' => 'ORDER BY m.id ASC',
        'artist_asc' => 'ORDER BY m.artist COLLATE NOCASE ASC, m.album COLLATE NOCASE ASC, m.title COLLATE NOCASE ASC',
        'title_asc' => 'ORDER BY m.title COLLATE NOCASE ASC',
        'album_asc' => 'ORDER BY m.album COLLATE NOCASE ASC, m.title COLLATE NOCASE ASC',
        'year_desc' => 'ORDER BY m.year DESC, m.album COLLATE NOCASE ASC, m.title COLLATE NOCASE ASC',
        'year_asc' => 'ORDER BY m.year ASC, m.album COLLATE NOCASE ASC, m.title COLLATE NOCASE ASC',
        'history_desc' => 'ORDER BY MAX(h.played_at) DESC',
        'history_asc' => 'ORDER BY MAX(h.played_at) ASC',
        'trending' => 'ORDER BY COALESCE(pc.total_plays, 0) DESC, m.id DESC LIMIT 100',
        'random' => 'ORDER BY RANDOM()',
      ];
      if ($view_type === 'get_favorites' || $view_type === 'get_listen_later') {
        $sort_map['manual_order'] = 'ORDER BY f.sort_order ASC';
        $sort_map['added_newest'] = 'ORDER BY f.sort_order DESC';
        $sort_map['added_oldest'] = 'ORDER BY f.sort_order ASC';
      } elseif ($view_type === 'get_offline_songs') {
        $sort_map['manual_order'] = 'ORDER BY os.sort_order ASC';
        $sort_map['added_newest'] = 'ORDER BY os.sort_order DESC';
        $sort_map['added_oldest'] = 'ORDER BY os.sort_order ASC';
      } elseif ($view_type === 'playlist_songs') {
        $sort_map['manual_order'] = 'ORDER BY ps.sort_order ASC';
        $sort_map['added_newest'] = 'ORDER BY ps.added_at DESC';
        $sort_map['added_oldest'] = 'ORDER BY ps.added_at ASC';
      } elseif ($view_type === 'mix_songs') {
        $sort_map['manual_order'] = 'ORDER BY ms.sort_order ASC';
      }
      $order_by = $sort_map[$sort] ?? $sort_map[$default_sort];
      
      $stmt = $db->prepare($sql . " " . $conditions . " " . $group_by . " " . $order_by);
      $stmt->execute($params);
      send_json($stmt->fetchAll(PDO::FETCH_COLUMN));
      break;

    case 'get_artists':
      $sort_key = $_GET['sort'] ?? 'name_asc';
      // Select user_id to correctly map primary artists
      $stmt = $db->prepare("SELECT artist, id, user_id, CASE WHEN image IS NOT NULL THEN 1 ELSE 0 END as has_img FROM music WHERE artist != '' AND artist IS NOT NULL AND (is_private = 0 OR user_id = ? OR match_artist(artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1) ORDER BY id DESC");
      $stmt->execute([$user_id, $user_id]);
      $rows = $stmt->fetchAll();
      $artists = [];
      
      $stmt_is_user = $db->prepare("SELECT id FROM users WHERE artist = ? COLLATE NOCASE");
      
      foreach ($rows as $row) {
        $parts = preg_split('/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+|\s*,\s*(?!(?:the|a|an|jr|sr)\b))\s*/i', $row['artist']);
        foreach ($parts as $index => $part) {
          $p = trim($part);
          if ($p !== '') {
            $key = strtolower($p);
            if (!isset($artists[$key])) {
              $stmt_is_user->execute([$p]);
              $uid = $stmt_is_user->fetchColumn();
              
              $artists[$key] = [
                  'name' => $p, 
                  'id' => $uid ? $uid : $row['id'], 
                  'has_img' => $row['has_img'],
                  'is_user' => (bool)$uid,
                  'user_id' => $uid ? $uid : ($index === 0 ? $row['user_id'] : null)
              ];
            } elseif (!$artists[$key]['has_img'] && $row['has_img'] && empty($artists[$key]['is_user'])) {
              $artists[$key]['id'] = $row['id'];
              $artists[$key]['has_img'] = 1;
            }
          }
        }
      }
      if ($sort_key === 'name_desc') {
        usort($artists, function($a, $b) { return strcasecmp($b['name'], $a['name']); });
      } else {
        usort($artists, function($a, $b) { return strcasecmp($a['name'], $b['name']); });
      }
      $sliced = array_slice($artists, $offset, PAGE_SIZE);
      send_json(array_values($sliced));
      break;

    case 'get_albums':
      $sort_key = $_GET['sort'] ?? 'album_asc';
      
      $stmt = $db->prepare("SELECT m.album, m.artist, m.user_id, m.id, m.year, m.last_modified, COALESCE((SELECT SUM(play_count) FROM play_counts WHERE song_id = m.id), 0) as pc FROM music m WHERE m.album != '' AND m.album != 'Unknown Album' AND m.album IS NOT NULL AND (m.is_private = 0 OR m.user_id = ? OR match_artist(m.artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1) ORDER BY m.id DESC");
      $stmt->execute([$user_id]);
      $rows = $stmt->fetchAll();
      
      $albums = [];
      foreach ($rows as $row) {
        $parts = @preg_split('/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+|\s*,\s*(?!(?:the|a|an|jr|sr)\b))\s*/i', $row['artist']);
        if (!is_array($parts)) $parts = [$row['artist']];
        foreach ($parts as $part) {
          $p = trim($part);
          if ($p !== '') {
            $key = strtolower($row['album'] . ':::' . $p);
            if (!isset($albums[$key])) {
              $albums[$key] = [
                'album' => $row['album'],
                'artist' => $p,
                'user_id' => $row['user_id'],
                'id' => $row['id'],
                'image_v' => $row['last_modified'],
                'year' => $row['year'],
                'song_count' => 1,
                'total_plays' => $row['pc']
              ];
            } else {
              $albums[$key]['song_count']++;
              $albums[$key]['total_plays'] += $row['pc'];
            }
          }
        }
      }
      
      usort($albums, function($a, $b) use ($sort_key) {
        switch ($sort_key) {
          case 'album_desc': return strcasecmp($b['album'], $a['album']);
          case 'artist_asc': return strcasecmp($a['artist'], $b['artist']);
          case 'artist_desc': return strcasecmp($b['artist'], $a['artist']);
          case 'year_desc': return ($b['year'] ?? 0) <=> ($a['year'] ?? 0);
          case 'year_asc': return ($a['year'] ?? 0) <=> ($b['year'] ?? 0);
          case 'album_asc':
          default: return strcasecmp($a['album'], $b['album']);
        }
      });
      
      $sliced = array_slice($albums, $offset, PAGE_SIZE);
      send_json(array_values($sliced));
      break;
    
    case 'get_genres':
      $stmt = $db->prepare("SELECT genre as name, MAX(id) as id FROM music WHERE genre != '' AND genre IS NOT NULL AND (is_private = 0 OR user_id = ? OR match_artist(artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1) GROUP BY genre ORDER BY genre COLLATE NOCASE" . $limit_clause);
      $stmt->execute([$user_id]);
      send_json($stmt->fetchAll());
      break;
    
    case 'get_years':
      $stmt = $db->prepare("SELECT CAST(year AS TEXT) as name, MAX(id) as id FROM music WHERE year IS NOT NULL AND year > 0 AND (is_private = 0 OR user_id = ? OR match_artist(artist, (SELECT artist FROM users WHERE id = ?)) = 1 OR {$is_super_admin} = 1) GROUP BY year ORDER BY year DESC" . $limit_clause);
      $stmt->execute([$user_id ?? 0]);
      send_json($stmt->fetchAll());
      break;

    case 'get_listen_later_ids':
      if (!$user_id) { send_json([]); }
      $stmt = $db->prepare("SELECT song_id FROM listen_later WHERE user_id = ?");
