    case 'get_stream':
      $id = intval($_GET['id'] ?? 0);
      $stmt = $db->prepare("SELECT file, user_id, is_private, artist FROM music WHERE id = ?");
      $stmt->execute([$id]);
      $song_stream = $stmt->fetch();
      
      if ($song_stream) {
        $file_path = $song_stream['file'];
        // Dynamic path resolution to prevent breaking if server/folder changes
        if (!file_exists($file_path)) {
          $dynamic_path = MUSIC_DIR . '/uploads/' . basename(dirname(dirname($file_path))) . '/' . basename(dirname($file_path)) . '/' . basename($file_path);
          if (file_exists($dynamic_path)) $file_path = $dynamic_path;
        }

        if (file_exists($file_path)) {
          $is_collab = false;
          if ($user_id) {
             $stmt_art = $db->prepare("SELECT artist FROM users WHERE id = ?");
             $stmt_art->execute([$user_id]);
             $u_art = $stmt_art->fetchColumn();
             if ($u_art && $db->query("SELECT match_artist(".$db->quote($song_stream['artist']).", ".$db->quote($u_art).")")->fetchColumn() == 1) {
                 $is_collab = true;
             }
          }
          if ($song_stream['is_private'] == 1 && $song_stream['user_id'] != $user_id && !$is_collab && $is_super_admin == 0) {
            http_response_code(403); exit;
          }
          session_write_close();
          while (ob_get_level() > 0) { @ob_end_clean(); }
          $filesize = filesize($file_path);
          
          $mime_type = 'audio/mpeg';
          $ext = strtolower(pathinfo($file_path, PATHINFO_EXTENSION));
          switch ($ext) {
            case 'flac': $mime_type = 'audio/flac'; break;
            case 'ogg': $mime_type = 'audio/ogg'; break;
            case 'wav': $mime_type = 'audio/wav'; break;
            case 'm4a': $mime_type = 'audio/mp4'; break;
          }

          header('Content-Type: ' . $mime_type);
          header('Accept-Ranges: bytes');
          
          $start = 0;
          $end = $filesize - 1;
          $length = $filesize;

          if (isset($_SERVER['HTTP_RANGE'])) {
            $range = str_replace('bytes=', '', $_SERVER['HTTP_RANGE']);
            $parts = explode('-', $range, 2);
            $start = intval($parts[0]);
            if (isset($parts[1]) && $parts[1] !== '') {
              $end = intval($parts[1]);
            }
            if ($start > $end || $start >= $filesize) {
              header('HTTP/1.1 416 Range Not Satisfiable');
              header("Content-Range: bytes */$filesize");
              exit;
            }
            $length = $end - $start + 1;
            header('HTTP/1.1 206 Partial Content');
            header("Content-Range: bytes $start-$end/$filesize");
          } else {
            header('HTTP/1.1 200 OK');
          }

          header('Content-Length: ' . $length);

          $f = @fopen($file_path, 'rb');
          if ($f) {
            fseek($f, $start);
            $chunk_size = 1024 * 8;
            $bytes_left = $length;
            @flush();
            while ($bytes_left > 0 && !feof($f)) {
              if (connection_aborted()) break;
              $read_size = min($chunk_size, $bytes_left);
              $data = fread($f, $read_size);
              if ($data === false) break;
              echo $data;
              @flush();
              $bytes_left -= strlen($data);
            }
            fclose($f);
          }
          exit;
        }
      }
      http_response_code(404);
      exit;

    case 'download_cover':
      $id = intval($_GET['id'] ?? 0);
      $stmt = $db->prepare("SELECT image, title, artist FROM music WHERE id = ?");
      $stmt->execute([$id]);
      $row = $stmt->fetch();
      
      $safeTitle = preg_replace('/[^a-zA-Z0-9_]/', '_', ($row['title'] ?? 'Unknown') . '_' . ($row['artist'] ?? 'Unknown'));

      if ($row && $row['image']) {
        header('Content-Type: image/webp');
        header('Content-Disposition: attachment; filename="' . $safeTitle . '_cover.webp"');
        echo $row['image'];
      } else {
        header('Content-Type: image/svg+xml');
        header('Content-Disposition: attachment; filename="' . $safeTitle . '_cover.svg"');
        $title = $row['title'] ?? 'Unknown';
        $hash = 0;
        for ($i = 0; $i < strlen($title); $i++) {
            $char = ord($title[$i]);
            $hash = ($char + ($hash << 5) - $hash) & 0xFFFFFFFF;
            if ($hash > 0x7FFFFFFF) $hash -= 0x100000000;
        }
        $h = abs($hash % 360);
        $c1 = "hsl({$h}, 50%, 35%)";
        $c2 = "hsl(" . (($h + 40) % 360) . ", 60%, 45%)";
        $c3 = "hsl(" . (($h + 80) % 360) . ", 60%, 35%)";
        echo '<?xml version="1.0" encoding="utf-8"?>
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="100%" height="100%">
          <defs>
            <linearGradient id="grad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stop-color="'.$c1.'" />
              <stop offset="50%" stop-color="'.$c2.'" />
              <stop offset="100%" stop-color="'.$c3.'" />
            </linearGradient>
            <filter id="shadow" x="-10%" y="-10%" width="120%" height="120%">
              <feDropShadow dx="0" dy="8" stdDeviation="12" flood-opacity="0.3"/>
            </filter>
          </defs>
          <rect width="512" height="512" fill="url(#grad)" />
          <g transform="translate(128, 128) scale(10.66)" fill="none" stroke="#ffffff" stroke-width="1.5" opacity="0.9" filter="url(#shadow)">
            <circle cx="12" cy="12" r="3"/>
            <path stroke-linecap="round" d="M21.95 13c-.501 5.054-4.765 9-9.95 9c-5.523 0-10-4.477-10-10c0-1.821.487-3.529 1.338-5M11 2.05a9.9 9.9 0 0 0-4 1.288"/>
            <path stroke-linecap="round" stroke-linejoin="round" d="M15 12V2.456a10.02 10.02 0 0 1 6.542 6.542"/>
          </g>
        </svg>';
      }
      exit;

    case 'get_image':
      header('Cache-Control: public, max-age=31536000, immutable');
      header('Pragma: cache');
      header('Expires: ' . gmdate('D, d M Y H:i:s', time() + 31536000) . ' GMT');
      $id = intval($_GET['id'] ?? 0);
      $size = $_GET['size'] ?? 'large';
      
      $stmt = $db->prepare("SELECT image, title, artist, last_modified FROM music WHERE id = ?");
      $stmt->execute([$id]);
      $row = $stmt->fetch();
      
      if ($row && $row['image']) {
        if ($size === 'small') {
          $shard = substr(md5((string)$id), 0, 2);
          $thumb_dir = MUSIC_DIR . '/thumbnails/' . $shard;
          $v = $row['last_modified'] ?? 0;
          $cache_path = $thumb_dir . '/small_' . $id . '_' . $v . '.webp';
          
          if (file_exists($cache_path)) {
            header('Content-Type: image/webp');
            readfile($cache_path);
            exit;
          }
          
          if (!is_dir($thumb_dir)) @mkdir($thumb_dir, 0755, true);
          
          // ADVANCED CLEANUP: Safely delete stale unmatched thumbnails strictly for this ID
          $all_shard_files = @scandir($thumb_dir);
          if ($all_shard_files) {
            foreach ($all_shard_files as $f) {
              if ($f !== '.' && $f !== '..' && $f !== basename($cache_path)) {
                if (preg_match('/^small_' . $id . '(?:_[0-9]+)?\.webp$/', $f)) {
                  @unlink($thumb_dir . '/' . $f);
                }
              }
            }
          }
          
          $img = @imagecreatefromstring($row['image']);
          if ($img) {
            $small = imagecreatetruecolor(200, 200);
            imagealphablending($small, false);
            imagesavealpha($small, true);
            $transparent = imagecolorallocatealpha($small, 255, 255, 255, 127);
            imagefilledrectangle($small, 0, 0, 200, 200, $transparent);
            imagecopyresampled($small, $img, 0, 0, 0, 0, 200, 200, imagesx($img), imagesy($img));
            
            ob_start();
            imagewebp($small, null, 40);
            $small_data = ob_get_clean();
            
            if (strlen($small_data) > 5120) { // Enforce 5KB max
               ob_start();
               imagewebp($small, null, 15); 
               $small_data = ob_get_clean();
            }
            
            @file_put_contents($cache_path, $small_data);
            imagedestroy($img);
            imagedestroy($small);
            
            header('Content-Type: image/webp');
            echo $small_data;
            exit;
          }
          // If image creation failed (corrupted DB image), nullify it to fallback to SVG
          $row['image'] = null;
        } else {
          header('Content-Type: image/webp');
          echo $row['image'];
          exit;
        }
      }
      
      // Unified SVG Generator
      header('Content-Type: image/svg+xml');
      $title = $row['title'] ?? 'Unknown';
      $hash = 0;
      for ($i = 0; $i < strlen($title); $i++) {
          $char = ord($title[$i]);
          $hash = ($char + ($hash << 5) - $hash) & 0xFFFFFFFF;
          if ($hash > 0x7FFFFFFF) $hash -= 0x100000000;
      }
      $h = abs($hash % 360);
      $c1 = "hsl({$h}, 50%, 35%)";
      $c2 = "hsl(" . (($h + 40) % 360) . ", 60%, 45%)";
      $c3 = "hsl(" . (($h + 80) % 360) . ", 60%, 35%)";
      echo '<?xml version="1.0" encoding="utf-8"?>
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="100%" height="100%">
        <defs>
          <linearGradient id="grad" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stop-color="'.$c1.'" />
            <stop offset="50%" stop-color="'.$c2.'" />
            <stop offset="100%" stop-color="'.$c3.'" />
          </linearGradient>
          <filter id="shadow" x="-10%" y="-10%" width="120%" height="120%">
            <feDropShadow dx="0" dy="8" stdDeviation="12" flood-opacity="0.3"/>
          </filter>
        </defs>
        <rect width="512" height="512" fill="url(#grad)" />
        <g transform="translate(128, 128) scale(10.66)" fill="none" stroke="#ffffff" stroke-width="1.5" opacity="0.9" filter="url(#shadow)">
          <circle cx="12" cy="12" r="3"/>
          <path stroke-linecap="round" d="M21.95 13c-.501 5.054-4.765 9-9.95 9c-5.523 0-10-4.477-10-10c0-1.821.487-3.529 1.338-5M11 2.05a9.9 9.9 0 0 0-4 1.288"/>
          <path stroke-linecap="round" stroke-linejoin="round" d="M15 12V2.456a10.02 10.02 0 0 1 6.542 6.542"/>
        </g>
      </svg>';
      exit;

    case 'get_user_playlists':
      if (!$user_id) { send_json([]); }
      $song_id = isset($_GET['song_id']) ? $_GET['song_id'] : '0';
      $sort_key = $_GET['sort'] ?? 'name_asc';
      $sort_map = [
        'name_asc' => 'ORDER BY p.name COLLATE NOCASE ASC',
        'name_desc' => 'ORDER BY p.name COLLATE NOCASE DESC',
        'modified_desc' => 'ORDER BY COALESCE((SELECT MAX(added_at) FROM playlist_songs WHERE playlist_id = p.id), p.created_at) DESC',
        'modified_asc' => 'ORDER BY COALESCE((SELECT MAX(added_at) FROM playlist_songs WHERE playlist_id = p.id), p.created_at) ASC',
      ];
      $order_by = $sort_map[$sort_key] ?? $sort_map['name_asc'];
      
      $is_added_sql = ", 0 as is_added";
      if ($song_id !== '0') {
        $sid = intval($song_id);
        $is_added_sql = ", (SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END FROM playlist_songs WHERE playlist_id = p.id AND song_id = {$sid}) as is_added";
      }
      
      $q = $_GET['q'] ?? '';
      $where_sql = "WHERE p.user_id = ?";
      $params = [$user_id];
      if ($q !== '') {
        $where_sql .= " AND (match_text(p.name, ?) = 1 OR match_text(p.description, ?) = 1)";
        $params[] = $q;
        $params[] = $q;
      }
      
      $stmt = $db->prepare("
        SELECT p.id, p.name, p.description, p.public_id, p.is_collaborative, p.is_private, p.user_id as owner_id, u.artist as creator, p.play_count, COUNT(ps.song_id) as song_count,
        (SELECT ps.song_id FROM playlist_songs ps WHERE ps.playlist_id = p.id ORDER BY ps.added_at DESC LIMIT 1) as image_id,
        (SELECT m.last_modified FROM playlist_songs ps2 JOIN music m ON ps2.song_id = m.id WHERE ps2.playlist_id = p.id ORDER BY ps2.added_at DESC LIMIT 1) as image_v
        {$is_added_sql}
        FROM playlists p 
        LEFT JOIN playlist_songs ps ON p.id = ps.playlist_id
        LEFT JOIN users u ON p.user_id = u.id
        $where_sql
        GROUP BY p.id, p.name, p.description, p.public_id, p.is_collaborative, p.is_private, p.user_id, u.artist, p.play_count
        {$order_by} {$limit_clause}
      ");
      $stmt->execute($params);
      send_json($stmt->fetchAll());
      break;

    case 'get_mixes':
      if (isset($_GET['refresh']) && $_GET['refresh'] == '1') {
        $db->exec("DELETE FROM mix_songs");
        $db->exec("DELETE FROM mixes");
      }
      
      $generate_count = 0;
      if (isset($_GET['refresh']) && $_GET['refresh'] == '1') {
         $generate_count = 24;
      } elseif (isset($_GET['generate']) && $_GET['generate'] == '1') {
         $generate_count = 24;
      } else {
         $mix_count = $db->query("SELECT COUNT(*) FROM mixes")->fetchColumn();
         if ($mix_count == 0) $generate_count = 24;
      }
      
      if ($generate_count > 0) {
        $mix_seeds_stmt = $db->query("
          SELECT * FROM (
            SELECT DISTINCT artist as seed_name, 'artist' as seed_type FROM music WHERE artist != 'Unknown Artist' AND artist != '' AND artist IS NOT NULL
            UNION
            SELECT DISTINCT genre as seed_name, 'genre' as seed_type FROM music WHERE genre != 'Unknown Genre' AND genre != '' AND genre IS NOT NULL
            UNION
            SELECT DISTINCT CAST(year AS TEXT) as seed_name, 'year' as seed_type FROM music WHERE year IS NOT NULL AND year > 0
          ) ORDER BY RANDOM() LIMIT $generate_count
        ");
        $seeds = $mix_seeds_stmt->fetchAll();
        foreach ($seeds as $seed) {
          $song_stmt = $db->prepare("SELECT id FROM music WHERE " . $seed['seed_type'] . " = ? ORDER BY RANDOM() LIMIT 50");
          $song_stmt->execute([$seed['seed_name']]);
          $song_ids = $song_stmt->fetchAll(PDO::FETCH_COLUMN);
          
          if (count($song_ids) < 50) {
            $needed = 50 - count($song_ids);
            $pad_stmt = $db->query("SELECT id FROM music ORDER BY RANDOM() LIMIT 100");
            $pad_candidates = $pad_stmt->fetchAll(PDO::FETCH_COLUMN);
            foreach ($pad_candidates as $cid) {
              if (!in_array($cid, $song_ids)) {
                $song_ids[] = $cid;
                $needed--;
                if ($needed <= 0) break;
              }
            }
          }
          
          if (empty($song_ids)) continue; 
          
          $img_stmt = $db->prepare("SELECT id FROM music WHERE " . $seed['seed_type'] . " = ? AND image IS NOT NULL ORDER BY RANDOM() LIMIT 1");
          $img_stmt->execute([$seed['seed_name']]);
          $img_id = $img_stmt->fetchColumn() ?: $song_ids[0];
          
          $public_id = bin2hex(random_bytes(8));
          $name = 'Mix - ' . $seed['seed_name'];
          $db->prepare("INSERT INTO mixes (public_id, name, creator, image_id) VALUES (?, ?, ?, ?)")->execute([$public_id, $name, 'PHP-Music', $img_id]);
          $mix_id = $db->lastInsertId();
          
          $order = 0;
          $insert_ms = $db->prepare("INSERT INTO mix_songs (mix_id, song_id, sort_order) VALUES (?, ?, ?)");
          foreach ($song_ids as $sid) {
            $insert_ms->execute([$mix_id, $sid, $order++]);
          }
        }
      }
      
      $sort_key = $_GET['sort'] ?? 'newest';
      $sort_map = [
        'name_asc' => 'ORDER BY name COLLATE NOCASE ASC',
        'name_desc' => 'ORDER BY name COLLATE NOCASE DESC',
        'newest' => 'ORDER BY id DESC',
        'oldest' => 'ORDER BY id ASC',
      ];
      $order_by = $sort_map[$sort_key] ?? $sort_map['newest'];
      
      $q = $_GET['q'] ?? '';
      $where_sql = "";
      $params = [];
      if ($q !== '') {
        $where_sql = "WHERE match_text(name, ?) = 1";
        $params[] = $q;
      }
      
      $stmt = $db->prepare("SELECT id, public_id, name, creator, image_id as image_id, (SELECT COUNT(*) FROM mix_songs WHERE mix_id = mixes.id) as song_count FROM mixes $where_sql $order_by $limit_clause");
      $stmt->execute($params);
      send_json($stmt->fetchAll());
      break;

    case 'get_collab_playlists':
      if (!$user_id) { send_json([]); }
      $sort_key = $_GET['sort'] ?? 'name_asc';
      $sort_map = [
        'name_asc' => 'ORDER BY p.name COLLATE NOCASE ASC',
        'name_desc' => 'ORDER BY p.name COLLATE NOCASE DESC',
        'modified_desc' => 'ORDER BY COALESCE((SELECT MAX(added_at) FROM playlist_songs WHERE playlist_id = p.id), p.created_at) DESC',
        'modified_asc' => 'ORDER BY COALESCE((SELECT MAX(added_at) FROM playlist_songs WHERE playlist_id = p.id), p.created_at) ASC',
      ];
      $order_by = $sort_map[$sort_key] ?? $sort_map['name_asc'];
      
      $stmt = $db->prepare("
        SELECT p.id, p.name, p.description, p.public_id, p.is_collaborative, p.is_private, p.user_id as owner_id, u.artist as creator, p.play_count, COUNT(ps.song_id) as song_count,
        (SELECT ps.song_id FROM playlist_songs ps WHERE ps.playlist_id = p.id ORDER BY ps.added_at DESC LIMIT 1) as image_id,
        (SELECT m.last_modified FROM playlist_songs ps2 JOIN music m ON ps2.song_id = m.id WHERE ps2.playlist_id = p.id ORDER BY ps2.added_at DESC LIMIT 1) as image_v
        FROM playlists p
        JOIN playlist_collaborators pc ON p.id = pc.playlist_id
        JOIN users u ON p.user_id = u.id
        LEFT JOIN playlist_songs ps ON p.id = ps.playlist_id
        WHERE pc.user_id = ?
        GROUP BY p.id, p.name, p.description, p.public_id, p.is_collaborative, p.is_private, p.user_id, u.artist, p.play_count
        {$order_by} {$limit_clause}
      ");
      $stmt->execute([$user_id]);
      send_json($stmt->fetchAll());
      break;

    case 'leave_collab':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $public_id = $data['public_id'];
      $stmt = $db->prepare("DELETE FROM playlist_collaborators WHERE user_id = ? AND playlist_id = (SELECT id FROM playlists WHERE public_id = ?)");
      $stmt->execute([$user_id, $public_id]);
      send_json(['status' => 'success', 'message' => 'You have left the collaboration.']);
      break;
      
    case 'manage_song_collaborators':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $song_id = intval($data['song_id'] ?? 0);
      $action_type = $data['collab_action']; 
      
      if ($action_type === 'search') {
        $q = $data['query'] ?? '';
        $stmt = $db->prepare("SELECT id, artist FROM users WHERE match_text(artist, ?) = 1 OR email LIKE ? LIMIT 10");
        $stmt->execute([$q, '%' . $q . '%']);
        send_json(['status' => 'success', 'users' => $stmt->fetchAll()]);
      }
      
      $stmt = $db->prepare("SELECT id, user_id, is_collaborative FROM music WHERE id = ?");
      $stmt->execute([$song_id]);
      $song = $stmt->fetch();
      
      if (!$song) {
        http_response_code(404); send_json(['status' => 'error', 'message' => 'Song not found.']);
      }
      
      if ($action_type === 'generate_link') {
        if ($song['user_id'] != $user_id && $is_super_admin == 0) {
          http_response_code(403); send_json(['status' => 'error', 'message' => 'Only the owner can generate links.']);
        }
        $db->exec("DELETE FROM song_invites WHERE expires_at IS NOT NULL AND expires_at <= CURRENT_TIMESTAMP");
        
        $expire_val = $data['expire'] ?? null;
        $expires_at = null;
        if ($expire_val && is_numeric($expire_val)) {
          $expires_at = date('Y-m-d H:i:s', time() + ((int)$expire_val * 60));
        }
        $token = bin2hex(random_bytes(16));
        $db->prepare("INSERT INTO song_invites (token, song_id, expires_at) VALUES (?, ?, ?)")->execute([$token, $song['id'], $expires_at]);
        send_json(['status' => 'success', 'token' => $token]);
      }

      if ($action_type === 'join') {
        $token = $data['token'] ?? '';
