        FROM playlist_invites pi 
        JOIN playlists p ON pi.playlist_id = p.id 
        JOIN users u ON p.user_id = u.id 
        WHERE pi.token = ? AND (pi.expires_at IS NULL OR pi.expires_at > CURRENT_TIMESTAMP)
