    case 'create_playlist':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $name = trim(htmlspecialchars($data['name'] ?? '', ENT_QUOTES, 'UTF-8'));
      $description = trim(htmlspecialchars($data['description'] ?? '', ENT_QUOTES, 'UTF-8'));
      $is_private = intval($data['is_private'] ?? 0);
      if (empty($name)) {
        http_response_code(400); send_json(['status' => 'error', 'message' => 'Playlist name cannot be empty.']);
      }
      
      try { $db->exec("ALTER TABLE playlists ADD COLUMN description TEXT;"); } catch(Exception $e) {}
      
      $public_id = bin2hex(random_bytes(8));
      $stmt = $db->prepare("INSERT INTO playlists (user_id, name, description, public_id, is_private) VALUES (?, ?, ?, ?, ?)");
      $stmt->execute([$user_id, $name, $description, $public_id, $is_private]);
      if ($is_private == 0) {
        $db->prepare("INSERT INTO activity_feed (user_id, action, target_name) VALUES (?, ?, ?)")->execute([$user_id, 'created a playlist', $name]);
      }
      send_json(['status' => 'success', 'message' => 'Playlist created.']);
      break;

    case 'get_activity_feed':
      if (!$user_id) { send_json([]); }
      
      try { $db->exec("ALTER TABLE users ADD COLUMN last_notif_clear DATETIME;"); } catch(Exception $e) {}
      try { $db->exec("ALTER TABLE users ADD COLUMN last_notif_read DATETIME;"); } catch(Exception $e) {}
      
      $stmt_times = $db->prepare("SELECT last_notif_clear, last_notif_read FROM users WHERE id = ?");
      $stmt_times->execute([$user_id]);
      $times = $stmt_times->fetch();
      $last_clear = $times['last_notif_clear'] ?: '2000-01-01 00:00:00';
      $last_read = $times['last_notif_read'] ?: '2000-01-01 00:00:00';
      
      $feed = [];
      
      $act_page = isset($_GET['page']) ? max(1, (int)$_GET['page']) : 1;
      $act_limit = 25;
      $act_offset = ($act_page - 1) * $act_limit;
      $db_fetch_limit = $act_offset + $act_limit; // Fetch enough to cover the current page offset slice

      // 1. My standard activity
      $stmt = $db->prepare("SELECT 'activity' as type, action, target_name, created_at FROM activity_feed WHERE user_id = ? AND created_at > ? ORDER BY created_at DESC LIMIT ?");
      $stmt->execute([$user_id, $last_clear, $db_fetch_limit]);
      $feed = array_merge($feed, $stmt->fetchAll());
      
      // 2. Incoming Comments and Replies
      $stmt2 = $db->prepare("
        SELECT 
          'comment_notif' as type,
          c.id as comment_id,
          c.song_id,
          c.content,
          c.created_at,
          CASE WHEN u.banned = 1 THEN 'Banned User' WHEN u.email LIKE 'deleted_%' THEN 'Deleted User' ELSE u.artist END as commenter_name,
          m.title as song_title,
          CASE 
            WHEN c.parent_id IS NOT NULL THEN 'reply'
            ELSE 'comment'
          END as notif_type
        FROM song_comments c
        JOIN users u ON c.user_id = u.id
        JOIN music m ON c.song_id = m.id
        LEFT JOIN song_comments pc ON c.parent_id = pc.id
        WHERE ((m.user_id = ? AND c.parent_id IS NULL AND c.user_id != ?) 
           OR (c.parent_id IS NOT NULL AND pc.user_id = ? AND c.user_id != ?))
           AND c.created_at > ?
        ORDER BY c.created_at DESC LIMIT ?
      ");
      $stmt2->execute([$user_id, $user_id, $user_id, $user_id, $last_clear, $db_fetch_limit]);
      $feed = array_merge($feed, $stmt2->fetchAll());
      
      // 3. Incoming Community Replies
      $stmt3 = $db->prepare("
        SELECT 
          'community_notif' as type,
          cp.id as post_id,
          cp.content,
          cp.created_at,
          CASE WHEN u.banned = 1 THEN 'Banned User' WHEN u.email LIKE 'deleted_%' THEN 'Deleted User' ELSE u.artist END as commenter_name,
          '' as song_title,
          'community_reply' as notif_type
        FROM community_posts cp
        JOIN users u ON cp.user_id = u.id
        JOIN community_posts parent_post ON cp.parent_id = parent_post.id
        WHERE parent_post.user_id = ? AND cp.user_id != ? AND cp.created_at > ?
        ORDER BY cp.created_at DESC LIMIT ?
      ");
      $stmt3->execute([$user_id, $user_id, $last_clear, $db_fetch_limit]);
      $feed = array_merge($feed, $stmt3->fetchAll());
      
      // 4. Incoming Messages
      $stmt4 = $db->prepare("
        SELECT 
          'message_notif' as type,
          m.id as message_id,
          m.content,
          m.created_at,
          CASE WHEN u.banned = 1 THEN 'Banned User' WHEN u.email LIKE 'deleted_%' THEN 'Deleted User' ELSE u.artist END as commenter_name,
          u.id as sender_id,
          'message' as notif_type
        FROM messages m
        JOIN users u ON m.sender_id = u.id
        WHERE m.receiver_id = ? AND m.created_at > ?
        ORDER BY m.created_at DESC LIMIT ?
      ");
      $stmt4->execute([$user_id, $last_clear, $db_fetch_limit]);
      $feed = array_merge($feed, $stmt4->fetchAll());

      // Sort all notifications by date
      usort($feed, function($a, $b) {
        return strtotime($b['created_at']) - strtotime($a['created_at']);
      });
      
      // Add unread status flags and slice safely based on the offset
      $final_feed = array_slice($feed, $act_offset, $act_limit);
      foreach ($final_feed as &$item) {
        $item['is_unread'] = (strtotime($item['created_at']) > strtotime($last_read));
      }
      unset($item);
      
      send_json($final_feed);
      break;

    case 'clear_activity_feed':
      if (!$user_id) { http_response_code(403); exit; }
      try { $db->exec("ALTER TABLE users ADD COLUMN last_notif_clear DATETIME;"); } catch(Exception $e) {}
      $db->prepare("UPDATE users SET last_notif_clear = CURRENT_TIMESTAMP WHERE id = ?")->execute([$user_id]);
      $db->prepare("DELETE FROM activity_feed WHERE user_id = ?")->execute([$user_id]);
      send_json(['status' => 'success']);
      break;

    case 'get_unread_notif_count':
      if (!$user_id) { send_json(['count' => 0]); }
      try { $db->exec("ALTER TABLE users ADD COLUMN last_notif_read DATETIME;"); } catch(Exception $e) {}
      try { $db->exec("ALTER TABLE users ADD COLUMN last_notif_clear DATETIME;"); } catch(Exception $e) {}
      
      $stmt_times = $db->prepare("SELECT MAX(COALESCE(last_notif_read, '2000-01-01 00:00:00'), COALESCE(last_notif_clear, '2000-01-01 00:00:00')) FROM users WHERE id = ?");
      $stmt_times->execute([$user_id]);
      $threshold = $stmt_times->fetchColumn() ?: '2000-01-01 00:00:00';

      $sql = "SELECT (
        (SELECT COUNT(*) FROM song_comments c JOIN music m ON c.song_id = m.id LEFT JOIN song_comments pc ON c.parent_id = pc.id WHERE ((m.user_id = :u AND c.parent_id IS NULL AND c.user_id != :u) OR (c.parent_id IS NOT NULL AND pc.user_id = :u AND c.user_id != :u)) AND c.created_at > :t) +
        (SELECT COUNT(*) FROM community_posts cp JOIN community_posts parent_post ON cp.parent_id = parent_post.id WHERE parent_post.user_id = :u AND cp.user_id != :u AND cp.created_at > :t) +
        (SELECT COUNT(*) FROM blog_comments bc JOIN blogs b ON bc.blog_id = b.id LEFT JOIN blog_comments pbc ON bc.parent_id = pbc.id WHERE ((b.user_id = :u AND bc.parent_id IS NULL AND bc.user_id != :u) OR (bc.parent_id IS NOT NULL AND pbc.user_id = :u AND bc.user_id != :u)) AND bc.created_at > :t) +
        (SELECT COUNT(*) FROM messages WHERE receiver_id = :u AND created_at > :t) +
        (SELECT COUNT(*) FROM activity_feed WHERE user_id = :u AND created_at > :t)
      ) as total_count";

      $stmt = $db->prepare($sql);
      $stmt->execute([':u' => $user_id, ':t' => $threshold]);
      $total_count = (int)$stmt->fetchColumn();

      send_json(['count' => $total_count]);
      break;

    case 'mark_notifs_read':
      if (!$user_id) { http_response_code(403); exit; }
      try { $db->exec("ALTER TABLE users ADD COLUMN last_notif_read DATETIME;"); } catch(Exception $e) {}
      $db->prepare("UPDATE users SET last_notif_read = CURRENT_TIMESTAMP WHERE id = ?")->execute([$user_id]);
      send_json(['status' => 'success']);
      break;

    case 'edit_playlist':
      if (!$user_id) { http_response_code(403); exit; }
      $data = json_decode(file_get_contents('php://input'), true);
      $public_id = $data['public_id'];
      $new_name = trim(htmlspecialchars($data['name'] ?? '', ENT_QUOTES, 'UTF-8'));
      $description = trim(htmlspecialchars($data['description'] ?? '', ENT_QUOTES, 'UTF-8'));
      $is_private = intval($data['is_private'] ?? 0);
      if (empty($new_name)) {
        http_response_code(400); send_json(['status' => 'error', 'message' => 'Playlist name cannot be empty.']);
      }
      
      // Forcefully ensure the description column exists to prevent 500 errors if the session wasn't reset
      try { $db->exec("ALTER TABLE playlists ADD COLUMN description TEXT;"); } catch(Exception $e) {}
      
      $stmt = $db->prepare("UPDATE playlists SET name = ?, description = ?, is_private = ?, is_collaborative = CASE WHEN ? = 1 THEN 0 ELSE is_collaborative END WHERE public_id = ? AND (user_id = ? OR {$is_admin} = 1)");
      $stmt->execute([$new_name, $description, $is_private, $is_private, $public_id, $user_id]);
      
      // Destroy collaborators safely if transitioning to Private
      if ($is_private == 1) {
        $db->prepare("DELETE FROM playlist_collaborators WHERE playlist_id = (SELECT id FROM playlists WHERE public_id = ?)")->execute([$public_id]);
      }
      
      send_json(['status' => 'success', 'message' => 'Playlist updated.']);
