        overflow: hidden;
        color: var(--ytm-primary-text);
      }
      .note-card-body {
        font-size: 0.95rem;
        color: var(--ytm-secondary-text);
        line-height: 1.5;
        flex-grow: 1;
        display: -webkit-box;
        -webkit-line-clamp: 5;
        -webkit-box-orient: vertical;
        overflow: hidden;
        word-break: break-word;
      }
      .note-card-footer {
        display: flex;
        justify-content: space-between;
