              <h2 id="calendar-time-display" class="fw-bold text-white mb-1" style="font-size: clamp(2rem, 6vw, 3.2rem); font-family: 'Roboto', sans-serif; letter-spacing: 1px; text-shadow: 0 4px 12px rgba(0,0,0,0.5);">00:00:00</h2>
