    <script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/js/bootstrap.bundle.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/sortablejs@latest/Sortable.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/cropperjs/1.6.1/cropper.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/nosleep/0.12.0/NoSleep.min.js"></script>
    <script>
      // Global Hashchange Interceptor for Playground
      window.addEventListener('hashchange', () => {
        // If the hash changes to playground and we are inside the main app (where the template exists), force a clean reload to boot it.
        if (window.location.hash.startsWith('#playground') && document.getElementById('play-client-template')) {
          window.location.reload();
        }
      });

      document.addEventListener('DOMContentLoaded', () => {
        // PLAYGROUND ROUTER INTERCEPTOR
        // If the URL contains #playground, halt main app boot and swap out the DOM for the client template.
        if (window.location.hash.startsWith('#playground')) {
          const tpl = document.getElementById('play-client-template');
          if (tpl) {
            document.open();
            document.write(tpl.innerHTML);
            document.close();
          }
          return; // Strictly abort further execution of the main app
        }

        'use strict';

        const escapeAttr = (str) => str ? String(str).replace(/'/g, "&apos;").replace(/"/g, "&quot;") : '';

        const getSvgPlaceholder = (title) => {
          let hash = 0;
          for (let i = 0; i < title.length; i++) {
            hash = title.charCodeAt(i) + ((hash << 5) - hash);
          }
          const h = Math.abs(hash % 360);
          const c1 = `hsl(${h}, 50%, 35%)`;
          const c2 = `hsl(${(h + 40) % 360}, 60%, 45%)`;
          const c3 = `hsl(${(h + 80) % 360}, 60%, 35%)`;
          const svgString = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="100%" height="100%"><defs><linearGradient id="grad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stop-color="${c1}"/><stop offset="50%" stop-color="${c2}"/><stop offset="100%" stop-color="${c3}"/></linearGradient><filter id="shadow" x="-10%" y="-10%" width="120%" height="120%"><feDropShadow dx="0" dy="8" stdDeviation="12" flood-opacity="0.3"/></filter></defs><rect width="512" height="512" fill="url(#grad)"/><g transform="translate(128, 128) scale(10.66)" fill="none" stroke="#ffffff" stroke-width="1.5" opacity="0.9" filter="url(#shadow)"><circle cx="12" cy="12" r="3"/><path stroke-linecap="round" d="M21.95 13c-.501 5.054-4.765 9-9.95 9c-5.523 0-10-4.477-10-10c0-1.821.487-3.529 1.338-5M11 2.05a9.9 9.9 0 0 0-4 1.288"/><path stroke-linecap="round" stroke-linejoin="round" d="M15 12V2.456a10.02 10.02 0 0 1 6.542 6.542"/></g></svg>`;
          return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svgString)}`;
        };
        
        window.scrollToCenter = (container, element, smooth = true) => {
          if (!container || !element) return false;
          
          const containerRect = container.getBoundingClientRect();
          const elementRect = element.getBoundingClientRect();
          
          // If the element or container is not visible (e.g. display: none), heights will be 0
          if (containerRect.height === 0 || elementRect.height === 0) return false;
          
          // Accurately calculate the scroll target using absolute bounding box coordinates
          const targetScroll = container.scrollTop + (elementRect.top - containerRect.top) - (container.clientHeight / 2) + (elementRect.height / 2);
          
          container.scrollTo({
            top: targetScroll,
            behavior: smooth ? 'smooth' : 'auto'
          });
          return true;
        };

        window.enforceScrollToActive = (paneId, queueListId, smooth = false) => {
          let attempts = 0;
          const tryScroll = () => {
            attempts++;
            const pane = document.getElementById(paneId);
            const activeItem = document.querySelector(`#${queueListId} .song-item.now-playing`);
            
            if (pane && activeItem) {
              const success = window.scrollToCenter(pane, activeItem, smooth);
              // Double check after 150ms to counteract layout shifts from images loading or modal fading in
              if (success && attempts === 1) {
                setTimeout(tryScroll, 150);
              } else if (!success && attempts < 15) {
                setTimeout(tryScroll, 50);
              }
            } else if (attempts < 15) {
              setTimeout(tryScroll, 50); 
            }
          };
          // Start the first attempt slightly deferred to allow initial DOM render
          setTimeout(tryScroll, 20);
        };

        const mainContent = document.getElementById('main-content');
        const contentArea = document.getElementById('content-area');
        const contentTitle = document.getElementById('content-title');
        const searchInputDesktop = document.getElementById('search-input-desktop');
        const searchInputMobile = document.getElementById('search-input-mobile');
        const searchBtnDesktop = document.getElementById('search-btn-desktop');
        const searchBtnMobile = document.getElementById('search-btn-mobile');
        const sortControls = document.getElementById('sort-controls');
        const sortSelect = document.getElementById('sort-select');
        const historyControls = document.getElementById('history-controls');
        const clearHistoryBtn = document.getElementById('clear-history-btn');
        const allNavLinks = document.querySelectorAll('.sidebar .nav-link');
        const contextMenu = document.getElementById('context-menu');
        const playerBar = document.getElementById('player-bar');
        const infiniteScrollLoader = document.getElementById('infinite-scroll-loader');
        const installPwaBtn = document.getElementById('install-pwa-btn');
        const checkUpdateBtn = document.getElementById('check-update-btn');
        const updateModalEl = document.getElementById('update-modal');
        const updateModal = updateModalEl ? new bootstrap.Modal(updateModalEl) : null;
        const updateModalBody = document.getElementById('update-modal-body');

        const pipBtnDesktop = document.getElementById('pip-btn-desktop');
        const pipBtnMobile = document.getElementById('pip-btn-mobile');
        
        const pipCanvas = document.createElement('canvas');
        pipCanvas.width = 500;
        pipCanvas.height = 500;
        const pipCtx = pipCanvas.getContext('2d', { willReadFrequently: true });
        const pipVideo = document.createElement('video');
        pipVideo.muted = true;
        pipVideo.playsInline = true;
        
        // FIX INFINITE SPINNER: Do not assign endless MediaStreams to video elements before the window finishes loading!
        // Chromium treats captureStream() as a pending network resource if attached too early.
        window.addEventListener('load', () => {
          try {
            const supportsPiP = ('documentPictureInPicture' in window) || document.pictureInPictureEnabled || (pipVideo.webkitSupportsPresentationMode && typeof pipVideo.webkitSetPresentationMode === 'function');
            if (pipCanvas.captureStream && supportsPiP) {
              pipVideo.srcObject = pipCanvas.captureStream(1);
            } else {
              if (pipBtnDesktop) pipBtnDesktop.style.display = 'none';
              if (pipBtnMobile) pipBtnMobile.style.display = 'none';
            }
          } catch(e) {
            if (pipBtnDesktop) pipBtnDesktop.style.display = 'none';
            if (pipBtnMobile) pipBtnMobile.style.display = 'none';
          }
        });
        
        const clearCacheBtn = document.getElementById('clear-cache-btn');
        const fullscreenBtn = document.getElementById('fullscreen-btn');
        const fullScanModalEl = document.getElementById('full-scan-modal');
        const fullScanIframe = document.getElementById('full-scan-iframe');

        const genresModalEl = document.getElementById('genres-modal');
        const genresModal = genresModalEl ? new bootstrap.Modal(genresModalEl) : null;
        const genresModalBody = document.getElementById('genres-modal-body');
        const createPlaylistModalEl = document.getElementById('create-playlist-modal');
        const createPlaylistModal = createPlaylistModalEl ? new bootstrap.Modal(createPlaylistModalEl) : null;
        const editPlaylistModalEl = document.getElementById('edit-playlist-modal');
        const editPlaylistModal = editPlaylistModalEl ? new bootstrap.Modal(editPlaylistModalEl) : null;
        const importPlaylistModalEl = document.getElementById('import-playlist-modal');
        const importPlaylistModal = importPlaylistModalEl ? new bootstrap.Modal(importPlaylistModalEl) : null;
        const importFavoritesModalEl = document.getElementById('import-favorites-modal');
        const importFavoritesModal = importFavoritesModalEl ? new bootstrap.Modal(importFavoritesModalEl) : null;
        const addToPlaylistModalEl = document.getElementById('add-to-playlist-modal');
        const addToPlaylistModal = addToPlaylistModalEl ? new bootstrap.Modal(addToPlaylistModalEl) : null;
        const addToPlaylistModalBody = document.getElementById('add-to-playlist-modal-body');
        const metadataModalEl = document.getElementById('metadata-modal');
        const metadataModal = metadataModalEl ? new bootstrap.Modal(metadataModalEl) : null;
        const metadataModalBody = document.getElementById('metadata-modal-body');
        const editMetadataModalEl = document.getElementById('edit-metadata-modal');
        const editMetadataModal = editMetadataModalEl ? new bootstrap.Modal(editMetadataModalEl) : null;
        const artistsModalEl = document.getElementById('artists-modal');
        const artistsModal = artistsModalEl ? new bootstrap.Modal(artistsModalEl) : null;
        const artistsModalBody = document.getElementById('artists-modal-body');
        const shareModalEl = document.getElementById('share-modal');
        const shareModal = shareModalEl ? new bootstrap.Modal(shareModalEl) : null;
        const shareModalTitle = document.getElementById('share-modal-title');
        const shareModalText = document.getElementById('share-modal-text');
        const shareUrlInput = document.getElementById('share-url-input');
        const copyShareUrlBtn = document.getElementById('copy-share-url-btn');
        const activityModalEl = document.getElementById('activity-modal');
        
        if (activityModalEl) {
          const body = document.getElementById('activity-modal-body');
          
          let activityPage = 1;
          const loadActivityFeed = async (append = false) => {
            if (!append) {
              activityPage = 1;
              body.innerHTML = '<div class="text-center p-4"><div class="spinner-border text-secondary" role="status"></div></div>';
            } else {
              const btn = document.getElementById('load-more-activity-btn');
              if (btn) btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Loading...';
            }
            
            const feed = await fetchData(`?action=get_activity_feed&page=${activityPage}`);
            
            const loadMoreBtnContainer = document.getElementById('load-more-activity-container');
            if (loadMoreBtnContainer) loadMoreBtnContainer.remove();

            if (feed && feed.length > 0) {
              const htmlStr = feed.map(item => {
                if (item.type === 'message_notif') {
                  const unreadBadge = item.is_unread ? '<span class="badge bg-danger ms-2" style="font-size: 0.65rem;">New</span>' : '';
                  const bgClass = item.is_unread ? 'bg-dark' : 'bg-transparent';
                  const cleanContent = item.content ? parseUserText(item.content).replace(/<[^>]*>?/gm, '') : 'Sent an image';

                  return `
                    <li class="list-group-item ${bgClass} text-white border-secondary py-3 open-chat-btn" data-userid="${item.sender_id}" data-artist="${escapeHTML(item.commenter_name)}" style="cursor: pointer;">
                      <div class="d-flex align-items-start gap-3">
                        <div class="mt-1"><i class="bi bi-chat-dots-fill text-info fs-5"></i></div>
                        <div class="flex-grow-1" style="min-width: 0;">
                          <div style="font-size: 0.95rem;"><span class="fw-bold">${escapeHTML(item.commenter_name)}</span> sent you a message${unreadBadge}</div>
                          <div class="text-secondary fst-italic my-1 text-truncate" style="font-size: 0.9rem; border-left: 2px solid #555; padding-left: 8px;">"${cleanContent}"</div>
                          <div class="d-flex justify-content-between align-items-center mt-2">
                            <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(item.created_at)}</small>
                            <button class="btn btn-sm btn-outline-light"><i class="bi bi-reply-fill"></i> Reply</button>
                          </div>
                        </div>
                      </div>
                    </li>
                  `;
                } else if (item.type === 'comment_notif' || item.type === 'community_notif') {
                  const isCommunity = item.type === 'community_notif';
                  const isReply = item.notif_type === 'reply' || item.notif_type === 'community_reply';
                  const unreadBadge = item.is_unread ? '<span class="badge bg-danger ms-2" style="font-size: 0.65rem;">New</span>' : '';
                  const bgClass = item.is_unread ? 'bg-dark' : 'bg-transparent';

                  let actionText = '';
                  let iconHTML = '';
                  let replyBtnHTML = '';

                  if (isCommunity) {
                    actionText = `<span class="fw-bold">${escapeHTML(item.commenter_name)}</span> replied to your community post${unreadBadge}`;
                    iconHTML = `<i class="bi bi-people-fill text-info fs-5"></i>`;
                    replyBtnHTML = `<button class="btn btn-sm btn-outline-light notif-comm-reply-btn" data-post-id="${item.post_id}" data-username="${escapeHTML(item.commenter_name)}"><i class="bi bi-reply-fill"></i> Reply</button>`;
                  } else {
                    actionText = isReply 
                      ? `<span class="fw-bold">${escapeHTML(item.commenter_name)}</span> replied to your comment on <span class="text-info">${escapeHTML(item.song_title)}</span>${unreadBadge}`
                      : `<span class="fw-bold">${escapeHTML(item.commenter_name)}</span> commented on your song <span class="text-info">${escapeHTML(item.song_title)}</span>${unreadBadge}`;
                    iconHTML = `<i class="bi bi-chat-dots-fill text-primary fs-5"></i>`;
                    replyBtnHTML = `<button class="btn btn-sm btn-outline-light notif-reply-btn" data-song-id="${item.song_id}" data-comment-id="${item.comment_id}" data-username="${escapeHTML(item.commenter_name)}"><i class="bi bi-reply-fill"></i> Reply</button>`;
                  }
                     
                  const cleanContent = parseUserText(item.content).replace(/<[^>]*>?/gm, ''); 

                  return `
                    <li class="list-group-item ${bgClass} text-white border-secondary py-3">
                      <div class="d-flex align-items-start gap-3">
                        <div class="mt-1">${iconHTML}</div>
                        <div class="flex-grow-1" style="min-width: 0;">
                          <div style="font-size: 0.95rem;">${actionText}</div>
                          <div class="text-secondary fst-italic my-1 text-truncate" style="font-size: 0.9rem; border-left: 2px solid #555; padding-left: 8px;">"${cleanContent}"</div>
                          <div class="d-flex justify-content-between align-items-center mt-2">
                            <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(item.created_at)}</small>
                            ${replyBtnHTML}
                          </div>
                        </div>
                      </div>
                    </li>
                  `;
                } else {
                  const unreadBadge = item.is_unread ? '<span class="badge bg-danger ms-2" style="font-size: 0.65rem;">New</span>' : '';
                  const bgClass = item.is_unread ? 'bg-dark' : 'bg-transparent';
                  return `
                    <li class="list-group-item ${bgClass} text-white border-secondary py-3">
                      <div class="d-flex align-items-center gap-3">
                        <div class="mt-1"><i class="bi bi-clock-history text-secondary fs-5"></i></div>
                        <div>
                          <div style="font-size: 0.95rem;">You ${escapeHTML(item.action)} ${item.target_name ? `<span class="text-info">${escapeHTML(item.target_name)}</span>` : ''}${unreadBadge}</div>
                          <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(item.created_at)}</small>
                        </div>
                      </div>
                    </li>
                  `;
                }
              }).join('');

              if (!append) {
                body.innerHTML = '<ul class="list-group list-group-flush" id="activity-list">' + htmlStr + '</ul>';
              } else {
                document.getElementById('activity-list').insertAdjacentHTML('beforeend', htmlStr);
              }

              if (feed.length === 25) {
                body.insertAdjacentHTML('beforeend', `
                  <div class="text-center p-3" id="load-more-activity-container">
                    <button class="btn btn-outline-light rounded-pill px-4 btn-sm fw-bold" id="load-more-activity-btn">Load More Activity</button>
                  </div>
                `);
                document.getElementById('load-more-activity-btn').addEventListener('click', () => {
                  activityPage++;
                  loadActivityFeed(true);
                });
              }
               
              if (!append) {
                setTimeout(async () => {
                  document.querySelectorAll('.notif-badge').forEach(b => b.classList.add('d-none'));
                  await fetchData('?action=mark_notifs_read', { method: 'POST' });
                  updateNotifBadge();
                }, 1500);
              }
            } else {
              if (!append) body.innerHTML = '<p class="text-secondary text-center p-4">No recent activity.</p>';
            }
          };

          activityModalEl.addEventListener('show.bs.modal', () => loadActivityFeed(false));

          const connectionsModalEl = document.getElementById('connections-modal');
          if (connectionsModalEl) {
            connectionsModalEl.addEventListener('click', async (e) => {
              const loadMoreBtn = e.target.closest('#load-more-conn-btn');
              if (loadMoreBtn) {
                e.preventDefault();
                window.connPage++;
                window.loadConnections(true);
                return;
              }
              
              const followBtn = e.target.closest('.follow-btn-modal');
              if (followBtn) {
                e.preventDefault();
                e.stopPropagation();
                if (!currentUser) return showToast('Please log in', 'error');
                const userId = followBtn.dataset.userId;
                const res = await fetchData('?action=toggle_follow', {
                  method: 'POST',
                  headers: {'Content-Type': 'application/json'},
                  body: JSON.stringify({ following_id: userId })
                });
                
                if (res && (res.status === 'followed' || res.status === 'unfollowed')) {
                  const isFollowing = res.status === 'followed';
                  followBtn.textContent = isFollowing ? 'Unfollow' : 'Follow';
                  followBtn.className = `btn btn-sm rounded-pill fw-bold follow-btn-modal px-3 flex-shrink-0 ${isFollowing ? 'btn-outline-light' : 'btn-danger'}`;
                  
                  if (currentView.type === 'artist_songs' || currentView.type === 'user_profile' || currentView.type === 'get_following') {
                    loadView(currentView); // Sync background view numbers
                  }
                } else {
                  showToast(res?.message || 'Error toggling follow', 'error');
                }
                return;
              }
            });
          }

          // --- FULL PAGE CHAT APP LOGIC ---
          window.getPreviewText = (htmlStr) => {
            if (!htmlStr) return '';
            const tmp = document.createElement('div');
            tmp.innerHTML = htmlStr;
            return tmp.textContent || tmp.innerText || '';
          };

          if (!window.chatAudioObj) {
            window.chatAudioObj = new Audio();
            window.chatAudioActiveMsgId = null;

            window.chatAudioObj.addEventListener('timeupdate', () => {
              if (window.chatAudioActiveMsgId && isFinite(window.chatAudioObj.duration)) {
                const playerEl = document.querySelector(`.chat-audio-player[data-msg-id="${window.chatAudioActiveMsgId}"]`);
                if (playerEl) {
                  const pct = (window.chatAudioObj.currentTime / window.chatAudioObj.duration) * 100;
                  const track = playerEl.querySelector('.chat-audio-progress');
                  const timeDisplay = playerEl.querySelector('.chat-audio-time');
                  const icon = playerEl.querySelector('.chat-audio-play-btn i');
                     
                  if (track) track.style.width = pct + '%';
                  if (timeDisplay) {
                    const cur = window.chatAudioObj.currentTime;
                    const m = Math.floor(cur / 60);
                    const s = Math.floor(cur % 60).toString().padStart(2, '0');
                    timeDisplay.innerText = `${m}:${s}`;
                  }
                  if (icon && !window.chatAudioObj.paused) {
                    icon.className = 'bi bi-pause-fill fs-4';
                  }
                }
              }
            });
            window.chatAudioObj.addEventListener('ended', () => {
              const playerEl = document.querySelector(`.chat-audio-player[data-msg-id="${window.chatAudioActiveMsgId}"]`);
              if (playerEl) {
                const icon = playerEl.querySelector('.chat-audio-play-btn i');
                const track = playerEl.querySelector('.chat-audio-progress');
                const timeDisplay = playerEl.querySelector('.chat-audio-time');
                if (icon) icon.className = 'bi bi-play-fill fs-4';
                if (track) track.style.width = '0%';
                if (timeDisplay) timeDisplay.innerText = '0:00';
              }
              window.chatAudioActiveMsgId = null;
            });
          }

          window.playChatAudio = (msgId, url) => {
            const isPlayingThis = window.chatAudioActiveMsgId == msgId && !window.chatAudioObj.paused;
             
            document.querySelectorAll('.chat-audio-play-btn i').forEach(i => i.className = 'bi bi-play-fill fs-4');
             
            if (isPlayingThis) {
              window.chatAudioObj.pause();
            } else {
              if (window.chatAudioActiveMsgId != msgId) {
                window.chatAudioObj.src = url;
                window.chatAudioActiveMsgId = msgId;
              }
                
              const mainAudio = document.getElementById('audio-player');
              if (mainAudio && !mainAudio.paused) {
                document.getElementById('btn-play-pause').click();
              }

              window.chatAudioObj.play().catch(e => console.error(e));
            }
          };
          
          window.seekChatAudio = (e, msgId) => {
            if (window.chatAudioActiveMsgId != msgId) return;
            const playerEl = document.querySelector(`.chat-audio-player[data-msg-id="${msgId}"]`);
            if (!playerEl) return;
            const trackContainer = playerEl.querySelector('.chat-audio-track');
            const rect = trackContainer.getBoundingClientRect();
            const pos = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
            if (isFinite(window.chatAudioObj.duration)) {
              window.chatAudioObj.currentTime = pos * window.chatAudioObj.duration;
            }
          };

          window.openChatFull = async (targetId, type, name) => {
            requestNotificationPermission(); // Ask OS permission to send Push Notifications
            activeChatConfig = { id: targetId, type: type, name: name };
            window.currentChatPage = 1; // Reset pagination bounds on new chat
            window.lastMessagesString = null; // Reset comparison state
            window.forceScrollToBottomNext = true; // Flag to snap scroll to bottom
            const mainArea = document.querySelector('.chat-main');
            const sidebarArea = document.querySelector('.chat-sidebar');
            
            const mentionBtn = document.getElementById('chat-mention-btn');
            const chatInput = document.getElementById('chat-input');
            if (mentionBtn) {
              if (type === 'group') mentionBtn.classList.remove('d-none');
              else mentionBtn.classList.add('d-none');
            }
            if (chatInput) {
              chatInput.placeholder = type === 'group' ? 'Type a message...' : 'Type a message...';
            }
            
            const chatInputArea = document.querySelector('.chat-input-area');
            if (chatInputArea) chatInputArea.style.display = 'flex';
             
            if (mainArea) mainArea.classList.add('active');
            if (sidebarArea && window.innerWidth < 768) sidebarArea.classList.add('hidden');
             
            const headerTitle = document.getElementById('chat-header-title');
            if (headerTitle) {
              const cacheBuster = Math.floor(Date.now() / 60000);
              headerTitle.innerHTML = (type === 'group' 
                ? `<div class="d-flex align-items-center justify-content-center rounded-circle me-3 overflow-hidden bg-dark" style="width: 44px; height: 44px; min-width: 44px; flex-shrink: 0; line-height: 1;"><img src="?action=get_group_image&id=${targetId}&v=${cacheBuster}" onerror="this.outerHTML='<i class=\\'bi bi-people-fill text-info fs-4\\'></i>'" style="width: 100%; height: 100%; object-fit: cover; display: block;"></div>` 
                : `<img src="?action=get_profile_picture&id=${targetId}&v=${cacheBuster}" class="rounded-circle me-3" style="width: 44px; height: 44px; min-width: 44px; object-fit: cover; flex-shrink: 0; display: block;">`) + 
                `<div class="d-flex flex-column justify-content-center" style="min-width: 0;">
                   <span class="text-truncate fw-bold" style="font-size: 1.1rem; line-height: 1.2;">${escapeHTML(name)}</span>
                   <span class="text-success small fw-medium" style="font-size: 0.8rem;">${type === 'group' ? 'Group Chat' : 'Active'}</span>
                 </div>`;
            }
             
            const pipBtn = document.getElementById('chat-pip-btn');
            if (pipBtn) {
              if ('documentPictureInPicture' in window && window.innerWidth >= 768) {
                pipBtn.classList.remove('d-none');
              } else {
                pipBtn.classList.add('d-none');
                pipBtn.classList.remove('d-md-flex');
              }
            }
            const headerDropdown = document.getElementById('chat-header-dropdown');
            if (headerDropdown) {
              headerDropdown.classList.remove('d-none');
              
              const optInfo = document.getElementById('chat-opt-info');
              if (optInfo) {
                optInfo.onclick = (e) => {
                  e.preventDefault();
                  if (type === 'group') window.showGroupInfo(targetId);
                  else window.loadView({ type: 'artist_songs', param: name, sort: 'album_asc', filter_user_id: targetId, artist_name: '' });
                };
              }
              
              const optSearch = document.getElementById('chat-opt-search');
              if (optSearch) {
                optSearch.onclick = (e) => {
                  e.preventDefault();
                  const searchContainer = document.getElementById('chat-floating-search');
                  if (searchContainer) {
                    searchContainer.classList.remove('d-none');
                    searchContainer.classList.add('d-flex');
                    const input = document.getElementById('chat-inner-search');
                    if (input) input.focus();
                  }
                };
              }
            }
            
            const closeChatSearchBtn = document.getElementById('close-chat-search');
            if (closeChatSearchBtn) {
              closeChatSearchBtn.onclick = (e) => {
                e.preventDefault();
                const searchContainer = document.getElementById('chat-floating-search');
                searchContainer.classList.remove('d-flex');
                searchContainer.classList.add('d-none');
                const input = document.getElementById('chat-inner-search');
                if (input) {
                  input.value = '';
                  input.dispatchEvent(new Event('input')); 
                }
              };
            }

            const msgContainer = document.getElementById('chat-messages-container');
            if (msgContainer) {
              msgContainer.innerHTML = '<div class="text-center p-5"><div class="spinner-border text-secondary"></div></div>';
            }
            if (typeof window.clearChatReply === 'function') window.clearChatReply();
             
            await window.refreshChatFull();
            if (window.chatPollingInterval) clearInterval(window.chatPollingInterval);
            window.chatPollingInterval = setInterval(window.refreshChatFull, 1500); // Ultra-fast real-time sync
          };

          window.currentChatFetchId = 0;

          window.loadOlderChatMessages = (e) => {
            if (e) { e.preventDefault(); e.stopPropagation(); }
            const listEl = document.getElementById('chat-messages-container');
            if (!listEl) return;
            
            const oldScrollHeight = listEl.scrollHeight;
            window.currentChatPage = (window.currentChatPage || 1) + 1;
            
            window.refreshChatFull(true).then(() => {
              // Exact scroll correction so position remains static
              setTimeout(() => {
                if (listEl) listEl.scrollTop = listEl.scrollHeight - oldScrollHeight;
              }, 50);
            });
          };

          window.refreshChatFull = async (forceSync = false) => {
            if (!activeChatConfig.id) return;
            // Prevent polling if user is reacting
            if (window.isReacting && !forceSync) return;
            
            let isMediaPlaying = false;
            if (window.chatAudioObj && !window.chatAudioObj.paused) isMediaPlaying = true;
            document.querySelectorAll('.chat-main video').forEach(v => {
              if (!v.paused && !v.ended) isMediaPlaying = true;
            });
            if (isMediaPlaying && !forceSync) return;
            
            window.currentChatFetchId++;
            const fetchId = window.currentChatFetchId;
            const page = window.currentChatPage || 1;
            
            try {
              // Add silent fetch (true) to prevent global error toasts blocking UI during rapid polls
              const messages = await fetchData(`?action=get_chat&target_id=${activeChatConfig.id}&chat_type=${activeChatConfig.type}&chat_page=${page}`, {}, true);
              
              if (fetchId !== window.currentChatFetchId || (window.isReacting && !forceSync)) return;

              // Prevent DOM flickering: Compare raw JSON state and skip if identical
              const newMessagesString = JSON.stringify(messages);
              if (!forceSync && window.lastMessagesString === newMessagesString) {
                return; // Nothing changed, skip DOM re-render!
              }
              window.lastMessagesString = newMessagesString;

              const doc = window.chatPipWindow ? window.chatPipWindow.document : document;
              const listEl = doc.getElementById('chat-messages-container');
              if (!listEl) return;
              
              const chatInputArea = doc.querySelector('.chat-input-area');

              if (messages && messages.status === 'blocked') {
                listEl.innerHTML = `<div class="text-center text-secondary opacity-75 p-4 mt-auto mb-auto"><i class="bi bi-slash-circle fs-1 d-block mb-3"></i>${escapeHTML(messages.message)}</div>`;
                if (chatInputArea) chatInputArea.style.display = 'none';
                return;
              } else if (messages && messages.status === 'error') {
                listEl.innerHTML = `<div class="text-center text-danger p-4 mt-auto mb-auto">${escapeHTML(messages.message)}</div>`;
                if (chatInputArea) chatInputArea.style.display = 'none';
                return;
              } else {
                if (chatInputArea) chatInputArea.style.display = 'flex';
              }

              if (messages && Array.isArray(messages) && messages.length > 0) {
                const isScrolledToBottom = listEl.scrollHeight - listEl.clientHeight <= listEl.scrollTop + 50;

                let olderBtnHtml = '';
                if (messages.length >= page * 25) {
                  olderBtnHtml = `<div class="text-center w-100 mb-4 mt-2" id="load-older-chat-container"><button class="btn btn-sm btn-outline-secondary rounded-pill px-4" onclick="window.loadOlderChatMessages(event)"><i class="bi bi-clock-history"></i> Load Older Messages</button></div>`;
                }

                listEl.innerHTML = olderBtnHtml + messages.map(m => {
                  const isMe = m.sender_id == currentUser.id;
                  const bubbleClass = isMe ? 'me' : 'other';
                  
                  let mediaHtml = '';
                  if (m.has_image) {
                    const mediaUrl = `?action=get_message_image&id=${m.id}`;
                    const thumbUrl = `?action=get_message_image&id=${m.id}&thumb=1`;
                    if (m.media_type && m.media_type.startsWith('video/')) {
                      mediaHtml = window.buildLazyMediaHtml(mediaUrl, m.media_type, thumbUrl, false);
                    } else if (m.media_type && m.media_type.startsWith('audio/')) {
                      mediaHtml = `
                        <div class="chat-audio-player d-flex align-items-center gap-3 mb-2 p-2 rounded shadow-sm" data-msg-id="${m.id}" style="background: rgba(0,0,0,0.25); border: 1px solid rgba(255,255,255,0.05); min-width: 220px;">
                          <button class="btn btn-danger rounded-circle d-flex align-items-center justify-content-center flex-shrink-0 chat-audio-play-btn" onclick="window.playChatAudio(${m.id}, '${mediaUrl}')" style="width: 38px; height: 38px; padding: 0; transition: transform 0.1s;" onmouseover="this.style.transform='scale(1.05)'" onmouseout="this.style.transform='scale(1)'">
                            <i class="bi bi-${window.chatAudioActiveMsgId == m.id && !window.chatAudioObj.paused ? 'pause' : 'play'}-fill fs-4"></i>
                          </button>
                          <div class="chat-audio-track flex-grow-1 position-relative" style="height: 6px; background: rgba(255,255,255,0.2); border-radius: 3px; cursor: pointer;" onclick="window.seekChatAudio(event, ${m.id})">
                            <div class="chat-audio-progress" style="width: ${window.chatAudioActiveMsgId == m.id && isFinite(window.chatAudioObj.duration) ? (window.chatAudioObj.currentTime / window.chatAudioObj.duration) * 100 : 0}%; height: 100%; background: var(--ytm-accent); border-radius: 3px; pointer-events: none; transition: width 0.1s linear;"></div>
                          </div>
                          <span class="chat-audio-time small fw-bold" style="font-size: 0.75rem; min-width: 35px; user-select: none; color: rgba(255,255,255,0.8);">
                            ${window.chatAudioActiveMsgId == m.id ? Math.floor(window.chatAudioObj.currentTime / 60) + ':' + Math.floor(window.chatAudioObj.currentTime % 60).toString().padStart(2, '0') : '0:00'}
                          </span>
                        </div>`;
                    } else {
                      mediaHtml = window.buildLazyMediaHtml(mediaUrl, m.media_type || 'image/webp', thumbUrl, false);
                    }
                  }
                  
                  const editedHtml = m.is_edited ? '<small class="text-white-50 ms-2" style="font-size: 0.65rem;">(Edited)</small>' : '';
                   
                  let replyHtml = '';
                  if (m.reply_to_id) {
                    const cleanRep = (m.reply_content || 'Photo').replace(/<[^>]*>?/gm, '');
                    replyHtml = `
                      <div class="chat-reply-quote" onclick="document.querySelector('.msg-anchor-${m.reply_to_id}')?.scrollIntoView({behavior:'smooth', block:'center'})">
                        <strong style="color: ${isMe ? '#fff' : 'var(--ytm-accent)'};">${escapeHTML(m.reply_sender || 'Someone')}</strong><br>
                        <span class="text-truncate d-block">${escapeHTML(cleanRep)}</span>
                      </div>
                    `;
                  }

                  let reactionsHtml = '';
                  if (m.reactions && m.reactions.length > 0) {
                    const reactMap = {};
                    m.reactions.forEach(r => {
                      if (!reactMap[r.reaction]) reactMap[r.reaction] = { count:0, me:false };
                      reactMap[r.reaction].count++;
                      if (r.user_id == currentUser.id) reactMap[r.reaction].me = true;
                    });
                      
                    const pills = Object.keys(reactMap).map(emoji => `
                      <span class="reaction-pill ${reactMap[emoji].me ? 'reacted' : ''}" onclick="window.toggleMsgReaction(${m.id}, '${emoji}')">
                        ${emoji} <small>${reactMap[emoji].count}</small>
                      </span>
                     `).join('');
                     reactionsHtml = `<div class="reactions-container">${pills}</div>`;
                  }

                  let senderNameHtml = '';
                  if (!isMe && activeChatConfig.type === 'group') {
                    senderNameHtml = `<div class="fw-bold mb-1 user-profile-link" data-userid="${m.sender_id}" data-artist="${encodeURIComponent(m.sender_name)}" style="font-size: 0.8rem; color: var(--ytm-accent); cursor: pointer;">${escapeHTML(m.sender_name)}</div>`;
                  }

                  const safeSender = m.sender_name ? escapeHTML(m.sender_name).replace(/&#39;/g, "\\'") : 'Someone';
                  const safeContent = m.content ? escapeHTML(m.content).replace(/&#39;/g, "\\'").replace(/\n/g, ' ').replace(/\r/g, '') : '';

                  // Build Dropdown Action Menu (Fixes double click bug & overlapping)
                  // Added data-bs-boundary="window" to prevent clipping inside overflow container
                  let actionHtml = `
                    <div class="dropdown msg-dropdown">
                      <button class="btn btn-link p-0 border-0 msg-opt-btn" type="button" data-bs-toggle="dropdown" data-bs-boundary="window" aria-expanded="false">
                        <i class="bi bi-chevron-down"></i>
                      </button>
                      <ul class="dropdown-menu shadow-lg border-0" style="background-color: #1e1e1e; min-width: 180px; z-index: 9999; border-radius: 12px; padding: 0.5rem 0;">
                        <li class="px-3 py-2 d-flex justify-content-between mb-1" style="background: rgba(255,255,255,0.05);">
                          ${['👍','❤️','😂','😮','😢'].map(em => `<button class="btn btn-link p-0 text-decoration-none fs-5" style="transition: transform 0.2s;" onmouseover="this.style.transform='scale(1.2)'" onmouseout="this.style.transform='scale(1)'" onclick="window.toggleMsgReaction(${m.id}, '${em}')">${em}</button>`).join('')}
                        </li>
                        <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-white" onclick="window.toggleStarMsg(${m.id})"><i class="bi ${m.is_starred ? 'bi-star-fill text-warning' : 'bi-star text-secondary'} fs-5"></i> ${m.is_starred ? 'Unstar' : 'Star'}</button></li>
                        <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-white" onclick="window.setChatReply(${m.id}, '${safeSender}', '${safeContent}')"><i class="bi bi-reply-fill text-info fs-5"></i> Reply</button></li>
                        <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-white" onclick="window.copyChatMsg(${m.id})"><i class="bi bi-copy text-secondary fs-5"></i> Copy Text</button></li>
                        ${isMe ? `
                        <li><hr class="dropdown-divider border-secondary opacity-50 my-1"></li>
                        <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-white" onclick="window.editChatMsg(${m.id}, '${safeContent}')"><i class="bi bi-pencil text-secondary fs-5"></i> Edit</button></li>
                        <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-danger fw-bold" onclick="window.delChatMsg(${m.id})"><i class="bi bi-trash text-danger fs-5"></i> Delete</button></li>
                        ` : ''}
                      </ul>
                    </div>
                  `;

                  // Format standard readable time (e.g. 10:45 AM)
                  const dateObj = m.created_at ? new Date(m.created_at.replace(' ', 'T')+'Z') : new Date();
                  const timeString = dateObj.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

                  return `
                    <div class="chat-bubble ${bubbleClass} msg-anchor-${m.id}">
                      ${actionHtml}
                      ${senderNameHtml}
                      ${replyHtml}
                      ${mediaHtml}
                      ${m.content ? `<div style="white-space: pre-wrap; margin-top: ${m.has_image ? '4px' : '0'};" id="msg-content-${m.id}">${parseUserText(m.content)}</div>` : ''}
                      ${reactionsHtml}
                      <div class="msg-time-stamp">${timeString} ${editedHtml}</div>
                    </div>
                  `;
                }).join('');
                
                // Force continuous downward scroll tracking during active PiP sessions [1]
                if (window.chatPipWindow || window.forceScrollToBottomNext || isScrolledToBottom) {
                  const scrollBottom = () => {
                    if (listEl) listEl.scrollTop = listEl.scrollHeight + 10000;
                  };
                  scrollBottom();
                  setTimeout(scrollBottom, 50);
                  setTimeout(scrollBottom, 150);
                  setTimeout(scrollBottom, 300); // 300ms accounts for late image/video renders expanding height
                  window.forceScrollToBottomNext = false;
                }
              } else {
                listEl.innerHTML = '<div class="text-center text-secondary p-4 mt-auto mb-auto">Start the conversation!</div>';
              }
              updateNotifBadge();
              window.checkMediaCache();
            } catch (err) {
              const listEl = document.getElementById('chat-messages-container');
              if (listEl) listEl.innerHTML = '<div class="text-center text-danger p-4 mt-auto mb-auto">Failed to load messages.</div>';
            }
          };

          window.setChatReply = (id, sender, content) => {
            const doc = window.chatPipWindow ? window.chatPipWindow.document : document;
            doc.getElementById('chat-reply-id').value = id;
            const preview = doc.getElementById('chat-reply-preview');
            preview.innerHTML = `<strong>Replying to ${sender}:</strong><br><span class="text-secondary text-truncate d-block">${content.replace(/<[^>]*>?/gm, '')}</span>`;
            doc.getElementById('chat-reply-bar').classList.add('active');
            doc.getElementById('chat-input').focus();
          };
          
          window.showFormattingHelp = (targetDoc) => {
            const doc = targetDoc || document;
            let helpBox = doc.getElementById('dynamic-formatting-help');
            if (!helpBox) {
              helpBox = doc.createElement('div');
              helpBox.id = 'dynamic-formatting-help';
              helpBox.style.cssText = 'position:fixed; top:50%; left:50%; transform:translate(-50%, -50%); background:#1a1a1a; border:1px solid #444; border-radius:12px; padding:24px; z-index:9999; box-shadow:0 10px 40px rgba(0,0,0,0.9); max-width:90%; width:380px; color:#fff;';
              helpBox.innerHTML = `
                <h6 class="fw-bold mb-3 border-bottom border-secondary pb-3"><i class="bi bi-info-circle text-info me-2"></i>Formatting Help</h6>
                <ul class="list-unstyled small text-secondary mb-4" style="line-height: 1.8; font-size: 0.9rem;">
                  <li class="mb-2"><strong class="text-white">Links:</strong> <code class="bg-black px-2 py-1 rounded border border-secondary">[url] link.com [/url]</code></li>
                  <li class="mb-2"><strong class="text-white">Images:</strong> <code class="bg-black px-2 py-1 rounded border border-secondary">[img] image.jpg [/img]</code></li>
                  <li class="mb-2"><strong class="text-white">Video:</strong> <code class="bg-black px-2 py-1 rounded border border-secondary">[video] link.mp4 [/video]</code></li>
                  <li class="mb-2"><strong class="text-white">Mentions:</strong> <code class="bg-black px-2 py-1 rounded border border-secondary">@Username</code></li>
                </ul>
                <button class="btn btn-outline-light btn-sm w-100 fw-bold py-2 rounded-pill" onclick="this.parentElement.remove()">Close</button>
              `;
              doc.body.appendChild(helpBox);
            }
          };

          window.handleManualDropdownClick = (e) => {
            const activeDoc = e.target.ownerDocument;
            const toggle = e.target.closest('[data-bs-toggle="dropdown"]');

            if (toggle && (toggle.id === 'profile-picture-header-desktop' || toggle.id === 'profile-picture-header-mobile')) {
              return;
            }

            if (toggle) {
              e.preventDefault();
              e.stopPropagation();
              e.stopImmediatePropagation(); // Prevents Bootstrap event listener collision
              
              const menu = toggle.closest('.dropdown, .dropup')?.querySelector('.dropdown-menu');
              if (!menu) return;
              const isOpen = menu.classList.contains('show');

              activeDoc.querySelectorAll('.dropdown-menu.show').forEach(m => {
                m.classList.remove('show');
                m.style.display = 'none';
              });

              if (!isOpen) {
                menu.classList.add('show');
                menu.style.display = 'block';

                const rect = toggle.getBoundingClientRect();
                const winHeight = activeDoc.defaultView.innerHeight;

                const menuHeight = menu.offsetHeight || 200;
                const menuWidth = menu.offsetWidth || 180;

                const offsetParent = menu.offsetParent || activeDoc.body;
                const parentRect = offsetParent.getBoundingClientRect();

                let topPos;
                if (rect.bottom + menuHeight > winHeight && rect.top - menuHeight > 0) {
                  topPos = rect.top - parentRect.top - menuHeight - 4;
                } else {
                  topPos = rect.bottom - parentRect.top + 4;
                }

                let leftPos = rect.right - parentRect.left - menuWidth;
                if (leftPos < 8) {
                  leftPos = Math.max(8, rect.left - parentRect.left);
                }

                menu.style.position = 'absolute';
                menu.style.top = topPos + 'px';
                menu.style.left = leftPos + 'px';
                menu.style.zIndex = '99999';
              }
            } else if (!e.target.closest('.dropdown-menu')) {
              const activeDoc = e.target.ownerDocument;
              activeDoc.querySelectorAll('.dropdown-menu.show').forEach(m => {
                m.classList.remove('show');
                m.style.display = 'none';
              });
            }
          };
          document.addEventListener('click', window.handleManualDropdownClick, true);
          
          // Custom dropdown logic for comments & community posts to bypass Bootstrap conflicts
          document.addEventListener('click', e => {
            const toggle = e.target.closest('.custom-opt-toggle');
            if (toggle) {
              e.preventDefault();
              e.stopPropagation();
              const menu = toggle.nextElementSibling;
              const isVisible = menu.style.display === 'block';
              
              // Hide all other custom menus
              document.querySelectorAll('.custom-opt-menu').forEach(m => m.style.display = 'none');
              
              if (!isVisible) {
                menu.style.display = 'block';
              }
              return;
            }
            
            // If clicking anywhere else, hide the menus
            if (!e.target.closest('.custom-opt-menu')) {
              document.querySelectorAll('.custom-opt-menu').forEach(m => m.style.display = 'none');
            }
          });
          
          // Back button logic bridging PiP and normal window
          document.addEventListener('click', (e) => {
            const backBtn = e.target.closest('#chat-back-btn');
            if (backBtn) {
              e.preventDefault();
              if (window.chatPipWindow) {
                window.chatPipWindow.close();
              } else {
                const main = document.querySelector('.chat-main');
                const sidebar = document.querySelector('.chat-sidebar');
                if (main) main.classList.remove('active');
                if (sidebar) sidebar.classList.remove('hidden');
                if (window.chatPollingInterval) clearInterval(window.chatPollingInterval);
              }
            }
          });

          // Auto-hide drop menus on chat scroll so they don't float around disconnected
          document.addEventListener('scroll', (e) => {
            if (e.target.classList && e.target.classList.contains('chat-messages')) {
               const activeDoc = e.target.ownerDocument;
               activeDoc.querySelectorAll('.dropdown-menu.show').forEach(m => {
                  m.classList.remove('show');
                  m.style.display = 'none';
               });
            }
          }, true);

          window.toggleMsgReaction = async (msgId, emoji) => {
            window.isReacting = true; // Lock background polling
            window.currentChatFetchId++; // Invalidate any currently running background polls

            // Optimistic UI Update: Apply visually before network confirms
            const doc = window.chatPipWindow ? window.chatPipWindow.document : document;
            const msgBubble = doc.querySelector(`.msg-anchor-${msgId}`);
            if (msgBubble) {
              let container = msgBubble.querySelector('.reactions-container');
              if (!container) {
                container = document.createElement('div');
                container.className = 'reactions-container';
                msgBubble.appendChild(container);
              }
              
              let foundPill = false;
              container.querySelectorAll('.reaction-pill').forEach(pill => {
                const pillEmoji = pill.textContent.replace(/[0-9]/g, '').trim(); // Safely extract emoji
                
                if (pillEmoji === emoji) {
                  foundPill = true;
                  const countEl = pill.querySelector('small');
                  let count = parseInt(countEl.textContent) || 0;
                  if (pill.classList.contains('reacted')) {
                    pill.classList.remove('reacted');
                    count--;
                    if (count <= 0) pill.remove();
                    else countEl.textContent = count;
                  } else {
                    pill.classList.add('reacted');
                    count++;
                    countEl.textContent = count;
                  }
                } else if (pill.classList.contains('reacted')) {
                  pill.classList.remove('reacted');
                  const countEl = pill.querySelector('small');
                  let count = parseInt(countEl.textContent) || 0;
                  count--;
                  if (count <= 0) pill.remove();
                  else countEl.textContent = count;
                }
              });
              
              if (!foundPill) {
                container.insertAdjacentHTML('beforeend', `<span class="reaction-pill reacted" onclick="window.toggleMsgReaction(${msgId}, '${emoji}')">${emoji} <small>1</small></span>`);
              }
            }
            
            // Dispatch async mutation
            await fetchData('?action=toggle_message_reaction', { method: 'POST', body: JSON.stringify({ message_id: msgId, reaction: emoji }) });
            
            window.isReacting = false; // Unlock polling
            window.refreshChatFull(true); // Force an immediate fresh sync from DB
          };
          
          window.copyChatMsg = (id) => {
            const contentEl = document.getElementById('msg-content-' + id);
            if (contentEl) {
              const text = contentEl.innerText || contentEl.textContent;
              if (navigator.clipboard && window.isSecureContext) {
                navigator.clipboard.writeText(text).then(() => showToast('Message copied!', 'success'));
              }
            }
          };

          // Advanced Edit Modal Logic with Undo/Redo Array
          let chatEditHistory = [];
          let chatEditIndex = -1;
          let chatEditTimeout = null;

          window.delChatMsg = (id) => {
            document.getElementById('delete-chat-msg-id').value = id;
            bootstrap.Modal.getOrCreateInstance(document.getElementById('delete-chat-msg-modal')).show();
          };

          const confirmDeleteChatBtn = document.getElementById('confirm-delete-chat-btn');
          if (confirmDeleteChatBtn) {
            confirmDeleteChatBtn.addEventListener('click', async () => {
              const id = document.getElementById('delete-chat-msg-id').value;
              const originalHtml = confirmDeleteChatBtn.innerHTML;
              confirmDeleteChatBtn.disabled = true;
              confirmDeleteChatBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span>';
              
              const res = await fetchData('?action=delete_message', { method: 'POST', body: JSON.stringify({ id: id }) });
              
              confirmDeleteChatBtn.disabled = false;
              confirmDeleteChatBtn.innerHTML = originalHtml;
              bootstrap.Modal.getInstance(document.getElementById('delete-chat-msg-modal')).hide();
              
              if (res && res.status === 'success') {
                window.refreshChatFull(true);
                showToast('Message deleted', 'success');
              }
            });
          }

          window.editChatMsg = (id, content) => {
            const decodedContent = decodeHTML(content);
            document.getElementById('edit-chat-msg-id').value = id;
            const inputEl = document.getElementById('edit-chat-msg-input');
            inputEl.value = decodedContent;
            
            // Reset History Array for Undo/Redo operations
            chatEditHistory = [decodedContent];
            chatEditIndex = 0;
            
            bootstrap.Modal.getOrCreateInstance(document.getElementById('edit-chat-msg-modal')).show();
          };

          const editChatInput = document.getElementById('edit-chat-msg-input');
          if (editChatInput) {
            editChatInput.addEventListener('input', (e) => {
              clearTimeout(chatEditTimeout);
              chatEditTimeout = setTimeout(() => {
                const val = e.target.value;
                if (chatEditHistory[chatEditIndex] !== val) {
                  chatEditHistory = chatEditHistory.slice(0, chatEditIndex + 1);
                  chatEditHistory.push(val);
                  if (chatEditHistory.length > 30) chatEditHistory.shift(); // Cap history to 30 states
                  else chatEditIndex++;
                }
              }, 400);
            });
          }

          const chatEditUndoBtn = document.getElementById('chat-edit-undo-btn');
          if (chatEditUndoBtn) {
            chatEditUndoBtn.addEventListener('click', () => {
              if (chatEditIndex > 0) {
                chatEditIndex--;
                document.getElementById('edit-chat-msg-input').value = chatEditHistory[chatEditIndex];
              }
            });
          }

          const chatEditRedoBtn = document.getElementById('chat-edit-redo-btn');
          if (chatEditRedoBtn) {
            chatEditRedoBtn.addEventListener('click', () => {
              if (chatEditIndex < chatEditHistory.length - 1) {
                chatEditIndex++;
                document.getElementById('edit-chat-msg-input').value = chatEditHistory[chatEditIndex];
              }
            });
          }

          const editChatForm = document.getElementById('edit-chat-msg-form');
          if (editChatForm) {
            editChatForm.addEventListener('submit', async (e) => {
              e.preventDefault();
              const id = document.getElementById('edit-chat-msg-id').value;
              const newContent = document.getElementById('edit-chat-msg-input').value;
              
              if (newContent.trim() !== '') {
                const btn = editChatForm.querySelector('button[type="submit"]');
                const origHtml = btn.innerHTML;
                btn.disabled = true;
                btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Saving...';
                
                await fetchData('?action=edit_message', { method: 'POST', body: JSON.stringify({ id: id, content: newContent }) });
                
                btn.disabled = false;
                btn.innerHTML = origHtml;
                bootstrap.Modal.getInstance(document.getElementById('edit-chat-msg-modal')).hide();
                window.refreshChatFull(true);
              }
            });
          }

          // Chat Media Preview logic
          window.handleChatImageSelection = (file, targetDoc = document) => {
            if (file) {
              if (file.size > 50 * 1024 * 1024) {
                showToast('File exceeds 50MB limit.', 'error');
                return;
              }
              const doc = targetDoc || (window.chatPipWindow ? window.chatPipWindow.document : document);
              const dataTransfer = new DataTransfer();
              dataTransfer.items.add(file);
              doc.getElementById('chat-image-input').files = dataTransfer.files;
               
              const previewBar = doc.getElementById('chat-img-preview-bar');
              const previewImg = doc.getElementById('chat-img-preview-src');
              const previewVid = doc.getElementById('chat-video-preview-src');
              const previewAud = doc.getElementById('chat-audio-preview-src');
              
              previewImg.classList.add('d-none');
              previewVid.classList.add('d-none');
              previewAud.classList.add('d-none');
              
              if (previewVid.src) URL.revokeObjectURL(previewVid.src);
              if (previewAud.src) URL.revokeObjectURL(previewAud.src);
              
              let fileType = file.type;
              if (!fileType) {
                const ext = file.name.split('.').pop().toLowerCase();
                if (['mp3', 'wav', 'ogg', 'm4a'].includes(ext)) fileType = 'audio/' + ext;
                else if (['mp4', 'webm', 'mov'].includes(ext)) fileType = 'video/' + ext;
              }
              
              if (fileType.startsWith('image/')) {
                const reader = new FileReader();
                reader.onload = ev => {
                  previewImg.src = ev.target.result;
                  previewImg.classList.remove('d-none');
                  previewBar.classList.add('active');
                };
                reader.readAsDataURL(file);
              } else if (fileType.startsWith('video/')) {
                previewVid.src = URL.createObjectURL(file);
                previewVid.classList.remove('d-none');
                previewBar.classList.add('active');
              } else if (fileType.startsWith('audio/')) {
                previewAud.src = URL.createObjectURL(file);
                previewAud.classList.remove('d-none');
                previewBar.classList.add('active');
              } else {
                showToast('Format not supported.', 'error');
                doc.getElementById('chat-image-input').value = '';
              }
            }
          };

          window.handleChatChangeGlob = e => {
            if (e.target.id === 'chat-image-input') {
              window.handleChatImageSelection(e.target.files[0], e.target.ownerDocument);
            }
          };
          document.addEventListener('change', window.handleChatChangeGlob);

          // Drag and Drop Images into Chat
          const chatMainArea = document.querySelector('.chat-main');
          if (chatMainArea) {
            chatMainArea.addEventListener('dragover', (e) => {
              e.preventDefault();
              e.stopPropagation();
              chatMainArea.style.opacity = '0.7';
            });
            chatMainArea.addEventListener('dragleave', (e) => {
              e.preventDefault();
              e.stopPropagation();
              chatMainArea.style.opacity = '1';
            });
            chatMainArea.addEventListener('drop', (e) => {
              e.preventDefault();
              e.stopPropagation();
              chatMainArea.style.opacity = '1';
              if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
                handleChatImageSelection(e.dataTransfer.files[0], e.target.ownerDocument);
              }
            });
          }

          window.clearChatImage = (targetDoc) => {
            const doc = targetDoc || (window.chatPipWindow ? window.chatPipWindow.document : document);
            doc.getElementById('chat-image-input').value = '';
            doc.getElementById('chat-img-preview-bar').classList.remove('active');
            doc.getElementById('chat-img-preview-src').classList.add('d-none');
            const vid = doc.getElementById('chat-video-preview-src');
            const aud = doc.getElementById('chat-audio-preview-src');
            vid.classList.add('d-none');
            aud.classList.add('d-none');
            vid.pause(); aud.pause();
            if (vid.src) URL.revokeObjectURL(vid.src);
            if (aud.src) URL.revokeObjectURL(aud.src);
          };

          window.clearChatReply = (targetDoc) => {
            const doc = targetDoc || (window.chatPipWindow ? window.chatPipWindow.document : document);
            doc.getElementById('chat-reply-id').value = '';
            doc.getElementById('chat-reply-bar').classList.remove('active');
          };

          window.handleChatInputGlob = (e) => {
            if (e.target.id === 'chat-input') {
              e.target.style.height = 'auto';
              e.target.style.height = (e.target.scrollHeight) + 'px';
            }
          };
          document.addEventListener('input', window.handleChatInputGlob);

          window.handleChatKeydownGlob = (e) => {
            if (e.target.id === 'chat-input' && e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              const form = e.target.ownerDocument.getElementById('chat-form-full');
              if (form) form.dispatchEvent(new Event('submit', { cancelable: true, bubbles: true }));
            }
          };
          document.addEventListener('keydown', window.handleChatKeydownGlob);

          // Group Chat Management
          window.showGroupInfo = async (id, page = 1) => {
            const res = await fetchData(`?action=get_group_info&id=${id}&page=${page}`);
            if (res && res.status === 'success') {
              const g = res.group;
              if (page === 1) {
                document.getElementById('group-info-name').textContent = g.name;
                document.getElementById('group-info-desc').textContent = g.description || 'No description provided.';
                document.getElementById('group-info-count').textContent = g.total_members || g.members.length;
              }
                
              // Set the group profile picture
              const groupImgContainer = document.getElementById('group-info-img-container');
              if (groupImgContainer) {
                groupImgContainer.innerHTML = `<img src="?action=get_group_image&id=${g.id}&t=${Date.now()}" onerror="this.outerHTML='<i class=\\'bi bi-people-fill text-secondary\\' style=\\'font-size: 3rem;\\'></i>'" style="width: 100%; height: 100%; object-fit: cover;">`;
              }

              const isOwner = g.owner_id == currentUser.id || (currentUser && currentUser.email === 'musiclibrary@mail.com');
              const controls = document.getElementById('group-owner-controls');
              if (isOwner) {
                controls.classList.remove('d-none');
                document.getElementById('group-btn-edit').onclick = async () => {
                  document.getElementById('group-manage-title').innerHTML = '<i class="bi bi-pencil-square text-warning me-2"></i>Edit Group';
                  document.getElementById('group-manage-id').value = g.id;
                  document.getElementById('group-manage-name').value = g.name;
                  document.getElementById('group-manage-desc').value = g.description || '';
                     
                  const previewImg = document.getElementById('group-manage-image-preview');
                  previewImg.src = `?action=get_group_image&id=${g.id}&t=${Date.now()}`;
                  previewImg.style.display = 'block';
                  if (groupCropper) { groupCropper.destroy(); groupCropper = null; }
                  if (document.getElementById('group-manage-image')) document.getElementById('group-manage-image').value = '';

                  document.getElementById('group-manage-submit').textContent = 'Save Changes';
                  document.getElementById('group-manage-submit').className = 'btn btn-warning text-dark fw-bold w-100';
                  bootstrap.Modal.getOrCreateInstance(document.getElementById('group-info-modal')).hide();
                  bootstrap.Modal.getOrCreateInstance(document.getElementById('group-manage-modal')).show();
                };
                document.getElementById('group-btn-delete').onclick = async () => {
                  if (confirm('Permanently delete this group?')) {
                    await fetchData('?action=delete_chat_group', { method:'POST', body: JSON.stringify({id: g.id}) });
                    bootstrap.Modal.getInstance(document.getElementById('group-info-modal')).hide();
                    loadView(currentView);
                  }
                };
                document.getElementById('group-btn-invite').onclick = async () => {
                  const exp = document.getElementById('group-invite-expire').value;
                  const iRes = await fetchData('?action=generate_group_invite', { method:'POST', body: JSON.stringify({id: g.id, expire: exp==='forever'?null:exp}) });
                  if (iRes && iRes.status === 'success') {
                    const link = window.location.origin + window.location.pathname + '?chat_invite=' + iRes.token;
                    navigator.clipboard.writeText(link);
                    showToast('Invite link copied!', 'success');
                  }
                };
              } else {
                controls.classList.add('d-none');
              }

              const membersHtml = g.members.map(m => `
                <div class="list-group-item bg-transparent text-white px-0 d-flex justify-content-between align-items-center border-secondary">
                   <div class="d-flex align-items-center gap-3 user-profile-link" data-userid="${m.id}" data-artist="${encodeURIComponent(m.artist)}" style="cursor: pointer;">
                     <img src="?action=get_profile_picture&id=${m.id}" class="rounded-circle" style="width:32px; height:32px; object-fit:cover;">
                     <div>
                       <div class="fw-bold fs-6 hover-underline">${escapeHTML(m.artist)}</div>
                       <small class="text-secondary" style="font-size:0.75rem;">ID: ${m.id}</small>
                     </div>
                   </div>
                   <div class="d-flex align-items-center gap-2">
                     ${isOwner && m.role !== 'owner' ? `<button class="btn btn-sm btn-outline-warning fw-bold transfer-owner-btn" data-userid="${m.id}">Make Owner</button>` : ''}
                     ${m.role === 'owner' ? '<span class="badge bg-warning text-dark"><i class="bi bi-star-fill"></i> Owner</span>' : ''}
                   </div>
                </div>
              `).join('');

              const container = document.getElementById('group-info-members');
              if (page === 1) {
                container.innerHTML = membersHtml;
              } else {
                container.insertAdjacentHTML('beforeend', membersHtml);
              }

              container.onclick = async (e) => {
                const transferBtn = e.target.closest('.transfer-owner-btn');
                if (transferBtn) {
                  const newOwnerId = transferBtn.dataset.userid;
                  if (confirm('Transfer ownership to this member? You will become a regular member.')) {
                    const res = await fetchData('?action=transfer_group_ownership', {
                      method: 'POST',
                      body: JSON.stringify({ group_id: g.id, new_owner_id: newOwnerId })
                    });
                    if (res && res.status === 'success') {
                      showToast(res.message, 'success');
                      window.showGroupInfo(g.id, 1);
                    } else {
                      showToast(res?.message || 'Error transferring ownership', 'error');
                    }
                  }
                }
              };

              const existingLoadMore = document.getElementById('group-load-more-btn');
              if (existingLoadMore) existingLoadMore.remove();

              if (g.members.length === 25) {
                container.insertAdjacentHTML('afterend', `
                  <button class="btn btn-outline-light btn-sm w-100 mt-2 mb-3 fw-bold" id="group-load-more-btn" onclick="window.showGroupInfo(${id}, ${page + 1})">
                    Load More Members
                  </button>
                `);
              }

              document.getElementById('group-btn-leave').onclick = async () => {
                const confirmMsg = isOwner ? 'As the owner, if you leave, ownership will be given to a random member. Leave group?' : 'Leave this group?';
                if (confirm(confirmMsg)) {
                  await fetchData('?action=leave_chat_group', { method:'POST', body: JSON.stringify({id: g.id}) });
                  bootstrap.Modal.getInstance(document.getElementById('group-info-modal')).hide();
                  loadView({ type: 'get_inbox', param: '', sort: '', filter_user_id: '' });
                }
              };
              bootstrap.Modal.getOrCreateInstance(document.getElementById('group-info-modal')).show();
            }
          };

          document.addEventListener('submit', async e => {
            if (e.target.id === 'group-manage-form') {
              e.preventDefault();
              const submitBtn = document.getElementById('group-manage-submit');
              submitBtn.disabled = true;
              submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Saving...';
               
              const id = document.getElementById('group-manage-id').value;
              const name = document.getElementById('group-manage-name').value;
              const desc = document.getElementById('group-manage-desc').value;
              const imgInput = document.getElementById('group-manage-image');
               
              const formData = new FormData();
              formData.append('name', name);
              formData.append('description', desc);
              if (id) formData.append('id', id);

              const processUpload = async () => {
                try {
                  const res = await fetch(`?action=${id ? 'edit_chat_group' : 'create_chat_group'}`, { method: 'POST', body: formData });
                  const result = await res.json();
                   
                  if (result && result.status === 'success') {
                    showToast(id ? 'Group updated' : 'Group created', 'success');
                    bootstrap.Modal.getInstance(document.getElementById('group-manage-modal')).hide();
                    loadView(currentView);
                  } else {
                    showToast(result.message || 'Action failed', 'error');
                  }
                } catch (err) {
                  showToast('Network error', 'error');
                }
                submitBtn.disabled = false;
                submitBtn.textContent = id ? 'Save Changes' : 'Create Group';
              };

              if (groupCropper) {
                groupCropper.getCroppedCanvas({ width: 300, height: 300 }).toBlob(blob => {
                  formData.append('image', blob, 'group.jpg');
                  processUpload();
                }, 'image/jpeg', 0.85);
              } else if (imgInput && imgInput.files.length > 0) {
                formData.append('image', imgInput.files[0]);
                processUpload();
              } else {
                processUpload();
              }
            }
          });
             
          window.handleChatSubmitGlob = async e => {
            if (e.target.id === 'chat-form-full') {
              e.preventDefault();
              const doc = e.target.ownerDocument;
              const input = doc.getElementById('chat-input');
              const imgInput = doc.getElementById('chat-image-input');
              const replyId = doc.getElementById('chat-reply-id').value;
               
              if (!input.value.trim() && imgInput.files.length === 0) return;
               
              const formData = new FormData();
              formData.append('target_id', activeChatConfig.id);
              formData.append('chat_type', activeChatConfig.type);
              formData.append('content', input.value);
              if (replyId) formData.append('reply_to_id', replyId);
              if (imgInput.files.length > 0) formData.append('image', imgInput.files[0]);

              const submitBtn = doc.getElementById('chat-submit-btn');
              const originalBtnHtml = submitBtn.innerHTML;
              submitBtn.disabled = true;
              submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm" style="width: 1.2rem; height: 1.2rem;"></span>';
              
              const progContainer = doc.getElementById('chat-upload-progress-container');
              const progBar = doc.getElementById('chat-upload-progress');
            if (imgInput.files.length > 0) {
               progContainer.classList.remove('d-none');
               progBar.style.width = '0%';
            }

            const xhr = new XMLHttpRequest();
            xhr.upload.onprogress = (evt) => {
              if (evt.lengthComputable && imgInput.files.length > 0) {
                const pct = Math.round((evt.loaded / evt.total) * 100);
                progBar.style.width = pct + '%';
              }
            };
            
            xhr.open('POST', '?action=send_message', true);
            xhr.onload = async () => {
              submitBtn.disabled = false;
              submitBtn.innerHTML = originalBtnHtml;
              progContainer.classList.add('d-none');
              
              if (xhr.status === 200) {
                try {
                  const result = JSON.parse(xhr.responseText);
                  if (result && result.status === 'success') {
                    input.value = '';
                    input.style.height = 'auto'; // Reset textarea height
                    window.clearChatImage(doc);
                    window.clearChatReply(doc);
                    window.forceScrollToBottomNext = true; // Snap viewport to bottom for new sent message
                    await window.refreshChatFull();
                  } else {
                    showToast(result.message || 'Failed to send', 'error');
                  }
                } catch (err) {
                  showToast('Invalid server response.', 'error');
                }
              } else {
                showToast('Network error during upload', 'error');
              }
            };
            xhr.onerror = () => {
              submitBtn.disabled = false;
              submitBtn.innerHTML = originalBtnHtml;
              progContainer.classList.add('d-none');
              showToast('Network error during upload', 'error');
            };
            xhr.send(formData);
            }
          };
          document.addEventListener('submit', async e => {
            if (e.target.id === 'chat-form-full') {
              await window.handleChatSubmitGlob(e);
            }
          });
          
          window.chatPipWindow = null;
          document.addEventListener('click', async (e) => {
            const pipBtn = e.target.closest('#chat-pip-btn');
            if (pipBtn) {
              if (window.chatPipWindow) {
                window.chatPipWindow.close();
                return;
              }
              if (!('documentPictureInPicture' in window)) return;
              
              try {
                window.chatPipWindow = await window.documentPictureInPicture.requestWindow({
                  width: 450,
                  height: 700
                });

                [...document.styleSheets].forEach(styleSheet => {
                  try {
                    const cssRules = [...styleSheet.cssRules].map(rule => rule.cssText).join('');
                    const style = document.createElement('style');
                    style.textContent = cssRules;
                    window.chatPipWindow.document.head.appendChild(style);
                  } catch (err) {
                    if (styleSheet.href) {
                      const link = document.createElement('link');
                      link.rel = 'stylesheet';
                      link.href = styleSheet.href;
                      window.chatPipWindow.document.head.appendChild(link);
                    }
                  }
                });

                const iconLink = document.createElement('link');
                iconLink.rel = 'stylesheet';
                iconLink.href = 'https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css';
                window.chatPipWindow.document.head.appendChild(iconLink);

                const chatMain = document.querySelector('.chat-main');
                const chatWrapper = document.querySelector('.chat-wrapper');
                
                window.chatPipWindow.document.body.style.background = 'var(--ytm-bg)';
                window.chatPipWindow.document.body.style.margin = '0';
                window.chatPipWindow.document.body.classList.add('pip-active');
                window.chatPipWindow.document.body.appendChild(chatMain);

                // Directly hide the PiP trigger button in the PiP window's document
                const pipBtnInPip = window.chatPipWindow.document.getElementById('chat-pip-btn');
                if (pipBtnInPip) {
                  pipBtnInPip.style.setProperty('display', 'none', 'important');
                }
                const backBtnInPip = window.chatPipWindow.document.getElementById('chat-back-btn');
                if (backBtnInPip) {
                  backBtnInPip.style.setProperty('display', 'none', 'important');
                }
                const formatHelpInPip = window.chatPipWindow.document.querySelector('.chat-formatting-help');
                if (formatHelpInPip) {
                  formatHelpInPip.style.setProperty('display', 'none', 'important');
                }

                // Force downward scroll on initialization
                setTimeout(() => {
                  const listEl = window.chatPipWindow.document.getElementById('chat-messages-container');
                  if (listEl) listEl.scrollTop = listEl.scrollHeight + 10000;
                }, 100);

                window.chatPipWindow.document.addEventListener('input', window.handleChatInputGlob);
                window.chatPipWindow.document.addEventListener('change', window.handleChatChangeGlob);
                window.chatPipWindow.document.addEventListener('keydown', window.handleChatKeydownGlob);
                window.chatPipWindow.document.addEventListener('submit', window.handleChatSubmitGlob);
                window.chatPipWindow.document.addEventListener('click', window.handleManualDropdownClick);

                window.chatPipWindow.addEventListener('pagehide', () => {
                  if (chatWrapper && chatMain) chatWrapper.appendChild(chatMain);
                  
                  // CRITICAL FIX: Restore PiP button visibility in main document!
                  const mainPipBtn = document.getElementById('chat-pip-btn');
                  if (mainPipBtn) mainPipBtn.style.removeProperty('display');
                  
                  const mainBackBtn = document.getElementById('chat-back-btn');
                  if (mainBackBtn) mainBackBtn.style.removeProperty('display');
                  
                  const mainFormatHelp = document.querySelector('.chat-formatting-help');
                  if (mainFormatHelp) mainFormatHelp.style.removeProperty('display');
                  
                  window.chatPipWindow = null;
                });
              } catch (err) {
                console.error(err);
                showToast('Failed to open Chat PiP', 'error');
              }
              return;
            }
          });
          
          // --- END FULL PAGE CHAT APP LOGIC ---
          const clearBtn = document.getElementById('clear-activity-btn');
          if (clearBtn) {
            clearBtn.addEventListener('click', async () => {
              if (confirm('Are you sure you want to clear all your notifications?')) {
                const res = await fetchData('?action=clear_activity_feed', { method: 'POST' });
                if (res && res.status === 'success') {
                  showToast('Notifications cleared.', 'success');
                  loadActivityFeed();
                  updateNotifBadge();
                }
              }
            });
          }
          
          body.addEventListener('click', async (e) => {
            const openChatBtn = e.target.closest('.open-chat-btn');
            if (openChatBtn) {
              bootstrap.Modal.getInstance(activityModalEl).hide();
              await loadView({ type: 'get_inbox', param: '', sort: '', filter_user_id: '' });
              window.openChatFull(openChatBtn.dataset.userid, 'dm', openChatBtn.dataset.artist);
              return;
            }
            const replyBtn = e.target.closest('.notif-reply-btn');
            if (replyBtn) {
              const songId = parseInt(replyBtn.dataset.songId);
              const commentId = parseInt(replyBtn.dataset.commentId);
              const username = replyBtn.dataset.username;
              
              bootstrap.Modal.getInstance(activityModalEl).hide();
              window.openCommentsModal(songId, commentId, username);
              return;
            }
            const commReplyBtn = e.target.closest('.notif-comm-reply-btn');
            if (commReplyBtn) {
              bootstrap.Modal.getInstance(activityModalEl).hide();
              loadView({ type: 'get_community', param: '', sort: 'newest', filter_user_id: '', artist_name: '' });
              setTimeout(() => {
                const input = document.getElementById('reply-community-post-input');
                const parentId = document.getElementById('reply-community-post-parent-id');
                if (input && parentId) {
                  parentId.value = commReplyBtn.dataset.postId;
                  const username = commReplyBtn.dataset.username.replace(/\s+/g, '');
                  input.value = `@${username} `;
                  const preview = document.getElementById('reply-community-post-preview');
                  if (preview) {
                    preview.innerHTML = `<strong class="text-white">Replying to ${escapeHTML(commReplyBtn.dataset.username)}</strong>`;
                  }
                  bootstrap.Modal.getOrCreateInstance(document.getElementById('reply-community-post-modal')).show();
                  setTimeout(() => input.focus(), 500);
                }
              }, 800);
            }
          });
        }

        // API Modal logic
        const apiUrlInput = document.getElementById('api-url-input');
        const copyApiBtn = document.getElementById('copy-api-btn');
        const apiModalEl = document.getElementById('api-modal');
        const apiActionSelect = document.getElementById('api-action-select');
        const apiMethodBadge = document.getElementById('api-method-badge');
        const apiPayloadContainer = document.getElementById('api-payload-container');
        const apiPayloadCode = document.getElementById('api-payload-code');

        const updateApiUrl = () => {
          if (!apiUrlInput || !apiActionSelect) return;
          const selectedOption = apiActionSelect.options[apiActionSelect.selectedIndex];
          const actionVal = selectedOption.value;
          
          const userKeyInput = document.getElementById('custom-api-key-input');
          const finalKey = userKeyInput && userKeyInput.value ? userKeyInput.value.trim() : '';
          
          let baseAppUrl = window.location.href.split('?')[0].split('#')[0];
          if (baseAppUrl.includes('null') || baseAppUrl.includes('srcdoc') || baseAppUrl === 'about:blank') {
            baseAppUrl = '';
          }
          baseAppUrl = baseAppUrl.replace(/\/+$/, ''); // Strip trailing slashes to prevent double slash bug
          
          let url = baseAppUrl + '/?access=api&action=' + actionVal;
          if (finalKey) url += '&api_key=' + encodeURIComponent(finalKey);
          apiUrlInput.value = url;

          const apiVisualOpenTabBtn = document.getElementById('api-visual-open-tab-btn');
          if (apiVisualOpenTabBtn) {
            let sourceType = 'all';
            let idName = '';
            if (actionVal.includes('playlist')) {
              sourceType = 'playlist';
              idName = '1';
            } else if (actionVal.includes('artist')) {
              sourceType = 'artist';
              idName = '1';
            }
            let absoluteBaseUrl = window.location.protocol + '//' + window.location.host + window.location.pathname;
            if (absoluteBaseUrl.includes('null') || absoluteBaseUrl.includes('srcdoc')) {
              absoluteBaseUrl = '';
            }
            absoluteBaseUrl = absoluteBaseUrl.replace(/\/+$/, ''); // Clean absolute URL for Playground injection
            
            apiVisualOpenTabBtn.dataset.sourceType = sourceType;
            apiVisualOpenTabBtn.dataset.idName = idName;
            apiVisualOpenTabBtn.dataset.backendUrl = absoluteBaseUrl;
            apiVisualOpenTabBtn.dataset.apiKey = finalKey;
          }
          
          const method = selectedOption.getAttribute('data-method') || 'GET';
          if (apiMethodBadge) {
            apiMethodBadge.textContent = method;
            apiMethodBadge.className = method === 'POST' ? 'badge bg-warning text-dark' : 'badge bg-primary';
          }

          const payload = selectedOption.getAttribute('data-body');
          if (payload && apiPayloadContainer && apiPayloadCode) {
            apiPayloadCode.textContent = payload;
            apiPayloadContainer.classList.remove('d-none');
          } else if (apiPayloadContainer) {
            apiPayloadContainer.classList.add('d-none');
          }

          // VISUAL CLIENT TESTER INJECTION (Iframe 2)
          const visualIframe = document.getElementById('api-visual-iframe');
          const templateEl = document.getElementById('play-client-template');

          if (visualIframe && templateEl) {
            // Unconditionally render playground client UI, letting it gracefully query using session cookie
            if (!visualIframe.srcdoc || visualIframe.srcdoc.includes('Access Denied')) {
              visualIframe.srcdoc = templateEl.innerHTML;
            }
                
            let sourceType = 'all';
            let idName = '';
            if (actionVal.includes('playlist')) {
              sourceType = 'playlist';
              idName = '1';
            } else if (actionVal.includes('artist')) {
              sourceType = 'artist';
              idName = '1';
            }
            const safeApiKey = finalKey ? encodeURIComponent(finalKey) : '';
            const hash = `#sourcetype=${sourceType}&id/name=${idName}&backendurl=${encodeURIComponent(baseAppUrl)}&apikey=${safeApiKey}`;
          
            if (visualIframe.contentWindow && visualIframe.contentWindow.location && visualIframe.contentWindow.document.readyState === 'complete') {
              visualIframe.contentWindow.location.hash = hash;
            } else {
              visualIframe.onload = () => {
                visualIframe.contentWindow.location.hash = hash;
              };
            }
          }

          // RAW JSON VIEWER LOGIC (Iframe 1)
          const apiExampleIframe = document.getElementById('api-example-iframe');
          if (apiExampleIframe) {
            
            apiExampleIframe.srcdoc = `<html><body style="background-color: #000000; color: #aaaaaa; font-family: monospace; font-size: 13px; margin: 0; padding: 12px;">Querying database for real data...</body></html>`;
            
            const injectIframe = (dataObj, color) => {
              const jsonString = JSON.stringify(dataObj, null, 2);
              apiExampleIframe.srcdoc = `<html><body style="background-color: #000000; color: ${color}; font-family: monospace; font-size: 13px; margin: 0; padding: 12px; white-space: pre-wrap; word-wrap: break-word;">${jsonString}</body></html>`;
            };

            const fallbackToFakeData = () => {
              const randomData = {
                status: "success", action_requested: actionVal, method: method,
                results: [{
                    id: Math.floor(Math.random() * 9000) + 1000, 
                    title: "Example Track " + Math.floor(Math.random() * 100),
                    artist: "Random Artist " + Math.floor(Math.random() * 50),
                    album: "Awesome Album Vol " + Math.floor(Math.random() * 10), 
                    duration: Math.floor(Math.random() * 200) + 120,
                    is_favorite: Math.random() > 0.5 ? 1 : 0
                }]
              };
              injectIframe(randomData, '#4ade80'); // Green text means FAKE data
            };

            if (method === 'GET') {
              let testUrl = apiUrlInput.value;
              
              // ADVANCED: Safely request an actual database entity to populate variables so you don't query empty/invalid IDs
              const fetchRealExample = async () => {
                try {
                  if (testUrl.includes('SONG_ID') || testUrl.includes('USER_ID') || testUrl.includes('PLAYLIST_ID')) {
                    const realSongs = await fetch('?access=api&action=get_songs&limit=1&api_key=' + encodeURIComponent(finalKey)).then(r=>r.json());
                    const realPlaylists = await fetch('?access=api&action=get_user_playlists&api_key=' + encodeURIComponent(finalKey)).then(r=>r.json());
                    
                    const sId = (realSongs && realSongs.length > 0) ? realSongs[0].id : '1';
                    const uId = (realSongs && realSongs.length > 0) ? realSongs[0].user_id : '1';
                    const pId = (realPlaylists && realPlaylists.length > 0) ? realPlaylists[0].public_id : '1';
                    
                    testUrl = testUrl.replace('SONG_ID', sId).replace('USER_ID', uId).replace('PLAYLIST_ID', pId).replace('YOUR_QUERY', 'a');
                  }

                  const res = await fetch(testUrl);
                  const data = await res.json();
                  
                  if (!data || data.status === 'error' || (Array.isArray(data) && data.length === 0)) {
                    fallbackToFakeData();
                  } else {
                    let displayData = Array.isArray(data) ? data.slice(0, 3) : data;
                    injectIframe(displayData, '#60a5fa'); // Blue text means REAL database data
                  }
                } catch (e) {
                  fallbackToFakeData();
                }
              };
              
              fetchRealExample();
            } else {
              fallbackToFakeData(); 
            }
          }
        };

        if (apiModalEl && apiUrlInput) {
          const userKeyInput = document.getElementById('custom-api-key-input');
          const apiVisualOpenTabBtn = document.getElementById('api-visual-open-tab-btn');
          
          // Secure one-time click listener for the Playground Standalone Tab overlay icon
          if (apiVisualOpenTabBtn) {
            apiVisualOpenTabBtn.addEventListener('click', (e) => {
              e.preventDefault();
              e.stopPropagation(); // Avoid triggering any container clicks
              const bUrl = apiVisualOpenTabBtn.dataset.backendUrl || window.location.origin + window.location.pathname;
              const safeApiKey = apiVisualOpenTabBtn.dataset.apiKey ? encodeURIComponent(apiVisualOpenTabBtn.dataset.apiKey) : '';
              const sourceType = apiVisualOpenTabBtn.dataset.sourceType || 'all';
              const idName = apiVisualOpenTabBtn.dataset.idName || '';
              
              // Constructs the secure hash containing the #playground routing indicator
              const hash = `#playground&sourcetype=${sourceType}&id/name=${idName}&backendurl=${encodeURIComponent(bUrl)}&apikey=${safeApiKey}`;
              
              window.open(bUrl + hash, '_blank');
            });
          }

          apiModalEl.addEventListener('show.bs.modal', async () => {
            window.userHasApiKeys = false;
            if (currentUser) {
              const myApis = await fetchData('?action=get_my_apis');
              if (myApis && myApis.length > 0) window.userHasApiKeys = true;
            }
            if (window.adminAutoToken === 'musiclibrary@mail.com' && document.getElementById('custom-api-key-input').value === '') {
              document.getElementById('custom-api-key-input').value = 'ADMIN_SESSION_BYPASS';
            }
            updateApiUrl();
          });
          if (apiActionSelect) apiActionSelect.addEventListener('change', updateApiUrl);
          if (userKeyInput) userKeyInput.addEventListener('input', updateApiUrl);
        }

        // API Visual Client Scaling & Fullscreen (16:9 Desktop Simulation)
        const resizeVisualIframe = () => {
          const iframe = document.getElementById('api-visual-iframe');
          if (!iframe) return;
          const container = iframe.parentElement;
          const containerWidth = container.clientWidth;
          const scale = containerWidth / 1280;
          iframe.style.transform = `scale(${scale})`;
          
          const containerHeight = container.clientHeight;
          const expectedHeight = containerWidth * (9/16);
          if (containerHeight > expectedHeight) {
            iframe.style.top = `${(containerHeight - expectedHeight) / 2}px`;
          } else {
            iframe.style.top = '0px';
          }
        };

        const visualContainer = document.getElementById('api-visual-container');
        const visualFullscreenBtn = document.getElementById('api-visual-fullscreen-btn');
        if (visualContainer && visualFullscreenBtn) {
          visualFullscreenBtn.addEventListener('click', () => {
            if (!document.fullscreenElement) {
              visualContainer.requestFullscreen().catch(err => {
                console.error("Fullscreen initiation failed:", err);
              });
            } else {
              document.exitFullscreen();
            }
          });
          
          visualContainer.addEventListener('dblclick', (e) => {
            if (e.target.closest('#api-visual-fullscreen-btn')) return;
            visualFullscreenBtn.click();
          });
        }

        document.addEventListener('fullscreenchange', () => {
          const btn = document.getElementById('api-visual-fullscreen-btn');
          if (btn) {
            btn.innerHTML = document.fullscreenElement ? '<i class="bi bi-fullscreen-exit"></i>' : '<i class="bi bi-fullscreen"></i>';
          }
          setTimeout(resizeVisualIframe, 100);
        });

        window.addEventListener('resize', resizeVisualIframe);

        const apiVisualTabBtn = document.getElementById('api-visual-tab-btn');
        if (apiVisualTabBtn) {
          apiVisualTabBtn.addEventListener('shown.bs.tab', () => {
            setTimeout(resizeVisualIframe, 100);
          });
        }

        if (copyApiBtn) {
          copyApiBtn.addEventListener('click', () => {
            const onSuccess = () => {
              copyApiBtn.textContent = 'Copied!';
              copyApiBtn.classList.replace('btn-danger', 'btn-success');
              setTimeout(() => {
                copyApiBtn.textContent = 'Copy';
                copyApiBtn.classList.replace('btn-success', 'btn-danger');
              }, 2000);
            };
            const onError = () => showToast('Failed to copy API link.', 'error');

            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(apiUrlInput.value).then(onSuccess).catch(onError);
            } else {
              const textArea = document.createElement("textarea");
              textArea.value = apiUrlInput.value;
              textArea.style.position = "fixed";
              textArea.style.top = "0";
              textArea.style.left = "0";
              textArea.style.opacity = "0";
              document.body.appendChild(textArea);
              textArea.focus();
              textArea.select();
              try {
                const successful = document.execCommand('copy');
                if (successful) onSuccess();
                else onError();
              } catch (err) {
                onError();
              }
              document.body.removeChild(textArea);
            }
          });
        }

        const getApiBtn = document.getElementById('get-api-btn');
        if (getApiBtn) {
          getApiBtn.addEventListener('click', (e) => {
            e.preventDefault();
            hideMobileSidebar();
            bootstrap.Modal.getOrCreateInstance(document.getElementById('api-modal')).show();
          });
        }

        const clearApiKeyBtn = document.getElementById('clear-api-key-btn');
        if (clearApiKeyBtn) {
          clearApiKeyBtn.addEventListener('click', () => {
            localStorage.removeItem('admin_api_key');
            window.adminApiKey = null;
            bootstrap.Modal.getInstance(document.getElementById('api-modal')).hide();
            showToast("API Master Key successfully scrubbed from cache memory.", "info");
          });
        }
        
        // Connect the Mobile API Jump Menu to the Scrollable Container
        const mobileApiNavSelect = document.getElementById('mobile-api-nav-select');
        if (mobileApiNavSelect) {
          mobileApiNavSelect.addEventListener('change', function() {
            const targetId = this.value;
            const targetElement = document.getElementById(targetId);
            const scrollContainer = document.querySelector('.api-content'); // The scrollable right column
            
            if (targetElement && scrollContainer) {
              // Calculate relative scroll position
              const topPos = targetElement.offsetTop;
              scrollContainer.scrollTo({
                top: topPos - 20, // Add slight padding so it's perfectly visible below the sticky header
                behavior: 'smooth'
              });
            }
          });
        }

        const playerTrackInfoMobile = document.querySelector('.player-bar .track-info.d-md-none');
        const playerModalEl = document.getElementById('player-modal');
        const playerModal = playerModalEl ? new bootstrap.Modal(playerModalEl) : null;
        
        const profilePictureHeaderDesktop = document.getElementById('profile-picture-header-desktop');
        const profilePictureHeaderMobile = document.getElementById('profile-picture-header-mobile');
        const profilePicturePreview = document.getElementById('profile-picture-preview');

        const playerElements = {
          art: [document.getElementById('player-art-desktop'), document.getElementById('player-art-mobile'), document.getElementById('player-modal-art'), document.getElementById('desktop-player-modal-art')],
          title: [document.getElementById('player-title-desktop'), document.getElementById('player-title-mobile'), document.getElementById('player-modal-title'), document.getElementById('desktop-player-modal-title')],
          artist: [document.getElementById('player-artist-desktop'), document.getElementById('player-artist-mobile'), document.getElementById('player-modal-artist'), document.getElementById('desktop-player-modal-artist')],
          currentTime: [document.getElementById('current-time'), document.getElementById('player-modal-current-time'), document.getElementById('desktop-player-modal-current-time')],
          timeLeft: [document.getElementById('time-left'), document.getElementById('player-modal-time-left'), document.getElementById('desktop-player-modal-time-left')],
          progress: [document.getElementById('progress-bar'), document.getElementById('player-modal-progress-bar'), document.getElementById('desktop-player-modal-progress-bar')],
          progressContainer: [document.getElementById('progress-container'), document.getElementById('player-modal-progress-container'), document.getElementById('desktop-player-modal-progress-container')],
          playPauseBtn: [document.getElementById('play-pause-btn-desktop'), document.getElementById('play-pause-btn-mobile'), document.getElementById('player-modal-play-pause-btn'), document.getElementById('desktop-player-modal-play-pause-btn')],
          prevBtn: [document.getElementById('prev-btn-desktop'), document.getElementById('prev-btn-mobile'), document.getElementById('player-modal-prev-btn'), document.getElementById('desktop-player-modal-prev-btn')],
          nextBtn: [document.getElementById('next-btn-desktop'), document.getElementById('next-btn-mobile'), document.getElementById('player-modal-next-btn'), document.getElementById('desktop-player-modal-next-btn')],
          shuffleBtn: [document.getElementById('shuffle-btn-desktop'), document.getElementById('shuffle-btn-mobile'), document.getElementById('player-modal-shuffle-btn'), document.getElementById('desktop-player-modal-shuffle-btn')],
          repeatBtn: [document.getElementById('repeat-btn-desktop'), document.getElementById('repeat-btn-mobile'), document.getElementById('player-modal-repeat-btn'), document.getElementById('desktop-player-modal-repeat-btn')],
          moreBtn: [document.getElementById('player-more-btn-desktop'), document.getElementById('player-more-btn-mobile'), document.getElementById('player-modal-more-btn'), document.getElementById('desktop-player-modal-more-btn')],
          volumeBtn: document.getElementById('volume-btn'),
          volumeSlider: document.getElementById('volume-slider'),
        };
        
        const desktopPlayerModalEl = document.getElementById('desktop-player-modal');
        const desktopPlayerModal = desktopPlayerModalEl ? new bootstrap.Modal(desktopPlayerModalEl) : null;
        
        if (playerModalEl) {
          playerModalEl.addEventListener('shown.bs.modal', () => {
            window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', false);
          });
          
          const mpQueueTabBtn = document.querySelector('button[data-bs-target="#mp-queue-pane"]');
          if (mpQueueTabBtn) {
            mpQueueTabBtn.addEventListener('shown.bs.tab', () => {
              window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', false);
            });
          }
        }
        
        if (desktopPlayerModalEl) {
          desktopPlayerModalEl.addEventListener('shown.bs.modal', () => {
            window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', false);
          });
          
          const dpQueueTabBtn = document.querySelector('button[data-bs-target="#dp-queue-pane"]');
          if (dpQueueTabBtn) {
            dpQueueTabBtn.addEventListener('shown.bs.tab', () => {
              window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', false);
            });
          }
        }
        
        const renderDesktopLyrics = () => {
          const lyricsContainer = document.getElementById('desktop-synced-lyrics');
          if (!lyricsContainer || !currentSong) return;

          if (currentSong.lyrics) {
            const lrcData = parseLRC(currentSong.lyrics);
            if (lrcData.length > 0) {
              currentLrcData = lrcData;
              currentLrcSongId = currentSong.id;
              currentLyricIndex = -1;
              
              lyricsContainer.innerHTML = lrcData.map((line, idx) => 
                `<div class="lyric-line" data-index="${idx}" data-time="${line.time}">${escapeHTML(line.text)}</div>`
              ).join('');
            } else {
              currentLrcData = null;
              currentLrcSongId = null;
              lyricsContainer.innerHTML = `<pre style="white-space: pre-wrap; font-family: 'Roboto', sans-serif;">${escapeHTML(currentSong.lyrics)}</pre>`;
            }
          } else {
            currentLrcData = null;
            currentLrcSongId = null;
            lyricsContainer.innerHTML = '<p class="text-center text-secondary">No lyrics available.</p>';
          }
        };

        window.renderQueue = async (reset = false, direction = 'down') => {
          const queueContainerDesktop = document.getElementById('desktop-player-queue-list');
          const queueContainerMobile = document.getElementById('mobile-player-queue-list');
          
          if (isQueueLoading) return;
          isQueueLoading = true;

          if (reset) {
            // Render a chunk specifically around the active song to save DOM memory!
            renderedQueueStart = Math.max(0, (typeof queueIndex !== 'undefined' && queueIndex > -1 ? queueIndex : 0) - 25);
            renderedQueueEnd = Math.min(queue.length, renderedQueueStart + 50);
            
            const listHtml = '<div class="text-center py-2 d-none" id="queue-load-prev"><button class="btn btn-sm btn-outline-secondary rounded-pill px-4" onclick="window.renderQueue(false, \'up\')"><i class="bi bi-arrow-up"></i> Load Previous</button></div><div class="song-list"></div><div class="text-center py-3 d-none" id="queue-load-next"><div class="spinner-border spinner-border-sm text-secondary"></div></div>';
            
            if (queueContainerDesktop) queueContainerDesktop.innerHTML = listHtml;
            if (queueContainerMobile) queueContainerMobile.innerHTML = listHtml;
          } else {
            if (direction === 'down') {
              if (renderedQueueEnd >= queue.length) {
                isQueueLoading = false;
                return;
              }
            } else if (direction === 'up') {
              if (renderedQueueStart <= 0) {
                isQueueLoading = false;
                return;
              }
            }
          }
          
          let chunkStart = 0;
          let chunkEnd = 0;
          
          if (reset) {
            chunkStart = renderedQueueStart;
            chunkEnd = renderedQueueEnd;
          } else if (direction === 'down') {
            chunkStart = renderedQueueEnd;
            chunkEnd = Math.min(queue.length, renderedQueueEnd + 25);
          } else if (direction === 'up') {
            chunkEnd = renderedQueueStart;
            chunkStart = Math.max(0, renderedQueueStart - 25);
          }

          const nextChunkIds = queue.slice(chunkStart, chunkEnd);
          const missingIds = nextChunkIds.filter(id => !globalSongCache[id]);
          
          // Fetch any data that isn't cached yet
          if (missingIds.length > 0) {
            const fetchedData = await fetchData('?action=get_queue_songs', {
              method: 'POST', headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ ids: missingIds })
            }, true);
            if (fetchedData) {
              fetchedData.forEach(song => globalSongCache[song.id] = song);
            }
          }
          
          let html = '';
          const escapeAttr = (str) => str ? String(str).replace(/'/g, "&apos;").replace(/"/g, "&quot;") : '';
          
          nextChunkIds.forEach((songId) => {
            const song = globalSongCache[songId];
            if (!song) return;
            const isNowPlaying = currentSong && (songId === currentSong.id);
            const coverSvg = getSvgPlaceholder(song.title || 'Unknown');
            
            html += `
              <div class="song-item py-md-3 ${isNowPlaying ? 'now-playing' : ''}" 
                data-song-id="${song.id}" 
                data-is-favorite="${song.is_favorite == 1 ? '1' : '0'}"
                data-is-collaborative="${song.is_collaborative == 1 ? '1' : '0'}"
                data-song-title="${escapeAttr(song.title)}"
                data-song-artist="${escapeAttr(song.artist)}"
                data-song-album="${escapeAttr(song.album)}"
                data-song-genre="${escapeAttr(song.genre)}"
                data-song-user-id="${song.user_id}">
                <div class="song-indicator-wrapper d-flex align-items-center justify-content-center">
                  <img src="?action=get_image&id=${song.id}&v=${song.last_modified || 0}&size=small" onerror="this.onerror=null; this.src='${coverSvg}';" class="song-thumb" loading="lazy" alt="${escapeAttr(song.title)}">
                  <i class="bi bi-soundwave playing-icon"></i>
                </div>
                <div class="song-title-wrapper text-truncate"><div class="song-title text-truncate">${song.is_private == 1 ? '<i class="bi bi-lock-fill text-warning me-1" title="Private Song"></i>' : ''}${song.title}</div></div>
                <div class="song-artist text-truncate" data-userid="${song.user_id}">
                  <div class="text-truncate">${formatArtistsHTML(song.artist, song.user_id, song.is_collaborative)}</div>
                  <div class="text-secondary d-md-none" style="font-size: 0.8rem; margin-top: 2px;" title="Play Count"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                </div>
                <div class="song-album text-truncate" data-album="${encodeURIComponent(song.album)}" data-userid="${song.user_id}">${song.album}</div>
                <div class="song-views d-none d-md-block text-truncate" title="${song.play_count || 0} views">${formatSongCount(song.play_count || 0)}</div>
                <div class="song-duration d-none d-md-block">${formatTime(song.duration)}</div>
                <div class="song-more"><button class="more-btn" data-song-id="${song.id}"><i class="bi bi-three-dots-vertical"></i></button></div>
                <div class="song-artist-mobile w-100 flex-column align-items-start">
                  <div class="d-flex justify-content-between align-items-center w-100">
                     <span class="song-artist-name text-truncate flex-grow-1" style="min-width: 0;">${formatArtistsHTML(song.artist, song.user_id, song.is_collaborative)}</span>
                     <span class="song-duration-mobile flex-shrink-0">${formatTime(song.duration)}</span>
                  </div>
                  <div class="text-secondary text-start" style="font-size: 0.8rem; margin-top: 2px;"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                </div>
              </div>`;
          });

          const appendHtmlToQueues = (action) => {
            [queueContainerDesktop, queueContainerMobile].forEach(container => {
              if (container) {
                const lst = container.querySelector('.song-list');
                if (lst) {
                  let oldScrollHeight = 0;
                  const pane = container.closest('.overflow-auto');
                  if (pane) oldScrollHeight = pane.scrollHeight;

                  if (action === 'append') lst.insertAdjacentHTML('beforeend', html);
                  else lst.insertAdjacentHTML('afterbegin', html);
                  
                  lst.querySelectorAll('.song-item:not(.v-obs)').forEach(el => { el.classList.add('v-obs'); virtualObserver.observe(el); });

                  if (action === 'prepend' && pane) {
                    pane.scrollTop += (pane.scrollHeight - oldScrollHeight);
                  }
                }
              }
            });
          };

          if (reset || direction === 'down') {
            appendHtmlToQueues('append');
            renderedQueueEnd = chunkEnd;
            if (reset) renderedQueueStart = chunkStart;
          } else if (direction === 'up') {
            appendHtmlToQueues('prepend');
            renderedQueueStart = chunkStart;
          }

          // Update load prev/next buttons safely
          [queueContainerDesktop, queueContainerMobile].forEach(container => {
             if (container) {
               const loadPrev = container.querySelector('#queue-load-prev');
               const loadNext = container.querySelector('#queue-load-next');
               if (loadPrev) {
                 if (renderedQueueStart > 0) loadPrev.classList.remove('d-none');
                 else loadPrev.classList.add('d-none');
               }
               if (loadNext) {
                 if (renderedQueueEnd < queue.length) loadNext.classList.remove('d-none');
                 else loadNext.classList.add('d-none');
               }
             }
          });

          isQueueLoading = false;

          // Dynamically indicate offline availability for ALL queue items
          caches.open('php-music-offline').then(cache => {
            const addedItems = document.querySelectorAll('#desktop-player-queue-list .song-item:not(.queue-cache-checked), #mobile-player-queue-list .song-item:not(.queue-cache-checked)');
            addedItems.forEach(async item => {
              item.classList.add('queue-cache-checked');
              const sid = item.dataset.songId;
              const req = await cache.match(`?action=get_stream&id=${sid}`, { ignoreSearch: false, ignoreVary: true });
              const titleWrapper = item.querySelector('.song-title-wrapper');
              
              if (!req) {
                item.classList.add('offline-missing');
                if (!navigator.onLine) {
                  item.style.transition = 'opacity 0.3s ease';
                  item.style.opacity = '0.4';
                }
                if (titleWrapper && !titleWrapper.querySelector('.offline-status-icon')) {
                   titleWrapper.insertAdjacentHTML('beforeend', ' <i class="bi bi-cloud-slash text-secondary offline-status-icon ms-1" title="Not saved offline" style="font-size: 0.85rem;"></i>');
                }
              } else {
                item.classList.remove('offline-missing');
                item.style.opacity = '1';
                if (titleWrapper && !titleWrapper.querySelector('.offline-status-icon')) {
                   titleWrapper.insertAdjacentHTML('beforeend', ' <i class="bi bi-cloud-check-fill text-success offline-status-icon ms-1" title="Available offline" style="font-size: 0.85rem;"></i>');
                }
              }
            });
          });
          
          // Focus the playing song if it was a total reset
          if (reset && currentSong) {
            if (typeof window.enforceScrollToActive === 'function') {
              window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', true);
              window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', true);
            }
          }
        };
        // Safely alias it into the global scope
        const renderQueue = window.renderQueue;

        const playerArtDesktop = document.getElementById('player-art-desktop');
        if (playerArtDesktop) {
          playerArtDesktop.addEventListener('click', () => {
            if (currentSong && desktopPlayerModal) {
              renderDesktopLyrics();
              renderQueue();
              desktopPlayerModal.show();
            }
          });
        }

        // Attach click events to BOTH desktop and mobile Up Next queues
        ['desktop-player-queue-list', 'mobile-player-queue-list'].forEach(qId => {
          const queueList = document.getElementById(qId);
          if (queueList) {
            queueList.addEventListener('click', e => {
              
              const moreBtn = e.target.closest('.more-btn');
              if (moreBtn) {
                e.preventDefault(); e.stopPropagation();
                showSongItemContextMenu(moreBtn);
                return;
              }
              
              const songArtistEl = e.target.closest('.artist-link, .song-artist, .song-artist-name');
              if (songArtistEl) {
                e.stopPropagation();
                 
                const songItem = e.target.closest('.song-item');
                const artistRaw = songItem ? songItem.getAttribute('data-song-artist') : (songArtistEl.dataset.artist ? decodeURIComponent(songArtistEl.dataset.artist) : songArtistEl.textContent.trim());
                const userId = songArtistEl.dataset.userid || (songItem ? songItem.getAttribute('data-song-user-id') : '') || '';
                 
                const artistsList = artistRaw.split(/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+)\s*|\s*,\s*(?!(?:the|a|an|jr|sr)\b)/i).filter(a => a && a.trim() !== '');
                if (artistsList.length > 1) {
                  // Keep the player modal open, simply display the choices popup on top
                  if (artistsModalBody) {
                    const modalTitle = artistsModalEl.querySelector('.modal-title');
                    if (modalTitle) modalTitle.textContent = 'Artists';
                    artistsModalBody.innerHTML = `
                      <div class="list-group list-group-flush rounded">
                        ${artistsList.map((a, idx) => `<button type="button" class="list-group-item list-group-item-action bg-transparent text-white border-secondary artist-modal-item py-3" data-artist="${encodeURIComponent(a)}" data-userid="${idx === 0 ? (userId || '') : ''}">${a}</button>`).join('')}
                      </div>
                    `;
                    if (artistsModal) artistsModal.show();
                  }
                } else {
                  // Only one artist exists: Close the player modals and navigate directly
                  closeOpenModals();
                  loadView({ type: 'artist_songs', param: artistRaw, sort: 'album_asc', filter_user_id: userId });
                }
                return;
              }

              const songAlbumEl = e.target.closest('.song-album');
              if (songAlbumEl) {
                e.stopPropagation();
                if (desktopPlayerModal) desktopPlayerModal.hide();
                if (playerModal) playerModal.hide();
                const songItem = e.target.closest('.song-item');
                
                let rawUserId = songAlbumEl.getAttribute('data-userid') || (songItem ? (songItem.getAttribute('data-userid') || songItem.getAttribute('data-song-user-id')) : '') || '';
                let validUserId = parseInt(rawUserId, 10);
                
                let albumRaw = decodeURIComponent(songAlbumEl.getAttribute('data-album') || '');
                let songArtistRaw = songItem ? (songItem.getAttribute('data-song-artist') || '') : '';
                const songArtistsList = songArtistRaw.split(/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+)\s*|\s*,\s*(?!(?:the|a|an|jr|sr)\b)/i).filter(a => a && a.trim() !== '');

                if (songArtistsList.length > 1) {
                  if (artistsModalBody) {
                    const modalTitle = artistsModalEl.querySelector('.modal-title');
                    if (modalTitle) modalTitle.textContent = 'Select Album Artist';
                    artistsModalBody.innerHTML = `
                      <div class="list-group list-group-flush rounded">
                        ${songArtistsList.map(a => `<button type="button" class="list-group-item list-group-item-action bg-transparent text-white border-secondary album-modal-item py-3" data-album="${encodeURIComponent(albumRaw)}" data-artist="${encodeURIComponent(a)}" data-userid="${rawUserId}">${escapeHTML(albumRaw)} (${escapeHTML(a)})</button>`).join('')}
                      </div>
                    `;
                    if (artistsModal) artistsModal.show();
                  }
                } else {
                  loadView({ 
                    type: 'album_songs', 
                    param: albumRaw, 
                    sort: 'title_asc', 
                    filter_user_id: (isNaN(validUserId) || validUserId <= 0) ? '' : validUserId,
                    artist_name: songArtistRaw
                  });
                }
                return;
              }

              const songItem = e.target.closest('.song-item');
              if (songItem) {
                const songId = parseInt(songItem.dataset.songId);
                const idx = queue.findIndex(id => id === songId);
                if (idx !== -1) {
                   queueIndex = idx;
                   playSongById(songId);
                } else {
                   setQueueAndPlay(songId);
                }
              }
            });
          }
        });

        const desktopLyricsContainer = document.getElementById('desktop-player-modal-lyrics-container');
        if (desktopLyricsContainer) {
          desktopLyricsContainer.addEventListener('click', (e) => {
            const line = e.target.closest('.lyric-line');
            if (line && currentSong && currentSong.id === currentLrcSongId && audio) {
              audio.currentTime = parseFloat(line.dataset.time);
            }
          });
        }

        const audio = new Audio();
        audio.crossOrigin = 'anonymous'; // CRITICAL: Unlocks Web Audio API effects like Equalizer
        const audioB = new Audio();
        audioB.crossOrigin = 'anonymous';
        
        let audioCtx, sourceA, sourceB, gainA, gainB, perSongGain, compressor, analyser;
        let visualizerDataArray;
        let eqBands = [];
        let spatialPanner, spatialBypass, spatialMix;
        let enableNormalization = true;
        let isEQEnabled = false;
        let isSpatialEnabled = false;
        let globalVolumeMultiplier = 1.0;
        let globalEQBands = [0, 0, 0, 0, 0];
        let crossfadeDuration = 3.0;
        let settingsSaveTimeout = null;

        const EQ_PRESETS = {
          'Flat': [0, 0, 0, 0, 0],
          'Rock': [5, 3, -2, 4, 6],
          'Jazz': [4, 2, -2, 2, 5],
          'Classical': [5, 3, -2, 4, 4],
          'Pop': [-2, 2, 5, 2, -2],
          'Bass Boost': [8, 5, 0, 0, 0]
        };

        const saveGlobalAudioSettings = async () => {
          if (!currentUser) return;
          clearTimeout(settingsSaveTimeout);
          settingsSaveTimeout = setTimeout(async () => {
            try {
               const settings = { 
                  enableNormalization: enableNormalization, 
                  isEQEnabled: isEQEnabled, 
                  isSpatialEnabled: isSpatialEnabled, 
                  globalVolumeMultiplier: parseFloat(globalVolumeMultiplier), 
                  globalEQBands: globalEQBands.map(b => parseFloat(b)), 
                  crossfadeDuration: parseFloat(crossfadeDuration) 
               };
               
               const response = await fetchData('?action=save_global_settings', {
                 method: 'POST', headers: {'Content-Type': 'application/json'},
                 body: JSON.stringify({ settings: settings })
               });
               
               if (response && response.status === 'success') {
                  // Update the local current user memory so it doesn't revert on next checkSession
                  currentUser.settings = JSON.stringify(settings);
               }
            } catch(e) {
               console.error("Failed to save audio settings", e);
            }
          }, 800); // 800ms debounce
        };

        const initWebAudio = () => {
          if (audioCtx) return;
          audioCtx = new (window.AudioContext || window.webkitAudioContext)();
          
          const freqs = [60, 230, 910, 3600, 14000];
          let prevNode = null;
          freqs.forEach((freq, i) => {
            let band = audioCtx.createBiquadFilter();
            band.type = i === 0 ? "lowshelf" : (i === freqs.length - 1 ? "highshelf" : "peaking");
            band.frequency.value = freq;
            band.gain.value = 0;
            eqBands.push(band);
            if (prevNode) prevNode.connect(band);
            prevNode = band;
          });

          compressor = audioCtx.createDynamicsCompressor();
          compressor.threshold.value = -24; 
          compressor.knee.value = 30;
          compressor.ratio.value = 12;      
          compressor.attack.value = 0.003;
          compressor.release.value = 0.25;
          
          spatialPanner = audioCtx.createPanner();
          spatialPanner.panningModel = 'HRTF';
          spatialPanner.distanceModel = 'inverse';
          if (spatialPanner.positionZ) spatialPanner.positionZ.value = 1.0;
          else spatialPanner.setPosition(0, 0, 1.0);
          
          spatialBypass = audioCtx.createGain();
          spatialMix = audioCtx.createGain();
          
          eqBands[eqBands.length - 1].connect(spatialBypass);
          eqBands[eqBands.length - 1].connect(spatialPanner);
          
          spatialBypass.connect(compressor);
          spatialPanner.connect(spatialMix);
          spatialMix.connect(compressor);

          analyser = audioCtx.createAnalyser();
          analyser.fftSize = 128;
          visualizerDataArray = new Uint8Array(analyser.frequencyBinCount);
          compressor.connect(analyser);
          analyser.connect(audioCtx.destination);

          sourceA = audioCtx.createMediaElementSource(audio);
          sourceB = audioCtx.createMediaElementSource(audioB);
          gainA = audioCtx.createGain();
          gainB = audioCtx.createGain();
          perSongGain = audioCtx.createGain();
          perSongGain.gain.value = 1;
          
          sourceA.connect(gainA);
          sourceB.connect(gainB);
          gainA.connect(perSongGain);
          gainB.connect(perSongGain);
          perSongGain.connect(eqBands[0]);
          
          toggleAudioEnhancements();
        };

        const applyAudioSettings = () => {
          if (!audioCtx || !currentSong) return;
          
          let targetVol = parseFloat(globalVolumeMultiplier);
          let targetEQ = globalEQBands.map(v => parseFloat(v) || 0);

          if (currentSong.replaygain && enableNormalization) {
            const rgLinear = Math.pow(10, parseFloat(currentSong.replaygain) / 20);
            targetVol *= Math.max(0.1, Math.min(rgLinear, 3.0));
          }

          if (currentSong.volume_multiplier !== null && currentSong.volume_multiplier !== undefined) {
            targetVol = parseFloat(currentSong.volume_multiplier);
          }
          
          if (currentSong.eq_bands) {
            try {
              const parsedEq = typeof currentSong.eq_bands === 'string' ? JSON.parse(currentSong.eq_bands) : currentSong.eq_bands;
              if (Array.isArray(parsedEq) && parsedEq.length === 5) {
                targetEQ = parsedEq.map(v => parseFloat(v) || 0);
              }
            } catch (err) {
              console.error("EQ Parse Error:", err);
            }
          } else if (!isEQEnabled) {
            targetEQ = [0, 0, 0, 0, 0];
          }

          if (audioCtx.state === 'suspended') {
            audioCtx.resume();
          }

          setTimeout(() => {
            if (perSongGain && perSongGain.gain) {
              perSongGain.gain.setTargetAtTime(targetVol, audioCtx.currentTime, 0.05);
            }
            eqBands.forEach((band, i) => {
              if (band && band.gain) {
                band.gain.setTargetAtTime(targetEQ[i], audioCtx.currentTime, 0.05);
              }
            });
          }, 50);
        };

        const toggleAudioEnhancements = () => {
          if (!audioCtx) return;
          compressor.ratio.value = enableNormalization ? 12 : 1; 
          
          // Direct value assignment to avoid context freezing bugs
          spatialBypass.gain.value = isSpatialEnabled ? 0 : 1;
          spatialMix.gain.value = isSpatialEnabled ? 1 : 0;

          applyAudioSettings();
        };

        // UI Event Listeners for Global Audio Settings
        document.getElementById('toggle-spatial').addEventListener('change', (e) => {
          isSpatialEnabled = e.target.checked;
          toggleAudioEnhancements();
          saveGlobalAudioSettings();
        });
        document.getElementById('global-vol-slider').addEventListener('input', (e) => {
          globalVolumeMultiplier = parseFloat(e.target.value);
          document.getElementById('global-vol-val').textContent = globalVolumeMultiplier + 'x';
          applyAudioSettings();
          saveGlobalAudioSettings();
        });

        document.getElementById('toggle-normalization').addEventListener('change', (e) => {
          enableNormalization = e.target.checked;
          toggleAudioEnhancements();
          saveGlobalAudioSettings();
        });

        document.getElementById('toggle-eq').addEventListener('change', (e) => {
          isEQEnabled = e.target.checked;
          document.getElementById('eq-sliders').classList.toggle('d-none', !isEQEnabled);
          toggleAudioEnhancements();
          saveGlobalAudioSettings();
        });

        document.querySelectorAll('#eq-sliders .eq-band').forEach(slider => {
          slider.addEventListener('input', (e) => {
            if (!audioCtx) initWebAudio();
            const bandIndex = parseInt(e.target.dataset.band);
            globalEQBands[bandIndex] = parseFloat(e.target.value);
            document.getElementById('eq-preset-select').value = 'Custom';
            applyAudioSettings();
            saveGlobalAudioSettings();
          });
        });

        document.getElementById('crossfade-slider').addEventListener('input', (e) => {
          crossfadeDuration = parseFloat(e.target.value);
          document.getElementById('crossfade-val').textContent = crossfadeDuration + 's';
          saveGlobalAudioSettings();
        });

        document.getElementById('eq-preset-select').addEventListener('change', (e) => {
          if (e.target.value === 'Custom') return;
          const preset = EQ_PRESETS[e.target.value];
          if (preset) {
            globalEQBands = [...preset];
            const eqSliders = document.querySelectorAll('#eq-sliders .eq-band');
            globalEQBands.forEach((val, i) => { if (eqSliders[i]) eqSliders[i].value = val; });
            if (!audioCtx) initWebAudio();
            applyAudioSettings();
            saveGlobalAudioSettings();
          }
        });

        document.body.addEventListener('click', initWebAudio, { once: true });
        let currentView = { type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' };
        let currentUser = null;
        let currentViewOwnerId = null;
        let currentSong = null;
        let queue = [];
        let originalQueue = [];
        let queueIndex = -1;
        let isPlaying = false;
        let isShuffle = localStorage.getItem('isShuffle') === 'true';
        let repeatMode = localStorage.getItem('repeatMode') || 'none';
        let queueDirty = true;
        let deferredInstallPrompt = null;
        let sortable = null;
        let songIdForPlaylist = null;
        let mixIdForPlaylist = null;
        let contextMenuItemEl = null;
        let previousVolume = 1;
        let cachedExploreData = null;
        let offlineViewSongsData = [];
        let currentLrcData = null;
        let currentLrcSongId = null;
        let currentLyricIndex = -1;
        let globalSongCache = {};
        let offlineSongsSet = new Set();
        let listenLaterSet = new Set();
        let renderedQueueStart = 0;
        let renderedQueueEnd = 0;
        let isQueueLoading = false;
        let sleepTimerInterval = null;
        let sleepTimerEndTime = 0;
        let wakeLockSentinel = null;
        let sleepTimerKeepAwake = false;
        
        let chatPollingInterval = null;
        let localRhythmGame = null;
        let activeChatConfig = { id: null, type: null, name: null };
        
        // --- SIMPLE VIRTUAL SCROLLING SCRIPT ---
        const virtualObserver = new IntersectionObserver((entries) => {
          entries.forEach(entry => {
            const el = entry.target;
            if (entry.isIntersecting) {
              // Restore HTML when scrolling into view
              if (el.dataset.virtualHtml) {
                el.innerHTML = el.dataset.virtualHtml;
                el.dataset.virtualHtml = '';
                el.style.height = ''; 
              }
            } else {
              // Extract and wipe HTML to free RAM when off-screen
              if (!el.dataset.virtualHtml && el.innerHTML !== '') {
                // Ignore the currently playing track to keep animations running natively
                if (el.classList.contains('now-playing')) return;
                const h = el.offsetHeight;
                if (h > 0) {
                   el.style.height = h + 'px';
                   el.dataset.virtualHtml = el.innerHTML;
                   el.innerHTML = '';
                }
              }
            }
          });
        }, { rootMargin: '800px 0px' });
        // ---------------------------------------

        let holdTimer;
        let multiSelectMode = false;
        let selectedSongs = new Set();
        const multiSelectBar = document.getElementById('multi-select-bar');
        const multiSelectCount = document.getElementById('multi-select-count');
        
        const PAGE_SIZE = 25;
        let currentPage = 1;
        let isLoadingMore = false;
        let allContentloaded = false;
        const PLAY_LOG_THRESHOLD = 30;

        const ICONS = {
          play: `<i class="bi bi-play-fill"></i>`,
          pause: `<i class="bi bi-pause-fill"></i>`,
          repeat: `<i class="bi bi-repeat"></i>`,
          repeatOne: `<i class="bi bi-repeat-1"></i>`,
          shuffle: `<i class="bi bi-shuffle"></i>`,
          prev: `<i class="bi bi-skip-start-fill"></i>`,
          next: `<i class="bi bi-skip-end-fill"></i>`,
          heart: `<i class="bi bi-heart"></i>`,
          heartFill: `<i class="bi bi-heart-fill"></i>`,
          volumeUp: `<i class="bi bi-volume-up-fill"></i>`,
          volumeDown: `<i class="bi bi-volume-down-fill"></i>`,
          volumeMute: `<i class="bi bi-volume-mute-fill"></i>`,
          spinner: `<div class="spinner-border text-secondary" style="width: 1.5rem; height: 1.5rem; border-width: 0.2em;" role="status"></div>`,
        };

        const updateFullscreenIcon = () => {
          if (fullscreenBtn) {
            const isFull = document.fullscreenElement || document.webkitFullscreenElement || document.msFullscreenElement || document.mozFullScreenElement;
            fullscreenBtn.innerHTML = isFull ? '<i class="bi bi-fullscreen-exit"></i><span>Exit Full Screen</span>' : '<i class="bi bi-arrows-fullscreen"></i><span>Full Screen</span>';
          }
        };

        if (fullscreenBtn)  {
          fullscreenBtn.addEventListener('click', (e) => {
            e.preventDefault();
            if (!document.fullscreenElement && !document.webkitFullscreenElement && !document.msFullscreenElement && !document.mozFullScreenElement) {
              if (document.documentElement.requestFullscreen) {
                document.documentElement.requestFullscreen();
              } else if (document.documentElement.webkitRequestFullscreen) {
                document.documentElement.webkitRequestFullscreen();
              } else if (document.documentElement.msRequestFullscreen) {
                document.documentElement.msRequestFullscreen();
              } else               if (document.documentElement.mozRequestFullScreen) {
                document.documentElement.mozRequestFullScreen();
              }
            } else {
              if (document.exitFullscreen) {
                document.exitFullscreen();
              } else if (document.webkitExitFullscreen) {
                document.webkitExitFullscreen();
              } else if (document.msExitFullscreen) {
                document.msExitFullscreen();
              } else if (document.mozCancelFullScreen) {
                document.mozCancelFullScreen();
              }
            }
          });
        }
        
        document.addEventListener('fullscreenchange', updateFullscreenIcon);
        document.addEventListener('webkitfullscreenchange', updateFullscreenIcon);
        document.addEventListener('MSFullscreenChange', updateFullscreenIcon);
        document.addEventListener('mozfullscreenchange', updateFullscreenIcon);

        window.lastPostTime = 0;
        window.checkPostCooldown = (btnEl = null) => {
          const now = Date.now();
          const diff = now - window.lastPostTime;
          if (diff < 10000) {
            const left = Math.ceil((10000 - diff) / 1000);
            showToast(`Please wait ${left} seconds before posting again.`, 'warning');
            if (btnEl) {
              const origHtml = btnEl.dataset.origHtml || btnEl.innerHTML;
              btnEl.dataset.origHtml = origHtml;
              btnEl.disabled = true;
              btnEl.innerHTML = `Wait ${left}s`;
              let counter = left;
              const intv = setInterval(() => {
                counter--;
                if (counter <= 0) {
                  clearInterval(intv);
                  btnEl.disabled = false;
                  btnEl.innerHTML = origHtml;
                } else {
                  btnEl.innerHTML = `Wait ${counter}s`;
                }
              }, 1000);
            }
            return false;
          }
          return true;
        };

        const preserveReplyState = (htmlString, containerId) => {
          const openReplies = [];
          document.querySelectorAll('[id^="comment-reply-container-"]:not(.d-none), [id^="comm-reply-container-"]:not(.d-none), [id^="blog-comment-reply-container-"]:not(.d-none)').forEach(el => {
            openReplies.push(el.id);
          });
          
          const container = document.getElementById(containerId);
          if (container) container.innerHTML = htmlString;
          
          openReplies.forEach(id => {
            const el = document.getElementById(id);
            if (el) {
              el.classList.remove('d-none');
              const btn = document.querySelector(`[data-target="${id}"]`);
              if (btn) {
                const icon = btn.querySelector('i');
                if(icon) icon.classList.replace('bi-chevron-down', 'bi-chevron-up');
              }
            }
          });
        };

        const formatTime = (seconds) => {
          if (isNaN(seconds) || seconds < 0) return '0:00';
          const min = Math.floor(seconds / 60);
          const sec = Math.floor(seconds % 60).toString().padStart(2, '0');
          return `${min}:${sec}`;
        };

        const formatSongCount = (count) => {
          let num = parseInt(count, 10);
          if (isNaN(num)) return '0';
          if (num >= 1000000000000) {
            return (num / 1000000000000).toFixed(1).replace(/\.0$/, '') + 't';
          }
          if (num >= 1000000000) {
            return (num / 1000000000).toFixed(1).replace(/\.0$/, '') + 'b';
          }
          if (num >= 1000000) {
            return (num / 1000000).toFixed(1).replace(/\.0$/, '') + 'm';
          }
          if (num >= 1000) {
            return (num / 1000).toFixed(1).replace(/\.0$/, '') + 'k';
          }
          return num.toString();
        };
        
        const parseLRC = (lrc) => {
          if (!lrc) return [];
          const lines = lrc.split('\n');
          const parsed = [];
          const timeReg = /\[\d{2,}:\d{2}(?:\.\d{1,3})?\]/g;
          for (let line of lines) {
            const times = line.match(timeReg);
            if (times) {
              const text = line.replace(timeReg, '').trim();
              times.forEach(t => {
                const min = parseInt(t.slice(1, 3));
                const sec = parseFloat(t.slice(4, -1));
                parsed.push({ time: min * 60 + sec, text: text || '♪' });
              });
            }
          }
          return parsed.sort((a, b) => a.time - b.time);
        };
        
        const escapeHTML = str => {
          if (!str) return '';
          return str.replace(/[&<>'"]/g, tag => ({'&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;'}[tag]));
        };
        
        window.openMediaPreview = (url, type) => {
          const rootDoc = window.document;
          const body = rootDoc.getElementById('media-preview-body');
          if (!body) return;
          
          // Use 100vh to ensure it scales correctly inside the fullscreen modal bounds
          if (type && type.startsWith('video/')) {
            body.innerHTML = `<video src="${url}" controls autoplay style="max-width: 100%; max-height: 100vh; object-fit: contain;"></video>`;
          } else {
            body.innerHTML = `<img src="${url}" style="max-width: 100%; max-height: 100vh; object-fit: contain;">`;
          }
          
          const dlBtn = rootDoc.getElementById('media-preview-download-btn');
          if (dlBtn) {
            const newDlBtn = dlBtn.cloneNode(true);
            dlBtn.parentNode.replaceChild(newDlBtn, dlBtn);
            newDlBtn.addEventListener('click', async () => {
              try {
                // Blob URLs cross-origin can fail basic <a> download tags depending on browser restrictions
                const a = rootDoc.createElement('a');
                a.href = url;
                const ext = type.startsWith('video/') ? 'mp4' : 'png';
                a.download = `media_${Date.now()}.${ext}`;
                rootDoc.body.appendChild(a);
                a.click();
                rootDoc.body.removeChild(a);
              } catch(e) {
                // Safe fallback to just opening the raw blob
                window.open(url, '_blank');
              }
            });
          }
          
          bootstrap.Modal.getOrCreateInstance(rootDoc.getElementById('media-preview-modal')).show();
        };

        document.getElementById('media-preview-modal')?.addEventListener('hidden.bs.modal', () => {
          document.getElementById('media-preview-body').innerHTML = '';
        });

        window.buildLazyMediaHtml = (url, type, thumbUrl, isExternal) => {
          let displayThumb = thumbUrl || url;
          if (isExternal && type.startsWith('video/')) {
            displayThumb = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNk+A8AAQUBAScY42YAAAAASUVORK5CYII=';
          }
          
          let hash = 0;
          for (let i = 0; i < url.length; i++) hash = url.charCodeAt(i) + ((hash << 5) - hash);
          const h1 = Math.abs(hash % 360);
          const bgStyle = `background: hsl(${h1}, 20%, 30%);`;
          
          const isVideo = type.startsWith('video/');
          const videoIcon = isVideo ? `<div class="lazy-video-icon"><i class="bi bi-camera-video-fill"></i></div>` : '';

          // Fix: Enforce min-height to prevent UI clipping when lazy image is a 1x1 transparent pixel
          return `
            <div class="lazy-media-wrapper mt-1 mb-2 shadow-sm w-100" data-media-src="${url}" data-media-type="${type}" style="${bgStyle} max-width: 400px; min-height: 150px; display: inline-block;">
              ${videoIcon}
              <img src="${displayThumb}" class="lazy-blur" alt="Media" loading="lazy" style="width: 100%; height: auto; min-height: 150px; max-height: 400px; object-fit: contain; display: block; margin: 0 auto;">
              <div class="lazy-overlay" onclick="window.downloadLazyMedia(this)">
                 <i class="bi bi-download lazy-download-icon"></i>
                 <div class="spinner-border text-light d-none lazy-download-spinner" style="width: 1.5rem; height: 1.5rem; border-width: 0.2em;"></div>
                 <span class="lazy-download-text">Download</span>
              </div>
            </div>`;
        };

        const getOpfsMediaDir = async () => {
          const root = await navigator.storage.getDirectory();
          return await root.getDirectoryHandle('chat_media_cache', { create: true });
        };

        window.downloadLazyMedia = async (overlayEl) => {
          const wrapper = overlayEl.closest('.lazy-media-wrapper');
          if (wrapper.dataset.loading === "true") return;
          wrapper.dataset.loading = "true";
          
          const url = wrapper.dataset.mediaSrc;
          const type = wrapper.dataset.mediaType;
          
          const icon = overlayEl.querySelector('.lazy-download-icon');
          const text = overlayEl.querySelector('.lazy-download-text');
          const spinner = overlayEl.querySelector('.lazy-download-spinner');
          
          if (icon) icon.classList.add('d-none');
          if (text) text.classList.add('d-none');
          if (spinner) spinner.classList.remove('d-none');
          
          try {
            let blobUrl;
            try {
              if (!navigator.storage || !navigator.storage.getDirectory) throw new Error("No OPFS Support");
              
              const mediaDir = await getOpfsMediaDir();
              const fileName = (url.split('/').pop().split('?')[0] || 'media_unknown') + '_' + (url.split('id=')[1] || Date.now());
              
              try {
                // Try to grab it from OPFS first
                const fileHandle = await mediaDir.getFileHandle(fileName);
                const file = await fileHandle.getFile();
                blobUrl = URL.createObjectURL(file);
              } catch (e) {
                // File doesn't exist in OPFS, fetch it over network
                const res = await fetch(url);
                if (!res.ok) throw new Error('Network download failed');
                const blob = await res.blob();
                
                // Save raw blob heavily into OPFS
                const fileHandle = await mediaDir.getFileHandle(fileName, { create: true });
                const writable = await fileHandle.createWritable();
                await writable.write(blob);
                await writable.close();
                
                blobUrl = URL.createObjectURL(blob);
              }
            } catch (opfsError) {
              // Fallback for browsers/Private Mode blocking OPFS: Directly download to RAM
              console.warn("OPFS caching bypassed, buffering to RAM.");
              const res = await fetch(url);
              if (!res.ok) throw new Error('Network download failed');
              const blob = await res.blob();
              blobUrl = URL.createObjectURL(blob);
            }
            
            if (type.startsWith('video/')) {
              wrapper.innerHTML = `<video src="${blobUrl}" controls class="w-100 h-100 rounded" style="max-height: 400px; display: block; object-fit: contain; cursor: pointer;" onclick="window.openMediaPreview('${blobUrl}', '${type}')"></video>`;
            } else {
              wrapper.innerHTML = `<img src="${blobUrl}" class="w-100 h-100 rounded" style="max-height: 400px; display: block; object-fit: contain; cursor: zoom-in;" onclick="window.openMediaPreview('${blobUrl}', '${type}')">`;
            }
            wrapper.classList.add('loaded');
            wrapper.style.background = 'transparent';
          } catch (err) {
            console.error(err);
            if (icon) icon.classList.remove('d-none');
            if (text) {
              text.classList.remove('d-none');
              text.textContent = 'Retry';
            }
            if (spinner) spinner.classList.add('d-none');
            wrapper.dataset.loading = "false";
          }
        };

        window.checkMediaCache = async () => {
          if (!navigator.storage || !navigator.storage.getDirectory) return;
          try {
              const mediaDir = await getOpfsMediaDir();
              const docs = [document];
              if (window.chatPipWindow) docs.push(window.chatPipWindow.document);
              
              for (let doc of docs) {
                const wrappers = doc.querySelectorAll('.lazy-media-wrapper:not(.cache-checked)');
                for (let wrapper of wrappers) {
                  wrapper.classList.add('cache-checked');
                  const url = wrapper.dataset.mediaSrc;
                  const type = wrapper.dataset.mediaType || 'image/webp';
                  const fileName = (url.split('/').pop().split('?')[0] || 'media_unknown') + '_' + (url.split('id=')[1] || Date.now());
                  
                  try {
                    const fileHandle = await mediaDir.getFileHandle(fileName);
                    const file = await fileHandle.getFile();
                    const blobUrl = URL.createObjectURL(file);
                    
                    if (type.startsWith('video/')) {
                      wrapper.innerHTML = `<video src="${blobUrl}" controls class="w-100 h-100 rounded" style="max-height: 400px; display: block; object-fit: contain; cursor: pointer;" onclick="window.openMediaPreview('${blobUrl}', '${type}')"></video>`;
                    } else {
                      wrapper.innerHTML = `<img src="${blobUrl}" class="w-100 h-100 rounded" style="max-height: 400px; display: block; object-fit: contain; cursor: zoom-in;" onclick="window.openMediaPreview('${blobUrl}', '${type}')">`;
                    }
                    wrapper.classList.add('loaded');
                    wrapper.style.background = 'transparent';
                  } catch (e) {
                    // Not cached in OPFS yet
                  }
                }
              }
          } catch(e) {}
        };

        // Safely decodes HTML entities back into symbols (like I&#039;m -> I'm) before pasting them into Input fields.
        const decodeHTML = (html) => {
          if (!html) return '';
          const txt = document.createElement("textarea");
          txt.innerHTML = html;
          return txt.value;
        };

        // Parses DB content to active HTML at runtime (Applies [video], [url] and @mentions)
        const parseUserText = (text) => {
          if (!text) return '';
          let parsed = text;
          
          // Safely transform explicit [img] tags
          parsed = parsed.replace(/\[img\]\s*([^\s<>\[\]]+)\s*\[\/img\]/gi, function(match, url) {
            return window.buildLazyMediaHtml(url, 'image/jpeg', '', true);
          });

          // Safely transform explicit [video] tags into responsive YouTube or Native Video players
          parsed = parsed.replace(/\[video\]\s*([^\s<>\[\]]+)\s*\[\/video\]/gi, function(match, url) {
            const ytMatch = url.match(/(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=)|youtu\.be\/)([^"&?\/\s]{11})/i);
            if (ytMatch && ytMatch[1]) {
              return `<div class="position-relative w-100 mb-2 mt-1 rounded overflow-hidden shadow-sm" style="padding-top: 56.25%; max-width: 500px;"><iframe src="https://www.youtube.com/embed/${ytMatch[1]}" class="position-absolute top-0 start-0 w-100 h-100" frameborder="0" allowfullscreen></iframe></div>`;
            }
            return window.buildLazyMediaHtml(url, 'video/mp4', '', true);
          });
          
          // Safely transform explicit [url] tags into active clickable links, auto-appending https:// if missing!
          parsed = parsed.replace(/\[url\]\s*([^\s<>\[\]]+)\s*\[\/url\]/gi, function(match, url) {
            let href = url.match(/^https?:\/\//i) ? url : 'https://' + url;
            return `<a href="${href}" target="_blank" class="text-info text-decoration-none hover-underline">${url}</a>`;
          });
          // Defensive fallback: Parse any unformatted raw URLs directly into active links
          parsed = parsed.replace(/(^|[^"'])(https?:\/\/[^\s<]+)/gi, '$1<a href="$2" target="_blank" class="text-info text-decoration-none hover-underline">$2</a>');
          
          // Convert mentions
          parsed = parsed.replace(/@([\w\.\-_]+)/g, '<strong class="text-info mention-link" data-artist="$1" style="cursor:pointer;" title="Go to Profile">@$1</strong>');
          return parsed;
        };

        // Global Event listener for toggling nested replies in Comments/Community
        document.addEventListener('click', e => {
          const toggleBtn = e.target.closest('.toggle-replies-btn');
          if (toggleBtn) {
            const targetId = toggleBtn.dataset.target;
            const container = document.getElementById(targetId);
            if (container) {
              container.classList.toggle('d-none');
              const icon = toggleBtn.querySelector('i');
              if (container.classList.contains('d-none')) {
                icon.classList.replace('bi-chevron-up', 'bi-chevron-down');
                toggleBtn.innerHTML = `<i class="bi bi-chevron-down"></i> View ${container.children.length} replies`;
              } else {
                icon.classList.replace('bi-chevron-down', 'bi-chevron-up');
                toggleBtn.innerHTML = `<i class="bi bi-chevron-up"></i> Hide replies`;
              }
            }
          }
        });

        const timeAgo = (isoString) => {
          if (!isoString) return '';
          const date = new Date(isoString);
          if (isNaN(date)) return isoString;
        
          const seconds = Math.floor((new Date() - date) / 1000);
          let interval = seconds / 31536000;
          if (interval > 1) return Math.floor(interval) + " years ago";
          interval = seconds / 2592000;
          if (interval > 1) return Math.floor(interval) + " months ago";
          interval = seconds / 86400;
          if (interval > 1) return Math.floor(interval) + " days ago";
          interval = seconds / 3600;
          if (interval > 1) return Math.floor(interval) + " hours ago";
          interval = seconds / 60;
          if (interval > 1) return Math.floor(interval) + " minutes ago";
          return "Just now";
        };

        window.exportData = async (url, defaultFilename) => {
          showToast('Exporting...', 'info');
          try {
            const res = await fetch(url);
            if (!res.ok) throw new Error('Export failed');
            const blob = await res.blob();
            const urlBlob = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = urlBlob;
            
            const disposition = res.headers.get('Content-Disposition');
            let filename = defaultFilename;
            if (disposition && disposition.indexOf('filename=') !== -1) {
              const matches = /filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/.exec(disposition);
              if (matches != null && matches[1]) {
                filename = matches[1].replace(/['"]/g, '');
              }
            }
            a.download = filename;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(urlBlob);
          } catch (err) {
            showToast('Failed to export', 'error');
          }
        };

        const fetchData = async (url, options = {}, silent = false) => {
          try {
            options.cache = 'no-store';
            const response = await fetch(url, options);
            if (!response.ok) {
              const errorData = await response.json().catch(() => null);
              const message = errorData ? errorData.message : `HTTP error! status: ${response.status}`;
              throw new Error(message);
            }
            if (response.headers.get("content-type")?.includes("application/json")) {
              return await response.json();
            }
            return await response.text();
          } catch (error) {
            console.error("Fetch error for " + url, error);
            if (!silent) showToast(error.message, 'error');
            return null;
          }
        };

        const updateAppFavicon = (url) => {
          document.querySelectorAll("link[rel*='icon']").forEach(el => el.remove());
          const link = document.createElement('link');
          link.id = 'app-favicon';
          link.rel = 'icon';
          link.type = url.includes('get_app_icon') ? 'image/svg+xml' : 'image/webp';
          link.href = url;
          document.head.appendChild(link);
        };

        document.addEventListener('click', (e) => {
          const copyBtn = e.target.closest('.copy-api-token-btn');
          if (copyBtn) {
            e.preventDefault();
            e.stopPropagation();
            const token = copyBtn.dataset.token;
            if (!token) return;
            
            const onSuccess = () => {
              const origHTML = copyBtn.innerHTML;
              copyBtn.innerHTML = '<i class="bi bi-check-lg text-success"></i>';
              showToast('API Key copied to clipboard!', 'success');
              setTimeout(() => { copyBtn.innerHTML = origHTML; }, 2000);
            };
            
            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(token).then(onSuccess);
            } else {
              const ta = document.createElement('textarea');
              ta.value = token;
              ta.style.position = 'fixed';
              ta.style.opacity = '0';
              document.body.appendChild(ta);
              ta.select();
              document.execCommand('copy');
              document.body.removeChild(ta);
              onSuccess();
            }
          }
        });

        const showToast = (message, type = 'info') => {
          const toastContainer = document.createElement('div');
          toastContainer.className = `toast-container position-fixed bottom-0 end-0 p-3`;
          toastContainer.style.zIndex = "1100";
          const toastEl = document.createElement('div');
          toastEl.className = `toast align-items-center text-white bg-${type === 'error' ? 'danger' : 'success'} border-0`;
          toastEl.setAttribute('role', 'alert');
          toastEl.setAttribute('aria-live', 'assertive');
          toastEl.setAttribute('aria-atomic', 'true');
          toastEl.innerHTML = `<div class="d-flex"><div class="toast-body">${message}</div><button type="button" class="btn-close btn-close-white me-2 m-auto" data-bs-dismiss="toast" aria-label="Close"></button></div>`;
          
          document.body.appendChild(toastContainer);
          toastContainer.appendChild(toastEl);
          
          const toast = new bootstrap.Toast(toastEl);
          toast.show();
          toastEl.addEventListener('hidden.bs.toast', () => toastContainer.remove());
        };
        
        const showLoader = (isInitial = true) => {
          if (isInitial) {
            contentArea.innerHTML = `<div class="loader">Loading...</div>`;
            contentTitle.classList.remove('d-none');
          } else {
            infiniteScrollLoader.classList.remove('d-none');
          }
        };

        const hideLoader = () => {
          infiniteScrollLoader.classList.add('d-none');
        };
        
        const updateContentTitle = (text, show = true) => {
          let decodedText = text;
          try {
            decodedText = decodeURIComponent(text.replace(/\+/g, ' '));
          } catch (e) {}

          if (decodedText) {
            document.title = decodedText + ' - PHP Music';
          }

          if (!show) {
            contentTitle.classList.add('d-none');
            return;
          }
          contentTitle.classList.remove('d-none');
          contentTitle.textContent = decodedText;
        };

        const updateMultiSelectUI = () => {
          if (selectedSongs.size > 0) {
            multiSelectBar.classList.remove('d-none');
            multiSelectCount.textContent = selectedSongs.size;
            if (sortable) sortable.option("disabled", true);
          } else {
            multiSelectBar.classList.add('d-none');
            multiSelectMode = false;
            document.querySelectorAll('.song-item.multi-selected').forEach(el => el.classList.remove('multi-selected'));
            if (sortable) sortable.option("disabled", false);
          }
        };

        const toggleSongSelection = (songItem) => {
          const songId = songItem.dataset.songId;
          if (selectedSongs.has(songId)) {
            selectedSongs.delete(songId);
            songItem.classList.remove('multi-selected');
          } else {
            selectedSongs.add(songId);
            songItem.classList.add('multi-selected');
          }
          updateMultiSelectUI();
        };

        let isDragging = false;
        let startX = 0, startY = 0;

        const startHold = (e) => {
          const songItem = e.target.closest('.song-item');
          if (!songItem || e.target.closest('.song-more')) return;
          
          isDragging = false;
          if (e.touches && e.touches.length > 0) {
            startX = e.touches[0].clientX;
            startY = e.touches[0].clientY;
          }
          
          holdTimer = setTimeout(() => {
            if (isDragging) return;
            if (!currentUser) {
              showToast('Please log in to use multi-select mode.', 'error');
              return;
            }
            multiSelectMode = true;
            if (sortable) {
              sortable.option("disabled", true);
              if (window.TouchEvent) {
                document.dispatchEvent(new TouchEvent('touchend'));
              }
            }
            if (!selectedSongs.has(songItem.dataset.songId)) {
              toggleSongSelection(songItem);
            }
          }, 1000);
        };

        const moveHold = (e) => {
          if (holdTimer && e.touches && e.touches.length > 0) {
            const dx = Math.abs(e.touches[0].clientX - startX);
            const dy = Math.abs(e.touches[0].clientY - startY);
            if (dx > 10 || dy > 10) {
              isDragging = true;
              clearTimeout(holdTimer);
            }
          }
        };

        const endHold = () => {
          if (holdTimer) clearTimeout(holdTimer);
        };

        contentArea.addEventListener('touchstart', startHold, {passive: true});
        contentArea.addEventListener('touchmove', moveHold, {passive: true});
        contentArea.addEventListener('touchend', endHold);
        contentArea.addEventListener('touchcancel', endHold);

        contentArea.addEventListener('contextmenu', (e) => {
          const songItem = e.target.closest('.song-item');
          const moreBtn = e.target.closest('.song-more');
          if (songItem || e.target.closest('.shelf-item')) {
            e.preventDefault();
            if (songItem && !moreBtn) {
              if (!currentUser) {
                showToast('Please log in to use multi-select mode.', 'error');
                return;
              }
              if (!multiSelectMode) {
                multiSelectMode = true;
                if (sortable) sortable.option("disabled", true);
              }
              toggleSongSelection(songItem);
            }
          }
        });

        document.getElementById('multi-action-dropdown-btn').addEventListener('click', (e) => {
          e.stopPropagation();
          const menu = document.getElementById('multi-action-dropdown-menu');
          menu.classList.toggle('show');
          menu.style.display = menu.classList.contains('show') ? 'block' : 'none';
        });

        document.addEventListener('click', (e) => {
          const menu = document.getElementById('multi-action-dropdown-menu');
          if (menu && menu.classList.contains('show') && !e.target.closest('#multi-action-dropdown-btn')) {
            menu.classList.remove('show');
            menu.style.display = 'none';
          }
        });

        document.getElementById('multi-cancel-btn').addEventListener('click', () => {
          selectedSongs.clear();
          updateMultiSelectUI();
        });

        document.getElementById('multi-select-all-btn').addEventListener('click', () => {
          const songItems = document.querySelectorAll('#content-area .song-item');
          if (songItems.length === 0) return;
          
          let allSelected = true;
          songItems.forEach(item => {
            if (!selectedSongs.has(item.dataset.songId)) allSelected = false;
          });

          if (allSelected) {
            selectedSongs.clear();
            songItems.forEach(item => item.classList.remove('multi-selected'));
          } else {
            songItems.forEach(item => {
              const songId = item.dataset.songId;
              if (songId) {
                selectedSongs.add(songId);
                item.classList.add('multi-selected');
              }
            });
          }
          updateMultiSelectUI();
        });

        document.getElementById('multi-add-favorite-btn').addEventListener('click', async () => {
          if (!currentUser || selectedSongs.size === 0) return;
          let added = 0;
          
          const favBtn = document.getElementById('multi-add-favorite-btn');
          const originalBtnHtml = favBtn.innerHTML;
          favBtn.innerHTML = '<i class="bi bi-hourglass-split text-danger" style="animation: spinner-border 1s linear infinite;"></i> <span class="text-white">Adding...</span>';
          
          for (let songId of selectedSongs) {
            let isFav = false;
            if (globalSongCache[songId]) {
              isFav = globalSongCache[songId].is_favorite == 1;
            } else {
              const el = document.querySelector(`.song-item[data-song-id="${songId}"]`);
              if (el && el.dataset.isFavorite === '1') isFav = true;
            }

            if (!isFav) {
              const result = await fetchData('?action=toggle_favorite', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ id: parseInt(songId) })
              });
              
              if (result && result.is_favorite) {
                added++;
                if (globalSongCache[songId]) globalSongCache[songId].is_favorite = 1;
                
                const songItemsInView = document.querySelectorAll(`.song-item[data-song-id="${songId}"], .shelf-item[data-song-id="${songId}"]`);
                songItemsInView.forEach(item => {
                  item.dataset.isFavorite = "1";
                });
                
                if (currentSong && currentSong.id == songId) {
                  currentSong.is_favorite = 1;
                  updateFavoriteIcons(true);
                }
              }
            }
          }
          
          favBtn.innerHTML = originalBtnHtml;
          if (added > 0) {
            showToast(`Added ${added} new songs to favorites!`, 'success');
          } else {
            showToast(`Selected songs are already in favorites.`, 'info');
          }
          selectedSongs.clear();
          updateMultiSelectUI();
        });

        const recacheOfflineSong = async (id) => {
          let tco = document.querySelector('.toast-container');
          if (!tco) {
            tco = document.createElement('div');
            tco.className = 'toast-container position-fixed bottom-0 end-0 p-3';
            tco.style.zIndex = "1100";
            document.body.appendChild(tco);
          }
          const pToast = document.createElement('div');
          pToast.className = 'toast align-items-center text-white bg-warning text-dark border-0 show mb-2';
          pToast.innerHTML = `<div class="d-flex"><div class="toast-body" id="re-offline-progress-${id}">Re-caching song (0%)...</div></div>`;
          tco.appendChild(pToast);

          try {
            const cache = await caches.open('php-music-offline');
            
            const keys = await cache.keys();
            for (let req of keys) {
              const u = new URL(req.url);
              // Clean up both audio (?id=) and charts (?song_id=)
              if (u.searchParams.get('id') == id || u.searchParams.get('song_id') == id) await cache.delete(req);
            }
            
            const v = globalSongCache[id] ? (globalSongCache[id].last_modified || 0) : 0;
            await cache.add(`?action=get_image&id=${id}&v=${v}`);
            await cache.add(`?action=get_song_data&id=${id}`);
            
            // Explicitly force the device to cache Rhythm Game charts so they load safely offline!
            await cache.add(`?action=get_all_rhythm_levels`).catch(()=>{});
            await cache.add(`?action=get_rhythm_levels&song_id=${id}`).catch(()=>{});
            const rgDiffs = ['easy', 'medium', 'hard', 'expert', 'master', 'demon'];
            for (let d of rgDiffs) {
              await cache.add(`?action=get_rhythm_chart&song_id=${id}&difficulty=${d}`).catch(()=>{});
            }

            const response = await fetch(`?action=get_stream&id=${id}`);
            const contentLength = response.headers.get('content-length');
            
            if (!contentLength) {
              await cache.put(`?action=get_stream&id=${id}`, response.clone());
            } else {
              const total = parseInt(contentLength, 10);
              let loaded = 0;
              const reader = response.body.getReader();
              const stream = new ReadableStream({
                async start(controller) {
                  while (true) {
                    const { done, value } = await reader.read();
                    if (done) break;
                    loaded += value.length;
                    const pct = Math.round((loaded / total) * 100);
                    const pctText = document.getElementById(`re-offline-progress-${id}`);
                    if (pctText) pctText.innerText = `Re-caching song (${pct}%)...`;
                    controller.enqueue(value);
                  }
                  controller.close();
                }
              });
              const newResponse = new Response(stream, { headers: response.headers, status: response.status, statusText: response.statusText });
              await cache.put(`?action=get_stream&id=${id}`, newResponse);
            }
            
            pToast.classList.replace('bg-warning', 'bg-success');
            pToast.classList.replace('text-dark', 'text-white');
            document.getElementById(`re-offline-progress-${id}`).innerText = 'Successfully re-cached!';
            setTimeout(() => pToast.remove(), 3000);
            
            const itemRow = document.querySelector(`.song-item[data-song-id="${id}"]`);
            if (itemRow) {
              itemRow.classList.remove('offline-missing');
              itemRow.style.opacity = '1';
              const warningIcon = itemRow.querySelector('.offline-missing-icon');
              if (warningIcon) warningIcon.remove();
            }
            offlineSongsSet.add(parseInt(id));
          } catch(e) {
            pToast.classList.replace('bg-warning', 'bg-danger');
            pToast.classList.replace('text-dark', 'text-white');
            document.getElementById(`re-offline-progress-${id}`).innerText = 'Failed to re-cache.';
            setTimeout(() => pToast.remove(), 3000);
          }
        };

        document.getElementById('multi-offline-btn').addEventListener('click', async () => {
          if (!currentUser || selectedSongs.size === 0) return;
          let processed = 0;
          const songIdsArray = Array.from(selectedSongs);
          
          const offlineBtn = document.getElementById('multi-offline-btn');
          offlineBtn.disabled = true;
          const originalBtnHtml = offlineBtn.innerHTML;
          offlineBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span> Processing...';
          
          for (let songId of songIdsArray) {
            if (!offlineSongsSet.has(parseInt(songId))) {
               await fetchData('?action=toggle_offline', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: parseInt(songId) }) });
            }
            await recacheOfflineSong(parseInt(songId));
            processed++;
          }
          
          offlineBtn.disabled = false;
          offlineBtn.innerHTML = originalBtnHtml;
          showToast(`Processed ${processed} songs for offline playback!`, 'success');
          selectedSongs.clear();
          updateMultiSelectUI();
        });

        document.getElementById('multi-remove-btn').addEventListener('click', async () => {
          if (!currentUser || selectedSongs.size === 0) return;
          if (['playlist_songs', 'get_favorites', 'get_offline_songs'].indexOf(currentView.type) === -1) {
            showToast('This action is only available inside a Playlist, Favorites, or Offline Library.', 'error');
            return;
          }
          if (!confirm('Are you sure you want to remove the selected songs from this view?')) return;

          let removed = 0;
          for (let songId of selectedSongs) {
            if (currentView.type === 'playlist_songs') {
              await fetchData('?action=remove_from_playlist', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ song_id: parseInt(songId), playlist_public_id: decodeURIComponent(currentView.param) }) });
              removed++;
            } else if (currentView.type === 'get_favorites') {
              await fetchData('?action=toggle_favorite', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: parseInt(songId) }) });
              if (globalSongCache[songId]) globalSongCache[songId].is_favorite = 0;
              if (currentSong && currentSong.id == songId) {
                currentSong.is_favorite = 0;
                updateFavoriteIcons(false);
              }
              removed++;
            } else if (currentView.type === 'get_offline_songs') {
              await fetchData('?action=toggle_offline', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: parseInt(songId) }) });
              try {
                const cache = await caches.open('php-music-offline');
                const keys = await cache.keys();
                for (let req of keys) {
                  const u = new URL(req.url);
                  if (u.searchParams.get('id') == songId || u.searchParams.get('song_id') == songId) await cache.delete(req);
                }
              } catch (e) {}
              offlineSongsSet.delete(parseInt(songId));
              removed++;
            }
          }

          showToast(`Removed ${removed} songs.`, 'success');
          selectedSongs.clear();
          updateMultiSelectUI();
          loadView(currentView); 
        });

        const buildPlaylistModalContent = (playlists) => {
          let html = `
            <div class="mb-3 d-flex gap-2">
              <input type="text" id="quick-create-playlist-input" class="form-control bg-transparent text-white border-secondary" placeholder="New Playlist Name">
              <button class="btn btn-danger" id="quick-create-playlist-btn"><i class="bi bi-plus"></i></button>
            </div>
          `;
          if (playlists && playlists.length > 0) {
            html += `
              <div class="list-group list-group-flush">
                ${playlists.map(p => `
                  <button type="button" class="list-group-item list-group-item-action d-flex align-items-center gap-3 add-to-playlist-item my-1 p-2 rounded ${p.is_added == 1 ? 'bg-secondary text-white border-0 opacity-75' : 'bg-transparent text-white border border-secondary'}" data-playlist-id="${p.id}" data-public-id="${p.public_id}" data-is-added="${p.is_added || 0}">
                    <img src="?action=get_image&id=${p.image_id || 0}&v=${p.image_v || 0}" class="rounded" style="width: 48px; height: 48px; object-fit: cover; background-color: var(--ytm-surface-2);">
                    <div class="d-flex flex-column flex-grow-1 text-start overflow-hidden">
                      <span class="text-truncate fw-medium">${escapeHTML(p.name)}</span>
                      <span class="small ${p.is_added == 1 ? 'text-white-50' : 'text-secondary'}">${p.song_count} songs</span>
                    </div>
                    ${p.is_added == 1 ? '<i class="bi bi-check-circle-fill text-success fs-5"></i>' : '<i class="bi bi-plus-circle fs-5"></i>'}
                  </button>
                `).join('')}
              </div>
            `;
          } else {
            html += `<p class="text-secondary text-center p-4">No playlists found. Create one above!</p>`;
          }
          return html;
        };

        const reRenderPlaylistModal = async () => {
           const songId = (songIdForPlaylist && songIdForPlaylist.length === 1) ? songIdForPlaylist[0] : '0';
           const playlists = await fetchData(`?action=get_user_playlists&song_id=${songId}&sort=modified_desc`);
           addToPlaylistModalBody.innerHTML = buildPlaylistModalContent(playlists);
        };

        document.getElementById('multi-add-playlist-btn').addEventListener('click', async () => {
          songIdForPlaylist = Array.from(selectedSongs);
          mixIdForPlaylist = null;
          await reRenderPlaylistModal();
          addToPlaylistModal.show();
          selectedSongs.clear();
          updateMultiSelectUI();
        });
        
        const renderViewDetailsHeader = (details, type, songsList = []) => {
          // FIXED: Added local formatter to convert total durations into Days, Hours, and Minutes (Spotify convention)
          const formatTotalDuration = (seconds) => {
            if (isNaN(seconds) || seconds <= 0) return '0 min';
            const secs = Math.round(seconds);
            const days = Math.floor(secs / 86400);
            const hours = Math.floor((secs % 86400) / 3600);
            const minutes = Math.floor((secs % 3600) / 60);
            
            let parts = [];
            if (days > 0) {
              parts.push(`${days} day${days > 1 ? 's' : ''}`);
            }
            if (hours > 0) {
              parts.push(`${hours} hr${hours > 1 ? 's' : ''}`);
            }
            if (minutes > 0 || parts.length === 0) {
              parts.push(`${minutes} min${minutes > 1 ? 's' : ''}`);
            }
            return parts.join(' ');
          };
        
          currentViewOwnerId = details ? details.user_id : null;
          let typeText = type.charAt(0).toUpperCase() + type.slice(1);
          let statsText = `${formatSongCount(details.song_count || 0)} songs &bull; ${formatTotalDuration(details.total_duration || 0)}`;
          if (details.play_count !== undefined && details.play_count !== null) {
            statsText += ` &bull; ${formatSongCount(details.play_count)} plays`;
          }
          if (details.followers_count !== undefined && details.followers_count !== null) {
            statsText += ` &bull; ${formatSongCount(details.followers_count)} followers`;
          }
          let shareButtonHTML = '', copyButtonHTML = '', downloadButtonHTML = '', downloadExportPlaylistZipButtonHTML = '';
          
          let playButtonHTML = '';
          if (songsList && songsList.length > 0) {
            playButtonHTML = `
              <button class="btn btn-danger d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-4 py-2 fw-bold me-2 shadow-lg border border-danger" onclick="const f=document.querySelector('.song-list .song-item'); if(f){f.click();}" style="font-size: 0.85rem; height: 38px;">
                <i class="bi bi-play-fill fs-5"></i> Play
              </button>
            `;
          }
          
          let shareId = '';
          let shareName = encodeURIComponent(details.name);
          
          // ADVANCED ALBUM ARTIST MATCHER
          let rawArtistId = currentView.filter_user_id || details.user_id;
          if (!rawArtistId && songsList && songsList.length > 0) {
            rawArtistId = songsList[0].user_id;
          }
          let artistIdForShare = parseInt(rawArtistId, 10);
          if (isNaN(artistIdForShare) || artistIdForShare <= 0) {
            artistIdForShare = '';
          }

          if (type === 'playlist') {
            typeText = `Playlist by ${escapeHTML(details.creator)}`;
            shareId = details.public_id;
            document.title = `${details.name} - ${details.creator} - PHP Music`;
            downloadButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary open-pd-btn" data-public-id="${details.public_id}" title="Download Playlist" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-download"></i> <span class="d-none d-md-inline">Download</span></button>`;
            downloadExportPlaylistZipButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary export-playlist-btn" data-public-id="${details.public_id}" title="Export Playlist" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-box-arrow-up"></i> <span class="d-none d-md-inline">Export</span></button>`;
            if (currentUser && currentUser.id !== details.user_id) {
              copyButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary copy-playlist-btn" data-public-id="${details.public_id}" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-copy"></i> <span class="d-none d-md-inline">Copy Playlist</span></button>`;
            }
          } else if (type === 'mix') {
            typeText = `My Mix`;
            shareId = details.public_id;
            document.title = `${details.name} - PHP Music`;
            downloadButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary add-mix-to-playlist-btn" data-mix-id="${details.public_id}" title="Add to Playlist" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-plus-lg"></i> <span class="d-none d-md-inline">Add to Playlist</span></button>`;
          } else if (type === 'artist') {
            shareId = artistIdForShare ? artistIdForShare : shareName; 
            document.title = `${details.name} - Artist - PHP Music`;
          } else if (type === 'album') {
            shareId = shareName;
            if (!artistIdForShare && details.user_id) artistIdForShare = details.user_id; 
            document.title = `${details.name} - Album - PHP Music`;
          } else if (type === 'profile') {
            typeText = 'My Profile';
            document.title = `${details.name} - PHP Music`;
          } else {
             document.title = `${details.name} - PHP Music`;
          }
          
          if (type !== 'profile'){
            let shareArtistName = currentView.artist_name || '';
            if (!shareArtistName && songsList && songsList.length > 0) {
              shareArtistName = songsList[0].artist;
            }
            shareButtonHTML = `
              <button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold share-view-btn border-secondary" title="Share ${type}" data-share-type="${type}" data-share-id="${shareId}" data-share-name="${shareName}" data-artist-id="${artistIdForShare}" data-artist-name="${encodeURIComponent(shareArtistName)}" data-image-url="${details.image_url}" style="font-size: 0.85rem; height: 38px;">
                <i class="bi bi-share-fill"></i> <span class="d-none d-md-inline">Share</span>
              </button>`;
          }

          let followButtonHTML = '';
          let messageButtonHTML = '';
          let blockButtonHTML = '';
          let reportButtonHTML = '';

          if (type === 'artist' && details.is_user && currentUser && currentUser.id !== details.user_id) {
            const followText = details.is_following ? 'Unfollow' : 'Follow';
            const followClass = details.is_following ? 'btn-outline-light border-secondary text-white' : 'btn-light text-dark';
            followButtonHTML = `<button class="btn ${followClass} d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-4 py-1 fw-bold follow-btn" data-user-id="${details.user_id}" style="font-size: 0.85rem; height: 38px;">${followText}</button>`;
             
            messageButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary message-btn" data-user-id="${details.user_id}" data-artist="${encodeURIComponent(details.name)}" title="Message User" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-chat-dots-fill"></i> <span class="d-none d-md-inline">Message</span></button>`;
             
            const blockText = details.is_blocked ? 'Unblock' : 'Block';
            const blockClass = details.is_blocked ? 'text-danger' : 'text-secondary';
            blockButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary block-btn" data-user-id="${details.user_id}" title="${blockText} User" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-slash-circle-fill ${blockClass}"></i> <span class="d-none d-md-inline">${blockText}</span></button>`;

            if (details.reported_id !== 1 && details.name !== 'Music Library') {
              reportButtonHTML = `<button class="btn btn-outline-light d-inline-flex align-items-center justify-content-center gap-2 rounded-pill px-3 py-1 fw-bold border-secondary report-user-btn" data-user-id="${details.user_id}" title="Report Profile" style="font-size: 0.85rem; height: 38px;"><i class="bi bi-flag-fill text-warning"></i> <span class="d-none d-md-inline">Report</span></button>`;
            }
          }

          // Make Connections Clickable if it's an artist/profile
          let finalStatsText = statsText;
          if (type === 'artist' || type === 'profile') {
            finalStatsText = `${formatSongCount(details.song_count || 0)} songs &bull; ${formatTime(details.total_duration || 0)}
              &bull; <a href="#" class="text-info text-decoration-none connection-trigger" data-id="${details.user_id}" data-type="followers">${formatSongCount(details.followers_count || 0)} followers</a>
              &bull; <a href="#" class="text-info text-decoration-none connection-trigger" data-id="${details.user_id}" data-type="following">${formatSongCount(details.following_count || 0)} following</a>`;
          }

          const bioHTML = (details.bio && (type === 'artist' || type === 'profile')) ? 
            `<div class="mt-2 text-secondary" style="font-size: 0.85rem; font-weight: 500; white-space: pre-wrap; max-width: 800px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden;" title="${escapeHTML(details.bio)}">${parseUserText(details.bio)}</div>` : 
            (details.description && type === 'playlist') ? 
            `<div class="mt-2 text-secondary" style="font-size: 0.85rem; font-weight: 500; white-space: pre-wrap; max-width: 800px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden;" title="${escapeHTML(details.description)}">${parseUserText(details.description)}</div>` : '';

          const headerHTML = `
            <div id="dynamic-view-header" class="view-details-header position-relative overflow-hidden" style="min-height: 250px; background-color: var(--ytm-surface); padding: 2.5rem 2rem;">
              ${(type === 'profile' || type === 'artist') && details.background_url ? `<div class="position-absolute w-100 h-100 top-0 start-0" style="background-image: url('${details.background_url}'); background-size: cover; background-position: center; filter: brightness(0.3) blur(8px); transform: scale(1.1); z-index: 0;"></div>` : ''}
              ${(type !== 'profile' && type !== 'artist') ? `<div class="position-absolute w-100 h-100 top-0 start-0" style="background-image: url('${details.image_url}'); background-size: cover; background-position: center; filter: brightness(0.3) blur(40px); transform: scale(1.2); z-index: 0; opacity: 0.5;"></div>` : ''}
              <div class="d-flex flex-column flex-md-row align-items-center align-items-md-end gap-4 position-relative w-100" style="z-index: 1;">
                <img src="${(type === 'profile' || type === 'artist') ? details.image_url + (details.image_url.includes('?') ? '&' : '?') + 't=' + new Date().getTime() : details.image_url}" alt="${escapeHTML(details.name)}" class="${(type === 'profile' || type === 'artist') ? 'rounded-circle' : 'rounded shadow-lg'}" style="width: 180px; height: 180px; box-shadow: 0 8px 30px rgba(0,0,0,0.5); aspect-ratio: 1/1; object-fit: cover; object-position: center; flex-shrink: 0;">
                <div class="d-flex flex-column align-items-center align-items-md-start text-center text-md-start flex-grow-1" style="min-width: 0;">
                  <div class="text-uppercase fw-bold mb-1" style="letter-spacing: 1px; font-size: 0.8rem; color: rgba(255,255,255,0.9); text-shadow: 0 2px 4px rgba(0,0,0,0.8);">${typeText}</div>
                  <h1 class="fw-bolder text-white mb-2" style="font-size: clamp(1.8rem, 4vw, 3rem); line-height: 1.1; letter-spacing: -1px; word-break: break-word; text-shadow: 0 4px 12px rgba(0,0,0,0.6);">${escapeHTML(details.name)}</h1>
                  <div class="stats mb-2" style="color: rgba(255,255,255,0.7); font-size: 0.85rem; font-weight: 500; text-shadow: 0 1px 3px rgba(0,0,0,0.5);">${finalStatsText}</div>
                  ${bioHTML}
                  <div class="d-flex flex-wrap align-items-center justify-content-center justify-content-md-start gap-2 mt-3 w-100">
                    ${playButtonHTML}
                    ${followButtonHTML}
                    ${messageButtonHTML}
                    ${blockButtonHTML}
                    ${reportButtonHTML}
                    ${copyButtonHTML}
                    ${shareButtonHTML}
                    ${downloadButtonHTML}
                    ${downloadExportPlaylistZipButtonHTML}
                  </div>
                </div>
              </div>
              <div style="position: absolute; bottom: 0; left: 0; right: 0; height: 120px; background: linear-gradient(to top, var(--ytm-bg), transparent); z-index: 0;"></div>
            </div>
            <div id="recommendation-alert-container"></div>
          `;
          contentArea.insertAdjacentHTML('afterbegin', headerHTML);

          // Extract color and apply beautiful gradient background
          const headerImg = new Image();
          headerImg.crossOrigin = 'anonymous';
          headerImg.onload = () => {
             const rgb = getAverageColor(headerImg);
             const headerBg = document.getElementById('dynamic-view-header');
             if (headerBg && !details.background_url) { // Prioritize user bg image if it exists
               headerBg.style.background = `linear-gradient(135deg, rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.7) 0%, rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.2) 50%, var(--ytm-bg) 100%)`;
             } else if (headerBg && details.background_url) {
               // If bg exists, just tint it slightly to match the theme
               headerBg.style.boxShadow = `inset 0 0 150px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.3)`;
             }
          };
          headerImg.src = details.image_url + (details.image_url.includes('?') ? '&' : '?') + 't=' + new Date().getTime();

          if (type === 'artist' || type === 'profile') {
            const isUser = details.is_user || type === 'profile';
            if (isUser) {
              setTimeout(async () => {
                const bPane = document.getElementById('blogs-pane');
                if (!bPane) return;
                const bData = await fetchData(`?action=get_blogs&artist_id=${details.user_id}&sort=newest`);
                window.artistBlogsData = bData || [];
                if (bData && bData.length > 0) {
                  bPane.innerHTML = `<div class="notes-grid" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px;">` + bData.map(b => `
                    <div class="note-card bg-dark text-white border-secondary hover-bg-dark blog-card-item" data-id="${b.public_id}" style="border-radius: 12px; cursor: pointer; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-4px)'" onmouseout="this.style.transform='translateY(0)'">
                      <div class="d-flex justify-content-between mb-2">
                        <span class="badge bg-primary text-white">Public Blog</span>
                        <span class="small text-secondary">${new Date(b.updated_at.replace(' ', 'T')+'Z').toLocaleDateString()}</span>
                      </div>
                      <div class="fw-bold fs-5 mb-2 text-truncate">${escapeHTML((b.title && b.title.trim() !== '') ? decodeHTML(b.title) : 'Untitled')}</div>
                      <div class="text-secondary small overflow-hidden" style="display: -webkit-box; -webkit-line-clamp: 4; -webkit-box-orient: vertical;">${escapeHTML(decodeHTML(b.content).replace(/<[^>]*>?/gm, '').replace(/[^a-zA-Z0-9\s.,!?]/g, ''))}</div>
                      <div class="mt-auto pt-3 d-flex justify-content-between align-items-center">
                        ${b.category && b.category !== 'all' ? `<span class="note-chip">${escapeHTML(b.category_name || 'Uncategorized')}</span>` : '<span></span>'}
                      </div>
                    </div>
                  `).join('') + `</div>`;
                } else {
                  bPane.innerHTML = `<div class="text-center p-5 text-secondary">No public blogs found.</div>`;
                }
              }, 300);
            }
            const hasPlaylists = details.playlists && details.playlists.length > 0;
            
            // Build the Desktop Sidebar for Recommended content
            let recommendedSidebarHTML = ``;
            if (details.recommended_artists && details.recommended_artists.length > 0) {
              recommendedSidebarHTML += `
                <div class="d-flex flex-column" style="min-height: 0; flex: 1 1 40%;">
                  <h6 class="text-white fw-bold border-bottom border-secondary pb-2 mb-2 text-uppercase d-flex align-items-center gap-2" style="letter-spacing: 1px; font-size: 0.85rem;"><i class="bi bi-stars text-warning fs-5"></i> Similar Artists</h6>
                  <div class="list-group list-group-flush bg-transparent overflow-auto modern-custom-scroll" style="padding-right: 4px; flex-grow: 1;">
                    ${details.recommended_artists.map(a => `
                      <div class="list-group-item list-group-item-action bg-transparent text-white border-0 rounded px-2 py-2 mb-1 d-flex align-items-center gap-3 user-profile-link" data-userid="${a.id}" data-artist="${encodeURIComponent(a.artist)}" style="cursor: pointer; transition: background 0.2s;" onmouseover="this.style.backgroundColor='rgba(255,255,255,0.08)'" onmouseout="this.style.backgroundColor='transparent'">
                        <img src="?action=get_profile_picture&id=${a.id}" class="rounded-circle shadow-sm" style="width: 48px; height: 48px; object-fit: cover; border: 1px solid rgba(255,255,255,0.1);">
                        <div class="fw-bold text-truncate" style="font-size: 0.95rem;">${escapeHTML(a.artist)}</div>
                      </div>
                    `).join('')}
                  </div>
                </div>
              `;
            }
            if (details.recommended_songs && details.recommended_songs.length > 0) {
              recommendedSidebarHTML += `
                <div class="d-flex flex-column" style="min-height: 0; flex: 1 1 60%;">
                  <h6 class="text-white fw-bold border-bottom border-secondary pb-2 mb-2 text-uppercase d-flex align-items-center gap-2" style="letter-spacing: 1px; font-size: 0.85rem;"><i class="bi bi-fire text-danger fs-5"></i> Popular Tracks</h6>
                  <div class="list-group list-group-flush bg-transparent overflow-auto modern-custom-scroll" style="padding-right: 4px; flex-grow: 1;">
                    ${details.recommended_songs.map(s => `
                      <div class="list-group-item list-group-item-action bg-transparent text-white border-0 rounded px-2 py-2 mb-1 d-flex align-items-center gap-3 top-result-card" data-song-id="${s.id}" style="cursor: pointer; transition: background 0.2s;" onmouseover="this.style.backgroundColor='rgba(255,255,255,0.08)'" onmouseout="this.style.backgroundColor='transparent'">
                        <img src="?action=get_image&id=${s.id}&v=${s.last_modified || 0}" class="rounded shadow-sm" style="width: 48px; height: 48px; object-fit: cover; border: 1px solid rgba(255,255,255,0.1);">
                        <div class="d-flex flex-column text-truncate justify-content-center">
                          <div class="fw-bold text-truncate" style="font-size: 0.95rem;">${escapeHTML(s.title)}</div>
                          <div class="text-secondary text-truncate" style="font-size: 0.8rem;">${escapeHTML(s.artist)}</div>
                        </div>
                      </div>
                    `).join('')}
                  </div>
                </div>
              `;
            }
            
            let tabsHTML = `
              <div class="row mt-4">
                <div class="col-12 col-lg-8">
                  <ul class="nav nav-tabs mb-3" id="artistTabs" role="tablist">
                    <li class="nav-item" role="presentation">
                      <button class="nav-link active" id="songs-tab" data-bs-toggle="tab" data-bs-target="#songs-pane" type="button" role="tab">All Songs</button>
                    </li>
                    ${isUser ? `
                    <li class="nav-item" role="presentation">
                      <button class="nav-link" id="playlists-tab" data-bs-toggle="tab" data-bs-target="#playlists-pane" type="button" role="tab">Playlists</button>
                    </li>
                    <li class="nav-item" role="presentation">
                      <button class="nav-link" id="blogs-tab" data-bs-toggle="tab" data-bs-target="#blogs-pane" type="button" role="tab">Blogs</button>
                    </li>` : ''}
                  </ul>
                  <div class="tab-content" id="artistTabsContent">
                    <div class="tab-pane fade show active" id="songs-pane" role="tabpanel"></div>
                    ${isUser ? `
                    <div class="tab-pane fade" id="playlists-pane" role="tabpanel">
                      ${hasPlaylists ? `
                      <div class="row row-cols-2 row-cols-sm-3 row-cols-md-4 g-4">
                        ${details.playlists.map(p => `
                          <div class="col">
                            <div class="card h-100 bg-transparent text-white border-0 playlist-card" data-playlist="${encodeURIComponent(p.public_id)}" style="cursor: pointer;">
                              ${(currentUser && (currentUser.id == details.user_id || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `<button class="playlist-more-btn" data-public-id="${p.public_id}" data-name="${escapeHTML(p.name)}" data-is-collab="${p.is_collaborative || 0}" data-is-private="${p.is_private || 0}" data-owner-id="${details.user_id}"><i class="bi bi-three-dots-vertical"></i></button>` : ''}
                              <div style="position: relative; display: block; border-radius: 6px; overflow: hidden;">
                                <img src="?action=get_image&id=${p.image_id || 0}&v=${p.image_v || 0}" class="card-img-top" alt="${escapeHTML(p.name)}" style="aspect-ratio: 1/1; object-fit: cover; background-color: var(--ytm-surface-2); margin-bottom: 0 !important;">
                                ${p.song_count !== undefined ? `<div class="position-absolute bottom-0 start-0 ms-2 mb-1 px-2 py-1 bg-dark bg-opacity-75 text-white rounded fw-bold" style="font-size: 0.75rem; backdrop-filter: blur(4px); line-height: 1;"><i class="bi bi-music-note-list"></i> ${formatSongCount(p.song_count)}</div>` : ''}
                              </div>
                              <div class="card-body px-0 py-2">
                                <h5 class="card-title fs-6 fw-normal text-truncate">${escapeHTML(p.name)}</h5>
                              </div>
                            </div>
                          </div>
                        `).join('')}
                      </div>
                      ` : `<div class="text-center p-5 text-secondary">No playlists found.</div>`}
                    </div>
                    <div class="tab-pane fade" id="blogs-pane" role="tabpanel">
                       <div class="text-center p-5 text-secondary" id="artist-blogs-loader"><span class="spinner-border spinner-border-sm"></span> Loading blogs...</div>
                    </div>` : ''}
                  </div>
                </div>
                <div class="col-12 col-lg-4 d-none d-lg-block">
                  <div class="p-3 rounded shadow-sm sticky-top d-flex flex-column gap-3" style="top: 100px; height: calc(100vh - 210px); background-color: var(--ytm-surface-2); border: 1px solid rgba(255,255,255,0.05);">
                    ${recommendedSidebarHTML || '<div class="text-center text-secondary small m-auto">No recommendations yet.</div>'}
                  </div>
                </div>
              </div>
            `;
            contentArea.insertAdjacentHTML('beforeend', tabsHTML);
            window.artistPlaylistsData = details.playlists || [];
          }
        };

        const formatArtistsHTML = (artistString, userId, isCollaborative = 1) => {
          if (!artistString) return escapeHTML('Unknown Artist');
          if (isCollaborative == 1) {
            const artistsList = artistString.split(/\s*(?:;|\||\s+&\s+|\s+feat\.?\s+|\s+ft\.?\s+|\s+featuring\s+|\s*,\s*(?!(?:the|a|an|jr|sr)\b))\s*/i).filter(a => a && a.trim() !== '');
            // Move icon to the front, and ONLY pass the User ID to the primary (first) artist in the split!
            return '<i class="bi bi-people-fill text-secondary me-1" title="Official Collaboration" style="font-size: 0.75rem;"></i> ' + artistsList.map((a, index) => `<span class="artist-link hover-underline" data-artist="${encodeURIComponent(a)}" data-userid="${index === 0 ? (userId || '') : ''}">${escapeHTML(a)}</span>`).join(', ');
          } else {
            return `<span class="artist-link hover-underline" data-artist="${encodeURIComponent(artistString)}" data-userid="${userId || ''}">${escapeHTML(artistString)}</span>`;
          }
        };

        const renderSongs = (songs, append = false) => {
          if (!append) {
            if (sortable) {
              sortable.destroy();
              sortable = null;
            }
            if (!contentArea.querySelector('.view-details-header') && currentView.type !== 'get_favorites' && currentView.type !== 'get_songs') {
              contentArea.innerHTML = '';
            } else if (currentView.type === 'get_favorites' && !contentArea.querySelector('.song-list')) {
            }
          }

          let targetContainer = document.getElementById('songs-pane') || contentArea;

          if (!songs || songs.length === 0) {
            if (currentPage === 1) {
              if (currentView.type === 'get_songs') {
                targetContainer.innerHTML = `
                  <div class="d-flex flex-column align-items-center justify-content-center text-secondary w-100" style="height: 60vh;">
                    <i class="bi bi-hdd-stack text-warning mb-3" style="font-size: 5rem;"></i>
                    <h3 class="fw-bold text-white">Database is Empty!</h3>
                    <p class="text-secondary mt-2 text-center" style="max-width: 400px;">There are no songs in the system. The admin must run a Full Library Scan to populate the database.</p>
                    <button class="btn btn-danger fw-bold px-4 py-2 mt-3" data-bs-toggle="modal" data-bs-target="#full-scan-modal">
                      <i class="bi bi-search me-2"></i>Scan Library Now
                    </button>
                  </div>
                `;
              } else {
                targetContainer.insertAdjacentHTML('beforeend', `<div class="text-center p-5 text-secondary">No songs found.</div>`);
              }
            }
            allContentloaded = true;
            hideLoader();
            return;
          }

          let songList = targetContainer.querySelector('.song-list');
          if (!songList) {
            songList = document.createElement('div');
            songList.className = 'song-list';
            const isHistory = currentView.type === 'get_history';
            const header = `<div class="song-list-header d-none d-md-grid" style="grid-template-columns: 40px minmax(0, 4fr) minmax(0, 3fr) minmax(0, 3fr) minmax(0, 2fr) ${isHistory ? 'minmax(0, 2fr)' : ''} 80px 40px;">
              <div>&nbsp;</div><div>Title</div><div>Artist</div><div>Album</div><div>Views</div>${isHistory ? '<div>Played</div>' : ''}<div>Time</div><div>&nbsp;</div>
            </div>`;
            targetContainer.insertAdjacentHTML('beforeend', header);
            targetContainer.appendChild(songList);
          }
          
          const escapeAttr = (str) => str ? String(str).replace(/'/g, "&apos;").replace(/"/g, "&quot;") : '';

          const songsHTML = songs.map((song) => {
            globalSongCache[song.id] = song;
            const isNowPlaying = currentSong && currentSong.id === song.id;
            const isHistory = currentView.type === 'get_history';
            const playedAtHTML = isHistory ? `<div class="played-at-text text-truncate" title="${timeAgo(song.played_at)}">${timeAgo(song.played_at)}</div>` : '';
            const coverSvg = getSvgPlaceholder(song.title || 'Unknown');
            return `
            <div class="song-item py-md-3 ${isNowPlaying ? 'now-playing' : ''} ${isHistory ? 'history-item' : ''}" 
              data-song-id="${song.id}" 
              data-is-favorite="${song.is_favorite == 1 ? '1' : '0'}"
              data-is-collaborative="${song.is_collaborative == 1 ? '1' : '0'}"
              data-song-title="${escapeAttr(song.title)}"
              data-song-artist="${escapeAttr(song.artist)}"
              data-song-album="${escapeAttr(song.album)}"
              data-song-genre="${escapeAttr(song.genre)}"
              data-song-user-id="${song.user_id}">
              <div class="song-indicator-wrapper d-flex align-items-center justify-content-center">
                <img src="?action=get_image&id=${song.id}&v=${song.last_modified || 0}&size=small" onerror="this.onerror=null; this.src='${coverSvg}';" class="song-thumb" loading="lazy" alt="${escapeAttr(song.title)}">
                <i class="bi bi-soundwave playing-icon"></i>
              </div>
              <div class="song-title-wrapper text-truncate"><div class="song-title text-truncate">${song.is_private == 1 ? '<i class="bi bi-lock-fill text-warning me-1" title="Private Song"></i>' : ''}${escapeHTML(song.title)}</div></div>
              <div class="song-artist text-truncate" data-userid="${song.user_id}">
                <div class="text-truncate">${formatArtistsHTML(song.artist, song.user_id, song.is_collaborative)}</div>
                <div class="text-secondary d-md-none" style="font-size: 0.8rem; margin-top: 2px;" title="Play Count"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                ${song.added_by_name ? `<div style="font-size: 0.7rem; color: var(--ytm-secondary-text); margin-top: 2px;">Added by: ${escapeHTML(song.added_by_name)}</div>` : ''}
              </div>
              <div class="song-album text-truncate" data-album="${encodeURIComponent(song.album)}" data-userid="${song.user_id}">${escapeHTML(song.album)}</div>
              <div class="song-views d-none d-md-block text-truncate" title="${song.play_count || 0} views">${formatSongCount(song.play_count || 0)}</div>
              ${isHistory ? `<div class="d-none d-md-block text-truncate">${playedAtHTML}</div>` : ''}
              <div class="song-duration d-none d-md-block">${formatTime(song.duration)}</div>
              <div class="song-more">
                <button class="more-btn" data-song-id="${song.id}">
                  <i class="bi bi-three-dots-vertical"></i>
                </button>
              </div>
              <div class="song-artist-mobile w-100 flex-column align-items-start">
                <div class="d-flex justify-content-between align-items-center w-100 gap-2">
                   <span class="song-artist-name text-truncate flex-grow-1" style="min-width: 0;">${formatArtistsHTML(song.artist, song.user_id, song.is_collaborative)}</span>
                   ${isHistory ? `<span class="text-secondary small flex-shrink-0">${timeAgo(song.played_at)}</span>` : ''}
                   <span class="song-duration-mobile flex-shrink-0">${formatTime(song.duration)}</span>
                </div>
                <div class="text-secondary text-start" style="font-size: 0.8rem; margin-top: 2px;"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
              </div>
            </div>
          `}).join('');
          
          songList.insertAdjacentHTML('beforeend', songsHTML);
          
          // Verify cache and show warning indicator for missing offline files
          if (currentView.type === 'get_offline_songs') {
            caches.open('php-music-offline').then(cache => {
              const addedItems = songList.querySelectorAll('.song-item:not(.cache-checked)');
              addedItems.forEach(async item => {
                item.classList.add('cache-checked');
                const sid = item.dataset.songId;
                const req = await cache.match(`?action=get_stream&id=${sid}`, { ignoreSearch: false, ignoreVary: true });
                if (!req) {
                  item.classList.add('offline-missing');
                  item.style.opacity = '0.4';
                  const titleWrapper = item.querySelector('.song-title-wrapper');
                  if (titleWrapper && !titleWrapper.querySelector('.offline-missing-icon')) {
                     titleWrapper.insertAdjacentHTML('beforeend', ' <i class="bi bi-cloud-slash-fill text-warning offline-missing-icon" title="Not fully cached. Please Re-download." style="font-size: 0.85rem; cursor: help;"></i>');
                  }
                }
              });
            });
          }

          const isSortableFavorites = currentView.type === 'get_favorites' && currentView.sort === 'manual_order';
          const isSortablePlaylist = currentView.type === 'playlist_songs' && currentView.sort === 'manual_order';
          const isSortableOffline = currentView.type === 'get_offline_songs' && currentView.sort === 'manual_order';

          if ((isSortableFavorites || isSortablePlaylist || isSortableOffline) && !sortable) {
            sortable = Sortable.create(songList, {
              animation: 150,
              ghostClass: 'ghost',
              delay: 250,
              delayOnTouchOnly: false,
              disabled: multiSelectMode,
              scroll: document.getElementById('main-content'),
              scrollSensitivity: 150,
              scrollSpeed: 30,
              onStart: function() {
                isDragging = true;
                if (holdTimer) clearTimeout(holdTimer);
              },
              onEnd: async (evt) => {
                isDragging = false;
                
                const isSuperAdmin = currentUser && currentUser.email && currentUser.email.toLowerCase() === 'musiclibrary@mail.com';
                if (isSortablePlaylist && (!currentUser || (currentViewOwnerId !== currentUser.id && !isSuperAdmin))) {
                  showToast("You're not the owner of this playlist.", "error");
                  loadView(currentView);
                  return;
                }
                
                const songItems = Array.from(songList.querySelectorAll('.song-item'));
                const newOrderIds = songItems.map(item => item.dataset.songId);
                
                let action = 'update_playlist_order';
                if (isSortableFavorites) action = 'update_favorite_order';
                else if (isSortableOffline) action = 'update_offline_order';

                const body = { 
                  ids: newOrderIds,
                  ...(isSortablePlaylist && { playlist_public_id: decodeURIComponent(currentView.param) })
                };
                
                await fetchData(`?action=${action}`, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify(body)
                });
              }
            });
          }
        };

        const renderGrid = (items, type, append = false) => {
          if (!append) contentArea.innerHTML = '';
          if (type === 'get_mixes' && !append) {
            contentArea.innerHTML = `
              <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(135deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                <div class="d-flex flex-wrap align-items-center justify-content-between gap-3 mb-4">
                  <div class="d-flex align-items-center gap-3">
                    <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                      <i class="bi bi-collection-play-fill text-danger fs-3"></i>
                    </div>
                    <div>
                      <h2 class="text-white fw-bold mb-1 fs-4">Auto Mixes</h2>
                      <p class="text-secondary small mb-0">Dynamically generated playlists based on your library's artists and genres.</p>
                    </div>
                  </div>
                </div>
                <div class="w-100 position-relative">
                  <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                  <input type="text" id="mixes-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search mixes..." value="${escapeHTML(currentView.searchQuery || '')}" style="height: 42px;">
                </div>
              </div>
            `;
            setTimeout(() => {
              const mSearch = document.getElementById('mixes-search-input');
              if (mSearch) {
                mSearch.addEventListener('input', (e) => {
                  clearTimeout(window.mixesSearchTimeout);
                  window.mixesSearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                });
                if (currentView.searchQuery) {
                  mSearch.focus();
                  mSearch.setSelectionRange(mSearch.value.length, mSearch.value.length);
                }
              }
            }, 0);
          } else if (type === 'get_user_playlists' && !append && currentUser) {
            contentArea.innerHTML = `
              <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(135deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                <div class="d-flex flex-wrap align-items-center justify-content-between gap-3 mb-4">
                  <div class="d-flex align-items-center gap-3">
                    <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                      <i class="bi bi-music-note-list text-danger fs-3"></i>
                    </div>
                    <div>
                      <h2 class="text-white fw-bold mb-1 fs-4">My Playlists</h2>
                      <p class="text-secondary small mb-0">Create, customize, and manage your private and public playlists.</p>
                    </div>
                  </div>
                  <div class="d-flex gap-2">
                    <button class="btn btn-sm btn-danger rounded-pill px-3 fw-bold shadow-sm" id="create-new-playlist-btn"><i class="bi bi-plus-lg me-1"></i> Create</button>
                    <button class="btn btn-sm btn-outline-light rounded-pill px-3 fw-medium shadow-sm" id="import-playlist-btn"><i class="bi bi-box-arrow-in-down me-1"></i> Import</button>
                  </div>
                </div>
                <div class="w-100 position-relative">
                  <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                  <input type="text" id="playlists-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search playlists..." value="${escapeHTML(currentView.searchQuery || '')}" style="height: 42px;">
                </div>
              </div>
            `;
            
            setTimeout(() => {
              const attachPlaylistSearch = () => {
                const handler = (e) => {
                  clearTimeout(window.playlistsSearchTimeout);
                  window.playlistsSearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                };
                const pSearch = document.getElementById('playlists-search-input');
                if (pSearch) {
                  pSearch.addEventListener('input', handler);
                  if (currentView.searchQuery) {
                    pSearch.focus();
                    pSearch.setSelectionRange(pSearch.value.length, pSearch.value.length);
                  }
                }
              };
              attachPlaylistSearch();
            }, 0);
          } else if (type === 'get_collab_playlists' && !append && currentUser) {
            contentArea.innerHTML = `
              <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(135deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                <div class="d-flex align-items-center gap-3">
                  <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                    <i class="bi bi-people-fill text-info fs-3"></i>
                  </div>
                  <div>
                    <h2 class="text-white fw-bold mb-1 fs-4">Shared With Me</h2>
                    <p class="text-secondary small mb-0">Collaborative playlists shared with you by other creators.</p>
                  </div>
                </div>
              </div>
            `;
          } else if (type === 'get_following' && !append && currentUser) {
            contentArea.innerHTML = `
              <div class="d-flex flex-wrap align-items-center justify-content-between p-3 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background-color: var(--ytm-surface-2); border: 1px solid #333;">
                <div class="text-white fw-bold fs-5 mb-3 mb-md-0 d-flex align-items-center"><i class="bi bi-person-lines-fill text-primary me-3 fs-3"></i> Following</div>
              </div>
            `;
          }
          
          if (!items || items.length === 0) {
            if (!append && type !== 'get_user_playlists') {
              contentArea.innerHTML += `<div class="text-center p-5 text-secondary">No ${type.replace('get_','')} found.</div>`;
            }
            allContentloaded = true;
            hideLoader();
            return;
          }

          let grid = contentArea.querySelector('.row');
          if (!grid) {
            grid = document.createElement('div');
            grid.className = 'row row-cols-2 row-cols-sm-3 row-cols-md-4 row-cols-lg-5 row-cols-xl-6 g-4';
            contentArea.appendChild(grid);
          }
          
          const itemsHTML = items.map(item => {
              let name, subtext, imageId, dataType, dataValue, icon, publicId, imgClass = 'rounded', titleClass = '', subtextClass = '';
              let imgSrc = `?action=get_image&id=`;
              if (type === 'get_albums') {
                name = item.album;
                subtext = item.artist;
                imageId = item.id;
                dataType = 'album';
                dataValue = name;
                publicId = '';
              } else if (type === 'get_artists') {
                name = item.name;
                subtext = null;
                imageId = item.id;
                dataType = 'artist';
                dataValue = name;
                publicId = '';
                imgClass = 'rounded-circle';
                titleClass = 'text-center';
                subtextClass = 'text-center';
                if (item.is_user) {
                  item.user_id = item.id;
                  imgSrc = `?action=get_profile_picture&id=`;
                }
              } else if (type === 'get_following') {
                name = item.name;
                subtext = 'Artist';
                imageId = item.id;
                dataType = 'artist';
                dataValue = name;
                publicId = '';
                imgClass = 'rounded-circle';
                titleClass = 'text-center';
                subtextClass = 'text-center';
                imgSrc = `?action=get_profile_picture&id=`;
              } else if (type === 'get_user_playlists' || type === 'get_collab_playlists' || type === 'get_mixes') {
                name = item.name;
                subtext = type === 'get_collab_playlists' ? `by ${item.creator} • ${formatSongCount(item.song_count)} songs` : (type === 'get_mixes' ? `Auto Mix • ${formatSongCount(item.song_count)} songs` : `${formatSongCount(item.song_count)} songs`);
                imageId = item.image_id;
                dataType = type === 'get_mixes' ? 'mix' : 'playlist';
                dataValue = item.public_id;
                publicId = item.public_id;
              } else if (type === 'get_categories') {
                name = item.name;
                subtext = `${item.item_count} items`;
                imageId = null;
                dataType = 'category';
                dataValue = item.id;
                publicId = '';
                icon = 'bi-folder-fill';
              } else if (type === 'get_genres' || type === 'get_years') {
                name = item.name;
                subtext = null;
                imageId = item.id;
                dataType = type === 'get_years' ? 'year' : 'genre';
                dataValue = name;
                publicId = '';
              } else {
                name = item.name || item;
                subtext = null;
                dataType = type.replace('get_','').slice(0, -1);
                dataValue = name;
                icon = 'bi-tag-fill';
                publicId = '';
              }
              
              const useridAttr = item.user_id ? `data-userid="${item.user_id}"` : (type === 'get_following' ? `data-userid="${item.id}"` : '');
              const artistNameAttr = (type === 'get_albums' && item.artist) ? `data-artistname="${encodeURIComponent(item.artist)}"` : '';

              let moreButton = '';
              if (type === 'get_user_playlists' || type === 'get_collab_playlists' || type === 'get_mixes') {
                moreButton = `
                <button class="playlist-more-btn ${type === 'get_mixes' ? 'mix-more-btn' : ''}" data-type="${type === 'get_mixes' ? 'mixes' : 'playlists'}" data-public-id="${publicId}" data-name="${escapeHTML(name)}" data-description="${escapeHTML(item.description || '')}" data-is-collab="${item.is_collaborative || 0}" data-is-private="${item.is_private || 0}" data-owner-id="${item.owner_id || ''}" data-creator="${escapeHTML(item.creator || '')}" data-image-id="${imageId || 0}">
                  <i class="bi bi-three-dots-vertical"></i>
                </button>`;
              } else if (type === 'get_albums') {
                moreButton = `
                <button class="playlist-more-btn album-more-btn" data-album="${encodeURIComponent(item.album)}" data-userid="${item.user_id || ''}" data-artistname="${encodeURIComponent(item.artist || '')}" data-id="${item.id || 0}">
                  <i class="bi bi-three-dots-vertical"></i>
                </button>`;
              }

              if (type === 'get_albums' || type === 'get_user_playlists' || type === 'get_collab_playlists' || type === 'get_mixes' || type === 'get_artists' || type === 'get_following' || type === 'get_genres' || type === 'get_years') {
                let songCountBadge = '';
                if ((type === 'get_albums' || type === 'get_user_playlists' || type === 'get_collab_playlists' || type === 'get_mixes') && item.song_count !== undefined) {
                  songCountBadge = `<div class="position-absolute bottom-0 start-0 ms-2 mb-2 px-2 py-1 bg-dark bg-opacity-75 text-white rounded fw-bold" style="font-size: 0.75rem; backdrop-filter: blur(4px); line-height: 1;"><i class="bi bi-music-note-list"></i> ${formatSongCount(item.song_count)}</div>`;
                }
                
                let viewCountHtml = '';
                if (type === 'get_albums' && item.total_plays !== undefined) {
                  viewCountHtml = `<div class="card-text small text-secondary text-truncate mt-1" style="font-size: 0.75rem;"><i class="bi bi-eye"></i> ${formatSongCount(item.total_plays)} views</div>`;
                } else if ((type === 'get_user_playlists' || type === 'get_collab_playlists' || type === 'get_mixes') && item.play_count !== undefined) {
                  viewCountHtml = `<div class="card-text small text-secondary text-truncate mt-1" style="font-size: 0.75rem;"><i class="bi bi-eye"></i> ${formatSongCount(item.play_count)} views</div>`;
                }

                // Determine whether it needs circle or standard card rounded corners
                let borderStyle = (imgClass === 'rounded-circle') ? 'border-radius: 50%;' : 'border-radius: 6px;';
                return `<div class="col">
                  <div class="card h-100 bg-transparent text-white border-0 playlist-card" data-${dataType}="${encodeURIComponent(dataValue)}" ${useridAttr} ${artistNameAttr} style="cursor: pointer;">
                    ${moreButton}
                    <div style="position: relative; display: block; ${borderStyle} overflow: hidden;">
                      <img src="${imgSrc}${imageId || 0}&v=${item.image_v || 0}&size=small" class="card-img-top" alt="${name}" style="aspect-ratio: 1/1; object-fit: cover; background-color: var(--ytm-surface-2); margin-bottom: 0 !important;">
                      ${songCountBadge}
                    </div>
                    <div class="card-body px-0 py-2">
                      <h5 class="card-title fs-6 fw-normal text-truncate ${titleClass}">
                        ${type === 'get_user_playlists' && item.is_private == 1 ? '<i class="bi bi-lock-fill text-warning me-1"></i>' : ''}${escapeHTML(name)}
                      </h5>
                      ${subtext ? `<p class="card-text small text-secondary text-truncate mb-0 ${subtextClass}">${escapeHTML(subtext)}</p>` : ''}
                      ${viewCountHtml}
                    </div>
                  </div>
                </div>`;
              } else {
                return `<div class="col">
                  <div class="card h-100 bg-transparent text-white border-0" data-${dataType}="${encodeURIComponent(dataValue)}" ${useridAttr} style="cursor: pointer;">
                    <div class="d-flex align-items-center justify-content-center rounded" style="aspect-ratio: 1/1; background-color: var(--ytm-surface-2);">
                      <i class="bi ${icon}" style="font-size: 4rem; color: var(--ytm-secondary-text);"></i>
                    </div>
                    <div class="card-body px-0 py-2">
                      <h5 class="card-title fs-6 fw-normal text-truncate">${escapeHTML(name)}</h5>
                      ${subtext ? `<p class="card-text small text-secondary text-truncate m-0">${escapeHTML(subtext)}</p>` : ''}
                    </div>
                  </div>
                </div>`;
              }
          }).join('');
          
          grid.insertAdjacentHTML('beforeend', itemsHTML);

          // Render footer actions for Mixes
          if (type === 'get_mixes') {
            const oldFooter = document.getElementById('mixes-footer-actions');
            if (oldFooter) oldFooter.remove();
            
            if (items && items.length > 0) {
              contentArea.insertAdjacentHTML('beforeend', `
                <div id="mixes-footer-actions" class="d-flex flex-wrap justify-content-center gap-3 mt-5 mb-5 w-100">
                  <button class="btn btn-outline-light rounded-pill px-4 py-2 fw-bold" id="mixes-load-more-btn"><i class="bi bi-chevron-down me-2"></i> Load More Mixes</button>
                  <button class="btn btn-danger rounded-pill px-4 py-2 fw-bold shadow-lg" id="mixes-refresh-btn"><i class="bi bi-arrow-clockwise me-2"></i> Refresh All Mixes</button>
                </div>
              `);
              
              const loadMoreBtn = document.getElementById('mixes-load-more-btn');
              if (loadMoreBtn) {
                loadMoreBtn.innerHTML = '<i class="bi bi-plus-lg me-2"></i> Generate More Mixes';
                loadMoreBtn.addEventListener('click', (e) => {
                  e.preventDefault();
                  loadMoreBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span> Generating...';
                  currentView.generate = '1';
                  loadView(currentView);
                });
              }
              
              const refreshBtn = document.getElementById('mixes-refresh-btn');
              if (refreshBtn) {
                refreshBtn.addEventListener('click', (e) => {
                  e.preventDefault();
                  refreshBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span> Generating...';
                  currentView.refresh = '1';
                  loadView(currentView);
                });
              }
            }
          }
        };
        
        const renderRecommendations = (data) => {
          contentArea.innerHTML = '';
          
          if (currentView.type === 'search') {
            const fd = currentView.f_date || '';
            const fdu = currentView.f_dur || '';
            const fs = currentView.f_sort || 'relevance';
            const fsd = currentView.f_start_date || '';
            const fed = currentView.f_end_date || '';

            const filterHTML = `
              <div class="search-filters-container w-100 mb-4 px-2 order-first" style="grid-column: 1 / -1;">
                <button class="btn btn-outline-light rounded-pill" type="button" data-bs-toggle="collapse" data-bs-target="#searchFiltersCollapse">
                  <i class="bi bi-sliders"></i> Filters ${(fsd || fed) ? '<span class="badge bg-danger rounded-circle p-1 ms-1"></span>' : ''}
                </button>
                <div class="collapse mt-3" id="searchFiltersCollapse">
                  <div class="card card-body bg-dark border-secondary text-white d-flex flex-row flex-wrap gap-5" style="border-radius: 12px;">
                    <div class="d-flex flex-column gap-2">
                      <h6 class="border-bottom border-secondary pb-2 mb-1 fw-bold text-secondary">UPLOAD DATE</h6>
                      <a href="#" class="text-decoration-none ${(fd === '' && !fsd && !fed) ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_date" data-val="">Any time</a>
                      <a href="#" class="text-decoration-none ${fd === 'today' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_date" data-val="today">Today</a>
                      <a href="#" class="text-decoration-none ${fd === 'week' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_date" data-val="week">This week</a>
                      <a href="#" class="text-decoration-none ${fd === 'month' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_date" data-val="month">This month</a>
                      <a href="#" class="text-decoration-none ${fd === 'year' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_date" data-val="year">This year</a>
                    </div>
                    <div class="d-flex flex-column gap-2" style="min-width: 200px;">
                      <h6 class="border-bottom border-secondary pb-2 mb-1 fw-bold text-secondary">CUSTOM DATE RANGE</h6>
                      <div class="d-flex flex-column gap-2">
                        <div>
                          <label class="form-label text-secondary small mb-1">Start Date</label>
                          <input type="date" id="filter-start-date" class="form-control form-control-sm bg-black text-white border-secondary" value="${fsd}">
                        </div>
                        <div>
                          <label class="form-label text-secondary small mb-1">End Date</label>
                          <input type="date" id="filter-end-date" class="form-control form-control-sm bg-black text-white border-secondary" value="${fed}">
                        </div>
                        <div class="d-flex gap-2 mt-1">
                          <button class="btn btn-sm btn-danger fw-bold flex-grow-1" id="apply-date-range-btn">Apply Range</button>
                          <button class="btn btn-sm btn-outline-secondary" id="clear-date-range-btn" title="Clear Range"><i class="bi bi-x-lg"></i></button>
                        </div>
                      </div>
                    </div>
                    <div class="d-flex flex-column gap-2">
                      <h6 class="border-bottom border-secondary pb-2 mb-1 fw-bold text-secondary">DURATION</h6>
                      <a href="#" class="text-decoration-none ${fdu === '' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_dur" data-val="">Any</a>
                      <a href="#" class="text-decoration-none ${fdu === 'short' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_dur" data-val="short">Under 4 minutes</a>
                      <a href="#" class="text-decoration-none ${fdu === 'long' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_dur" data-val="long">Over 20 minutes</a>
                    </div>
                    <div class="d-flex flex-column gap-2">
                      <h6 class="border-bottom border-secondary pb-2 mb-1 fw-bold text-secondary">SORT BY</h6>
                      <a href="#" class="text-decoration-none ${fs === 'relevance' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_sort" data-val="relevance">Relevance</a>
                      <a href="#" class="text-decoration-none ${fs === 'date' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_sort" data-val="date">Upload date</a>
                      <a href="#" class="text-decoration-none ${fs === 'views' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_sort" data-val="views">View count</a>
                      <a href="#" class="text-decoration-none ${fs === 'likes' ? 'text-white fw-bold' : 'text-secondary hover-white'} filter-opt" data-filter="f_sort" data-val="likes">Rating (Songs only)</a>
                    </div>
                  </div>
                </div>
              </div>
            `;
            // Insert filters at the very top of content area
            contentArea.insertAdjacentHTML('afterbegin', filterHTML);
            
            document.querySelectorAll('.filter-opt').forEach(opt => {
              opt.addEventListener('click', (e) => {
                e.preventDefault();
                const key = opt.dataset.filter;
                const val = opt.dataset.val;
                currentView[key] = val;
                if (key === 'f_date') {
                  delete currentView.f_start_date;
                  delete currentView.f_end_date;
                }
                
                const collapseEl = document.getElementById('searchFiltersCollapse');
                const isExpanded = collapseEl && collapseEl.classList.contains('show');
                
                loadView(currentView);
                
                if (isExpanded) {
                  setTimeout(() => {
                    const newCollapse = document.getElementById('searchFiltersCollapse');
                    if (newCollapse) newCollapse.classList.add('show');
                  }, 300);
                }
              });
            });

            document.getElementById('apply-date-range-btn')?.addEventListener('click', () => {
              const startVal = document.getElementById('filter-start-date').value;
              const endVal = document.getElementById('filter-end-date').value;
              
              if (!startVal && !endVal) {
                return showToast('Please select a start or end date.', 'warning');
              }
              
              currentView.f_start_date = startVal;
              currentView.f_end_date = endVal;
              currentView.f_date = ''; // Clear preset date selection
              
              const collapseEl = document.getElementById('searchFiltersCollapse');
              const isExpanded = collapseEl && collapseEl.classList.contains('show');
              
              loadView(currentView);
              
              if (isExpanded) {
                setTimeout(() => {
                  const newCollapse = document.getElementById('searchFiltersCollapse');
                  if (newCollapse) newCollapse.classList.add('show');
                }, 300);
              }
            });

            document.getElementById('clear-date-range-btn')?.addEventListener('click', () => {
              delete currentView.f_start_date;
              delete currentView.f_end_date;
              
              const collapseEl = document.getElementById('searchFiltersCollapse');
              const isExpanded = collapseEl && collapseEl.classList.contains('show');
              
              loadView(currentView);
              
              if (isExpanded) {
                setTimeout(() => {
                  const newCollapse = document.getElementById('searchFiltersCollapse');
                  if (newCollapse) newCollapse.classList.add('show');
                }, 300);
              }
            });
          }

          if (!data || !data.shelves || data.shelves.length === 0) {
            contentArea.insertAdjacentHTML('beforeend', `<div class="text-center p-5 text-secondary">No results found.</div>`);
            return;
          }

          data.shelves.forEach(shelf => {
            let itemsHTML = '';

            if (shelf.type === 'top_result') {
              const song = shelf.items[0];
              const coverSvg = getSvgPlaceholder(song.title || 'Unknown');
              const shelfHTML = `
                <div class="recommendation-shelf mb-4">
                  <div class="shelf-header">
                    <h3 class="shelf-title">${shelf.title}</h3>
                  </div>
                  <div class="card bg-transparent border-secondary d-flex flex-row align-items-center p-3 top-result-card" data-song-id="${song.id}" style="border-radius: 12px; cursor: pointer; max-width: 600px; transition: background 0.2s;" onmouseover="this.style.backgroundColor='var(--ytm-surface-2)'" onmouseout="this.style.backgroundColor='transparent'">
                    <img src="?action=get_image&id=${song.id}&v=${song.last_modified || 0}&size=small" onerror="this.onerror=null; this.src='${coverSvg}';" style="width: 100px; height: 100px; object-fit: cover; border-radius: 8px; margin-right: 1.5rem; box-shadow: 0 4px 10px rgba(0,0,0,0.5);">
                    <div class="d-flex flex-column justify-content-center overflow-hidden w-100">
                      <h4 class="text-white text-truncate mb-1 fw-bold">${escapeHTML(song.title)}</h4>
                      <p class="text-secondary text-truncate mb-0">Song • ${escapeHTML(song.artist)}</p>
                    </div>
                    <button class="btn btn-danger rounded-circle ms-auto me-2 d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; flex-shrink: 0;"><i class="bi bi-play-fill fs-3"></i></button>
                  </div>
                </div>
              `;
              contentArea.insertAdjacentHTML('beforeend', shelfHTML);
              return;
            }
            
            if (shelf.type === 'songs_list') {
              const shelfHTML = `
                <div class="recommendation-shelf mb-4">
                  <div class="shelf-header">
                    <h3 class="shelf-title">${shelf.title}</h3>
                  </div>
                  <div id="search-songs-pane"></div>
                </div>
              `;
              contentArea.insertAdjacentHTML('beforeend', shelfHTML);
              const targetPane = document.getElementById('search-songs-pane');

              let songList = document.createElement('div');
              songList.className = 'song-list';
              const header = `<div class="song-list-header d-none d-md-grid" style="grid-template-columns: 40px minmax(0, 4fr) minmax(0, 3fr) minmax(0, 3fr) minmax(0, 2fr) 80px 40px;">
                <div></div><div>Title</div><div>Artist</div><div>Album</div><div>Views</div><div>Time</div><div></div>
              </div>`;
              targetPane.insertAdjacentHTML('beforeend', header);
              
              const escapeAttr = (str) => str ? String(str).replace(/'/g, "&apos;").replace(/"/g, "&quot;") : '';
              const songsHTML = shelf.items.map(song => {
                const isNowPlaying = currentSong && currentSong.id === song.id;
                const coverSvg = getSvgPlaceholder(song.title || 'Unknown');
                return `
                <div class="song-item py-md-3 ${isNowPlaying ? 'now-playing' : ''}" 
                  data-song-id="${song.id}" 
                  data-is-favorite="${song.is_favorite == 1 ? '1' : '0'}"
                  data-is-collaborative="${song.is_collaborative == 1 ? '1' : '0'}"
                  data-song-title="${escapeAttr(song.title)}"
                  data-song-artist="${escapeAttr(song.artist)}"
                  data-song-album="${escapeAttr(song.album)}"
                  data-song-genre="${escapeAttr(song.genre)}"
                  data-song-user-id="${song.user_id}">
                  <div class="song-indicator-wrapper d-flex align-items-center justify-content-center">
                    <img src="?action=get_image&id=${song.id}&v=${song.last_modified || 0}" onerror="this.src='${coverSvg}'" class="song-thumb" loading="lazy" alt="${escapeAttr(song.title)}">
                    <i class="bi bi-soundwave playing-icon"></i>
                  </div>
                  <div class="song-title-wrapper text-truncate"><div class="song-title text-truncate">${song.is_private == 1 ? '<i class="bi bi-lock-fill text-warning me-1" title="Private Song"></i>' : ''}${song.title}</div></div>
                  <div class="song-artist text-truncate" data-artist="${encodeURIComponent(song.artist)}" data-userid="${song.user_id}">
                    <div class="text-truncate">${song.artist}</div>
                    <div class="text-secondary d-md-none" style="font-size: 0.8rem; margin-top: 2px;" title="Play Count"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                  </div>
                  <div class="song-album text-truncate" data-album="${encodeURIComponent(song.album)}" data-userid="${song.user_id}">${song.album}</div>
                  <div class="song-views d-none d-md-block text-truncate" title="${song.play_count || 0} views">${formatSongCount(song.play_count || 0)}</div>
                  <div class="song-duration d-none d-md-block">${formatTime(song.duration)}</div>
                  <div class="song-more">
                    <button class="more-btn" data-song-id="${song.id}">
                      <i class="bi bi-three-dots-vertical"></i>
                    </button>
                  </div>
                  <div class="song-artist-mobile w-100 flex-column align-items-start">
                    <div class="d-flex justify-content-between align-items-center w-100">
                       <span class="song-artist-name text-truncate flex-grow-1" style="min-width: 0;">${song.artist}</span>
                       <span class="song-duration-mobile flex-shrink-0">${formatTime(song.duration)}</span>
                    </div>
                    <div class="text-secondary text-start" style="font-size: 0.8rem; margin-top: 2px;"><i class="bi bi-eye"></i> ${formatSongCount(song.play_count || 0)}</div>
                  </div>
                </div>
              `}).join('');
              songList.insertAdjacentHTML('beforeend', songsHTML);
              targetPane.appendChild(songList);
              return;
            }

            if (shelf.type === 'songs') {
              itemsHTML = shelf.items.map(song => {
                const coverSvg = getSvgPlaceholder(song.title || 'Unknown');
                return `
                <div class="shelf-item position-relative" 
                  data-song-id="${song.id}" 
                  data-is-favorite="${song.is_favorite == 1 ? '1' : '0'}"
                  data-is-collaborative="${song.is_collaborative == 1 ? '1' : '0'}"
                  data-song-title="${escapeAttr(song.title)}"
                  data-song-artist="${escapeAttr(song.artist)}"
                  data-song-album="${escapeAttr(song.album)}"
                  data-song-genre="${escapeAttr(song.genre)}"
                  data-song-user-id="${song.user_id}">
                  <button class="playlist-more-btn more-btn" data-song-id="${song.id}"><i class="bi bi-three-dots-vertical"></i></button>
                  <img src="?action=get_image&id=${song.id}&v=${song.last_modified || 0}&size=small" onerror="this.onerror=null; this.src='${coverSvg}';" alt="${escapeHTML(song.title)}">
                  <div class="item-title">${escapeHTML(song.title)}</div>
                  <div class="item-subtitle" data-artist="${encodeURIComponent(song.artist)}" data-userid="${song.user_id}">${escapeHTML(song.artist)}</div>
                </div>
              `}).join('');
            } else if (shelf.type === 'albums') {
              itemsHTML = shelf.items.map(album => `
                <div class="shelf-item position-relative" data-album="${encodeURIComponent(album.album)}" data-userid="${album.user_id || ''}" data-artistname="${encodeURIComponent(album.artist || '')}">
                  <button class="playlist-more-btn album-more-btn" data-album="${encodeURIComponent(album.album)}" data-userid="${album.user_id || ''}" data-artistname="${encodeURIComponent(album.artist || '')}" data-id="${album.id || 0}"><i class="bi bi-three-dots-vertical"></i></button>
                  <div style="position: relative; display: block; margin-bottom: 0.5rem; border-radius: 6px; overflow: hidden;">
                    <img src="?action=get_image&id=${album.id || 0}&v=${album.image_v || 0}&size=small" alt="${escapeHTML(album.album)}" style="margin-bottom: 0 !important; border-radius: 0 !important;">
                    ${album.song_count !== undefined ? `<div class="position-absolute bottom-0 start-0 ms-1 mb-1 px-2 py-1 bg-dark bg-opacity-75 text-white rounded fw-bold" style="font-size: 0.7rem; backdrop-filter: blur(4px); line-height: 1;"><i class="bi bi-music-note-list"></i> ${formatSongCount(album.song_count)}</div>` : ''}
                  </div>
                  <div class="item-title">${escapeHTML(album.album)}</div>
                  <div class="item-subtitle">${escapeHTML(album.artist)}</div>
                  ${album.total_plays !== undefined ? `<div class="item-subtitle mt-1" style="font-size: 0.75rem;"><i class="bi bi-eye"></i> ${formatSongCount(album.total_plays)} views</div>` : ''}
                </div>
              `).join('');
            } else if (shelf.type === 'playlists' || shelf.type === 'mixes') {
              itemsHTML = shelf.items.map(playlist => `
                <div class="shelf-item position-relative" data-${shelf.type === 'mixes' ? 'mix' : 'playlist'}="${encodeURIComponent(playlist.public_id)}">
                  <button class="playlist-more-btn mix-more-btn" data-type="${shelf.type}" data-public-id="${playlist.public_id}" data-name="${escapeHTML(playlist.name)}" data-creator="${escapeHTML(playlist.creator)}" data-image-id="${playlist.image_id || 0}"><i class="bi bi-three-dots-vertical"></i></button>
                  <div style="position: relative; display: block; margin-bottom: 0.5rem; border-radius: 6px; overflow: hidden;">
                    <img src="?action=get_image&id=${playlist.image_id || 0}&v=${playlist.image_v || 0}&size=small" alt="${escapeHTML(playlist.name)}" style="margin-bottom: 0 !important; border-radius: 0 !important;">
                    ${playlist.song_count !== undefined ? `<div class="position-absolute bottom-0 start-0 ms-1 mb-1 px-2 py-1 bg-dark bg-opacity-75 text-white rounded fw-bold" style="font-size: 0.7rem; backdrop-filter: blur(4px); line-height: 1;"><i class="bi bi-music-note-list"></i> ${formatSongCount(playlist.song_count)}</div>` : ''}
                  </div>
                  <div class="item-title">${escapeHTML(playlist.name)}</div>
                  <div class="item-subtitle">by ${escapeHTML(playlist.creator)}</div>
                  ${playlist.play_count !== undefined ? `<div class="item-subtitle mt-1" style="font-size: 0.75rem;"><i class="bi bi-eye"></i> ${formatSongCount(playlist.play_count)} views</div>` : ''}
                </div>
              `).join('');
            } else if (shelf.type === 'artists') {
              itemsHTML = shelf.items.map(artist => `
                <div class="shelf-item text-center" data-artist="${encodeURIComponent(artist.name)}" data-userid="${artist.is_user ? artist.id : ''}">
                  <img src="${artist.is_user ? `?action=get_profile_picture&id=${artist.id}` : `?action=get_image&id=${artist.id || 0}&v=${artist.image_v || 0}`}" class="rounded-circle" alt="${escapeHTML(artist.name)}" style="aspect-ratio: 1/1; object-fit: cover;">
                  <div class="item-title mt-2">${escapeHTML(artist.name)}</div>
                  <div class="item-subtitle text-uppercase small text-secondary">Artist</div>
                </div>
              `).join('');
            }

            const shelfHTML = `
              <div class="recommendation-shelf">
                <div class="shelf-header">
                  <h3 class="shelf-title">${shelf.title}</h3>
                  ${shelf.connected_view ? `<button class="btn btn-sm btn-outline-light border-0" data-view="${shelf.connected_view}" ${shelf.param ? `data-view-param="${shelf.param}"` : ''}>See All</button>` : ''}
                </div>
                <div class="shelf-items">
                  ${itemsHTML}
                </div>
              </div>
            `;
            contentArea.insertAdjacentHTML('beforeend', shelfHTML);
          });
        };

        const renderUserStats = (data) => {
          contentArea.innerHTML = `
            <div class="user-stats-page px-3 py-4">
              <div class="d-flex align-items-center justify-content-center gap-3 mb-4 border-bottom border-secondary pb-4">
                <i class="bi bi-bar-chart-line-fill text-info" style="font-size: 3rem;"></i>
                <div class="text-start">
                  <h2 class="content-title text-white fw-bold mb-0">My Statistics</h2>
                  <p class="text-secondary mb-0">Your overall engagement across PHP Music</p>
                </div>
              </div>
              <div class="row g-4 mt-2">
                <div class="col-6 col-md-3">
                  <div class="card bg-dark border-secondary h-100 shadow-lg" style="border-radius: 16px; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-5px)'" onmouseout="this.style.transform='translateY(0)'">
                    <div class="card-body text-center p-4">
                      <div class="rounded-circle d-flex align-items-center justify-content-center mx-auto mb-3" style="width: 60px; height: 60px; background-color: rgba(13, 110, 253, 0.1);">
                        <i class="bi bi-cloud-upload-fill text-primary fs-3"></i>
                      </div>
                      <h3 class="fw-bold text-white mb-1" style="font-size: 2.5rem;">${formatSongCount(data.stats.uploads)}</h3>
                      <p class="text-secondary text-uppercase fw-bold small mb-0" style="letter-spacing: 1px;">Uploads</p>
                    </div>
                  </div>
                </div>
                <div class="col-6 col-md-3">
                  <div class="card bg-dark border-secondary h-100 shadow-lg" style="border-radius: 16px; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-5px)'" onmouseout="this.style.transform='translateY(0)'">
                    <div class="card-body text-center p-4">
                      <div class="rounded-circle d-flex align-items-center justify-content-center mx-auto mb-3" style="width: 60px; height: 60px; background-color: rgba(220, 53, 69, 0.1);">
                        <i class="bi bi-heart-fill text-danger fs-3"></i>
                      </div>
                      <h3 class="fw-bold text-white mb-1" style="font-size: 2.5rem;">${formatSongCount(data.stats.favorites)}</h3>
                      <p class="text-secondary text-uppercase fw-bold small mb-0" style="letter-spacing: 1px;">Favorites</p>
                    </div>
                  </div>
                </div>
                <div class="col-6 col-md-3">
                  <div class="card bg-dark border-secondary h-100 shadow-lg" style="border-radius: 16px; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-5px)'" onmouseout="this.style.transform='translateY(0)'">
                    <div class="card-body text-center p-4">
                      <div class="rounded-circle d-flex align-items-center justify-content-center mx-auto mb-3" style="width: 60px; height: 60px; background-color: rgba(25, 135, 84, 0.1);">
                        <i class="bi bi-music-note-list text-success fs-3"></i>
                      </div>
                      <h3 class="fw-bold text-white mb-1" style="font-size: 2.5rem;">${formatSongCount(data.stats.playlists)}</h3>
                      <p class="text-secondary text-uppercase fw-bold small mb-0" style="letter-spacing: 1px;">Playlists</p>
                    </div>
                  </div>
                </div>
                <div class="col-6 col-md-3">
                  <div class="card bg-dark border-secondary h-100 shadow-lg" style="border-radius: 16px; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-5px)'" onmouseout="this.style.transform='translateY(0)'">
                    <div class="card-body text-center p-4">
                      <div class="rounded-circle d-flex align-items-center justify-content-center mx-auto mb-3" style="width: 60px; height: 60px; background-color: rgba(255, 193, 7, 0.1);">
                        <i class="bi bi-play-circle-fill text-warning fs-3"></i>
                      </div>
                      <h3 class="fw-bold text-white mb-1" style="font-size: 2.5rem;">${formatSongCount(data.stats.play_count)}</h3>
                      <p class="text-secondary text-uppercase fw-bold small mb-0" style="letter-spacing: 1px;">Total Plays</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          `;
        };
        
        const setupSortOptions = (viewType) => {
          const isSortable = ['get_favorites', 'get_listen_later', 'get_notes', 'get_blogs', 'get_community', 'get_offline_songs', 'artist_songs', 'album_songs', 'genre_songs', 'year_songs', 'user_profile', 'playlist_songs', 'get_history', 'get_albums', 'get_artists', 'get_user_playlists', 'get_collab_playlists', 'get_my_apis', 'get_following'].includes(viewType);
          
          if (isSortable) {
            let options = {};
            
            switch(viewType) {
              case 'genre_songs':
              case 'year_songs':
                options = {
                  'id_desc': 'Recently Added', 'artist_asc': 'Artist', 'title_asc': 'Title', 'album_asc': 'Album',
                  'year_desc': 'Year (Newest)', 'year_asc': 'Year (Oldest)'
                };
                break;
              case 'artist_songs':
                 options = { 'album_asc': 'Album', 'title_asc': 'Title', 'year_desc': 'Year (Newest)', 'year_asc': 'Year (Oldest)'};
                 break;
              case 'album_songs':
                 options = { 'title_asc': 'Title', 'year_desc': 'Year (Newest)', 'year_asc': 'Year (Oldest)'};
                 break;
              case 'user_profile':
                  options = { 'id_desc': 'Recently Added', 'artist_asc': 'Artist', 'title_asc': 'Title', 'album_asc': 'Album',
                  'year_desc': 'Year (Newest)', 'year_asc': 'Year (Oldest)'};
                  break;
              case 'get_favorites':
              case 'get_listen_later':
              case 'get_offline_songs':
              case 'playlist_songs':
                options = { 
                  'manual_order': 'My Order', 'added_newest': 'Added Newest', 'added_oldest': 'Added Oldest',
                  'artist_asc': 'Artist', 'title_asc': 'Title', 'album_asc': 'Album'
                };
                break;
              case 'get_history':
                options = { 
                  'history_desc': 'Recently Played', 'history_asc': 'Oldest Played',
                  'artist_asc': 'Artist', 'title_asc': 'Title', 'album_asc': 'Album'
                };
                break;
              case 'get_notes':
              case 'get_blogs':
                options = { 'newest': 'Newest', 'oldest': 'Oldest', 'modified': 'Recently Modified' };
                break;
              case 'get_community':
                options = { 'newest': 'Newest', 'most_liked': 'Most Liked', 'following': 'Following Users' };
                break;
              case 'get_albums':
                options = {
                  'album_asc': 'Title (A-Z)', 'album_desc': 'Title (Z-A)', 
                  'artist_asc': 'Artist (A-Z)', 'artist_desc': 'Artist (Z-A)',
                  'year_desc': 'Year (Newest)', 'year_asc': 'Year (Oldest)'
                };
                break;
              case 'get_artists':
                options = { 'name_asc': 'Name (A-Z)', 'name_desc': 'Name (Z-A)' };
                break;
              case 'get_mixes':
                options = {
                  'newest': 'Newest', 'oldest': 'Oldest',
                  'name_asc': 'Name (A-Z)', 'name_desc': 'Name (Z-A)'
                };
                break;
              case 'get_user_playlists':
              case 'get_collab_playlists':
                options = {
                  'name_asc': 'Name (A-Z)', 'name_desc': 'Name (Z-A)',
                  'modified_desc': 'Date Modified (Newest)', 'modified_asc': 'Date Modified (Oldest)'
                };
                break;
              case 'get_following':
                options = {
                  'newest': 'Recently Followed', 'oldest': 'Oldest Followed', 'name_asc': 'Name (A-Z)', 'name_desc': 'Name (Z-A)'
                };
                break;
              case 'get_my_apis':
                options = { 'newest': 'Newest', 'oldest': 'Oldest', 'modified': 'Recently Modified' };
                break;
            }

            sortSelect.innerHTML = Object.entries(options).map(([value, text]) => `<option value="${value}" ${currentView.sort === value ? 'selected' : ''}>${text}</option>`).join('');
            sortControls.classList.remove('d-none');
          } else {
            sortControls.classList.add('d-none');
          }

          if (viewType === 'get_history') {
            historyControls.classList.remove('d-none');
          } else {
            historyControls.classList.add('d-none');
          }
        };

        const loadMoreContent = async () => {
          if (isLoadingMore || allContentloaded || currentView.type === 'search') return;
          if (!currentUser && (currentView.type === 'get_favorites' || currentView.type === 'get_offline_songs' || currentView.type === 'get_history' || currentView.type === 'get_following')) return;
          
          isLoadingMore = true;
          showLoader(false);
          
          currentPage++;
          if (currentView.type === 'get_trending' && currentPage > 4) {
            allContentloaded = true;
            isLoadingMore = false;
            hideLoader();
            return;
          }
          let data;
          const { type, param, sort, filter_user_id, artist_name } = currentView;

          const params = new URLSearchParams({ page: currentPage, sort: sort });
          if (filter_user_id) {
            params.append('filter_user_id', filter_user_id);
          }
          if (artist_name) {
            params.append('artist_name', artist_name);
          }
          if (currentView.searchQuery) params.append('q', currentView.searchQuery);
          if (currentView.filter) params.append('filter', currentView.filter);

          switch (type) {
            case 'get_songs':
            case 'get_favorites':
            case 'get_listen_later':
            case 'get_history':
            case 'get_trending':
              data = await fetchData(`?action=${type}&${params.toString()}`);
              renderSongs(data, true);
              break;
            case 'get_offline_songs':
              if (offlineViewSongsData && offlineViewSongsData.length > 0) {
                 const startIndex = (currentPage - 1) * PAGE_SIZE;
                 const endIndex = startIndex + PAGE_SIZE;
                 data = offlineViewSongsData.slice(startIndex, endIndex);
                 if (data.length > 0) {
                   renderSongs(data, true);
                 }
                 if (endIndex >= offlineViewSongsData.length) {
                   allContentloaded = true;
                 }
              } else {
                 data = [];
                 allContentloaded = true;
              }
              break;
            case 'user_profile':
              const profileData = await fetchData(`?action=get_view_data&type=profile&sort=${sort}&page=${currentPage}`);
              if (profileData && profileData.songs) {
                renderSongs(profileData.songs, true);
                data = profileData.songs;
              }
              break;
            case 'artist_songs':
            case 'album_songs':
            case 'genre_songs':
            case 'year_songs':
              const filterType = type.split('_')[0];
              const viewData = await fetchData(`?action=get_view_data&type=${filterType}&name=${param}&${params.toString()}`);
              if (viewData && viewData.songs) {
                renderSongs(viewData.songs, true);
                data = viewData.songs;
              }
              break;
            case 'playlist_songs':
              params.delete('sort');
              const playlistData = await fetchData(`?action=get_view_data&type=playlist&name=${param}&sort=${sort}&page=${currentPage}`);
              if (playlistData && playlistData.songs) {
                renderSongs(playlistData.songs, true);
                data = playlistData.songs;
              }
              break;
            case 'get_categories':
            case 'get_albums':
            case 'get_artists':
            case 'get_genres':
            case 'get_years':
            case 'get_mixes':
            case 'get_user_playlists':
            case 'get_collab_playlists':
            case 'get_following':
            case 'get_projects':
              data = await fetchData(`?action=${type}&${params.toString()}`);
              renderGrid(data, type, true);
              break;
            case 'get_my_apis':
              data = await fetchData(`?action=${type}&${params.toString()}`);
              if (data && data.length > 0) {
                document.getElementById('apis-list-container').insertAdjacentHTML('beforeend', data.map(api => `
                  <div class="card bg-dark border-secondary text-white p-3 shadow-sm hover-bg-dark" style="border-radius: 12px;">
                    <div class="d-flex justify-content-between align-items-center mb-3">
                      <h5 class="fw-bold m-0"><i class="bi bi-terminal text-info me-2"></i>${escapeHTML(api.name)}</h5>
                      <button class="btn btn-sm btn-outline-danger delete-api-btn" data-id="${api.id}"><i class="bi bi-trash"></i></button>
                    </div>
                    <div class="d-flex flex-column gap-2 small text-secondary">
                      <div><strong>Status:</strong> <span class="badge ${api.status === 'active' ? 'bg-success' : (api.status === 'pending' ? 'bg-info text-dark' : 'bg-danger')}">${api.status.toUpperCase()}</span></div>
                      <div><strong>Token:</strong> ${api.status === 'pending' ? '<code class="text-info fs-6">Waiting for Admin Verification...</code>' : `<code class="text-info fs-6">${escapeHTML(api.token)}</code><button class="btn btn-sm btn-outline-info py-0 px-2 ms-2 copy-api-token-btn" data-token="${escapeHTML(api.token)}" title="Copy Key"><i class="bi bi-clipboard"></i></button>`}</div>
                      <div><strong>Uses:</strong> ${api.uses} / 1000 this month</div>
                      <div><strong>Expires:</strong> ${api.expires_at ? new Date(api.expires_at.replace(' ', 'T')+'Z').toLocaleDateString() : 'Never'}</div>
                    </div>
                  </div>
                `).join(''));
                
                document.querySelectorAll('.delete-api-btn').forEach(btn => {
                  btn.replaceWith(btn.cloneNode(true));
                });
                document.querySelectorAll('.delete-api-btn').forEach(btn => {
                  btn.addEventListener('click', async () => {
                    if (confirm('Are you sure you want to delete this API key permanently? Any apps using it will break.')) {
                      const res = await fetchData('?action=delete_my_api', { method: 'POST', body: JSON.stringify({ id: btn.dataset.id }) });
                      if (res && res.status === 'success') {
                        showToast('API Key deleted.', 'success');
                        loadView(currentView);
                      }
                    }
                  });
                });
              }
              break;
            case 'get_notes':
              data = await fetchData(`?action=get_notes&${params.toString()}`);
              if (data && data.length > 0) {
                 const grid = document.getElementById('notes-grid');
                 if (grid) {
                   const html = data.map(n => {
                    const decodedTitle = decodeHTML(n.title || '');
                    const decodedContent = decodeHTML(n.content || '');
                    const cleanContent = decodedContent.replace(/<[^>]*>?/gm, '');
                    const catName = window.getCategoryName(n.category);
                    return `
                      <div class="note-card note-card-item" data-id="${n.id}">
                        ${n.starred == 1 ? '<button class="card-star-btn starred"><i class="bi bi-star-fill text-warning"></i></button>' : '<button class="card-star-btn"><i class="bi bi-star"></i></button>'}
                        <div class="note-card-title">${escapeHTML(decodedTitle || cleanContent.split(/\s+/).slice(0, 5).join(' ') || 'Untitled Note')}</div>
                        <div class="note-card-body">${escapeHTML(cleanContent)}</div>
                        <div class="note-card-footer">
                          <span>${new Date(n.updated_at.replace(' ', 'T') + 'Z').toLocaleDateString()}</span>
                          ${n.category && n.category !== 'all' ? `<span class="note-chip">${escapeHTML(catName)}</span>` : ''}
                        </div>
                      </div>
                    `;
                   }).join('');
                   grid.insertAdjacentHTML('beforeend', html);
                   window.currentNotesList = window.currentNotesList.concat(data);
                   if (typeof window.bindNoteCardEvents === 'function') window.bindNoteCardEvents(grid);
                 }
              }
              break;
            case 'get_tasks':
              data = await fetchData(`?action=get_tasks&${params.toString()}`);
              if (data && data.length > 0) {
                 const grid = document.getElementById('tasks-grid');
                 if (grid) {
                   const html = data.map(t => {
                    let items = [];
                    try { items = JSON.parse(t.items); } catch(e) {}
                    const catName = window.getCategoryName(t.category);
                    const itemsHtml = items.slice(0, 4).map(item => `
                      <div class="task-card-item ${item.completed ? 'completed' : ''}">
                        <i class="bi ${item.completed ? 'bi-check-square-fill text-success' : 'bi-square'}"></i>
                        <span style="word-break: break-word;">${escapeHTML(item.text)}</span>
                      </div>
                    `).join('') + (items.length > 4 ? `<div class="text-secondary small mt-1">+${items.length - 4} more</div>` : '');

                    return `
                      <div class="note-card task-card-wrapper" data-id="${t.id}">
                        ${t.starred == 1 ? '<button class="card-star-btn starred"><i class="bi bi-star-fill text-warning"></i></button>' : '<button class="card-star-btn"><i class="bi bi-star"></i></button>'}
                        <div class="note-card-title">${escapeHTML(decodeHTML(t.title) || 'Untitled Task List')}</div>
                        <div class="flex-grow-1 overflow-hidden mt-2">${itemsHtml}</div>
                        <div class="note-card-footer mt-3">
                          <span>${new Date(t.updated_at.replace(' ', 'T') + 'Z').toLocaleDateString()}</span>
                          ${t.category && t.category !== 'all' ? `<span class="note-chip">${escapeHTML(catName)}</span>` : ''}
                        </div>
                      </div>
                    `;
                   }).join('');
                   grid.insertAdjacentHTML('beforeend', html);
                   window.currentTasksList = window.currentTasksList.concat(data);
                   if (typeof window.bindNoteCardEvents === 'function') window.bindNoteCardEvents(grid, true);
                 }
              }
              break;
            case 'get_blogs':
              data = await fetchData(`?action=get_blogs&${params.toString()}`);
              if (data && data.length > 0) {
                const grid = document.getElementById('blogs-grid');
                if (grid) {
                  const html = data.map(b => `
                    <div class="note-card bg-dark text-white border-secondary hover-bg-dark blog-card-owner" data-id="${b.public_id}" style="border-radius: 12px; cursor: pointer; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-4px)'" onmouseout="this.style.transform='translateY(0)'">
                      <div class="d-flex justify-content-between align-items-center mb-2">
                        <span class="badge ${b.status === 'public' ? 'bg-success' : 'bg-secondary'}">${b.status === 'public' ? 'Published' : 'Draft/Private'}</span>
                        <span class="small text-secondary">${new Date(b.updated_at.replace(' ', 'T')+'Z').toLocaleDateString()}</span>
                      </div>
                      <div class="fw-bold fs-5 mb-2 text-truncate">${escapeHTML((b.title && b.title.trim() !== '') ? decodeHTML(b.title) : 'Untitled')}</div>
                      <div class="text-secondary small overflow-hidden" style="display: -webkit-box; -webkit-line-clamp: 4; -webkit-box-orient: vertical;">${escapeHTML(decodeHTML(b.content).replace(/<[^>]*>?/gm, '').replace(/[^a-zA-Z0-9\s.,!?]/g, ''))}</div>
                      <div class="mt-auto pt-3 d-flex justify-content-between align-items-center">
                        ${b.category && b.category !== 'all' ? `<span class="note-chip">${escapeHTML(window.getCategoryName(b.category, 'blog'))}</span>` : '<span></span>'}
                      </div>
                    </div>
                  `).join('');
                  grid.insertAdjacentHTML('beforeend', html);
                  window.currentBlogsList = window.currentBlogsList.concat(data);
                  if (typeof window.bindBlogCardEvents === 'function') window.bindBlogCardEvents(grid);
                }
              }
              break;
            case 'get_community':
              data = await fetchData(`?action=get_community&${params.toString()}`);
              if (data && data.length > 0) {
                  const feed = document.getElementById('community-feed');
                  if (feed) {
                    feed.insertAdjacentHTML('beforeend', data.map(p => `
                    <div class="card bg-transparent border-secondary text-white">
                      <div class="card-body">
                        <div class="d-flex justify-content-between align-items-start mb-3">
                          <div class="d-flex align-items-center gap-3 ${p.is_disabled ? '' : 'user-profile-link'}" data-userid="${p.user_id}" data-artist="${encodeURIComponent(p.artist)}" style="${p.is_disabled ? 'cursor: default;' : 'cursor: pointer;'}" ${p.is_disabled ? '' : 'title="View Profile"'}>
                            <img src="?action=get_profile_picture&id=${p.user_id}" style="width:40px; height:40px; border-radius:50%; object-fit:cover;">
                            <div>
                              <div class="fw-bold hover-underline">${escapeHTML(p.artist)}</div>
                              <small class="text-secondary">${timeAgo(p.created_at)}</small>
                            </div>
                          </div>
                          ${(currentUser && (currentUser.id == p.user_id || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `
                          <div>
                            <button class="btn btn-sm btn-outline-light me-1 edit-post-btn" data-id="${p.id}" data-content="${escapeHTML(p.content)}"><i class="bi bi-pencil"></i></button>
                            <button class="btn btn-sm btn-outline-danger delete-post-btn" data-id="${p.id}"><i class="bi bi-trash"></i></button>
                          </div>` : ''}
                        </div>
                        <p class="mb-3" style="font-size: 1.05rem;">${escapeHTML(p.content)}</p>
                        <div class="d-flex gap-3">
                          <button class="btn btn-sm border-0 px-0 d-flex align-items-center gap-2 ${p.my_reaction === 'like' ? 'text-info' : 'text-secondary'} community-react-btn" data-id="${p.id}" data-reaction="like">
                            <i class="bi ${p.my_reaction === 'like' ? 'bi-hand-thumbs-up-fill' : 'bi-hand-thumbs-up'} fs-5"></i> <span>${p.like_count}</span>
                          </button>
                          <button class="btn btn-sm border-0 px-0 d-flex align-items-center gap-2 ${p.my_reaction === 'dislike' ? 'text-danger' : 'text-secondary'} community-react-btn" data-id="${p.id}" data-reaction="dislike">
                            <i class="bi ${p.my_reaction === 'dislike' ? 'bi-hand-thumbs-down-fill' : 'bi-hand-thumbs-down'} fs-5"></i> <span>${p.dislike_count}</span>
                          </button>
                        </div>
                      </div>
                    </div>`).join(''));
                  }
              }
              break;
            default:
              allContentloaded = true;
          }
          
          let countCheck = data ? data.length : 0;
          if (data && currentView.type === 'get_community') {
            countCheck = data.filter(i => i.parent_id == null).length; // Only count root items for infinite scroll bounds
          }
          if (!data || countCheck < PAGE_SIZE && currentView.type !== 'search') {
            allContentloaded = true;
          }

          isLoadingMore = false;
          hideLoader();
        };

        const updateActiveNavLink = (viewType) => {
          allNavLinks.forEach(l => l.classList.remove('active'));
          document.querySelectorAll('.note-filter-link').forEach(el => el.classList.remove('active', 'text-white'));
          document.querySelectorAll('.task-filter-link').forEach(el => el.classList.remove('active', 'text-white'));
          document.querySelectorAll('.cat-nav-link').forEach(el => el.classList.remove('active', 'text-white'));
          let activeLink;
          switch (viewType) {
            case 'artist_songs': activeLink = document.querySelector('.nav-link[data-view="get_artists"]'); break;
            case 'album_songs': activeLink = document.querySelector('.nav-link[data-view="get_albums"]'); break;
            case 'genre_songs': activeLink = document.querySelector('.nav-link[data-view="get_genres"]'); break;
            case 'year_songs': activeLink = document.querySelector('.nav-link[data-view="get_years"]'); break;
            case 'mix_songs': activeLink = document.querySelector('.nav-link[data-view="get_mixes"]'); break;
            case 'playlist_songs': activeLink = document.querySelector('.nav-link[data-view="get_user_playlists"]'); break;
            case 'view_blog':
            case 'get_blogs': 
              const blogFilter = currentView.filter || 'all';
              const bFilterLink = document.querySelector(`.blog-filter-link[data-view="get_blogs"][data-filter="${blogFilter}"]`) 
                              || document.querySelector(`.blog-filter-link[data-filter="${blogFilter}"]`);
              if (bFilterLink) {
                bFilterLink.classList.add('active', 'text-white');
                const collapseParent = bFilterLink.closest('.collapse');
                if (collapseParent && !collapseParent.classList.contains('show')) {
                   bootstrap.Collapse.getOrCreateInstance(collapseParent).show();
                }
              }
              activeLink = document.querySelector('a[href="#blogsSubmenu"]');
              break;
            case 'get_notes':
              const noteFilter = currentView.filter || 'all';
              const filterLink = document.querySelector(`.note-filter-link[data-view="${viewType}"][data-filter="${noteFilter}"]`) 
                              || document.querySelector(`.note-filter-link[data-filter="${noteFilter}"]`);
              if (filterLink) {
                filterLink.classList.add('active', 'text-white');
                const collapseParent = filterLink.closest('.collapse');
                if (collapseParent && !collapseParent.classList.contains('show')) {
                   bootstrap.Collapse.getOrCreateInstance(collapseParent).show();
                }
              }
              activeLink = document.querySelector('a[href="#notesSubmenu"]');
              break;
            case 'get_projects':
            case 'manage_note_categories':
            case 'get_categories':
              let navSelector = '';
              if (viewType === 'get_projects') {
                navSelector = `.filter-nav-link[data-view="${viewType}"][data-filter="${currentView.filter || 'note'}"]`;
              } else {
                navSelector = `.cat-nav-link[data-view="${viewType}"][data-cat-type="${currentView.filter || 'note'}"]`;
              }
              
              if (currentView.filter === 'task') {
                activeLink = document.querySelector('a[href="#tasksSubmenu"]');
                const subLink = document.querySelector(navSelector);
                if (subLink) {
                  subLink.classList.add('active', 'text-white');
                  const collapseParent = subLink.closest('.collapse');
                  if (collapseParent && !collapseParent.classList.contains('show')) bootstrap.Collapse.getOrCreateInstance(collapseParent).show();
                }
              } else if (currentView.filter === 'blog') {
                activeLink = document.querySelector('a[href="#blogsSubmenu"]');
                const subLink = document.querySelector(navSelector);
                if (subLink) {
                  subLink.classList.add('active', 'text-white');
                  const collapseParent = subLink.closest('.collapse');
                  if (collapseParent && !collapseParent.classList.contains('show')) bootstrap.Collapse.getOrCreateInstance(collapseParent).show();
                }
              } else {
                activeLink = document.querySelector('a[href="#notesSubmenu"]');
                const subLink = document.querySelector(navSelector);
                if (subLink) {
                  subLink.classList.add('active', 'text-white');
                  const collapseParent = subLink.closest('.collapse');
                  if (collapseParent && !collapseParent.classList.contains('show')) bootstrap.Collapse.getOrCreateInstance(collapseParent).show();
                }
              }
              break;
            case 'get_tasks':
              const taskFilter = currentView.filter || 'all';
              const tFilterLink = document.querySelector(`.task-filter-link[data-view="${viewType}"][data-filter="${taskFilter}"]`) 
                              || document.querySelector(`.task-filter-link[data-filter="${taskFilter}"]`);
              if (tFilterLink) {
                tFilterLink.classList.add('active', 'text-white');
                const collapseParent = tFilterLink.closest('.collapse');
                if (collapseParent && !collapseParent.classList.contains('show')) {
                   bootstrap.Collapse.getOrCreateInstance(collapseParent).show();
                }
              }
              activeLink = document.querySelector('a[href="#tasksSubmenu"]');
              break;
            default: activeLink = document.querySelector(`.nav-link[data-view="${viewType}"]`);
          }
          if (activeLink) {
            activeLink.classList.add('active');
          }
        };

        let viewDebounceTimer = null;
        let viewLoadCounter = 0;
        const loadView = async (viewConfig, pushHistory = true) => {
          viewLoadCounter++;
          const currentLoadId = viewLoadCounter;

          // Cleanup custom sort from profile/artist pages if navigating away
          if (viewConfig.type !== 'user_profile' && viewConfig.type !== 'artist_songs') {
            const existingCustomSort = document.getElementById('artist-custom-sort-container');
            if (existingCustomSort) existingCustomSort.remove();
            const existingCustomCat = document.getElementById('artist-custom-cat-container');
            if (existingCustomCat) existingCustomCat.remove();
          }

          // DEBOUNCE: Prevent rapid firing of database queries on fast clicks
          if (viewDebounceTimer) clearTimeout(viewDebounceTimer);
          showLoader(true);
          
          await new Promise(resolve => {
            viewDebounceTimer = setTimeout(resolve, 200);
          });
          
          if (currentLoadId !== viewLoadCounter) return;

          const edOver = document.getElementById('editorOverlay');
          const taskOver = document.getElementById('taskEditorOverlay');
          const blogOver = document.getElementById('blogEditorOverlay');

          if (notePipWin) { notePipWin.close(); notePipWin = null; }
          if (taskPipWin) { taskPipWin.close(); taskPipWin = null; }
          if (blogPipWin) { blogPipWin.close(); blogPipWin = null; }

          if (edOver && edOver.classList.contains('active')) {
            saveCurrentEditorNote(true);
            edOver.classList.remove('active');
            activeEditorNote = null;
          }
          if (taskOver && taskOver.classList.contains('active')) {
            window.saveCurrentTask(true);
            taskOver.classList.remove('active');
          }
          if (blogOver && blogOver.classList.contains('active')) {
            saveCurrentBlog(true);
            blogOver.classList.remove('active');
          }

          if (localRhythmGame) {
            localRhythmGame.destroy();
          }

          if (pushHistory) {
            const isSameView = currentView.type === viewConfig.type &&
                               currentView.param === viewConfig.param &&
                               currentView.sort === viewConfig.sort &&
                               currentView.filter_user_id === viewConfig.filter_user_id &&
                               currentView.artist_name === viewConfig.artist_name;
            if (!isSameView) {
              history.pushState({ viewConfig }, "", window.location.pathname);
            }
          }

          if (typeof virtualObserver !== 'undefined' && virtualObserver) {
            virtualObserver.disconnect();
          }

          selectedSongs.clear();
          updateMultiSelectUI();
          
          if (window.selectedNoteIds) {
            window.selectedNoteIds.clear();
            window.multiSelectNoteMode = false;
            if (typeof updateNoteSelectionUI === 'function') updateNoteSelectionUI();
          }
          if (window.selectedBlogIds) {
            window.selectedBlogIds.clear();
            window.multiSelectBlogMode = false;
            if (typeof updateBlogSelectionUI === 'function') updateBlogSelectionUI();
          }
          
          if (sortable) {
            sortable.destroy();
            sortable = null;
          }
          
          mainContent.scrollTop = 0;
          currentPage = 1;
          allContentloaded = false;
          isLoadingMore = false;
          currentViewOwnerId = null;
          showLoader();

          currentView = viewConfig;
          try {
            localStorage.setItem('ytm_lastView', JSON.stringify(currentView));
          } catch (e) {}
          updateActiveNavLink(currentView.type);
          setupSortOptions(currentView.type);

          // Check if view requires Authentication and User is logged out
          const authRequiredViews = [
            'get_inbox', 'user_profile', 'get_user_stats', 'get_offline_songs', 
            'get_favorites', 'get_listen_later', 'get_history', 'get_recommendations', 
            'get_user_playlists', 'get_collab_playlists', 'get_following', 'get_community', 
            'get_notes', 'get_tasks', 'get_blogs', 'get_categories', 
            'manage_note_categories', 'get_projects', 'get_my_apis'
          ];
          
          if (!currentUser && authRequiredViews.includes(currentView.type)) {
            setTimeout(() => {
              const authModalEl = document.getElementById('auth-required-modal');
              if (authModalEl) bootstrap.Modal.getOrCreateInstance(authModalEl).show();
            }, 100);
          }

          const pageHeaderEl = document.querySelector('.page-header');
          const mainContentEl = document.getElementById('main-content');
          if (currentView.type === 'get_inbox' || currentView.type === 'rhythm_game' || currentView.type === 'photo_editor') {
            if (pageHeaderEl) pageHeaderEl.classList.add('d-none');
            contentArea.style.padding = '0';
            contentArea.style.margin = '0';
            contentArea.style.width = '100%';
            contentArea.style.maxWidth = '100%';
            contentArea.style.height = '100%';
            contentArea.style.display = 'flex';
            contentArea.style.flexDirection = 'column';
            if (mainContentEl) {
              mainContentEl.style.height = '100%';
              mainContentEl.style.overflow = 'hidden';
              mainContentEl.style.display = 'flex';
              mainContentEl.style.flexDirection = 'column';
            }
            if (currentView.type === 'rhythm_game') {
              if (isPlaying && typeof togglePlayPause === 'function') {
                togglePlayPause();
              }
              if (playerBar) playerBar.classList.add('d-none');
              document.body.classList.remove('player-visible');
            }
          } else {
            if (pageHeaderEl) pageHeaderEl.classList.remove('d-none');
            contentArea.style.padding = '';
            contentArea.style.margin = '';
            contentArea.style.width = '';
            contentArea.style.maxWidth = '';
            contentArea.style.height = '';
            contentArea.style.display = '';
            contentArea.style.flexDirection = '';
            if (mainContentEl) {
              mainContentEl.style.height = '';
              mainContentEl.style.overflow = '';
              mainContentEl.style.display = '';
              mainContentEl.style.flexDirection = '';
            }
            if (playerBar && currentSong) {
              playerBar.classList.remove('d-none');
              document.body.classList.add('player-visible');
            }
          }
          
          let data;
          let pageParams = new URLSearchParams({ sort: currentView.sort, page: 1 });
          if (currentView.filter_user_id) pageParams.append('filter_user_id', currentView.filter_user_id);
          if (currentView.artist_name) pageParams.append('artist_name', currentView.artist_name);
          if (currentView.f_date) pageParams.append('f_date', currentView.f_date);
          if (currentView.f_dur) pageParams.append('f_dur', currentView.f_dur);
          if (currentView.f_sort) pageParams.append('f_sort', currentView.f_sort);
          if (currentView.f_start_date) pageParams.append('f_start_date', currentView.f_start_date);
          if (currentView.f_end_date) pageParams.append('f_end_date', currentView.f_end_date);
          if (currentView.filter) pageParams.append('filter', currentView.filter);
          if (currentView.refresh) {
            pageParams.append('refresh', currentView.refresh);
            delete currentView.refresh;
          }
          if (currentView.generate) {
            pageParams.append('generate', currentView.generate);
            delete currentView.generate;
          }
          
          if (!navigator.onLine && currentView.type !== 'get_offline_songs' && currentView.type !== 'rhythm_game') {
            if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
              loadView({ type: 'get_offline_songs', param: '', sort: 'manual_order', filter_user_id: '' });
              return;
            }
            updateContentTitle('Offline', false);
            contentArea.innerHTML = `
              <div class="d-flex flex-column align-items-center justify-content-center text-center p-5 w-100" style="height: 60vh;">
                <i class="bi bi-wifi-off text-secondary mb-3" style="font-size: 5rem;"></i>
                <h3 class="fw-bold text-white">You are currently offline</h3>
                <p class="text-secondary mt-2 mb-4" style="max-width: 400px;">Try to play offline songs in your offline library.</p>
                <div class="d-flex gap-3 justify-content-center flex-wrap">
                  <button class="btn btn-outline-light fw-bold px-4 py-2 rounded-pill" onclick="window.loadView({ type: 'get_offline_songs', param: '', sort: 'manual_order', filter_user_id: '' })"><i class="bi bi-cloud-check-fill text-success me-2"></i> Offline Library</button>
                  <button class="btn btn-danger fw-bold px-4 py-2 rounded-pill" onclick="window.loadView({ type: 'rhythm_game', param: '', sort: '', filter_user_id: '' })"><i class="bi bi-controller me-2"></i> Rhythm Game</button>
                </div>
              </div>
            `;
            allContentloaded = true;
            hideLoader();
            return;
          }

          switch (currentView.type) {
            case 'rhythm_game':
