                  </div>
                `;

                // Initialize Drag and Drop for Chat
                const chatMainEl = document.querySelector('.chat-main');
                if (chatMainEl) {
                  chatMainEl.addEventListener('dragover', (e) => {
                    e.preventDefault(); e.stopPropagation();
                    chatMainEl.style.boxShadow = 'inset 0 0 20px var(--ytm-accent)';
                  });
                  chatMainEl.addEventListener('dragleave', (e) => {
                    e.preventDefault(); e.stopPropagation();
                    chatMainEl.style.boxShadow = 'none';
                  });
                  chatMainEl.addEventListener('drop', (e) => {
                    e.preventDefault(); e.stopPropagation();
                    chatMainEl.style.boxShadow = 'none';
                    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
                      if (typeof window.handleChatImageSelection === 'function') {
                        window.handleChatImageSelection(e.dataTransfer.files[0]);
                      }
                    }
                  });
                }

                // Load Inbox List
                const loadInboxList = async (query = '') => {
                  const listEl = document.getElementById('inbox-list');
                  if (!listEl) return;
                  
                  let inbox = await fetchData('?action=get_inbox');
                  if (!Array.isArray(inbox)) inbox = []; // Protect against SQL error strings

                  if (query) {
                    inbox = inbox.filter(i => i.name && i.name.toLowerCase().includes(query.toLowerCase()));
                  }

                  if (inbox.length > 0) {
                    listEl.innerHTML = inbox.map(m => {
                      const isGroup = m.chat_type === 'group';
                      let previewText = window.getPreviewText(m.content);
                      if (m.has_image) {
                        if (m.media_type && m.media_type.startsWith('video/')) previewText = 'Video';
                        else if (m.media_type && m.media_type.startsWith('audio/')) previewText = 'Audio';
                        else previewText = 'Photo';
                      }
                      const isMe = m.sender_id == currentUser.id;
                      
                      let activeHtml = '';
                      if (!isGroup && m.last_active) {
                        const mins = Math.floor((new Date() - new Date(m.last_active + 'Z')) / 60000);
                        activeHtml = `<span class="position-absolute bottom-0 end-0 p-1 ${mins<5 ? 'bg-success' : 'bg-secondary'} border border-dark rounded-circle" title="Active"></span>`;
                      }

                      const cacheBuster = Math.floor(Date.now() / 60000);
                      return `
                      <div class="list-group-item bg-transparent text-white border-secondary px-3 py-3 d-flex align-items-center gap-3 rounded mb-1" style="cursor: pointer; transition: background 0.2s;" onmouseover="this.style.backgroundColor='var(--ytm-surface-2)'" onmouseout="this.style.backgroundColor='transparent'" onclick="window.openChatFull(${m.target_id}, '${m.chat_type}', '${escapeHTML(m.name).replace(/&#39;/g, "\\'")}')">
                        <div class="position-relative">
                          ${isGroup ? `<div class="rounded-circle bg-dark d-flex align-items-center justify-content-center border border-secondary overflow-hidden" style="width: 50px; height: 50px;"><img src="?action=get_group_image&id=${m.target_id}&v=${cacheBuster}" onerror="this.outerHTML='<i class=\\'bi bi-people-fill text-info fs-4\\'></i>'" style="width: 100%; height: 100%; object-fit: cover;"></div>` : `<img src="?action=get_profile_picture&id=${m.target_id}&v=${cacheBuster}" class="rounded-circle shadow-sm" style="width: 50px; height: 50px; object-fit: cover;">`}
                          ${activeHtml}
                        </div>
                        <div class="flex-grow-1 overflow-hidden">
                          <div class="d-flex justify-content-between align-items-center">
                            <span class="fw-bold text-truncate">${escapeHTML(m.name)}${isGroup && m.member_count ? ` <small class="text-secondary fw-normal">(${m.member_count} members)</small>` : ''}</span>
                            <small class="text-secondary" style="font-size: 0.7rem;">${timeAgo(m.created_at)}</small>
                          </div>
                          <div class="text-secondary small text-truncate ${m.unread_count > 0 ? 'text-white fw-bold' : ''}">
                             ${isGroup && !isMe && m.content ? `<span class="text-info">${m.sender_name || 'Someone'}:</span> ` : ''}
                             ${isMe && !isGroup ? 'You: ' : ''}${m.has_image ? '<i class="bi bi-image"></i> ' : ''}${escapeHTML(previewText) || 'New Chat'}
                          </div>
                        </div>
                        ${m.unread_count > 0 ? `<span class="badge bg-danger rounded-pill">${m.unread_count}</span>` : ''}
                      </div>
                    `}).join('');
                  } else {
                    listEl.innerHTML = '<div class="p-4 text-center text-secondary">No conversations. Search to start one!</div>';
                  }
                };
                
                loadInboxList();
                
                let inboxSearchTimeout = null;
                document.getElementById('inbox-search-input').addEventListener('input', (e) => {
                  clearTimeout(inboxSearchTimeout);
                  inboxSearchTimeout = setTimeout(async () => {
                    const q = e.target.value.trim();
                    await loadInboxList(q); // Must await the inbox rendering FIRST
                    
                    if (q.length > 1) {
                      const res = await fetchData(`?action=search&q=${encodeURIComponent(q)}`);
                      if (res && res.shelves) {
                        const artistShelf = res.shelves.find(s => s.type === 'artists');
                        if (artistShelf && artistShelf.items.length > 0) {
                          const users = artistShelf.items.filter(u => u.is_user);
                          if (users.length > 0) {
                             const listEl = document.getElementById('inbox-list');
                             const extraHtml = `<h6 class="text-secondary small fw-bold mt-3 mb-2 px-2">NEW CHATS</h6>` + users.map(u => `
                                <div class="list-group-item bg-transparent text-white border-secondary px-3 py-2 d-flex align-items-center gap-3 rounded mb-1" style="cursor: pointer;" onmouseover="this.style.backgroundColor='var(--ytm-surface-2)'" onmouseout="this.style.backgroundColor='transparent'" onclick="window.openChatFull(${u.id}, 'dm', '${escapeHTML(u.name).replace(/&#39;/g, "\\'")}')">
                                  <img src="?action=get_profile_picture&id=${u.id}&v=${Math.floor(Date.now() / 60000)}" class="rounded-circle" style="width: 40px; height: 40px; object-fit: cover;">
                                  <span class="fw-bold">${escapeHTML(u.name)}</span>
                                </div>
                             `).join('');
                             listEl.innerHTML += extraHtml;
                          }
                        }
                      }
                    }
                  }, 400); // 400ms debounce prevents SQLite from locking and wiping the UI
                });

                // Real-time client-side Starred messages filter
                document.addEventListener('input', (e) => {
                  if (e.target.id === 'starred-search-input') {
                    const q = e.target.value.toLowerCase().trim();
                    const items = document.querySelectorAll('#starred-msgs-list .list-group-item');
                    items.forEach(item => {
                      const text = item.textContent.toLowerCase();
                      if (text.includes(q)) {
                        item.classList.remove('d-none');
                        item.style.setProperty('display', 'flex', 'important');
                      } else {
                        item.classList.add('d-none');
                        item.style.setProperty('display', 'none', 'important');
                      }
                    });
                  }
                });

                // INNER CHAT SEARCH LOGIC
                const chatInnerSearch = document.getElementById('chat-inner-search');
                if (chatInnerSearch) {
                  chatInnerSearch.addEventListener('input', (e) => {
                    const q = e.target.value.toLowerCase();
                    const bubbles = document.querySelectorAll('.chat-bubble');
                    bubbles.forEach(b => {
                      if (b.textContent.toLowerCase().includes(q)) b.style.display = '';
                      else b.style.display = 'none';
                    });
                  });
                }

                // FORCE MANUAL TAB SWITCHING AND CSS DISPLAY OVERRIDES
                document.querySelectorAll('#chat-tabs .nav-link').forEach(btn => {
                  btn.addEventListener('click', (e) => {
                    e.preventDefault();
                    document.querySelectorAll('#chat-tabs .nav-link').forEach(b => b.classList.remove('active'));
                    document.querySelectorAll('.chat-sidebar .tab-pane').forEach(p => { 
                      p.classList.remove('show', 'active'); 
                      p.style.display = 'none'; 
                      p.style.opacity = '0'; 
                    });
                    
                    const targetId = btn.getAttribute('data-target');
                    btn.classList.add('active');
                    const pane = document.querySelector(targetId);
                    if (pane) {
                      pane.classList.add('show', 'active');
                      pane.style.display = 'flex'; // Enforce flex globally for perfect layout
                      setTimeout(() => { pane.style.opacity = '1'; }, 50);
                    }
                    
                    if (targetId === '#tab-starred') window.loadStarredMessages(1);
                    if (targetId === '#tab-status') window.loadStatuses(1);
                  });
                });

                // INJECT STATUS MODAL IF NOT EXISTS
                if (!document.getElementById('status-manage-modal')) {
                  const modalHtml = `
                    <div class="modal fade" id="status-manage-modal" tabindex="-1">
                      <div class="modal-dialog modal-dialog-centered modal-lg">
                        <div class="modal-content" style="background-color: var(--ytm-surface); border: 1px solid #404040; border-radius: 16px; box-shadow: 0 10px 30px rgba(0,0,0,0.8);">
                          <div class="modal-header border-0 pb-2">
                            <h5 class="modal-title text-white fw-bold"><i class="bi bi-camera-fill text-danger me-2"></i>Create Status</h5>
                            <button type="button" class="btn-close btn-close-white" data-bs-dismiss="modal"></button>
                          </div>
                          <div class="modal-body p-4">
                            <form id="status-post-form-modal" onsubmit="window.submitStatusForm(event)">
                              <textarea id="status-input-text" class="form-control bg-dark text-white border-secondary mb-3" rows="3" placeholder="What's happening?"></textarea>
                              <label class="form-label text-secondary small fw-bold mb-2">ATTACH MEDIA (OPTIONAL)</label>
                              <input type="file" id="status-input-media" class="form-control bg-dark text-white border-secondary mb-4" accept="image/*,video/mp4,video/webm">
                              <button type="submit" class="btn btn-danger w-100 fw-bold rounded-pill py-2 shadow-sm">Post Status</button>
                            </form>
                          </div>
                        </div>
                      </div>
                    </div>
                  `;
                  document.body.insertAdjacentHTML('beforeend', modalHtml);
                }

                const listStarred = document.getElementById('starred-msgs-list');
                if (listStarred) {
                  listStarred.addEventListener('scroll', () => {
                    if (listStarred.scrollTop + listStarred.clientHeight >= listStarred.scrollHeight - 50) {
                      const btn = document.getElementById('load-more-starred-btn');
                      if (btn && !btn.disabled) {
                        btn.disabled = true;
                        btn.click();
                      }
                    }
                  });
                }

                const listStatus = document.getElementById('status-list');
                if (listStatus) {
                  listStatus.addEventListener('scroll', () => {
                    if (listStatus.scrollTop + listStatus.clientHeight >= listStatus.scrollHeight - 50) {
                      const btn = document.getElementById('load-more-status-btn');
                      if (btn && !btn.disabled) {
                        btn.disabled = true;
                        btn.click();
                      }
                    }
                  });
                }

                window.toggleStarMsg = async (msgId) => {
                  const res = await fetchData('?action=toggle_star_message', { method: 'POST', body: JSON.stringify({ message_id: msgId }) });
                  if (res && res.status) {
                    showToast(res.status === 'starred' ? 'Message starred' : 'Message unstarred', 'success');
                    window.refreshChatFull(true);
                    if (document.getElementById('tab-starred').classList.contains('active')) {
                       window.loadStarredMessages(1);
                    }
                  }
                };

                window.currentStarredPage = 1;
                window.loadStarredMessages = async (page = 1) => {
                  window.currentStarredPage = page;
                  const listEl = document.getElementById('starred-msgs-list');
                  if (!listEl) return;
                  
                  if (page === 1) {
                    const searchInp = document.getElementById('starred-search-input');
                    if (searchInp) searchInp.value = '';
                    listEl.innerHTML = '<div class="text-center p-4"><div class="spinner-border text-secondary"></div></div>';
                  } else {
                    const btn = document.getElementById('load-more-starred-btn');
                    if (btn) btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Loading...';
                  }

                  let msgs = await fetchData(`?action=get_starred_messages&page=${page}`);
                  if (!Array.isArray(msgs)) msgs = [];
                  
                  const btnContainer = document.getElementById('load-more-starred-container');
                  if (btnContainer) btnContainer.remove();

                  if (msgs.length > 0) {
                    const cacheBuster = Math.floor(Date.now() / 60000);
                    const html = msgs.map(m => {
                      const isMe = m.sender_id == currentUser.id;
                      let mediaHtml = '';
                      if (m.has_image) {
                        const mediaUrl = `?action=get_message_image&id=${m.id}`;
                        const thumbUrl = `?action=get_message_image&id=${m.id}&thumb=1`;
                        if (m.media_type && m.media_type.startsWith('video/')) {
                          mediaHtml = window.buildLazyMediaHtml(mediaUrl, m.media_type, thumbUrl, false);
                        } else if (m.media_type && m.media_type.startsWith('audio/')) {
                          mediaHtml = `<div class="p-2 bg-dark rounded border border-secondary mt-2"><i class="bi bi-file-earmark-music text-warning"></i> Audio Message</div>`;
                        } else {
                          mediaHtml = window.buildLazyMediaHtml(mediaUrl, m.media_type || 'image/webp', thumbUrl, false);
                        }
                      }
                      const safeDate = m.created_at ? new Date(m.created_at.replace(' ', 'T')+'Z').toLocaleDateString() : 'Just now';
                      return `
                      <div class="list-group-item bg-transparent text-white px-3 py-3 d-flex flex-column gap-2 rounded mb-3 shadow-sm border border-secondary" style="background: linear-gradient(145deg, rgba(255,193,7,0.05), rgba(0,0,0,0.2)); border-left: 4px solid var(--ytm-accent) !important;">
                        <div class="d-flex justify-content-between align-items-center mb-1">
                          <div class="d-flex align-items-center gap-2 user-profile-link" data-userid="${m.sender_id}" data-artist="${encodeURIComponent(m.sender_name || 'You')}" style="cursor: pointer;">
                            <img src="?action=get_profile_picture&id=${m.sender_id}&v=${cacheBuster}" class="rounded-circle shadow-sm" style="width: 36px; height: 36px; object-fit: cover;">
                            <div class="d-flex flex-column">
                              <span class="fw-bold fs-6 text-warning"><i class="bi bi-star-fill me-1"></i>${escapeHTML(m.sender_name || 'You')}</span>
                            </div>
                          </div>
                          <small class="text-secondary" style="font-size: 0.75rem;">${safeDate}</small>
                        </div>
                        ${m.content ? `<div class="text-light px-1" style="font-size: 0.95rem; white-space: pre-wrap; line-height: 1.5;">${parseUserText(m.content)}</div>` : ''}
                        ${mediaHtml}
                        <div class="d-flex justify-content-end mt-2 pt-2 border-top border-secondary opacity-75">
                          <button class="btn btn-sm btn-link text-secondary text-decoration-none py-0 px-2 fw-bold" onclick="window.toggleStarMsg(${m.id})"><i class="bi bi-star-fill"></i> Unstar</button>
                        </div>
                      </div>
                    `}).join('');
                    
                    if (page === 1) listEl.innerHTML = html;
                    else listEl.insertAdjacentHTML('beforeend', html);
                    
                    if (msgs.length === 25) {
                      listEl.insertAdjacentHTML('beforeend', `
                        <div class="text-center mt-3 mb-2" id="load-more-starred-container">
                          <button class="btn btn-sm btn-outline-light rounded-pill px-4 fw-bold" id="load-more-starred-btn" onclick="window.loadStarredMessages(${page + 1})">Load Older Messages</button>
                        </div>
                      `);
                    } else if (page > 1) {
                      listEl.insertAdjacentHTML('beforeend', '<div class="text-center p-3 text-secondary small">No more starred messages.</div>');
                    }
                  } else {
                    if (page === 1) listEl.innerHTML = '<div class="p-4 text-center text-secondary">No starred messages.</div>';
                  }
                };

                window.currentStatusPage = 1;
                window.loadStatuses = async (page = 1) => {
                  window.currentStatusPage = page;
                  const listEl = document.getElementById('status-list');
                  if (!listEl) return;
                  
                  if (page === 1) listEl.innerHTML = '<div class="text-center p-4"><div class="spinner-border text-secondary"></div></div>';
                  else {
                    const btn = document.getElementById('load-more-status-btn');
                    if (btn) btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Loading...';
                  }

                  let stats = await fetchData(`?action=get_statuses&page=${page}`);
                  if (!Array.isArray(stats)) stats = [];
                  
                  const btnContainer = document.getElementById('load-more-status-container');
                  if (btnContainer) btnContainer.remove();

                  if (stats.length > 0) {
                    const html = stats.map(s => {
                      let mediaHtml = '';
                      if (s.image) {
                        const mUrl = `?action=get_status_media&id=${s.id}`;
                        const mType = s.media_type || 'image/webp'; // Safe fallback prevents crash
                        if (mType.startsWith('video/')) {
                          mediaHtml = `<video src="${mUrl}" controls class="w-100 mt-2 rounded" style="max-height: 250px; background: #000;"></video>`;
                        } else {
                          mediaHtml = `<img src="${mUrl}" class="w-100 mt-2 rounded" style="max-height: 250px; object-fit: contain; background: #000;">`;
                        }
                      }
                      return `
                      <div class="list-group-item bg-transparent text-white border-secondary px-3 py-3 d-flex flex-column gap-2 rounded mb-2 shadow-sm" style="background: rgba(255,255,255,0.05) !important;">
                        <div class="d-flex justify-content-between align-items-center">
                          <div class="d-flex align-items-center gap-2 user-profile-link" data-userid="${s.user_id}" data-artist="${encodeURIComponent(s.name)}" style="cursor: pointer;">
                            <img src="?action=get_profile_picture&id=${s.user_id}" class="rounded-circle" style="width: 32px; height: 32px; object-fit: cover;">
                            <span class="fw-bold">${escapeHTML(s.name)}</span>
                          </div>
                          <div class="d-flex align-items-center gap-2">
                            <small class="text-secondary" style="font-size: 0.75rem;">${timeAgo(s.created_at)}</small>
                            ${s.user_id == currentUser.id ? `<button class="btn btn-sm btn-link text-danger p-0" onclick="window.deleteStatus(${s.id})"><i class="bi bi-trash"></i></button>` : ''}
                          </div>
                        </div>
                        ${s.content ? `<div class="text-light mt-1" style="font-size: 1rem; white-space: pre-wrap;">${parseUserText(s.content)}</div>` : ''}
                        ${mediaHtml}
                      </div>
                    `}).join('');

                    if (page === 1) listEl.innerHTML = html;
                    else listEl.insertAdjacentHTML('beforeend', html);

                    if (stats.length === 25) {
                      listEl.insertAdjacentHTML('beforeend', `
                        <div class="text-center mt-3 mb-2" id="load-more-status-container">
                          <button class="btn btn-sm btn-outline-light rounded-pill px-4 fw-bold" id="load-more-status-btn" onclick="window.loadStatuses(${page + 1})">Load Older Statuses</button>
                        </div>
                      `);
                    } else if (page > 1) {
                      listEl.insertAdjacentHTML('beforeend', '<div class="text-center p-3 text-secondary small">No more statuses.</div>');
                    }
                  } else {
                    if (page === 1) listEl.innerHTML = '<div class="p-4 text-center text-secondary">No recent status updates from your network.</div>';
                  }
                };

                window.deleteStatus = async (id) => {
                  if (confirm('Delete this status update?')) {
                    await fetchData('?action=delete_status', { method: 'POST', body: JSON.stringify({ id }) });
                    window.loadStatuses(1);
                  }
                };

                window.submitStatusForm = async (e) => {
                  e.preventDefault();
                  const form = e.target;
                  const txt = document.getElementById('status-input-text').value;
                  const fileInput = document.getElementById('status-input-media');
                  const submitBtn = form.querySelector('button[type="submit"]');
                  
                  if (!txt.trim() && fileInput.files.length === 0) return;
                  
                  submitBtn.disabled = true;
                  const origHTML = submitBtn.innerHTML;
                  submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span>';
                  
                  const fd = new FormData();
                  fd.append('content', txt);
                  if (fileInput.files.length > 0) fd.append('image', fileInput.files[0]);
                  
                  try {
                    const response = await fetch('?action=post_status', { method: 'POST', body: fd });
                    const res = await response.json();
                    
                    if (res && res.status === 'success') {
                      form.reset();
                      const statusModal = bootstrap.Modal.getInstance(document.getElementById('status-manage-modal'));
                      if (statusModal) statusModal.hide();
                      if (typeof window.loadStatuses === 'function') window.loadStatuses(1);
                      showToast('Status posted!', 'success');
                    } else {
                      showToast(res.message || 'Failed to post status', 'error');
                    }
                  } catch (err) {
                    showToast('Upload failed. Connection error.', 'error');
                  }
                  
                  submitBtn.disabled = false;
                  submitBtn.innerHTML = origHTML;
                };

              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to view messages.</div>`;
              }
              allContentloaded = true;
              break;
            case 'get_songs':
              updateContentTitle('All Songs', false);
              if (!cachedExploreData) {
                cachedExploreData = await fetchData(`?action=get_explore`);
              }
              if (cachedExploreData && cachedExploreData.shelves && cachedExploreData.shelves.length > 0) {
                renderRecommendations(cachedExploreData);
              } else {
                contentArea.innerHTML = '';
              }
              const allTracksHeader = `
                <div class="d-flex justify-content-between align-items-center mt-5 mb-3 px-2">
                  <h3 class="m-0 fw-bold">All Tracks</h3>
                  <div class="d-flex align-items-center gap-2">
                    <label for="sort-select-all" class="text-secondary small d-none d-sm-block">Sort by</label>
                    <select id="sort-select-all" class="form-select form-select-sm" style="width: auto;">
                      <option value="random" ${currentView.sort === 'random' ? 'selected' : ''}>Random Shuffle</option>
                      <option value="id_desc" ${currentView.sort === 'id_desc' ? 'selected' : ''}>Recently Added</option>
                      <option value="artist_asc" ${currentView.sort === 'artist_asc' ? 'selected' : ''}>Artist</option>
                      <option value="title_asc" ${currentView.sort === 'title_asc' ? 'selected' : ''}>Title</option>
                      <option value="album_asc" ${currentView.sort === 'album_asc' ? 'selected' : ''}>Album</option>
                      <option value="year_desc" ${currentView.sort === 'year_desc' ? 'selected' : ''}>Year (Newest)</option>
                      <option value="year_asc" ${currentView.sort === 'year_asc' ? 'selected' : ''}>Year (Oldest)</option>
                    </select>
                  </div>
                </div>
              `;
              contentArea.insertAdjacentHTML('beforeend', allTracksHeader);
              document.getElementById('sort-select-all').addEventListener('change', (e) => {
                loadView({ ...currentView, sort: e.target.value });
              });
              data = await fetchData(`?action=get_songs&${pageParams.toString()}`);
              renderSongs(data, true);
              document.getElementById('sort-controls').classList.add('d-none');
              break;
            case 'user_profile':
              updateContentTitle('', false);
              
              if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);
              
              const profileViewData = await fetchData(`?action=get_view_data&type=profile&${pageParams.toString()}`);
              contentArea.innerHTML = '';
              if (profileViewData && profileViewData.details) {
                renderViewDetailsHeader(profileViewData.details, 'profile');
                
                const existingCustomSort = document.getElementById('artist-custom-sort-container');
                if (existingCustomSort) existingCustomSort.remove();

                const customSortHTML = `
                    <div id="artist-custom-sort-container" class="d-none align-items-center gap-2">
                      <label for="artist-custom-sort-select" class="text-secondary small">Sort by</label>
                      <select id="artist-custom-sort-select" class="form-select form-select-sm" style="width: auto;"></select>
                    </div>
                `;
                document.querySelector('.header-controls').insertAdjacentHTML('afterbegin', customSortHTML);

                const searchHTML = `
                  <div class="px-3 mb-3 mt-4 d-flex flex-wrap gap-3 align-items-center justify-content-between w-100">
                    <div class="position-relative" style="max-width: 400px; width: 100%;">
                      <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                      <input type="text" id="view-songs-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search songs..." value="${escapeHTML(currentView.searchQuery || '')}">
                    </div>
                    <div id="artist-custom-cat-container" class="d-none align-items-center gap-2 ms-auto"></div>
                  </div>
                `;
                const targetPane = document.getElementById('artistTabsContent') || contentArea;
                targetPane.insertAdjacentHTML('beforebegin', searchHTML);
                
                // Define the sorting and filtering engines (matching the artist profile engine)
                window.filterAndSortArtistPlaylists = () => {
                  const sInp = document.getElementById('view-songs-search-input');
                  const sSel = document.getElementById('artist-custom-sort-select');
                  if (!sInp || !sSel) return;
                  const query = sInp.value.toLowerCase().trim();
                  const sortVal = sSel.value;
                  let filtered = [...(window.artistPlaylistsData || [])];
                  if (query) filtered = filtered.filter(p => p.name.toLowerCase().includes(query) || (p.description && p.description.toLowerCase().includes(query)));
                  filtered.sort((a, b) => {
                    if (sortVal === 'newest') return new Date(b.created_at || 0) - new Date(a.created_at || 0);
                    if (sortVal === 'modified') return new Date(b.image_v || 0) - new Date(a.image_v || 0);
                    if (sortVal === 'name_asc') return a.name.localeCompare(b.name);
                    if (sortVal === 'name_desc') return b.name.localeCompare(a.name);
                    if (sortVal === 'songs_desc') return (b.song_count || 0) - (a.song_count || 0);
                    if (sortVal === 'songs_asc') return (a.song_count || 0) - (b.song_count || 0);
                    return 0;
                  });
                  const pane = document.getElementById('playlists-pane');
                  if (!pane) return;
                  if (filtered.length === 0) { pane.innerHTML = '<div class="text-center p-5 text-secondary">No playlists found.</div>'; return; }
                  pane.innerHTML = `<div class="row row-cols-2 row-cols-sm-3 row-cols-md-4 g-4">${filtered.map(p => `
                    <div class="col">
                      <div class="card h-100 bg-transparent text-white border-0 playlist-card" data-playlist="${encodeURIComponent(p.public_id)}" style="cursor: pointer;">
                        ${(currentUser && (currentUser.id == currentViewOwnerId || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `<button class="playlist-more-btn" data-public-id="${p.public_id}" data-name="${escapeHTML(p.name)}" data-is-collab="${p.is_collaborative || 0}" data-is-private="${p.is_private || 0}" data-owner-id="${currentViewOwnerId}"><i class="bi bi-three-dots-vertical"></i></button>` : ''}
                        <div style="position: relative; display: block; border-radius: 6px; overflow: hidden;">
                          <img src="?action=get_image&id=${p.image_id || 0}&v=${p.image_v || 0}&size=small" class="card-img-top" alt="${escapeHTML(p.name)}" style="aspect-ratio: 1/1; object-fit: cover; background-color: var(--ytm-surface-2); margin-bottom: 0 !important;">
                          ${p.song_count !== undefined ? `<div class="position-absolute bottom-0 start-0 ms-2 mb-1 px-2 py-1 bg-dark bg-opacity-75 text-white rounded fw-bold" style="font-size: 0.75rem; backdrop-filter: blur(4px); line-height: 1;"><i class="bi bi-music-note-list"></i> ${formatSongCount(p.song_count)}</div>` : ''}
                        </div>
                        <div class="card-body px-0 py-2"><h5 class="card-title fs-6 fw-normal text-truncate">${escapeHTML(p.name)}</h5></div>
                      </div>
                    </div>
                  `).join('')}</div>`;
                };

                window.filterAndSortArtistBlogs = () => {
                  const sInp = document.getElementById('view-songs-search-input');
                  const sSel = document.getElementById('artist-custom-sort-select');
                  const catSel = document.getElementById('artist-custom-cat-sort');
                  if (!sInp || !sSel) return;
                  const query = sInp.value.toLowerCase().trim();
                  const sortVal = sSel.value;
                  const catVal = catSel ? catSel.value : '';
                  
                  let filtered = [...(window.artistBlogsData || [])];
                  if (query) filtered = filtered.filter(b => b.title.toLowerCase().includes(query) || (b.content && b.content.toLowerCase().includes(query)));
                  if (catVal) filtered = filtered.filter(b => (b.category || 'all') === catVal);
                  
                  filtered.sort((a, b) => {
                    if (sortVal === 'newest') return new Date(b.created_at.replace(' ', 'T')+'Z') - new Date(a.created_at.replace(' ', 'T')+'Z');
                    if (sortVal === 'oldest') return new Date(a.created_at.replace(' ', 'T')+'Z') - new Date(b.created_at.replace(' ', 'T')+'Z');
                    if (sortVal === 'modified') return new Date(b.updated_at.replace(' ', 'T')+'Z') - new Date(a.updated_at.replace(' ', 'T')+'Z');
                    if (sortVal === 'title_asc') return a.title.localeCompare(b.title);
                    return 0;
                  });
                  const pane = document.getElementById('blogs-pane');
                  if (!pane) return;
                  if (filtered.length === 0) { pane.innerHTML = '<div class="text-center p-5 text-secondary">No blogs found.</div>'; return; }
                  pane.innerHTML = `<div class="notes-grid" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px;">${filtered.map(b => `
                    <div class="note-card bg-dark text-white border-secondary hover-bg-dark blog-card-item" data-id="${b.public_id}" style="border-radius: 12px; cursor: pointer; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-4px)'" onmouseout="this.style.transform='translateY(0)'">
                      <div class="d-flex justify-content-between mb-2">
                        <span class="badge bg-primary text-white">Public Blog</span>
                        <span class="small text-secondary">${new Date(b.updated_at.replace(' ', 'T')+'Z').toLocaleDateString()}</span>
                      </div>
                      <div class="fw-bold fs-5 mb-2 text-truncate">${escapeHTML((b.title && b.title.trim() !== '') ? decodeHTML(b.title) : 'Untitled')}</div>
                      <div class="text-secondary small overflow-hidden" style="display: -webkit-box; -webkit-line-clamp: 4; -webkit-box-orient: vertical;">${escapeHTML(decodeHTML(b.content).replace(/<[^>]*>?/gm, '').replace(/[^a-zA-Z0-9\s.,!?]/g, ''))}</div>
                      <div class="mt-auto pt-3 d-flex justify-content-between align-items-center">
                        ${b.category && b.category !== 'all' ? `<span class="note-chip">${escapeHTML(b.category_name || 'Uncategorized')}</span>` : '<span></span>'}
                      </div>
                    </div>
                  `).join('')}</div>`;
                };

                const updateArtistSearchAndSortUI = (activeTabId) => {
                  const sInp = document.getElementById('view-songs-search-input');
                  const sCont = document.getElementById('artist-custom-sort-container');
                  const sSel = document.getElementById('artist-custom-sort-select');
                  const gSort = document.getElementById('sort-controls');
                  const cCont = document.getElementById('artist-custom-cat-container');
                  if (!sInp) return;
                  
                  sInp.value = "";
                  
                  if (activeTabId === 'songs-tab') {
                    sInp.placeholder = "Search songs...";
                    if (sCont) sCont.classList.replace('d-flex', 'd-none');
                    if (cCont) cCont.classList.replace('d-flex', 'd-none');
                    if (gSort) gSort.classList.remove('d-none');
                  } else if (activeTabId === 'playlists-tab') {
                    sInp.placeholder = "Search playlists...";
                    if (gSort) gSort.classList.add('d-none');
                    if (cCont) cCont.classList.replace('d-flex', 'd-none');
                    if (sCont && sSel) {
                      sSel.innerHTML = '<option value="newest">Newest</option><option value="modified">Recently Modified</option><option value="name_asc">Name (A-Z)</option><option value="name_desc">Name (Z-A)</option><option value="songs_desc">Most Songs</option><option value="songs_asc">Least Songs</option>';
                      sCont.classList.replace('d-none', 'd-flex');
                      if (!sCont.classList.contains('d-flex')) sCont.classList.add('d-flex');
                    }
                    window.filterAndSortArtistPlaylists();
                  } else if (activeTabId === 'blogs-tab') {
                    sInp.placeholder = "Search blogs...";
                    if (gSort) gSort.classList.add('d-none');
                    if (sCont && sSel) {
                      sSel.innerHTML = '<option value="newest">Newest</option><option value="oldest">Oldest</option><option value="modified">Recently Modified</option><option value="title_asc">Title (A-Z)</option>';
                      sCont.classList.replace('d-none', 'd-flex');
                      if (!sCont.classList.contains('d-flex')) sCont.classList.add('d-flex');
                    }
                    
                    if (cCont) {
                      const uniqueCategories = [];
                      const categoryMap = new Set();
                      (window.artistBlogsData || []).forEach(b => {
                        const catId = b.category || 'all';
                        if (catId !== 'all' && !categoryMap.has(catId)) {
                          categoryMap.add(catId);
                          uniqueCategories.push({ id: catId, name: b.category_name || 'Unknown' });
                        }
                      });
                      
                      const truncateText = (str, len = 20) => str.length > len ? str.substring(0, len - 2) + '...' : str;
                      
                      cCont.innerHTML = `
                        <label for="artist-custom-cat-sort" class="text-secondary small ms-1">Category</label>
                        <select id="artist-custom-cat-sort" class="form-select form-select-sm" style="width: auto; max-width: 200px;">
                          <option value="">All Categories</option>
                          ${uniqueCategories.map(c => `<option value="${escapeHTML(c.id)}" title="${escapeHTML(c.name)}">${escapeHTML(truncateText(c.name))}</option>`).join('')}
                        </select>
                      `;
                      document.getElementById('artist-custom-cat-sort').addEventListener('change', window.filterAndSortArtistBlogs);
                      cCont.classList.replace('d-none', 'd-flex');
                    }
                    
                    window.filterAndSortArtistBlogs();
                  }
                };

                setTimeout(() => {
                  const viewSearch = document.getElementById('view-songs-search-input');
                  const sortSelect = document.getElementById('artist-custom-sort-select');
                  
                  if (viewSearch) {
                    viewSearch.addEventListener('input', (e) => {
                      const activeTab = document.querySelector('#artistTabs .nav-link.active');
                      const activeTabId = activeTab ? activeTab.id : 'songs-tab';
                      if (activeTabId === 'songs-tab') {
                        clearTimeout(window.viewSearchTimeout);
                        window.viewSearchTimeout = setTimeout(() => {
                          currentView.searchQuery = e.target.value;
                          loadView(currentView);
                        }, 400);
                      } else if (activeTabId === 'playlists-tab') {
                        window.filterAndSortArtistPlaylists();
                      } else if (activeTabId === 'blogs-tab') {
                        window.filterAndSortArtistBlogs();
                      }
                    });
                    
                    if (currentView.searchQuery) {
                       viewSearch.focus();
                       viewSearch.setSelectionRange(viewSearch.value.length, viewSearch.value.length);
                    }
                  }

                  if (sortSelect) {
                    sortSelect.addEventListener('change', () => {
                      const activeTab = document.querySelector('#artistTabs .nav-link.active');
                      const activeTabId = activeTab ? activeTab.id : 'songs-tab';
                      if (activeTabId === 'playlists-tab') {
                        window.filterAndSortArtistPlaylists();
                      } else if (activeTabId === 'blogs-tab') {
                        window.filterAndSortArtistBlogs();
                      }
                    });
                  }

                  const artistTabs = document.getElementById('artistTabs');
                  if (artistTabs) {
                    artistTabs.addEventListener('shown.bs.tab', (e) => {
                      updateArtistSearchAndSortUI(e.target.id);
                    });
                  }
                }, 0);
                
                renderSongs(profileViewData.songs, false);
                data = profileViewData.songs;
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your profile.</div>`;
              }
              break;
            case 'get_user_stats':
              updateContentTitle('My Statistics', !!currentUser);
              if (currentUser) {
                const userStatsData = await fetchData(`?action=get_user_stats`);
                if (userStatsData) renderUserStats(userStatsData);
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your statistics.</div>`;
              }
              allContentloaded = true;
              break;
            case 'get_offline_songs':
              updateContentTitle('Offline Music', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(145deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                    <div class="d-flex flex-wrap align-items-center justify-content-between gap-3">
                      <div class="d-flex align-items-center gap-3">
                        <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                          <i class="bi bi-cloud-arrow-down-fill text-info fs-3"></i>
                        </div>
                        <div>
                          <h2 class="text-white fw-bold mb-1 fs-4">Offline Library</h2>
                          <p class="text-secondary small mb-0">Listen to your cached tracks without an internet connection.</p>
                        </div>
                      </div>
                      <div class="d-flex flex-wrap gap-2 w-100 w-md-auto justify-content-md-end">
                        <button class="btn btn-warning rounded-pill px-4 fw-bold shadow-sm text-dark flex-grow-1 flex-md-grow-0 text-nowrap" id="recache-all-offline-btn">
                          <i class="bi bi-arrow-repeat me-1"></i> Re-cache All
                        </button>
                        <div class="dropdown flex-grow-1 flex-md-grow-0">
                          <button class="btn btn-outline-light rounded-pill px-4 fw-medium shadow-sm w-100 text-nowrap" type="button" data-bs-toggle="dropdown" aria-expanded="false">
                            <i class="bi bi-three-dots"></i> Options
                          </button>
                          <ul class="dropdown-menu dropdown-menu-dark shadow-lg border-secondary" style="background-color: var(--ytm-surface-2); border-radius: 12px; min-width: 220px;">
                            <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-white" id="import-offline-btn"><i class="bi bi-box-arrow-in-down fs-5 text-info"></i> Import Library</button></li>
                            <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-white" id="export-offline-btn"><i class="bi bi-box-arrow-up fs-5 text-info"></i> Export Library</button></li>
                            <li><hr class="dropdown-divider border-secondary opacity-50 my-1"></li>
                            <li><button class="dropdown-item d-flex align-items-center gap-3 py-2 text-danger fw-bold" id="remove-all-offline-btn"><i class="bi bi-trash-fill fs-5"></i> Clear Offline Cache</button></li>
                          </ul>
                        </div>
                      </div>
                    </div>
                  </div>`;
                
                let allData = await fetchData(`?action=get_offline_songs&sort=${currentView.sort}&all=1`, {}, true);
                
                // OFFLINE FALLBACK: If API fails, dynamically extract metadata from the local hardware cache
                if ((!allData || allData.length === 0) && !navigator.onLine) {
                  try {
                    const cache = await caches.open('php-music-offline');
                    const keys = await cache.keys();
                    allData = [];
                    for (let req of keys) {
                      if (req.url.includes('action=get_song_data')) {
                        const res = await cache.match(req);
                        if (res) {
                          const songData = await res.json();
                          if (songData && songData.id) allData.push(songData);
                        }
                      }
                    }
                  } catch (e) {
                    console.error("Offline cache extraction failed", e);
                  }
                }

                if (allData && allData.length > 0) {
                  offlineViewSongsData = allData;
                  data = offlineViewSongsData.slice(0, PAGE_SIZE);
                  renderSongs(data, true);
                  if (offlineViewSongsData.length <= PAGE_SIZE) allContentloaded = true;
                } else {
                  offlineViewSongsData = [];
                  renderSongs([], true);
                  allContentloaded = true;
                }
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your offline music.</div>`;
              }
              break;
            case 'get_favorites':
              updateContentTitle('Favorites', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(135deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                    <div class="d-flex align-items-center justify-content-between gap-3 flex-wrap">
                      <div class="d-flex align-items-center gap-3">
                        <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                          <i class="bi bi-heart-fill text-danger fs-3"></i>
                        </div>
                        <div>
                          <h2 class="text-white fw-bold mb-1 fs-4">My Favorites</h2>
                          <p class="text-secondary small mb-0">Your personal collection of top tracks.</p>
                        </div>
                      </div>
                      <div class="d-flex gap-2 flex-wrap">
                      <button class="btn btn-outline-light rounded-pill px-4 fw-medium shadow-sm" id="export-favorites-btn"><i class="bi bi-box-arrow-up me-1"></i> Export</button>
                      <button class="btn btn-outline-light rounded-pill px-4 fw-medium shadow-sm" id="import-favorites-btn"><i class="bi bi-box-arrow-in-down me-1"></i> Import</button>
                    </div>
                  </div>`;
                data = await fetchData(`?action=get_favorites&${pageParams.toString()}`);
                renderSongs(data, true);
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your favorites.</div>`;
              }
              break;
            case 'get_listen_later':
              updateContentTitle('Listen Later', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(145deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                    <div class="d-flex align-items-center gap-3">
                      <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                        <i class="bi bi-clock-fill text-warning fs-3"></i>
                      </div>
                      <div>
                        <h2 class="text-white fw-bold mb-1 fs-4">Listen Later</h2>
                        <p class="text-secondary small mb-0">Tracks bookmarked for your future listening sessions.</p>
                      </div>
                    </div>
                  </div>`;
                data = await fetchData(`?action=get_listen_later&${pageParams.toString()}`);
                renderSongs(data, true);
                
                setTimeout(() => {
                  if (currentView.sort === 'manual_order' && !sortable) {
                    const sList = contentArea.querySelector('.song-list');
                    if (sList) {
                      sortable = Sortable.create(sList, {
                        animation: 150, delay: 250, delayOnTouchOnly: false,
                        onEnd: async () => {
                          const ids = Array.from(sList.querySelectorAll('.song-item')).map(item => item.dataset.songId);
                          await fetchData('?action=update_listen_later_order', { method: 'POST', body: JSON.stringify({ids}) });
                        }
                      });
                    }
                  }
                }, 500);

              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see listen later.</div>`;
              }
              break;

            case 'get_history':
              updateContentTitle('History', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(145deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                    <div class="d-flex flex-wrap align-items-center justify-content-between gap-3">
                      <div class="d-flex align-items-center gap-3">
                        <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                          <i class="bi bi-clock-history text-secondary fs-3"></i>
                        </div>
                        <div>
                          <h2 class="text-white fw-bold mb-1 fs-4">Playback History</h2>
                          <p class="text-secondary small mb-0">Review and manage your recently played tracks.</p>
                        </div>
                      </div>
                      <div class="d-flex gap-2">
                        <button class="btn btn-sm btn-outline-danger rounded-pill px-3 fw-bold" id="clear-history-btn" title="Clear History">
                          <i class="bi bi-trash"></i> Clear History
                        </button>
                      </div>
                    </div>
                  </div>`;
                data = await fetchData(`?action=get_history&${pageParams.toString()}`);
                renderSongs(data, true);
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your history.</div>`;
              }
              break;

            case 'get_trending':
              updateContentTitle('Top 100 Trending', true);
              contentArea.innerHTML = `
                <div class="p-4 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background: linear-gradient(145deg, var(--ytm-surface-2), #151515); border: 1px solid rgba(255,255,255,0.05);">
                  <div class="d-flex align-items-center gap-3">
                    <div class="d-flex align-items-center justify-content-center" style="width: 50px; height: 50px; min-width: 50px;">
                      <i class="bi bi-graph-up-arrow text-success fs-3"></i>
                    </div>
                    <div>
                      <h2 class="text-white fw-bold mb-1 fs-4">Top 100 Trending</h2>
                      <p class="text-secondary small mb-0">The most played tracks across the entire platform.</p>
                    </div>
                  </div>
                </div>`;
              data = await fetchData(`?action=get_trending&${pageParams.toString()}`);
              renderSongs(data, true);
              break;

            case 'manage_note_categories':
              const mCatType = currentView.filter || 'note';
              let manageTitle = 'Manage Note Categories';
              if (mCatType === 'task') manageTitle = 'Manage Task Categories';
              else if (mCatType === 'blog') manageTitle = 'Manage Blog Categories';
              updateContentTitle(manageTitle, !!currentUser);
              
              if (currentUser) {
                if (mCatType === 'task' && (!window.taskCategories || window.taskCategories.length === 0)) {
                   window.taskCategories = await fetchData('?action=get_note_categories&type=task') || [];
                } else if (mCatType === 'blog' && (!window.blogCategories || window.blogCategories.length === 0)) {
                   window.blogCategories = await fetchData('?action=get_note_categories&type=blog') || [];
                } else if (mCatType === 'note' && (!window.noteCategories || window.noteCategories.length === 0)) {
                   window.noteCategories = await fetchData('?action=get_note_categories&type=note') || [];
                }
                
                contentArea.innerHTML = `
                  <div class="d-flex w-100 justify-content-between align-items-center mb-4 px-md-3">
                    <h4 class="text-white fw-bold m-0"><i class="bi bi-tags text-danger me-2"></i> Edit ${mCatType === 'task' ? 'Task' : (mCatType === 'blog' ? 'Blog' : 'Note')} Categories</h4>
                  </div>
                  <div class="px-md-3 mb-5" style="max-width: 600px;">
                    <div class="d-flex gap-2 mb-4">
                      <input type="text" id="newCatInputPage" data-type="${mCatType}" class="form-control bg-dark text-white border-secondary" placeholder="New Category Name" />
                      <button class="btn btn-danger px-4 fw-bold" id="addCatBtnPage">Add</button>
                    </div>
                    <div class="cat-manage-list d-flex flex-column gap-2" id="cat-manage-list-page"></div>
                  </div>
                `;
                window.loadManageCategoriesPage(mCatType);
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to manage categories.</div>`;
              }
              break;

            case 'view_blog':
              updateContentTitle('', false);
              const blogData = await fetchData(`?action=get_blog&public_id=${currentView.param}`);
              if (blogData) {
                document.title = `${decodeHTML(blogData.title)} - PHP Music Blog`;
                
                const isOwner = currentUser && (currentUser.id == blogData.user_id || currentUser.email === 'musiclibrary@mail.com');
                let editButtonHTML = '';
                if (isOwner) {
                  editButtonHTML = `<button class="btn btn-warning text-dark rounded-pill px-3 fw-bold edit-blog-btn me-2" data-id="${blogData.public_id}" title="Edit Blog"><i class="bi bi-pencil-fill me-1"></i> Edit</button>`;
                }

                // Render with marked if available
                let finalContent = decodeHTML(blogData.content);
                if (typeof marked !== 'undefined') {
                  marked.use({ gfm: true });
                  finalContent = marked.parse(finalContent);
                } else {
                  finalContent = `<pre style="white-space: pre-wrap; font-family: sans-serif;">${escapeHTML(finalContent)}</pre>`;
                }

                let collaboratorsHTML = '';
                if (blogData.collaborators && blogData.collaborators.length > 0) {
                  collaboratorsHTML = `
                    <div class="mt-2 d-flex flex-wrap align-items-center gap-2 small text-secondary">
                      <span class="fw-bold" style="font-size: 0.8rem;">Collaborators:</span>
                      ${blogData.collaborators.map(c => `
                        <span class="badge bg-dark border border-secondary text-light user-profile-link px-2 py-1" data-userid="${c.id}" data-artist="${encodeURIComponent(c.artist)}" style="cursor: pointer; font-size: 0.75rem; display: inline-flex; align-items: center; gap: 4px;">
                          <img src="?action=get_profile_picture&id=${c.id}" class="rounded-circle" style="width: 16px; height: 16px; object-fit: cover;">
                          ${escapeHTML(c.artist)}
                        </span>
                      `).join('')}
                    </div>
                  `;
                }

                contentArea.innerHTML = `
                  <div class="container pb-5 mt-4" style="max-width: 900px;">
                    <nav aria-label="breadcrumb" class="mb-4">
                      <ol class="breadcrumb">
                        <li class="breadcrumb-item"><a href="#" class="text-info text-decoration-none" onclick="document.querySelector('.user-profile-link[data-userid=\\'${blogData.user_id}\\']').click(); return false;">${escapeHTML(blogData.author)}</a></li>
                        <li class="breadcrumb-item active text-secondary" aria-current="page">Blog Post</li>
                      </ol>
                    </nav>
                    <h1 class="text-white fw-bold mb-4" style="font-size: clamp(2rem, 5vw, 3.5rem); line-height: 1.2;">${escapeHTML(decodeHTML(blogData.title))}</h1>
                    <div class="d-flex justify-content-between align-items-center mb-5 border-bottom border-secondary pb-4 flex-wrap gap-3">
                      <div class="d-flex align-items-center gap-3 user-profile-link" data-userid="${blogData.user_id}" data-artist="${encodeURIComponent(blogData.author)}" style="cursor: pointer;">
                         <img src="?action=get_profile_picture&id=${blogData.user_id}" class="rounded-circle" style="width: 45px; height: 45px; object-fit: cover;">
                         <div>
                           <div class="fw-bold text-white hover-underline">${escapeHTML(blogData.author)}</div>
                           <div class="text-secondary small">
                             ${new Date(blogData.created_at.replace(' ', 'T')+'Z').toLocaleDateString()} 
