                      </div>
                      ` : '<p class="text-secondary mb-4 small"><i class="bi bi-lock-fill me-1"></i> Log in to post comments and react to this blog.</p>'}
                      
                      <div class="d-flex justify-content-between align-items-center mb-4 ps-2">
                        <select id="blog-comments-sort-select" class="form-select form-select-sm w-auto bg-dark text-white border-secondary rounded-pill">
                          <option value="newest">Newest</option>
                          <option value="oldest">Oldest</option>
                          <option value="most_replied">Most Replied</option>
                        </select>
                      </div>
                      
                      <div id="blog-comments-list" class="d-flex flex-column gap-3"></div>
                      <div class="text-center mt-4 mb-2 d-none" id="load-more-blog-comments-container">
                        <button class="btn btn-outline-light btn-sm px-4 rounded-pill" id="load-more-blog-comments-btn">Load More Comments</button>
                      </div>
                    </div>
                  </div>
                `;

                window.activeBlogPublicId = blogData.public_id;
                window.refreshBlogComments(true);
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary"><i class="bi bi-x-circle-fill text-danger fs-1 d-block mb-3"></i>Blog not found or is private.</div>`;
              }
              allContentloaded = true;
              break;

            case 'get_blogs':
              if (currentUser && (!window.blogCategories || window.blogCategories.length === 0)) {
                window.blogCategories = await fetchData('?action=get_note_categories&type=blog') || [];
              }
              
              let blogFilter = currentView.filter || 'all';
              let blogTitle = 'My Blogs';
              if (blogFilter === 'public') blogTitle = 'Published Blogs';
              else if (blogFilter === 'private') blogTitle = 'Drafts / Private';
              else if (blogFilter !== 'all') {
                blogTitle = window.getCategoryName(blogFilter, 'blog') + ' Blogs';
              }
              updateContentTitle(blogTitle, !!currentUser);
              
              if (currentUser) {
                window.renderNoteCategories();
                contentArea.innerHTML = `
                  <div class="d-flex w-100 justify-content-between align-items-center mb-4 px-md-3 mt-2">
                    <div class="position-relative" style="max-width: 400px; width: 100%;">
                      <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                      <input type="text" id="blogs-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search blogs..." value="${escapeHTML(currentView.searchQuery || '')}">
                    </div>
                    <button class="btn btn-info text-dark rounded-pill px-4 shadow-sm fw-bold new-blog-btn ms-2 text-nowrap">
                      <i class="bi bi-plus-lg me-1"></i> New
                    </button>
                  </div>
                  <div id="blogs-grid" class="notes-grid px-md-3 mb-5" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); gap: 16px;"></div>
                `;
                
                document.getElementById('blogs-search-input').addEventListener('input', (e) => {
                  clearTimeout(window.notesSearchTimeout);
                  window.notesSearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                });

                if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);
                pageParams.set('filter', blogFilter);
                
                const blogs = await fetchData(`?action=get_blogs&${pageParams.toString()}`);
                const grid = document.getElementById('blogs-grid');
                window.currentBlogsList = blogs || [];
                window.selectedBlogIds = new Set();
                window.multiSelectBlogMode = false;
                
                if (blogs && blogs.length > 0) {
                  grid.innerHTML = blogs.map(b => `
                    <div class="note-card bg-dark text-white border-secondary hover-bg-dark blog-card-owner" data-id="${b.public_id}" style="border-radius: 12px; cursor: pointer; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-4px)'" onmouseout="this.style.transform='translateY(0)'">
                      <div class="d-flex justify-content-between align-items-center mb-2">
                        <span class="badge ${b.status === 'public' ? 'bg-success' : 'bg-secondary'}">${b.status === 'public' ? 'Published' : 'Draft/Private'}</span>
                        <span class="small text-secondary">${new Date(b.updated_at.replace(' ', 'T')+'Z').toLocaleDateString()}</span>
                      </div>
                      <div class="fw-bold fs-5 mb-2 text-truncate">${escapeHTML((b.title && b.title.trim() !== '') ? decodeHTML(b.title) : 'Untitled')}</div>
                      <div class="text-secondary small overflow-hidden" style="display: -webkit-box; -webkit-line-clamp: 4; -webkit-box-orient: vertical;">${escapeHTML(decodeHTML(b.content).replace(/<[^>]*>?/gm, '').replace(/[^a-zA-Z0-9\s.,!?]/g, ''))}</div>
                      <div class="mt-auto pt-3 d-flex justify-content-between align-items-center">
                        ${b.category && b.category !== 'all' ? `<span class="note-chip">${escapeHTML(window.getCategoryName(b.category, 'blog'))}</span>` : '<span></span>'}
                      </div>
                    </div>
                  `).join('');
                  
                  window.bindBlogCardEvents(grid);
                } else {
                  grid.style.display = 'block';
                  if (currentView.searchQuery) {
                    grid.innerHTML = '<div class="text-center text-secondary py-5">No blogs found.</div>';
                  } else {
                    grid.innerHTML = '<div class="text-center text-secondary py-5">You haven\'t written any blogs yet. Click "New" to start!</div>';
                  }
                }
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to write and manage blogs.</div>`;
              }
              break;

            case 'get_notes':
              let noteFilter = currentView.filter || 'all';
              let filterName = noteFilter === 'all' ? 'All Notes' : (noteFilter === 'starred' ? 'Starred' : 'Category');
              if (noteFilter !== 'all' && noteFilter !== 'starred') {
                const catText = document.querySelector(`.note-filter-link[data-filter="${noteFilter}"]`)?.textContent;
                if (catText) filterName = catText.trim();
              }
              if (noteFilter.startsWith('proj_')) filterName = 'Workspace Notes';
              updateContentTitle(filterName, !!currentUser);

              if (currentUser) {
                if (!window.noteCategories || window.noteCategories.length === 0) {
                  window.noteCategories = await fetchData('?action=get_note_categories&type=note') || [];
                }
                if (!window.taskCategories || window.taskCategories.length === 0) {
                  window.taskCategories = await fetchData('?action=get_note_categories&type=task') || [];
                }
                window.renderNoteCategories();

                contentArea.innerHTML = `
                  <div class="d-flex w-100 justify-content-between align-items-center mb-4 px-md-3">
                    <div class="position-relative" style="max-width: 400px; width: 100%;">
                      <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                      <input type="text" id="notes-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search notes..." value="${escapeHTML(currentView.searchQuery || '')}">
                    </div>
                    <button class="btn btn-danger rounded-pill px-4 shadow-sm fw-bold new-note-btn ms-2 text-nowrap">
                      <i class="bi bi-plus-lg me-1"></i> New
                    </button>
                  </div>
                  <div id="notes-grid" class="notes-grid px-md-3 mb-5" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px;"></div>
                `;

                document.getElementById('notes-search-input').addEventListener('input', (e) => {
                  clearTimeout(window.notesSearchTimeout);
                  window.notesSearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                });

                if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);
                pageParams.set('filter', noteFilter);
                
                const notes = await fetchData(`?action=get_notes&${pageParams.toString()}`);
                const grid = document.getElementById('notes-grid');
                window.currentNotesList = notes || [];
                window.selectedNoteIds = new Set();
                window.multiSelectNoteMode = false;
                
                if (notes && notes.length > 0) {
                  grid.innerHTML = notes.map(n => {
                    // Force decode &#039; into standard strings so preview renders them normally
                    const decodedTitle = decodeHTML(n.title || '');
                    const decodedContent = decodeHTML(n.content || '');
                    const cleanContent = decodedContent.replace(/<[^>]*>?/gm, ''); // Strip html for preview
                    const catName = window.getCategoryName(n.category);
                    return `
                      <div class="note-card note-card-item" data-id="${n.id}">
                        ${n.starred == 1 ? '<button class="card-star-btn starred"><i class="bi bi-star-fill text-warning"></i></button>' : '<button class="card-star-btn"><i class="bi bi-star"></i></button>'}
                        <div class="note-card-title">${escapeHTML(decodedTitle || cleanContent.split(/\s+/).slice(0, 5).join(' ') || 'Untitled Note')}</div>
                        <div class="note-card-body">${escapeHTML(cleanContent)}</div>
                        <div class="note-card-footer">
                          <span>${new Date(n.updated_at.replace(' ', 'T') + 'Z').toLocaleDateString()}</span>
                          ${n.category && n.category !== 'all' ? `<span class="note-chip">${escapeHTML(catName)}</span>` : ''}
                        </div>
                      </div>
                    `;
                  }).join('');
                  
                  window.bindNoteCardEvents = (container, isTask = false) => {
                    const selector = isTask ? '.task-card-wrapper:not(.bound)' : '.note-card-item:not(.bound)';
                    container.querySelectorAll(selector).forEach(card => {
                      card.classList.add('bound');
                      let pressTimer;
                      let startX = 0, startY = 0;

                      const doToggle = () => {
                        const now = Date.now();
                        // Prevent double-toggle if contextmenu or click fires right after the touch timer
                        if (card.dataset.lastToggle && now - parseInt(card.dataset.lastToggle) < 800) {
                          return; 
                        }
                        card.dataset.lastToggle = now;
                        toggleNoteMultiSelect(card.dataset.id);
                      };
                      
                      // Touch (Mobile) long-press
                      const startTouch = (e) => { 
                        if (e.target.closest('.card-star-btn')) return;
                        if (e.touches && e.touches.length > 0) {
                          startX = e.touches[0].clientX; startY = e.touches[0].clientY;
                        }
                        pressTimer = setTimeout(() => { 
                          doToggle(); 
                          if (navigator.vibrate) navigator.vibrate(50);
                        }, 400); 
                      };
                      const cancelTouch = () => clearTimeout(pressTimer);
                      const moveTouch = (e) => {
                        if (!e.touches) return;
                        const dx = Math.abs(e.touches[0].clientX - startX);
                        const dy = Math.abs(e.touches[0].clientY - startY);
                        if (dx > 10 || dy > 10) clearTimeout(pressTimer);
                      };
                      
                      card.addEventListener('touchstart', startTouch, { passive: true });
                      card.addEventListener('touchend', cancelTouch);
                      card.addEventListener('touchcancel', cancelTouch);
                      card.addEventListener('touchmove', moveTouch, { passive: true });

                      // Desktop Right-Click (and mobile simulated context menu)
                      card.addEventListener('contextmenu', (e) => {
                        if (e.target.closest('.card-star-btn')) return;
                        e.preventDefault(); 
                        doToggle();
                      });
                    });
                  };
                  window.bindNoteCardEvents(grid);

                } else {
                  grid.style.display = 'block';
                  grid.innerHTML = '<div class="text-center text-secondary py-5">No notes found.</div>';
                }
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your notes.</div>`;
              }
              break;

            case 'get_tasks':
              let taskFilter = currentView.filter || 'all';
              let taskFilterName = taskFilter === 'all' ? 'All Tasks' : (taskFilter === 'starred' ? 'Starred Tasks' : 'Category Tasks');
              if (taskFilter.startsWith('proj_')) taskFilterName = 'Workspace Tasks';
              updateContentTitle(taskFilterName, !!currentUser);

              if (currentUser) {
                if (!window.taskCategories || window.taskCategories.length === 0) {
                  window.taskCategories = await fetchData('?action=get_note_categories&type=task') || [];
                }
                if (!window.noteCategories || window.noteCategories.length === 0) {
                  window.noteCategories = await fetchData('?action=get_note_categories&type=note') || [];
                }
                window.renderNoteCategories();

                contentArea.innerHTML = `
                  <div class="d-flex w-100 justify-content-between align-items-center mb-4 px-md-3">
                    <div class="position-relative" style="max-width: 400px; width: 100%;">
                      <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                      <input type="text" id="tasks-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search tasks..." value="${escapeHTML(currentView.searchQuery || '')}">
                    </div>
                    <button class="btn btn-danger rounded-pill px-4 shadow-sm fw-bold new-task-btn ms-2 text-nowrap">
                      <i class="bi bi-plus-lg me-1"></i> New
                    </button>
                  </div>
                  <div id="tasks-grid" class="notes-grid px-md-3 mb-5" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px;"></div>
                `;

                document.getElementById('tasks-search-input').addEventListener('input', (e) => {
                  clearTimeout(window.notesSearchTimeout);
                  window.notesSearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                });

                if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);
                pageParams.set('filter', taskFilter);
                
                const tasks = await fetchData(`?action=get_tasks&${pageParams.toString()}`);
                const grid = document.getElementById('tasks-grid');
                window.currentTasksList = tasks || [];
                window.selectedNoteIds = new Set();
                window.multiSelectNoteMode = false;
                
                if (tasks && tasks.length > 0) {
                  grid.innerHTML = tasks.map(t => {
                    let items = [];
                    try { items = JSON.parse(t.items); } catch(e) {}
                    const catName = window.getCategoryName(t.category);
                    
                    const itemsHtml = items.slice(0, 4).map(item => `
                      <div class="task-card-item ${item.completed ? 'completed' : ''}">
                        <i class="bi ${item.completed ? 'bi-check-square-fill text-success' : 'bi-square'}"></i>
                        <span style="word-break: break-word;">${escapeHTML(item.text)}</span>
                      </div>
                    `).join('') + (items.length > 4 ? `<div class="text-secondary small mt-1">+${items.length - 4} more</div>` : '');

                    return `
                      <div class="note-card task-card-wrapper" data-id="${t.id}">
                        ${t.starred == 1 ? '<button class="card-star-btn starred"><i class="bi bi-star-fill text-warning"></i></button>' : '<button class="card-star-btn"><i class="bi bi-star"></i></button>'}
                        <div class="note-card-title">${escapeHTML(decodeHTML(t.title) || 'Untitled Task List')}</div>
                        <div class="flex-grow-1 overflow-hidden mt-2">${itemsHtml}</div>
                        <div class="note-card-footer mt-3">
                          <span>${new Date(t.updated_at.replace(' ', 'T') + 'Z').toLocaleDateString()}</span>
                          ${t.category && t.category !== 'all' ? `<span class="note-chip">${escapeHTML(catName)}</span>` : ''}
                        </div>
                      </div>
                    `;
                  }).join('');
                  
                  window.bindNoteCardEvents(grid, true);

                } else {
                  grid.style.display = 'block';
                  grid.innerHTML = '<div class="text-center text-secondary py-5">No tasks found.</div>';
                }
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to see your tasks.</div>`;
              }
              break;

            case 'get_community':
              updateContentTitle('Community', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="d-flex flex-wrap align-items-center justify-content-between p-3 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background-color: var(--ytm-surface-2); border: 1px solid #333;">
                    <div class="text-white fw-bold fs-5 mb-3 mb-md-0 d-flex align-items-center"><i class="bi bi-people text-info me-3 fs-3"></i> Community</div>
                    <div class="d-flex gap-2 align-items-center w-100 mt-2">
                      <input type="text" id="community-search-input" class="form-control bg-dark text-white border-secondary" placeholder="Search posts..." value="${escapeHTML(currentView.searchQuery || '')}">
                    </div>
                  </div>
                  <div class="mx-md-3 mb-5 mt-2">
                    <div class="d-flex gap-3">
                      <img src="?action=get_profile_picture&id=${currentUser.id}" class="rounded-circle shadow-sm flex-shrink-0 d-none d-sm-block mt-1 border border-secondary border-opacity-25" style="width: 48px; height: 48px; object-fit: cover;">
                      <div class="flex-grow-1 rich-input-container" data-target-id="community-post-input">
                        <form id="community-post-form" class="bg-transparent position-relative mb-2">
                          <input type="hidden" id="community-parent-id" value="">
                          <div class="d-flex flex-column bg-dark rounded-4 p-2 shadow-inner" style="border: 1px solid rgba(255,255,255,0.12); transition: border-color 0.3s;" onfocusin="this.style.borderColor='#3ea6ff'" onfocusout="this.style.borderColor='rgba(255,255,255,0.12)'">
                            <div class="editor-toolbar d-flex flex-wrap align-items-center gap-1 mb-2 px-3 py-2 rounded-4 shadow-sm" style="background-color: #212121; border: 1px solid rgba(255,255,255,0.05);">
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="bold" title="Bold"><i class="bi bi-type-bold fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="italic" title="Italic"><i class="bi bi-type-italic fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="strikethrough" title="Strikethrough"><i class="bi bi-type-strikethrough fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="heading" title="Heading"><i class="bi bi-type-h1 fs-6"></i></button>
                              <div class="vr bg-secondary mx-2 opacity-25" style="width: 2px; border-radius: 2px; min-height: 20px;"></div>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="ul" title="Bullet List"><i class="bi bi-list-ul fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="ol" title="Numbered List"><i class="bi bi-list-ol fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="task" title="Task List"><i class="bi bi-ui-checks fs-6"></i></button>
                              <div class="vr bg-secondary mx-2 opacity-25" style="width: 2px; border-radius: 2px; min-height: 20px;"></div>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="quote" title="Blockquote"><i class="bi bi-quote fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="code" title="Code Block"><i class="bi bi-code-slash fs-6"></i></button>
                              <div class="vr bg-secondary mx-2 opacity-25" style="width: 2px; border-radius: 2px; min-height: 20px;"></div>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="table" title="Table"><i class="bi bi-table fs-6"></i></button>
                              <div class="vr bg-secondary mx-2 opacity-25" style="width: 2px; border-radius: 2px; min-height: 20px;"></div>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="align-left" title="Align Left"><i class="bi bi-text-left fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="align-center" title="Align Center"><i class="bi bi-text-center fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="align-right" title="Align Right"><i class="bi bi-text-right fs-6"></i></button>
                              <div class="vr bg-secondary mx-2 opacity-25" style="width: 2px; border-radius: 2px; min-height: 20px;"></div>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="link" title="Link"><i class="bi bi-link-45deg fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="image" title="Image"><i class="bi bi-image fs-6"></i></button>
                              <button type="button" class="btn btn-sm btn-link text-secondary border-0 hover-white text-decoration-none" data-md="video" title="Video"><i class="bi bi-camera-video fs-6"></i></button>
                            </div>
                            <div class="d-flex align-items-end">
                              <textarea id="community-post-input" class="form-control bg-transparent text-white border-0 shadow-none modern-custom-scroll" placeholder="Start typing here... (Markdown & Task-lists supported)" maxlength="5000" rows="4" required style="resize: none; min-height: 120px; max-height: 400px; padding: 10px 14px; font-size: 1rem; line-height: 1.5;" oninput="this.style.height = ''; this.style.height = Math.max(120, this.scrollHeight) + 'px'"></textarea>
                              <button type="submit" class="btn btn-info text-dark rounded-circle d-flex align-items-center justify-content-center m-1 flex-shrink-0 shadow-sm" style="width: 44px; height: 44px; transition: transform 0.2s;" onmouseover="this.style.transform='scale(1.1)'" onmouseout="this.style.transform='scale(1)'"><i class="bi bi-send-fill fs-5"></i></button>
                            </div>
                          </div>
                        </form>
                      </div>
                    </div>
                    <div class="d-flex justify-content-end align-items-center mb-4 mt-3 ps-2">
                      <select id="community-sort-select" class="form-select form-select-sm w-auto bg-dark text-white border-secondary rounded-pill">
                        <option value="newest" ${currentView.sort === 'newest' ? 'selected' : ''}>Newest</option>
                        <option value="most_liked" ${currentView.sort === 'most_liked' ? 'selected' : ''}>Most Liked</option>
                        <option value="most_replied" ${currentView.sort === 'most_replied' ? 'selected' : ''}>Most Replied</option>
                        <option value="following" ${currentView.sort === 'following' ? 'selected' : ''}>Following</option>
                      </select>
                    </div>
                  </div>
                  <div id="community-feed" class="d-flex flex-column gap-3 mx-md-3 mb-4"></div>`;
                  
                document.getElementById('community-search-input').addEventListener('input', (e) => {
                  clearTimeout(window.communitySearchTimeout);
                  window.communitySearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                });
                
                document.getElementById('community-sort-select').addEventListener('change', (e) => {
                  currentView.sort = e.target.value;
                  loadView(currentView);
                });

                document.getElementById('community-post-form').addEventListener('submit', async e => {
                  e.preventDefault();
                  const form = e.target;
                  const submitBtn = form.querySelector('button[type="submit"]');
                  if (!window.checkPostCooldown(submitBtn)) return;
                  
                  const input = document.getElementById('community-post-input');
                  const parentId = document.getElementById('community-parent-id').value;
                  
                  if (submitBtn) {
                    submitBtn.dataset.origHtml = submitBtn.innerHTML;
                    submitBtn.disabled = true;
                    submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span>';
                  }
                  
                  await fetchData('?action=create_community_post', { method:'POST', body: JSON.stringify({content: input.value, parent_id: parentId || null}) });
                  
                  if (submitBtn) {
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = submitBtn.dataset.origHtml;
                  }
                  
                  window.lastPostTime = Date.now();
                  input.value = '';
                  document.getElementById('community-parent-id').value = '';
                  input.placeholder = "What's on your mind? (use @ to mention)";
                  loadView(currentView);
                });

                if (currentView.searchQuery) pageParams.append('q', currentView.searchQuery);
                const posts = await fetchData(`?action=get_community&${pageParams.toString()}`);
                const feed = document.getElementById('community-feed');
                
                if (posts && posts.length > 0) {
                  const buildCommunityTree = (postsList, parent = null) => {
                    const children = postsList.filter(p => p.parent_id == parent);
                    if (children.length === 0) return '';
                    
                    const renderContent = (raw) => {
                      let decoded = decodeHTML(raw || '');
                      let parsed = parseUserText(decoded);
                      if (typeof marked !== 'undefined') {
                        try { parsed = marked.parse(parsed); } catch(e) {}
                      }
                      return `<div class="rich-comment-box" style="font-size: 1.05rem; line-height: 1.6; word-break: break-word; color: #f1f1f1;">${parsed}</div>`;
                    };

                    const styleInjection = parent === null ? `
                      <style>
                        .rich-comment-box img, .rich-comment-box video, .rich-comment-box iframe { max-width: 100%; max-height: 500px; border-radius: 12px; margin: 12px 0; box-shadow: 0 8px 30px rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.1); object-fit: contain; background: #000; transition: transform 0.3s ease; display: block; }
                        .rich-comment-box img:hover { transform: scale(1.02); }
                        .rich-comment-box a { color: #3ea6ff; text-decoration: none; font-weight: 500; padding: 2px 4px; border-radius: 4px; transition: all 0.2s ease; }
                        .rich-comment-box a:hover { color: #fff; background: rgba(62,166,255,0.2); }
                        .rich-comment-box blockquote { border-left: 4px solid #10b981; padding: 12px 20px; margin: 16px 0; background: linear-gradient(90deg, rgba(16,185,129,0.1) 0%, transparent 100%); border-radius: 0 12px 12px 0; color: #ddd; font-style: italic; font-size: 1.05rem; }
                        .rich-comment-box pre { background: #080808; padding: 16px; border-radius: 12px; border: 1px solid #222; overflow-x: auto; margin: 16px 0; box-shadow: inset 0 4px 10px rgba(0,0,0,0.5); }
                        .rich-comment-box code { font-family: 'Consolas', 'Courier New', monospace; background: rgba(255,255,255,0.08); padding: 3px 6px; border-radius: 6px; font-size: 0.85em; color: #ff8888; }
                        .rich-comment-box ul, .rich-comment-box ol { padding-left: 24px; margin-bottom: 12px; }
                        .rich-comment-box li { margin-bottom: 6px; }
                        .rich-comment-box p { margin-bottom: 12px; }
                        .rich-comment-box p:last-child { margin-bottom: 0; }
                        .rich-comment-box .mention-link { color: #ff4da6; background: rgba(255,77,166,0.15); padding: 2px 8px; border-radius: 12px; transition: 0.2s; border: 1px solid rgba(255,77,166,0.3); display: inline-block; font-weight: bold; }
                        .rich-comment-box .mention-link:hover { background: rgba(255,77,166,0.3); color: #fff; transform: translateY(-2px); box-shadow: 0 4px 12px rgba(255,77,166,0.3); }
                        .phpmusic-comments-action-btn { transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1); border-radius: 50px; padding: 6px 16px; font-weight: 600; display: inline-flex; align-items: center; justify-content: center; gap: 8px; background: rgba(255,255,255,0.05); color: #aaa; border: 1px solid rgba(255,255,255,0.02); cursor: pointer; backdrop-filter: blur(4px); }
                        .phpmusic-comments-action-btn:hover { background: rgba(255,255,255,0.15); color: #fff; transform: scale(1.05); border-color: rgba(255,255,255,0.1); }
                        .phpmusic-comments-action-btn:active { transform: scale(0.95); }
                        .phpmusic-comments-action-btn.active-like { color: #fff; background: rgba(255,255,255,0.15); border-color: rgba(255,255,255,0.3); text-shadow: 0 0 8px rgba(255,255,255,0.3); }
                        .phpmusic-comments-action-btn.active-dislike { color: #fff; background: rgba(255,255,255,0.15); border-color: rgba(255,255,255,0.3); text-shadow: 0 0 8px rgba(255,255,255,0.3); } }
                        @keyframes slideFadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
                        .comm-card { background: linear-gradient(145deg, rgba(30,30,30,0.8) 0%, rgba(15,15,15,0.95) 100%); border: 1px solid rgba(255,255,255,0.08); box-shadow: 0 8px 32px rgba(0,0,0,0.4); border-radius: 20px; margin-bottom: 24px; transition: transform 0.2s, box-shadow 0.2s; }
                        .comm-card:hover { transform: translateY(-2px); box-shadow: 0 12px 40px rgba(0,0,0,0.6); border-color: rgba(255,255,255,0.12); }
                      </style>
                    ` : '';

                    if (parent === null) {
                      return styleInjection + children.map(p => `
                        <div class="comm-card p-4" style="animation: slideFadeIn 0.4s ease forwards;">
                          <div class="d-flex justify-content-between align-items-start mb-3">
                            <div class="d-flex align-items-center gap-3 ${p.is_disabled ? '' : 'user-profile-link'}" data-userid="${p.user_id}" data-artist="${encodeURIComponent(p.artist)}" style="${p.is_disabled ? 'cursor: default;' : 'cursor: pointer;'}" ${p.is_disabled ? '' : 'title="View Profile"'}>
                              <div class="position-relative">
                                <img src="?action=get_profile_picture&id=${p.user_id}" class="rounded-circle shadow-lg" style="width:52px; height:52px; object-fit:cover; border: 2px solid rgba(255,255,255,0.1); transition: transform 0.3s;" onmouseover="this.style.transform='scale(1.1)'" onmouseout="this.style.transform='scale(1)'">
                                ${p.user_id == currentUser?.id ? `<span class="position-absolute bottom-0 end-0 bg-success border border-secondary rounded-circle shadow-sm" style="width: 14px; height: 14px; z-index: 2;" title="You"></span>` : ''}
                              </div>
                              <div class="d-flex flex-column justify-content-center">
                                <div class="fw-bolder text-white hover-underline" style="font-size: 1.1rem; letter-spacing: 0.3px;">${escapeHTML(p.artist)}</div>
                                <span class="text-secondary fw-medium d-flex align-items-center gap-1" style="font-size: 0.8rem;">
                                  <i class="bi bi-clock"></i> ${timeAgo(p.created_at)}
                                </span>
                              </div>
                            </div>
                            ${(currentUser && (currentUser.id == p.user_id || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `
                            <div class="position-relative flex-shrink-0 ms-2 custom-opt-dropdown">
                              <button class="btn btn-link text-secondary p-0 border-0 custom-opt-toggle" type="button"><i class="bi bi-three-dots-vertical fs-5"></i></button>
                              <ul class="dropdown-menu dropdown-menu-dark shadow-lg border-secondary custom-opt-menu" style="position: absolute; right: 0; top: 100%; display: none; z-index: 1060; min-width: 150px;">
                                <li><button class="dropdown-item edit-post-btn" data-id="${p.id}" data-content="${escapeHTML(p.content)}"><i class="bi bi-pencil"></i> Edit</button></li>
                                <li><button class="dropdown-item text-danger delete-post-btn" data-id="${p.id}"><i class="bi bi-trash"></i> Delete</button></li>
                              </ul>
                            </div>` : ''}
                          </div>
                          
                          <div class="mb-4 text-light" style="font-size: 1.1rem; line-height: 1.6;">
                            ${renderContent(p.content)}
                          </div>
                          
                          <div class="d-flex gap-2 align-items-center pt-3 border-top border-secondary border-opacity-25 flex-wrap">
                            <button class="phpmusic-comments-action-btn community-react-btn ${p.my_reaction === 'like' ? 'active-like' : ''}" data-id="${p.id}" data-reaction="like" title="Like">
                              <i class="bi ${p.my_reaction === 'like' ? 'bi-hand-thumbs-up-fill' : 'bi-hand-thumbs-up'} fs-5"></i> 
                              <span style="font-size: 1rem;">${p.like_count}</span>
                            </button>
                            
                            <button class="phpmusic-comments-action-btn community-react-btn ${p.my_reaction === 'dislike' ? 'active-dislike' : ''}" data-id="${p.id}" data-reaction="dislike" title="Dislike">
                              <i class="bi ${p.my_reaction === 'dislike' ? 'bi-hand-thumbs-down-fill' : 'bi-hand-thumbs-down'} fs-5"></i> 
                              <span style="font-size: 1rem;">${p.dislike_count}</span>
                            </button>
                            
                            <button class="phpmusic-comments-action-btn community-reply-btn" data-id="${p.id}" data-username="${escapeHTML(p.artist)}" data-content="${escapeHTML(p.content)}" title="Reply">
                              <i class="bi bi-chat-left-text fs-5"></i> 
                              <span style="font-size: 1rem;">Reply ${children.filter(ch => ch.parent_id == p.id).length > 0 ? `(${children.filter(ch => ch.parent_id == p.id).length})` : ''}</span>
                            </button>
                          </div>
                          
                          <div class="mt-3">${buildCommunityTree(postsList, p.id)}</div>
                        </div>`).join('');
                    } else {
                      const renderReplyContent = (raw) => {
                        let decoded = decodeHTML(raw || '');
                        let parsed = parseUserText(decoded);
                        if (typeof marked !== 'undefined') {
                          try { parsed = marked.parse(parsed); } catch(e) {}
                        }
                        return `<div class="rich-comment-box" style="font-size: 0.95rem; line-height: 1.5; word-break: break-word; color: #e1e1e1;">${parsed}</div>`;
                      };

                      const repliesHtml = children.map(p => `
                        <div class="d-flex gap-3 mb-3 position-relative border-start border-top border-dark border-2 rounded-4 p-2" style="animation: slideFadeIn 0.3s ease forwards; --bs-border-opacity: .5;">
                          <div class="d-flex flex-column align-items-center" style="width: 36px; flex-shrink: 0;">
                            <img src="?action=get_profile_picture&id=${p.user_id}" 
                                 class="rounded-circle shadow-sm ${p.is_disabled ? '' : 'user-profile-link'}" 
                                 data-userid="${p.user_id}" 
                                 data-artist="${encodeURIComponent(p.artist)}" 
                                 style="width:36px; height:36px; object-fit:cover; cursor:${p.is_disabled ? 'default' : 'pointer'}; border: 1px solid rgba(255,255,255,0.15); transition: transform 0.3s;"
                                 onmouseover="this.style.transform='scale(1.15)'"
                                 onmouseout="this.style.transform='scale(1)'">
                            ${children.filter(ch => ch.parent_id == p.id).length > 0 ? `<div class="mt-2" style="width: 2px; flex-grow: 1; background: linear-gradient(to bottom, rgba(255,255,255,0.1), transparent); border-radius: 2px;"></div>` : ''}
                          </div>
                          
                          <div class="flex-grow-1" style="min-width: 0;">
                            <div class="d-flex justify-content-between align-items-start mb-1">
                              <div class="d-flex align-items-center flex-wrap gap-2">
                                <span class="fw-bold text-white ${p.is_disabled ? '' : 'user-profile-link'}" 
                                      data-userid="${p.user_id}" 
                                      data-artist="${encodeURIComponent(p.artist)}" 
                                      style="font-size: 0.9rem; cursor:${p.is_disabled ? 'default' : 'pointer'}; text-shadow: 0 1px 2px rgba(0,0,0,0.5);"
                                      onmouseover="this.style.textDecoration='underline'"
                                      onmouseout="this.style.textDecoration='none'">
                                  ${escapeHTML(p.artist)}
                                </span>
                                <span class="text-secondary d-flex align-items-center gap-1 fw-medium" style="font-size: 0.7rem; opacity: 0.8;">
                                  <i class="bi bi-clock"></i> ${timeAgo(p.created_at)}
                                </span>
                              </div>
                              ${(currentUser && (currentUser.id == p.user_id || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `
                                <div class="position-relative flex-shrink-0 ms-2 custom-opt-dropdown">
                                  <button class="btn btn-link text-secondary p-0 border-0 custom-opt-toggle" type="button"><i class="bi bi-three-dots-vertical fs-5"></i></button>
                                  <ul class="dropdown-menu dropdown-menu-dark shadow-lg border-secondary custom-opt-menu" style="position: absolute; right: 0; top: 100%; display: none; z-index: 1060; min-width: 150px;">
                                    <li><button class="dropdown-item edit-post-btn" data-id="${p.id}" data-content="${escapeHTML(p.content)}"><i class="bi bi-pencil"></i> Edit</button></li>
                                    <li><button class="dropdown-item text-danger delete-post-btn" data-id="${p.id}"><i class="bi bi-trash"></i> Delete</button></li>
                                  </ul>
                                </div>
                              ` : ''}
                            </div>
                            
                            <div class="p-2 mb-2">
                              ${renderReplyContent(p.content)}
                            </div>
                            
                            <div class="d-flex align-items-center flex-wrap gap-2 mt-1">
                              <button class="phpmusic-comments-action-btn community-react-btn ${p.my_reaction === 'like' ? 'active-like' : ''}" data-id="${p.id}" data-reaction="like" style="padding: 4px 12px; font-size: 0.85rem;">
                                <i class="bi ${p.my_reaction === 'like' ? 'bi-hand-thumbs-up-fill' : 'bi-hand-thumbs-up'} fs-6"></i>
                                <span>${p.like_count || 0}</span>
                              </button>
                              
                              <button class="phpmusic-comments-action-btn community-react-btn ${p.my_reaction === 'dislike' ? 'active-dislike' : ''}" data-id="${p.id}" data-reaction="dislike" style="padding: 4px 12px; font-size: 0.85rem;">
                                <i class="bi ${p.my_reaction === 'dislike' ? 'bi-hand-thumbs-down-fill' : 'bi-hand-thumbs-down'} fs-6"></i>
                                <span>${p.dislike_count || 0}</span>
                              </button>
                              
                              <button class="phpmusic-comments-action-btn community-reply-btn" data-id="${p.id}" data-username="${escapeHTML(p.artist)}" data-content="${escapeHTML(p.content)}" style="padding: 4px 12px; font-size: 0.85rem;">
                                <i class="bi bi-chat-left-text fs-6"></i> Reply
                              </button>
                            </div>
                            
                            <div class="mt-3">${buildCommunityTree(postsList, p.id)}</div>
                          </div>
                        </div>
                      `).join('');
                      
                      return `
                        <div class="ps-3 ms-2 position-relative mt-2" style="border-left: 2px solid rgba(255,255,255,0.1); border-radius: 0 0 0 12px;">
                          <button class="btn btn-link text-info text-decoration-none fw-bold d-inline-flex align-items-center gap-2 toggle-replies-btn mb-3 p-0" data-target="comm-reply-container-${parent}" style="font-size: 0.95rem; transition: 0.2s;" onmouseover="this.style.textShadow='0 0 12px rgba(0, 188, 212, 0.6)'" onmouseout="this.style.textShadow='none'">
                            <div class="d-flex align-items-center justify-content-center bg-info text-dark rounded-circle shadow-sm" style="width: 24px; height: 24px;">
                              <i class="bi bi-chevron-down" style="font-size: 0.85rem;"></i>
                            </div>
                            View ${children.length} ${children.length === 1 ? 'reply' : 'replies'}
                          </button>
                          <div id="comm-reply-container-${parent}" class="d-none mt-2 pt-2">
                            ${repliesHtml}
                          </div>
                        </div>
                      `;
                    }
                  };
                  
                  feed.innerHTML = buildCommunityTree(posts);
                  setTimeout(window.checkMediaCache, 100);
                } else {
                  feed.innerHTML = '<div class="text-center text-secondary py-5">No posts found. Be the first!</div>';
                }
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to view the community.</div>`;
              }
              break;
            case 'get_recommendations':
              updateContentTitle('For You', !!currentUser);
              if (currentUser) {
                data = await fetchData(`?action=get_recommendations`);
                renderRecommendations(data);
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to get recommendations.</div>`;
              }
              allContentloaded = true;
              break;
            case 'get_categories':
              updateContentTitle('Categories', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="d-flex flex-wrap align-items-center justify-content-between p-3 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background-color: var(--ytm-surface-2); border: 1px solid #333;">
                    <div class="text-white fw-bold fs-5 mb-3 mb-md-0 d-flex align-items-center"><i class="bi bi-folder-fill text-warning me-3 fs-3"></i> My Categories</div>
                    <button class="btn btn-warning text-dark rounded-pill px-4 fw-medium shadow-sm edit-cat-btn-global" data-type="${currentView.filter || 'note'}" data-view="manage_note_categories"><i class="bi bi-tags me-1"></i> Edit Categories</button>
                  </div>
                `;
                data = await fetchData(`?action=${currentView.type}&${pageParams.toString()}`);
                renderGrid(data, currentView.type, true); 
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">Log in to view categories.</div>`;
              }
              break;
            case 'get_my_apis':
              updateContentTitle('My APIs', !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="d-flex flex-wrap align-items-center justify-content-between p-3 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background-color: var(--ytm-surface-2); border: 1px solid #333;">
                    <div class="text-white fw-bold fs-5 mb-3 mb-md-0 d-flex align-items-center"><i class="bi bi-code-slash text-danger me-3 fs-3"></i> My APIs</div>
                    <div class="d-flex gap-2 flex-wrap align-items-center">
                      <div class="position-relative">
                        <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                        <input type="text" id="api-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search APIs..." value="${escapeHTML(currentView.searchQuery || '')}">
                      </div>
                      <button class="btn btn-danger rounded-pill px-4 fw-bold shadow-sm" id="request-api-btn"><i class="bi bi-plus-lg me-1"></i> Request Key</button>
                    </div>
                  </div>
                  <div id="apis-list-container" class="mx-md-3 mb-5 d-flex flex-column gap-3"></div>
                `;
                
                document.getElementById('api-search-input').addEventListener('input', (e) => {
                  clearTimeout(window.apiSearchTimeout);
                  window.apiSearchTimeout = setTimeout(() => {
                    currentView.searchQuery = e.target.value;
                    loadView(currentView);
                  }, 400);
                });

                if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);

                document.getElementById('request-api-btn').addEventListener('click', async () => {
                  const name = prompt("Enter a name for your API Key (e.g. Discord Bot):");
                  if (name && name.trim() !== '') {
                    const res = await fetchData('?action=request_api', { method: 'POST', body: JSON.stringify({ name }) });
                    if (res) {
                      showToast(res.message, res.status);
                      if (res.status === 'success') loadView(currentView);
                    }
                  }
                });
                
                data = await fetchData(`?action=get_my_apis&${pageParams.toString()}`);
                if (data && data.length > 0) {
                  document.getElementById('apis-list-container').innerHTML = data.map(api => `
                    <div class="card bg-dark border-secondary text-white p-3 shadow-sm hover-bg-dark" style="border-radius: 12px;">
                      <div class="d-flex justify-content-between align-items-center mb-3">
                        <h5 class="fw-bold m-0"><i class="bi bi-terminal text-info me-2"></i>${escapeHTML(api.name)}</h5>
                        <button class="btn btn-sm btn-outline-danger delete-api-btn" data-id="${api.id}"><i class="bi bi-trash"></i></button>
                      </div>
                      <div class="d-flex flex-column gap-2 small text-secondary">
                        <div><strong>Status:</strong> <span class="badge ${api.status === 'active' ? 'bg-success' : (api.status === 'pending' ? 'bg-info text-dark' : 'bg-danger')}">${api.status.toUpperCase()}</span></div>
                        <div><strong>Token:</strong> ${api.status === 'pending' ? '<code class="text-info fs-6">Waiting for Admin Verification...</code>' : `<code class="text-info fs-6">${escapeHTML(api.token)}</code><button class="btn btn-sm btn-outline-info py-0 px-2 ms-2 copy-api-token-btn" data-token="${escapeHTML(api.token)}" title="Copy Key"><i class="bi bi-clipboard"></i></button>`}</div>
                        <div><strong>Uses:</strong> ${api.uses} / 1000 this month</div>
                        <div><strong>Expires:</strong> ${api.expires_at ? new Date(api.expires_at.replace(' ', 'T')+'Z').toLocaleDateString() : 'Never'}</div>
                      </div>
                    </div>
                  `).join('');
                  
                  document.querySelectorAll('.delete-api-btn').forEach(btn => {
                    btn.addEventListener('click', async () => {
                      if (confirm('Are you sure you want to delete this API key permanently? Any apps using it will break.')) {
                        const res = await fetchData('?action=delete_my_api', { method: 'POST', body: JSON.stringify({ id: btn.dataset.id }) });
                        if (res && res.status === 'success') {
                          showToast('API Key deleted.', 'success');
                          loadView(currentView);
                        }
                      }
                    });
                  });
                } else {
                  document.getElementById('apis-list-container').style.display = 'block';
                  if (currentView.searchQuery) {
                    document.getElementById('apis-list-container').innerHTML = '<div class="text-center text-secondary py-5">No APIs found matching your search.</div>';
                  } else {
                    document.getElementById('apis-list-container').innerHTML = '<div class="text-center p-5 text-secondary">You do not have any API Keys yet. Request one above!</div>';
                  }
                }
              }
              break;

            case 'get_projects': {
              const pType = currentView.filter || 'note';
              const pTitle = pType === 'task' ? 'Task Projects' : (pType === 'blog' ? 'Blog Projects' : 'Note Projects');
              const pIcon = pType === 'task' ? 'bi-check2-square text-success' : (pType === 'blog' ? 'bi-journal-richtext text-info' : 'bi-journal-text text-warning');
              
              updateContentTitle(pTitle, !!currentUser);
              if (currentUser) {
                contentArea.innerHTML = `
                  <div class="d-flex flex-wrap align-items-center justify-content-between p-3 mx-md-3 mt-3 mb-4 rounded-4 shadow-sm" style="background-color: var(--ytm-surface-2); border: 1px solid #333;">
                    <div class="text-white fw-bold fs-5 mb-3 mb-md-0 d-flex align-items-center"><i class="bi bi-briefcase-fill text-danger me-3 fs-3"></i> ${pTitle}</div>
                    <button class="btn btn-info text-dark rounded-pill px-4 fw-bold shadow-sm create-typed-project-btn" data-type="${pType}"><i class="bi bi-plus-lg me-1"></i> New Project</button>
                  </div>
                  <div id="projects-list-container" class="mx-md-3 mb-5 d-flex flex-column gap-3"></div>
                `;
                data = await fetchData(`?action=get_projects&filter=${pType}`);
                if (data && data.length > 0) {
                  document.getElementById('projects-list-container').innerHTML = data.map(p => `
                    <div class="card bg-dark border-secondary text-white p-3 shadow-sm hover-bg-dark" style="border-radius: 12px; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-2px)'" onmouseout="this.style.transform='translateY(0)'">
                      <div class="d-flex justify-content-between align-items-center mb-3">
                        <h5 class="fw-bold m-0"><i class="bi bi-briefcase text-info me-2"></i>${escapeHTML(p.name)}</h5>
                        ${p.owner_id == currentUser.id ? `<button class="btn btn-sm btn-outline-danger delete-project-btn" data-id="${p.id}"><i class="bi bi-trash"></i></button>` : `<div class="d-flex align-items-center gap-2"><span class="badge bg-secondary">Shared with you</span> <button class="btn btn-sm btn-outline-warning leave-project-btn" data-id="${p.id}" title="Leave Project"><i class="bi bi-box-arrow-left"></i></button></div>`}
                      </div>
                      <div class="d-flex gap-4 small text-secondary">
                        <span><i class="bi bi-person-fill"></i> Owner: ${escapeHTML(p.owner_name)}</span>
                        <span><i class="bi bi-people"></i> ${p.member_count} Members</span>
                      </div>
                      <div class="d-flex gap-2 mt-3">
                        ${pType === 'note' ? `<button class="btn btn-sm btn-outline-light flex-grow-1 fw-bold project-nav-btn" data-target="get_notes" data-filter="proj_${p.id}"><i class="bi bi-journal-text text-warning"></i> ${p.note_count} Notes</button>` : ''}
                        ${pType === 'task' ? `<button class="btn btn-sm btn-outline-light flex-grow-1 fw-bold project-nav-btn" data-target="get_tasks" data-filter="proj_${p.id}"><i class="bi bi-check2-square text-success"></i> ${p.task_count} Tasks</button>` : ''}
                        ${pType === 'blog' ? `<button class="btn btn-sm btn-outline-light flex-grow-1 fw-bold project-nav-btn" data-target="get_blogs" data-filter="proj_${p.id}"><i class="bi bi-journal-text text-info"></i> ${p.blog_count} Blogs</button>` : ''}
                        ${p.owner_id == currentUser.id ? `<button class="btn btn-sm btn-info text-dark fw-bold invite-project-btn" data-id="${p.id}"><i class="bi bi-people-fill"></i> Manage</button>` : ''}
                      </div>
                    </div>
                  `).join('');
                } else {
                  document.getElementById('projects-list-container').innerHTML = '<div class="text-center p-5 text-secondary">No collaborative projects found. Create one above!</div>';
                }
              }
              break;
            }
            case 'get_albums':
            case 'get_artists':
            case 'get_genres':
            case 'get_years':
            case 'get_mixes':
            case 'get_user_playlists':
            case 'get_collab_playlists':
            case 'get_following':
              let title = currentView.type.replace('get_', '');
              title = title.charAt(0).toUpperCase() + title.slice(1);
              if (title === 'User_playlists') title = 'Playlists';
              if (title === 'Collab_playlists') title = 'Shared with me';
              updateContentTitle(title);
              pageParams.delete('page');
              
              // Apply search parameter globally for any grid views that support it
              if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);
              
              data = await fetchData(`?action=${currentView.type}&${pageParams.toString()}`);
              renderGrid(data, currentView.type, false);
              break;
            case 'artist_songs':
            case 'album_songs':
            case 'genre_songs':
            case 'year_songs':
            case 'playlist_songs':
            case 'mix_songs':
              const type = currentView.type.split('_')[0];
              const name_param = encodeURIComponent(currentView.param);
              updateContentTitle('', false);
              
              if (currentView.searchQuery) pageParams.set('q', currentView.searchQuery);
              
              const typeViewData = await fetchData(`?action=get_view_data&type=${type}&name=${name_param}&${pageParams.toString()}`);
              contentArea.innerHTML = '';
              if (typeViewData && typeViewData.details) {
                renderViewDetailsHeader(typeViewData.details, type, typeViewData.songs);
                
                if (type === 'artist') {
                  const existingCustomSort = document.getElementById('artist-custom-sort-container');
                  if (existingCustomSort) existingCustomSort.remove();

                  const customSortHTML = `
                      <div id="artist-custom-sort-container" class="d-none align-items-center gap-2">
                        <label for="artist-custom-sort-select" class="text-secondary small">Sort by</label>
                        <select id="artist-custom-sort-select" class="form-select form-select-sm" style="width: auto;"></select>
                      </div>
                  `;
                  document.querySelector('.header-controls').insertAdjacentHTML('afterbegin', customSortHTML);

                  const searchHTML = `
                    <div class="px-3 mb-3 mt-4 d-flex flex-wrap gap-3 align-items-center justify-content-between w-100">
                      <div class="position-relative" style="max-width: 400px; width: 100%;">
                        <i class="bi bi-search position-absolute top-50 start-0 translate-middle-y ms-3 text-secondary"></i>
                        <input type="text" id="view-songs-search-input" class="form-control bg-dark text-white border-secondary rounded-pill ps-5" placeholder="Search songs..." value="${escapeHTML(currentView.searchQuery || '')}">
                      </div>
                      <div id="artist-custom-cat-container" class="d-none align-items-center gap-2 ms-auto"></div>
                    </div>
                  `;
                  const targetPane = document.getElementById('artistTabsContent') || contentArea;
                  targetPane.insertAdjacentHTML('beforebegin', searchHTML);
                  
                  // Define the sorting and filtering engines
                  window.filterAndSortArtistPlaylists = () => {
                    const sInp = document.getElementById('view-songs-search-input');
                    const sSel = document.getElementById('artist-custom-sort-select');
                    if (!sInp || !sSel) return;
                    const query = sInp.value.toLowerCase().trim();
                    const sortVal = sSel.value;
                    let filtered = [...(window.artistPlaylistsData || [])];
                    if (query) filtered = filtered.filter(p => p.name.toLowerCase().includes(query) || (p.description && p.description.toLowerCase().includes(query)));
                    filtered.sort((a, b) => {
                      if (sortVal === 'newest') return new Date(b.created_at || 0) - new Date(a.created_at || 0);
                      if (sortVal === 'modified') return new Date(b.image_v || 0) - new Date(a.image_v || 0);
                      if (sortVal === 'name_asc') return a.name.localeCompare(b.name);
                      if (sortVal === 'name_desc') return b.name.localeCompare(a.name);
                      if (sortVal === 'songs_desc') return (b.song_count || 0) - (a.song_count || 0);
                      if (sortVal === 'songs_asc') return (a.song_count || 0) - (b.song_count || 0);
                      return 0;
                    });
                    const pane = document.getElementById('playlists-pane');
                    if (!pane) return;
                    if (filtered.length === 0) { pane.innerHTML = '<div class="text-center p-5 text-secondary">No playlists found.</div>'; return; }
                    pane.innerHTML = `<div class="row row-cols-2 row-cols-sm-3 row-cols-md-4 g-4">${filtered.map(p => `
                      <div class="col">
                        <div class="card h-100 bg-transparent text-white border-0 playlist-card" data-playlist="${encodeURIComponent(p.public_id)}" style="cursor: pointer;">
                          ${(currentUser && (currentUser.id == currentViewOwnerId || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `<button class="playlist-more-btn" data-public-id="${p.public_id}" data-name="${escapeHTML(p.name)}" data-is-collab="${p.is_collaborative || 0}" data-is-private="${p.is_private || 0}" data-owner-id="${currentViewOwnerId}"><i class="bi bi-three-dots-vertical"></i></button>` : ''}
                          <div style="position: relative; display: block; border-radius: 6px; overflow: hidden;">
                            <img src="?action=get_image&id=${p.image_id || 0}&v=${p.image_v || 0}&size=small" class="card-img-top" alt="${escapeHTML(p.name)}" style="aspect-ratio: 1/1; object-fit: cover; background-color: var(--ytm-surface-2); margin-bottom: 0 !important;">
                            ${p.song_count !== undefined ? `<div class="position-absolute bottom-0 start-0 ms-2 mb-1 px-2 py-1 bg-dark bg-opacity-75 text-white rounded fw-bold" style="font-size: 0.75rem; backdrop-filter: blur(4px); line-height: 1;"><i class="bi bi-music-note-list"></i> ${formatSongCount(p.song_count)}</div>` : ''}
                          </div>
                          <div class="card-body px-0 py-2"><h5 class="card-title fs-6 fw-normal text-truncate">${escapeHTML(p.name)}</h5></div>
                        </div>
                      </div>
                    `).join('')}</div>`;
                  };

                  window.filterAndSortArtistBlogs = () => {
                    const sInp = document.getElementById('view-songs-search-input');
                    const sSel = document.getElementById('artist-custom-sort-select');
                    const catSel = document.getElementById('artist-custom-cat-sort');
                    if (!sInp || !sSel) return;
                    const query = sInp.value.toLowerCase().trim();
                    const sortVal = sSel.value;
                    const catVal = catSel ? catSel.value : '';
                    
                    let filtered = [...(window.artistBlogsData || [])];
                    if (query) filtered = filtered.filter(b => b.title.toLowerCase().includes(query) || (b.content && b.content.toLowerCase().includes(query)));
                    if (catVal) filtered = filtered.filter(b => (b.category || 'all') === catVal);
                    
                    filtered.sort((a, b) => {
                      if (sortVal === 'newest') return new Date(b.created_at.replace(' ', 'T')+'Z') - new Date(a.created_at.replace(' ', 'T')+'Z');
                      if (sortVal === 'oldest') return new Date(a.created_at.replace(' ', 'T')+'Z') - new Date(b.created_at.replace(' ', 'T')+'Z');
                      if (sortVal === 'modified') return new Date(b.updated_at.replace(' ', 'T')+'Z') - new Date(a.updated_at.replace(' ', 'T')+'Z');
                      if (sortVal === 'title_asc') return a.title.localeCompare(b.title);
                      return 0;
                    });
                    const pane = document.getElementById('blogs-pane');
                    if (!pane) return;
                    if (filtered.length === 0) { pane.innerHTML = '<div class="text-center p-5 text-secondary">No blogs found.</div>'; return; }
                    pane.innerHTML = `<div class="notes-grid" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px;">${filtered.map(b => `
                      <div class="note-card bg-dark text-white border-secondary hover-bg-dark blog-card-item" data-id="${b.public_id}" style="border-radius: 12px; cursor: pointer; transition: transform 0.2s;" onmouseover="this.style.transform='translateY(-4px)'" onmouseout="this.style.transform='translateY(0)'">
                        <div class="d-flex justify-content-between mb-2">
                          <span class="badge bg-primary text-white">Public Blog</span>
                          <span class="small text-secondary">${new Date(b.updated_at.replace(' ', 'T')+'Z').toLocaleDateString()}</span>
                        </div>
                        <<div class="fw-bold fs-5 mb-2 text-truncate">${escapeHTML((b.title && b.title.trim() !== '') ? decodeHTML(b.title) : 'Untitled')}</div>
                      <div class="text-secondary small overflow-hidden" style="display: -webkit-box; -webkit-line-clamp: 4; -webkit-box-orient: vertical;">${escapeHTML(decodeHTML(b.content).replace(/<[^>]*>?/gm, '').replace(/[^a-zA-Z0-9\s.,!?]/g, ''))}</div>
                        <div class="mt-auto pt-3 d-flex justify-content-between align-items-center">
                          ${b.category && b.category !== 'all' ? `<span class="note-chip">${escapeHTML(b.category_name || 'Uncategorized')}</span>` : '<span></span>'}
                        </div>
                      </div>
                    `).join('')}</div>`;
                  };

                  const updateArtistSearchAndSortUI = (activeTabId) => {
                    const sInp = document.getElementById('view-songs-search-input');
                    const sCont = document.getElementById('artist-custom-sort-container');
                    const sSel = document.getElementById('artist-custom-sort-select');
                    const gSort = document.getElementById('sort-controls');
                    const cCont = document.getElementById('artist-custom-cat-container');
                    if (!sInp) return;
                    
                    sInp.value = "";
                    
                    if (activeTabId === 'songs-tab') {
                      sInp.placeholder = "Search songs...";
                      if (sCont) sCont.classList.replace('d-flex', 'd-none');
                      if (cCont) cCont.classList.replace('d-flex', 'd-none');
                      if (gSort) gSort.classList.remove('d-none');
                    } else if (activeTabId === 'playlists-tab') {
                      sInp.placeholder = "Search playlists...";
                      if (gSort) gSort.classList.add('d-none');
                      if (cCont) cCont.classList.replace('d-flex', 'd-none');
                      if (sCont && sSel) {
                        sSel.innerHTML = '<option value="newest">Newest</option><option value="modified">Recently Modified</option><option value="name_asc">Name (A-Z)</option><option value="name_desc">Name (Z-A)</option><option value="songs_desc">Most Songs</option><option value="songs_asc">Least Songs</option>';
                        sCont.classList.replace('d-none', 'd-flex');
                        if (!sCont.classList.contains('d-flex')) sCont.classList.add('d-flex');
                      }
                      window.filterAndSortArtistPlaylists();
                    } else if (activeTabId === 'blogs-tab') {
                      sInp.placeholder = "Search blogs...";
                      if (gSort) gSort.classList.add('d-none');
                      if (sCont && sSel) {
                        sSel.innerHTML = '<option value="newest">Newest</option><option value="oldest">Oldest</option><option value="modified">Recently Modified</option><option value="title_asc">Title (A-Z)</option>';
                        sCont.classList.replace('d-none', 'd-flex');
                        if (!sCont.classList.contains('d-flex')) sCont.classList.add('d-flex');
                      }
                      
                      if (cCont) {
                        const uniqueCategories = [];
                        const categoryMap = new Set();
                        (window.artistBlogsData || []).forEach(b => {
                          const catId = b.category || 'all';
                          if (catId !== 'all' && !categoryMap.has(catId)) {
                            categoryMap.add(catId);
                            uniqueCategories.push({ id: catId, name: b.category_name || 'Unknown' });
                          }
                        });
                        
                        const truncateText = (str, len = 20) => str.length > len ? str.substring(0, len - 2) + '...' : str;
                        
                        cCont.innerHTML = `
                          <label for="artist-custom-cat-sort" class="text-secondary small ms-1">Category</label>
                          <select id="artist-custom-cat-sort" class="form-select form-select-sm" style="width: auto; max-width: 200px;">
                            <option value="">All Categories</option>
                            ${uniqueCategories.map(c => `<option value="${escapeHTML(c.id)}" title="${escapeHTML(c.name)}">${escapeHTML(truncateText(c.name))}</option>`).join('')}
                          </select>
                        `;
                        document.getElementById('artist-custom-cat-sort').addEventListener('change', window.filterAndSortArtistBlogs);
                        cCont.classList.replace('d-none', 'd-flex');
                      }
                      
                      window.filterAndSortArtistBlogs();
                    }
                  };

                  setTimeout(() => {
                    const viewSearch = document.getElementById('view-songs-search-input');
                    const sortSelect = document.getElementById('artist-custom-sort-select');
                    
                    if (viewSearch) {
                      viewSearch.addEventListener('input', (e) => {
                        const activeTab = document.querySelector('#artistTabs .nav-link.active');
                        const activeTabId = activeTab ? activeTab.id : 'songs-tab';
                        if (activeTabId === 'songs-tab') {
                          clearTimeout(window.viewSearchTimeout);
                          window.viewSearchTimeout = setTimeout(() => {
                            currentView.searchQuery = e.target.value;
                            loadView(currentView);
                          }, 400);
                        } else if (activeTabId === 'playlists-tab') {
                          window.filterAndSortArtistPlaylists();
                        } else if (activeTabId === 'blogs-tab') {
                          window.filterAndSortArtistBlogs();
                        }
                      });
                      
                      if (currentView.searchQuery) {
                         viewSearch.focus();
                         viewSearch.setSelectionRange(viewSearch.value.length, viewSearch.value.length);
                      }
                    }

                    if (sortSelect) {
                      sortSelect.addEventListener('change', () => {
                        const activeTab = document.querySelector('#artistTabs .nav-link.active');
                        const activeTabId = activeTab ? activeTab.id : 'songs-tab';
                        if (activeTabId === 'playlists-tab') {
                          window.filterAndSortArtistPlaylists();
                        } else if (activeTabId === 'blogs-tab') {
                          window.filterAndSortArtistBlogs();
                        }
                      });
                    }

                    const artistTabs = document.getElementById('artistTabs');
                    if (artistTabs) {
                      artistTabs.addEventListener('shown.bs.tab', (e) => {
                        updateArtistSearchAndSortUI(e.target.id);
                      });
                    }
                  }, 0);
                }
                
                renderSongs(typeViewData.songs, false);
                data = typeViewData.songs;
              } else {
                contentArea.innerHTML = `<div class="text-center p-5 text-secondary">User not found or this user already deleted.</div>`;
              }
              break;
            case 'search':
              updateContentTitle(`Search: "${currentView.param}"`);
              pageParams.delete('sort');
              pageParams.append('q', currentView.param);
              data = await fetchData(`?action=search&${pageParams.toString()}`);
              if (data && data.shelves) {
                renderRecommendations(data);
              }
              allContentloaded = true;
              break;
          }

          let countCheckView = data ? data.length : 0;
          if (data && currentView.type === 'get_community') {
            countCheckView = data.filter(i => i.parent_id == null).length; // Only count root items
          }
          if (data && countCheckView < PAGE_SIZE && currentView.type !== 'search') {
            allContentloaded = true;
          }
          if (viewConfig.highlight) {
            const findAndHighlight = () => {
              const songToHighlight = contentArea.querySelector(`.song-item[data-song-id="${viewConfig.highlight}"]`);
              if (songToHighlight) {
                songToHighlight.scrollIntoView({ behavior: 'smooth', block: 'center' });
                songToHighlight.style.transition = 'background-color 2s ease';
                songToHighlight.style.backgroundColor = 'rgba(255, 0, 0, 0.3)';
                setTimeout(() => {
                  songToHighlight.style.backgroundColor = '';
                }, 2000);
              } else if (!allContentloaded) {
                // Auto-load next page recursively until the highlighted track is found!
                loadMoreContent().then(() => {
                  setTimeout(findAndHighlight, 100);
                });
              }
            };
            setTimeout(findAndHighlight, 500);
          }

          hideLoader();
        };
        window.loadView = loadView; // Expose to global scope for inline onclick handlers

        const logPlay = (songId) => {
          if (!currentUser) return;
          const played_at_iso = new Date().toISOString();
          const url = '?action=log_play';
          
          const payload = { id: songId, played_at: played_at_iso };
          if (window.activeQueueContext && window.activeQueueContext.type === 'playlist_songs') {
            payload.playlist_public_id = decodeURIComponent(window.activeQueueContext.param);
          }
          const data = JSON.stringify(payload);
          
          if (navigator.sendBeacon) {
            const blob = new Blob([data], { type: 'application/json; charset=UTF-8' });
            navigator.sendBeacon(url, blob);
          } else {
            fetch(url, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: data,
              keepalive: true,
            }).catch(error => console.error('Beacon fallback fetch error for log_play:', error));
          }
        };

        let playDebounceTimer = null;
        let playRequestCounter = 0;
        const playSongById = async (songId) => {
          playRequestCounter++;
          const currentPlayId = playRequestCounter;
          
          // DEBOUNCE: Protect rapid track skipping to prevent DB and audio buffer locks
          if (playDebounceTimer) clearTimeout(playDebounceTimer);
          updatePlayPauseIcons(true); // Show buffering spinner immediately
          
          await new Promise(resolve => {
            playDebounceTimer = setTimeout(resolve, 250);
          });
          
          if (currentPlayId !== playRequestCounter) return;

          // AUTOMATIC OFFLINE SKIP: If offline, ensure song is cached first
          if (!navigator.onLine) {
            const cache = await caches.open('php-music-offline');
            const req = await cache.match(`?action=get_stream&id=${songId}`, { ignoreSearch: false, ignoreVary: true });
            if (!req) {
              console.warn(`Song ${songId} not cached. Skipping automatically because you are offline.`);
              showToast("Skipped: Not available offline.", "info");
              // Delay slightly to prevent infinite loop locking if all songs are missing
              setTimeout(() => playNext(), 500);
              return;
            }
          }

          let data = await fetchData(`?action=get_song_data&id=${songId}`, {}, true);
          
          // OFFLINE FALLBACK: If API fails, check the local memory cache!
          if (!data) {
            if (globalSongCache[songId]) {
              data = Object.assign({}, globalSongCache[songId]);
              if (!data.stream_url) data.stream_url = `?action=get_stream&id=${songId}`;
              if (!data.image_url) data.image_url = `?action=get_image&id=${songId}&v=${globalSongCache[songId]?.last_modified || 0}`;
            } else {
              showToast("Song data not available offline.", "error");
              return;
            }
          }
          
          currentSong = data;
          globalSongCache[currentSong.id] = currentSong;
          currentSong.logged = false;
          
          // Ensure the new song is physically rendered in the DOM queues before highlighting
          if (typeof queueIndex !== 'undefined' && (queueIndex < renderedQueueStart || queueIndex >= renderedQueueEnd)) {
            await window.renderQueue(true); // Force a re-render centered around the active song
          }
          
          initWebAudio();
          if (audioCtx.state === 'suspended') audioCtx.resume();
          applyAudioSettings(currentSong.id);

          if (isPlaying && audio.currentTime > 0 && !audio.paused) {
            audioB.src = audio.src;
            audioB.currentTime = audio.currentTime;
            audioB.play().catch(e => {
              if (e.name !== 'AbortError') console.error("AudioB play failed:", e);
            });
            
            gainB.gain.setValueAtTime(1, audioCtx.currentTime);
            gainB.gain.linearRampToValueAtTime(0, audioCtx.currentTime + crossfadeDuration);
            
            setTimeout(() => { audioB.pause(); audioB.src = ''; }, crossfadeDuration * 1000);
            
            gainA.gain.setValueAtTime(0, audioCtx.currentTime);
            gainA.gain.linearRampToValueAtTime(1, audioCtx.currentTime + crossfadeDuration);
          } else {
            gainA.gain.value = 1;
            gainB.gain.value = 0;
          }

          audio.src = currentSong.stream_url;
          audio.load();
          audio.play().catch(e => {
            if (e.name !== 'AbortError') {
              console.error("Audio play failed:", e);
            }
          });
          isPlaying = true;
          updatePlayerUI();
          if (!visAnimId) drawVisualizer();
          
          if ('mediaSession' in navigator) {
            navigator.mediaSession.metadata = new MediaMetadata({
              title: currentSong.title, artist: currentSong.artist, album: currentSong.album,
              artwork: [{ src: currentSong.image_url, sizes: '500x500', type: 'image/webp' }]
            });
            navigator.mediaSession.setActionHandler('play', togglePlayPause);
            navigator.mediaSession.setActionHandler('pause', togglePlayPause);
            navigator.mediaSession.setActionHandler('previoustrack', playPrev);
            navigator.mediaSession.setActionHandler('nexttrack', playNext);
            navigator.mediaSession.setActionHandler('seekbackward', () => { audio.currentTime = Math.max(0, audio.currentTime - 10); });
            navigator.mediaSession.setActionHandler('seekforward', () => { audio.currentTime = Math.min(audio.duration, audio.currentTime + 10); });
          }
        };

        const updatePlayerUI = () => {
          if (!currentSong) return;
          if (playerBar.classList.contains('d-none') && currentView.type !== 'rhythm_game') {
            playerBar.classList.remove('d-none');
            document.body.classList.add('player-visible');
          }
          const imageUrl = `?action=get_image&id=${currentSong.id}&v=${currentSong.last_modified || 0}`;
          
          // Apply dynamic blurred background to modals
          const mobileBg = document.getElementById('mobile-player-bg');
          const desktopBg = document.getElementById('desktop-player-bg');
          if (mobileBg) mobileBg.style.backgroundImage = `url('${imageUrl}')`;
          if (desktopBg) desktopBg.style.backgroundImage = `url('${imageUrl}')`;
          if (docPipWindow) {
            const pipBg = docPipWindow.document.getElementById('pip-bg');
            if (pipBg) pipBg.style.backgroundImage = `url('${imageUrl}')`;
          }

          playerElements.art.forEach(el => el.src = imageUrl);
          updateAppFavicon(imageUrl);

          // Clear previous theme instantly on track change to prevent getting stuck
          document.querySelectorAll('.player-modal-content').forEach(modal => {
            modal.classList.remove('theme-light-bg');
          });
          if (docPipWindow && docPipWindow.document.body) {
            docPipWindow.document.body.classList.remove('theme-light-bg');
          }

          // Dynamically adjust modal text theme based on cover brightness
          const themeImg = new Image();
          themeImg.crossOrigin = 'anonymous';
          themeImg.onload = () => {
            const rgb = getAverageColor(themeImg);
            const brightness = Math.round(((parseInt(rgb.r) * 299) + (parseInt(rgb.g) * 587) + (parseInt(rgb.b) * 114)) / 1000);
             
            // If brightness is high (light cover art), trigger light mode
            if (brightness > 130) {
              document.querySelectorAll('.player-modal-content').forEach(modal => {
                modal.classList.add('theme-light-bg');
              });
              if (docPipWindow && docPipWindow.document.body) {
                 docPipWindow.document.body.classList.add('theme-light-bg');
              }
            }
          };
          // Append timestamp to bypass stubborn browser caches that prevent onload triggering
          themeImg.src = imageUrl + '&t=' + new Date().getTime();
          playerElements.title.forEach(el => el.textContent = currentSong.title);
          playerElements.artist.forEach(el => el.innerHTML = formatArtistsHTML(currentSong.artist, currentSong.user_id, currentSong.is_collaborative));
          document.title = `${currentSong.title} • ${currentSong.artist}`;
          
          if (docPipWindow) {
            docPipWindow.document.title = `${currentSong.title} • ${currentSong.artist}`;
          }

          updatePlayPauseIcons();
          updateFavoriteIcons(currentSong.is_favorite == 1);
          
          document.querySelectorAll('.song-item.now-playing').forEach(el => el.classList.remove('now-playing'));
          document.querySelectorAll(`.song-item[data-song-id="${currentSong.id}"]`).forEach(el => el.classList.add('now-playing'));

          if (typeof renderDesktopLyrics === 'function' && desktopPlayerModalEl && desktopPlayerModalEl.classList.contains('show')) {
            renderDesktopLyrics();
            window.enforceScrollToActive('dp-queue-pane', 'desktop-player-queue-list', true);
          }

          if (playerModalEl && playerModalEl.classList.contains('show')) {
            window.enforceScrollToActive('mp-queue-pane', 'mobile-player-queue-list', true);
          }

          if (playerModalEl && playerModalEl.classList.contains('show')) {
            setTimeout(() => {
              const activeMobileModal = document.querySelector('#mobile-player-queue-list .song-item.now-playing');
              const pane = document.getElementById('mp-queue-pane');
              if (activeMobileModal && pane && activeMobileModal.offsetParent !== null) {
                window.scrollToCenter(pane, activeMobileModal, true);
              }
            }, 50);
          }

          if (typeof window.renderPipLyrics === 'function') {
            window.renderPipLyrics();
          }

          if (pipCtx) {
            const img = new Image();
            img.crossOrigin = 'anonymous';
            img.onload = () => {
              currentCoverImageObj = img;
              pipVideo.play().catch(()=>{});
            };
            img.src = imageUrl;
          }
        };

        const updatePlayPauseIcons = (isBuffering = false) => {
          let icon = isPlaying ? ICONS.pause : ICONS.play;
          if (isBuffering) icon = ICONS.spinner;
          
          playerElements.playPauseBtn.forEach(btn => {
            btn.innerHTML = icon;
            btn.title = isPlaying ? "Pause" : "Play";
          });
          if ('mediaSession' in navigator) {
            navigator.mediaSession.playbackState = isPlaying ? "playing" : "paused";
          }
        };
        
        const updateRepeatIcons = () => {
          let icon = ICONS.repeat, title = "Repeat Off";
          playerElements.repeatBtn.forEach(btn => btn.classList.remove('active'));
          if (repeatMode === 'one') {
            icon = ICONS.repeatOne; title = "Repeat One";
            playerElements.repeatBtn.forEach(btn => btn.classList.add('active'));
          } else if (repeatMode === 'all') {
            title = "Repeat All";
            playerElements.repeatBtn.forEach(btn => btn.classList.add('active'));
          }
          playerElements.repeatBtn.forEach(btn => {
            btn.innerHTML = icon; btn.title = title;
          });
        };
        
        const updateShuffleButtons = () => {
          playerElements.shuffleBtn.forEach(btn => {
            btn.classList.toggle('active', isShuffle);
            btn.title = isShuffle ? "Shuffle On" : "Shuffle Off";
          });
        };
        
        const updateFavoriteIcons = (isFav) => {
          const favButtonsInModal = document.querySelectorAll('#player-modal-favorite-btn, .context-menu-item[data-action="toggle_favorite"]');
          const icon = isFav ? ICONS.heartFill : ICONS.heart;
          favButtonsInModal.forEach(btn => {
            btn.innerHTML = icon + (btn.tagName === 'LI' ? ' Remove from Favorites' : '');
            btn.classList.toggle('active', isFav);
          });
          const contextMenuItem = contextMenu.querySelector('.context-menu-item[data-action="toggle_favorite"]');
          if (contextMenuItem) {
            contextMenuItem.innerHTML = `${icon} ${isFav ? 'Remove from Favorites' : 'Add to Favorites'}`;
          }
        };

        const updateVolumeSliderFill = () => {
          if (!playerElements.volumeSlider) return;
          const slider = playerElements.volumeSlider;
          const value = (slider.value - slider.min) / (slider.max - slider.min);
          const percent = value * 100;
          slider.style.background = `linear-gradient(to right, var(--ytm-primary-text) ${percent}%, var(--ytm-surface-2) ${percent}%)`;
        };
        
        const updateVolumeIcon = () => {
          if (!playerElements.volumeBtn) return;
          if (audio.muted || audio.volume === 0) {
            playerElements.volumeBtn.innerHTML = ICONS.volumeMute;
          } else if (audio.volume < 0.5) {
            playerElements.volumeBtn.innerHTML = ICONS.volumeDown;
          } else {
            playerElements.volumeBtn.innerHTML = ICONS.volumeUp;
          }
        };

        let isTogglingFavorite = false;
        const toggleFavorite = async (songId) => {
          if (!currentUser) {
            showToast('Please log in to add favorites.', 'error');
            return;
          }
          
          // DEBOUNCE: Protect SQLite from write-locks if user spams the heart button
          if (isTogglingFavorite) return;
          isTogglingFavorite = true;
          setTimeout(() => { isTogglingFavorite = false; }, 500); 
          
          const result = await fetchData('?action=toggle_favorite', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ id: songId })
          });
          if (result) {
            if (currentSong && currentSong.id === songId) {
              currentSong.is_favorite = result.is_favorite ? 1 : 0;
              updateFavoriteIcons(result.is_favorite);
            }
        
            const songItemsInView = document.querySelectorAll(`.song-item[data-song-id="${songId}"], .shelf-item[data-song-id="${songId}"]`);
        
            if (currentView.type === 'get_favorites' && !result.is_favorite) {
              songItemsInView.forEach(item => {
                item.style.transition = 'opacity 0.3s ease';
                item.style.opacity = '0';
                setTimeout(() => item.remove(), 300);
              });
            } else {
              songItemsInView.forEach(item => {
                item.dataset.isFavorite = result.is_favorite ? "1" : "0";
              });
            }
        
            const contextMenuItem = contextMenu.querySelector('.context-menu-item[data-action="toggle_favorite"]');
            if (contextMenuItem) {
              const isFav = result.is_favorite;
              const favText = isFav ? "Remove from Favorites" : "Add to Favorites";
              const favIcon = isFav ? ICONS.heartFill : ICONS.heart;
              contextMenuItem.innerHTML = `${favIcon} ${favText}`;
            }
        
            showToast(result.status === 'added' ? 'Added to favorites' : 'Removed from favorites', 'success');
          }
        };

        const showAllGenresModal = async () => {
          if (!genresModal || !genresModalBody) return;
          genresModalBody.innerHTML = `<div class="text-center"><div class="spinner-border" role="status"><span class="visually-hidden">Loading...</span></div></div>`;
          genresModal.show();
          
          const allGenres = await fetchData('?action=get_all_genres');
          if (allGenres && allGenres.length > 0) {
            const genresHTML = allGenres.map(g => 
              `<button type="button" class="btn btn-light border-0 m-1 genre-modal-btn" data-genre="${encodeURIComponent(g)}">${g}</button>`
            ).join('');
            genresModalBody.innerHTML = `<div class="d-flex flex-wrap justify-content-center">${genresHTML}</div>`;
          } else {
            genresModalBody.innerHTML = `<p class="text-secondary text-center">No genres found.</p>`;
          }
        };
        
        const showShareModal = (type, id, name, artistId, artistName = '', customImageUrl = '', playlistId = '', scorePayload = '') => {
          const decodedName = decodeURIComponent(name || '');
          let shareUrl = `${window.location.origin}${window.location.pathname}?share_type=${type}`;

          const cleanId = String(id).replace(/undefined|null|nan/gi, '').trim();
          const cleanName = String(name).replace(/undefined|null|nan/gi, '').trim();
          const cleanArtistId = parseInt(artistId, 10);
          const finalArtistId = (!isNaN(cleanArtistId) && cleanArtistId > 0) ? cleanArtistId : '';
          const cleanArtistName = String(artistName).replace(/undefined|null|nan/gi, '').trim();
          
          let previewDesc = `Share this ${type} with your friends`;
          
          if (type === 'album') {
            shareUrl += `&album_name=${encodeURIComponent(decodedName || cleanId)}`;
            if (finalArtistId !== '') {
              shareUrl += `&artist_id=${finalArtistId}`;
            }
            if (cleanArtistName !== '') {
              const decodedArtistName = decodeURIComponent(cleanArtistName);
              shareUrl += `&artist_name=${encodeURIComponent(decodedArtistName)}`;
              previewDesc = `Album by ${decodedArtistName}`;
            } else {
              previewDesc = 'Album';
            }
          } else if (type === 'game' && finalArtistId !== '') {
            // New format for sharing Rhythm Game Artist Profiles
            shareUrl += `&artist_id=${finalArtistId}`;
            if (cleanArtistName !== '') {
              const decodedArtistName = decodeURIComponent(cleanArtistName);
              shareUrl += `&artist_name=${encodeURIComponent(decodedArtistName)}`;
              previewDesc = `${decodedArtistName} - Rhythm Game Profile`;
            } else {
              previewDesc = 'Artist - Rhythm Game Profile';
            }
          } else {
            if (cleanId !== '') {
              shareUrl += `&id=${cleanId}`;
            } else if (cleanName !== '') {
              shareUrl += `&id=${encodeURIComponent(cleanName)}`;
            }
            if (playlistId) {
              shareUrl += `&playlist_id=${playlistId}`;
            }
            if (type === 'song') previewDesc = 'Song';
            if (type === 'artist') previewDesc = 'Artist Profile';
            if (type === 'playlist') previewDesc = 'Public Playlist';
            if (type === 'mix') previewDesc = 'Custom Mix';
            if (type === 'blog') previewDesc = 'Blog Post';
            if (type === 'game') previewDesc = 'Rhythm Game';
          }

          document.getElementById('share-modal-title').textContent = `Share`;
          document.getElementById('share-modal-preview-title').textContent = decodedName;
          document.getElementById('share-modal-preview-desc').textContent = previewDesc;
          shareUrlInput.value = shareUrl;

          // Fetch the cover image URL dynamically
          let imageUrl = '?action=get_app_icon&size=512';
          if (customImageUrl) {
            imageUrl = customImageUrl;
          } else if (type === 'song' && cleanId) {
            imageUrl = `?action=get_image&id=${cleanId}`;
          } else if (type === 'artist' && cleanId) {
            imageUrl = `?action=get_profile_picture&id=${cleanId}`;
          } else if (type === 'album' && globalSongCache) {
            const albumSong = Object.values(globalSongCache).find(s => s.album === decodedName);
            if (albumSong) {
              imageUrl = `?action=get_image&id=${albumSong.id}`;
            }
          } else if (currentSong) {
            imageUrl = `?action=get_image&id=${currentSong.id}`;
          }

          const shareCover = document.getElementById('share-modal-cover');
          if (shareCover) {
            shareCover.src = imageUrl;
            shareCover.style.display = 'block';
          }

          // Construct absolute image URL for embeds
          const absImageUrl = new URL(imageUrl, window.location.href).href;
          const imgEnc = encodeURIComponent(absImageUrl);

          // Removed Cover Image URL from text payload as requested
          const textPayload = scorePayload ? encodeURIComponent(scorePayload) : encodeURIComponent(`Check out "${decodedName}" on PHP Music`);
          const urlEnc = encodeURIComponent(shareUrl);

          // Null-safe helper function to open apps and silently copy image to Clipboard
          const setShareUrl = (id, url) => {
            const el = document.getElementById(id);
            if (el) {
              const newEl = el.cloneNode(true);
              el.parentNode.replaceChild(newEl, el);
              
              newEl.addEventListener('click', async (e) => {
                e.preventDefault();
                
                // 1. Open the app link (WhatsApp, Twitter, etc.) immediately to prevent popup blockers
                window.open(url, '_blank');
                
                // 2. Silently convert and copy the image directly to the user's Clipboard
                if (navigator.clipboard && window.isSecureContext) {
                  try {
                    const response = await fetch(imageUrl);
                    const blob = await response.blob();
                    
                    // The Clipboard API strictly requires image/png format
                    let clipboardBlob = blob;
                    if (blob.type !== 'image/png') {
                      const img = new Image();
                      const canvas = document.createElement('canvas');
                      const ctx = canvas.getContext('2d');
                      
                      await new Promise((resolve, reject) => {
                        img.onload = () => {
                          canvas.width = img.width;
                          canvas.height = img.height;
                          ctx.drawImage(img, 0, 0);
                          canvas.toBlob(b => { clipboardBlob = b; resolve(); }, 'image/png');
                        };
                        img.onerror = reject;
                        img.src = URL.createObjectURL(blob);
                      });
                    }
                    
                    // Write to clipboard
                    await navigator.clipboard.write([
                      new ClipboardItem({ 'image/png': clipboardBlob })
                    ]);
                    
                    showToast('Cover image copied! Paste it in the chat.', 'success');
                  } catch (err) {
                    console.error("Clipboard copy failed. Your browser may not support image clipboard writing.", err);
                  }
                }
              });
            }
          };

          setShareUrl('share-facebook', `https://www.facebook.com/sharer/sharer.php?u=${urlEnc}`);
          setShareUrl('share-twitter', `https://twitter.com/intent/tweet?url=${urlEnc}&text=${textPayload}`);
          setShareUrl('share-whatsapp', `https://api.whatsapp.com/send?text=${textPayload}%3A%20${urlEnc}`);
          setShareUrl('share-telegram', `https://t.me/share/url?url=${urlEnc}&text=${textPayload}`);
          setShareUrl('share-messenger', `fb-messenger://share/?link=${urlEnc}`);
          setShareUrl('share-reddit', `https://reddit.com/submit?url=${urlEnc}&title=${textPayload}`);
          setShareUrl('share-linkedin', `https://www.linkedin.com/sharing/share-offsite/?url=${urlEnc}`);
          setShareUrl('share-pinterest', `https://pinterest.com/pin/create/button/?url=${urlEnc}&description=${textPayload}&media=${imgEnc}`);
          setShareUrl('share-line', `https://line.me/R/msg/text/?${textPayload}%20${urlEnc}`);
          setShareUrl('share-discord', `https://discord.com/channels/@me`);
          setShareUrl('share-skype', `https://web.skype.com/share?url=${urlEnc}&text=${textPayload}`);
          setShareUrl('share-wechat', `weixin://`);
          setShareUrl('share-tumblr', `https://www.tumblr.com/widgets/share/tool?canonicalUrl=${urlEnc}&title=${encodeURIComponent(decodedName)}&posttype=photo&content=${imgEnc}`);
          setShareUrl('share-mastodon', `https://mastodon.social/share?text=${textPayload}&url=${urlEnc}`);
          setShareUrl('share-hackernews', `https://news.ycombinator.com/submitlink?u=${urlEnc}&t=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-pocket', `https://getpocket.com/save?url=${urlEnc}&title=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-vk', `https://vk.com/share.php?url=${urlEnc}&title=${encodeURIComponent(decodedName)}&image=${imgEnc}`);
          setShareUrl('share-flipboard', `https://share.flipboard.com/bookmarklet/popout?v=2&title=${encodeURIComponent(decodedName)}&url=${urlEnc}`);
          setShareUrl('share-email', `mailto:?subject=${encodeURIComponent(decodedName)}&body=${textPayload}%20${urlEnc}`);
          setShareUrl('share-sms', `sms:?&body=${textPayload}%20${urlEnc}`);
          setShareUrl('share-threads', `https://www.threads.net/intent/post?text=${textPayload}%20${urlEnc}`);
          setShareUrl('share-snapchat', `https://snapchat.com/scan?attachmentUrl=${urlEnc}`);
          setShareUrl('share-slack', `slack://`);
          setShareUrl('share-twitch', `https://www.twitch.tv/`);
          setShareUrl('share-medium', `https://medium.com/`);
          setShareUrl('share-quora', `https://www.quora.com/`);
          setShareUrl('share-tiktok', `https://www.tiktok.com/`);
          setShareUrl('share-instagram', `instagram://`);
          setShareUrl('share-youtube', `https://youtube.com/`);
          setShareUrl('share-spotify', `https://open.spotify.com/`);
          setShareUrl('share-github', `https://github.com/`);
          setShareUrl('share-wordpress', `https://wordpress.com/press-this.php?u=${urlEnc}&t=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-dribbble', `https://dribbble.com/`);
          setShareUrl('share-weibo', `http://service.weibo.com/share/share.php?url=${urlEnc}&title=${textPayload}`);
          setShareUrl('share-qq', `http://connect.qq.com/widget/shareqq/index.html?url=${urlEnc}&title=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-kakaotalk', `kakaotalk://`);
          setShareUrl('share-viber', `viber://forward?text=${textPayload}%20${urlEnc}`);
          setShareUrl('share-signal', `sgnl://share?text=${textPayload}%20${urlEnc}`);
          setShareUrl('share-buffer', `https://buffer.com/add?url=${urlEnc}&text=${textPayload}`);
          setShareUrl('share-digg', `http://digg.com/submit?url=${urlEnc}&title=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-douban', `http://www.douban.com/recommend/?url=${urlEnc}&title=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-trello', `https://trello.com/add-card?url=${urlEnc}&name=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-xing', `https://www.xing.com/spi/shares/new?url=${urlEnc}`);
          setShareUrl('share-yammer', `https://www.yammer.com/messages/new?status=${textPayload}%20${urlEnc}`);
          setShareUrl('share-blogger', `https://www.blogger.com/blog-this.g?u=${urlEnc}&n=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-evernote', `https://www.evernote.com/clip.action?url=${urlEnc}&title=${encodeURIComponent(decodedName)}`);
          setShareUrl('share-mewe', `https://mewe.com/share?link=${urlEnc}`);
          setShareUrl('share-diaspora', `https://share.diasporafoundation.org/?title=${encodeURIComponent(decodedName)}&url=${urlEnc}`);
          setShareUrl('share-taringa', `https://www.taringa.net/`);
          setShareUrl('share-teams', `https://teams.microsoft.com/share?href=${urlEnc}&msgText=${textPayload}`);
          
          copyShareUrlBtn.textContent = 'Copy';
          copyShareUrlBtn.disabled = false;

          const systemShareBtn = document.getElementById('system-share-btn');
          if (systemShareBtn) {
            if (navigator.share) {
              systemShareBtn.style.display = 'block';
              
              const newBtn = systemShareBtn.cloneNode(true);
              const newCopyBtn = newBtn;
              systemShareBtn.parentNode.replaceChild(newCopyBtn, systemShareBtn);
              
              newCopyBtn.addEventListener('click', async () => {
                newCopyBtn.disabled = true;
                const originalText = newCopyBtn.innerHTML;
                newCopyBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span> Preparing...';

                try {
                  const shareData = {
                    title: decodedName,
                    text: scorePayload || `Check out "${decodedName}" on PHP Music!`,
                    url: shareUrl
                  };

                  // Prevent appending invalid/fallback images that crash navigator.share on mobile
                  if (imageUrl && !imageUrl.includes('get_app_icon')) {
                    try {
                      const response = await fetch(imageUrl);
                      const blob = await response.blob();
                      if (blob.type.startsWith('image/')) {
                        const file = new File([blob], 'cover.jpg', { type: blob.type });
                        if (navigator.canShare && navigator.canShare({ files: [file] })) {
                          shareData.files = [file];
                        }
                      }
                    } catch (imgErr) {
                      console.warn("Could not attach image to share payload", imgErr);
                    }
                  }

                  await navigator.share(shareData);
                } catch (err) {
                  if (err.name !== 'AbortError') {
                    if (typeof showToast === 'function') showToast('Failed to share via System Apps.', 'error');
                  }
                } finally {
                  newCopyBtn.disabled = false;
                  newCopyBtn.innerHTML = originalText;
                }
              });
            } else {
              systemShareBtn.style.display = 'none';
            }
          }

          if (shareModal) shareModal.show();
        };
        
        const positionContextMenu = (buttonEl) => {
          const buttonRect = buttonEl.getBoundingClientRect();
          const menuWidth = contextMenu.offsetWidth;
          const menuHeight = contextMenu.offsetHeight;
          const margin = 5;
          
          let x = buttonRect.right - menuWidth;
          let y = buttonRect.bottom + margin;

          if (x < margin) x = margin;
          if (y + menuHeight > window.innerHeight) y = buttonRect.top - menuHeight - margin;
          if (y < margin) y = margin; 

          contextMenu.style.left = `${x}px`;
          contextMenu.style.top = `${y}px`;
        }
        
        const buildAndShowPlaylistContextMenu = (buttonEl, playlistData) => {
          if (contextMenu.style.display === 'block' && contextMenuItemEl === buttonEl) {
            contextMenu.style.display = 'none';
            return;
          }
          contextMenuItemEl = buttonEl;
          const { publicId, name, description, isCollab, isPrivate, ownerId } = playlistData;
          
          let menuItems = '';
          
          const isOwner = currentUser && (currentUser.id == ownerId || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1);

          if (isOwner) {
            if (!isPrivate) {
              const collabText = isCollab ? 'Make Private' : 'Make Collaborative';
              const collabIcon = isCollab ? '<i class="bi bi-lock-fill"></i>' : '<i class="bi bi-globe"></i>';
              menuItems += `<li class="context-menu-item" data-action="toggle_collab" data-public-id="${publicId}">${collabIcon} ${collabText}</li>`;
              if (isCollab) {
                menuItems += `<li class="context-menu-item" data-action="manage_collab" data-public-id="${publicId}" data-name="${escapeHTML(name)}"><i class="bi bi-people-fill"></i> Manage Collaborators</li>`;
