            const public_id = document.getElementById('edit-playlist-id-input').value;
            const name = document.getElementById('edit-playlist-name-input').value;
            const descInput = document.getElementById('edit-playlist-desc-input');
            const description = descInput ? descInput.value : '';
            const is_private = document.getElementById('edit-playlist-is-private').checked ? 1 : 0;
            const data = await fetchData('?action=edit_playlist', {
              method: 'POST', headers: {'Content-Type': 'application/json'},
              body: JSON.stringify({ public_id, name, description, is_private })
            });
            if (data && data.status === 'success') {
              if (editPlaylistModal) editPlaylistModal.hide();
              editPlaylistForm.reset();
              showToast(data.message, 'success');
              loadView(currentView);
            }
          });
        }

        importPlaylistForm.addEventListener('submit', async e => {
          e.preventDefault();
          const fileInput = document.getElementById('import-playlist-file');
          if (fileInput.files.length === 0) return;
          
          const file = fileInput.files[0];
          const reader = new FileReader();
          
          reader.onload = async (event) => {
            try {
              const importData = JSON.parse(event.target.result);
              if (!importData.songs || !Array.isArray(importData.songs)) {
                showToast('Invalid JSON format.', 'error');
                return;
              }
              if (!importData.name) {
                if (confirm("Playlist name is missing or data doesn't match perfectly. Do you want to add new data anyway?")) {
                  importData.name = "Imported Playlist";
                } else {
                  fileInput.value = '';
                  return;
                }
              }
              
              const btn = importPlaylistForm.querySelector('button[type="submit"]');
              const originalText = btn.innerHTML;
              btn.disabled = true;
              btn.innerHTML = '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span> Scanning Library...';
              
              const response = await fetch('?action=import_playlist', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(importData)
              });
              
              const result = await response.json();
              if (result) {
                showToast(result.message, result.status);
                if (result.status === 'success') {
                  importPlaylistModal.hide();
                  importPlaylistForm.reset();
                  loadView(currentView);
                }
              }
              btn.disabled = false;
              btn.innerHTML = originalText;
            } catch (err) {
              showToast('Failed to parse JSON or import.', 'error');
              const btn = importPlaylistForm.querySelector('button[type="submit"]');
              btn.disabled = false;
              btn.textContent = 'Import';
            }
          };
          reader.readAsText(file);
        });

        const importOfflineForm = document.getElementById('import-offline-form');
        if (importOfflineForm) {
          importOfflineForm.addEventListener('submit', async e => {
            e.preventDefault();
            const fileInput = document.getElementById('import-offline-file');
            if (fileInput.files.length === 0) return;
            
            const file = fileInput.files[0];
            const reader = new FileReader();
            
            reader.onload = async (event) => {
              try {
                const importData = JSON.parse(event.target.result);
                if (!importData.songs || !Array.isArray(importData.songs)) {
                  showToast('Invalid JSON format.', 'error');
                  return;
                }
                if (importData.name !== "Offline Music") {
                  if (!confirm("Data name doesn't match standard offline backup. Do you want to add new data anyway?")) {
                    fileInput.value = '';
                    return;
                  }
                }
                
                const btn = importOfflineForm.querySelector('button[type="submit"]');
                const originalText = btn.innerHTML;
                btn.disabled = true;
                btn.innerHTML = '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span> Scanning Library...';
                
                const response = await fetch('?action=import_offline', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify(importData)
                });
                
                const result = await response.json();
                if (result) {
                  showToast(result.message, result.status);
                  if (result.status === 'success') {
                    const modalEl = document.getElementById('import-offline-modal');
                    if (modalEl) bootstrap.Modal.getOrCreateInstance(modalEl).hide();
                    importOfflineForm.reset();
                    fetchData('?action=get_offline_ids').then(ids => {
                      if (ids) offlineSongsSet = new Set(ids.map(id => parseInt(id)));
                      currentView.sort = 'manual_order';
                      const sortSelectEl = document.getElementById('sort-select');
                      if (sortSelectEl) sortSelectEl.value = 'manual_order';
                      loadView(currentView);
                    });
                  }
                }
                btn.disabled = false;
                btn.innerHTML = originalText;
              } catch (err) {
                showToast('Failed to parse JSON or import.', 'error');
                const btn = importOfflineForm.querySelector('button[type="submit"]');
                btn.disabled = false;
                btn.textContent = 'Import';
              }
            };
            reader.readAsText(file);
          });
        }
        
        if (importFavoritesForm) {
          importFavoritesForm.addEventListener('submit', async e => {
            e.preventDefault();
            const fileInput = document.getElementById('import-favorites-file');
            if (fileInput.files.length === 0) return;
            
            const file = fileInput.files[0];
            const reader = new FileReader();
            
            reader.onload = async (event) => {
              try {
                const importData = JSON.parse(event.target.result);
                if (!importData.songs || !Array.isArray(importData.songs)) {
                  showToast('Invalid JSON format.', 'error');
                  return;
                }
                if (importData.name !== "Favorites") {
                  if (!confirm("Data name doesn't match standard favorites backup. Do you want to add new data anyway?")) {
                    fileInput.value = '';
                    return;
                  }
                }
                
                const btn = importFavoritesForm.querySelector('button[type="submit"]');
                const originalText = btn.innerHTML;
                btn.disabled = true;
                btn.innerHTML = '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span> Scanning Library...';
                
                const response = await fetch('?action=import_favorites', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify(importData)
                });
                
                const result = await response.json();
                if (result) {
                  showToast(result.message, result.status);
                  if (result.status === 'success') {
                    importFavoritesModal.hide();
                    importFavoritesForm.reset();
                    loadView(currentView);
                  }
                }
                btn.disabled = false;
                btn.innerHTML = originalText;
              } catch (err) {
                showToast('Failed to parse JSON or import.', 'error');
                const btn = importFavoritesForm.querySelector('button[type="submit"]');
                btn.disabled = false;
                btn.textContent = 'Import';
              }
            };
            reader.readAsText(file);
          });
        }

        let metadataCropper = null;

        const isCollabCheckEl = document.getElementById('edit-metadata-is-collaborative');
        if (isCollabCheckEl) {
          isCollabCheckEl.addEventListener('change', (e) => {
            const container = document.getElementById('edit-song-collab-container');
            if (container) {
              container.classList.toggle('d-none', !e.target.checked);
            }
          });
        }
        
        const manageSongCollabBtn = document.getElementById('manage-song-collab-btn');
        if (manageSongCollabBtn) {
          manageSongCollabBtn.addEventListener('click', () => {
            const songId = document.getElementById('edit-metadata-id').value;
            if (!songId) {
              showToast("Save the song first before managing collaborators.", "error");
              return;
            }
            const songCollabModalEl = document.getElementById('song-collab-modal');
            if (songCollabModalEl) {
              const editMetaModalEl = document.getElementById('edit-metadata-modal');
              if (editMetaModalEl) {
                const editMetaModal = bootstrap.Modal.getInstance(editMetaModalEl);
                if (editMetaModal) editMetaModal.hide();
              }
              const songCollabModal = new bootstrap.Modal(songCollabModalEl);
              const collabInput = document.getElementById('song-collab-input');
              const collabDropdown = document.getElementById('song-collab-search-dropdown');
              document.getElementById('song-collab-song-id').value = songId;
              let selectedCollabUserId = null;
              
              const loadCollabs = async () => {
                const res = await fetchData('?action=manage_song_collaborators', {
                  method: 'POST', headers: {'Content-Type': 'application/json'},
                  body: JSON.stringify({ song_id: songId, collab_action: 'list' })
                });
                const listEl = document.getElementById('song-collab-list');
                if (res && res.status === 'success') {
                  if (res.collaborators.length === 0) {
                    listEl.innerHTML = '<p class="text-secondary small">No collaborators yet.</p>';
                  } else {
                    listEl.innerHTML = res.collaborators.map(c => `
                      <div class="list-group-item bg-transparent text-white d-flex justify-content-between align-items-center border-secondary px-0">
                        <div class="d-flex align-items-center gap-3">
                          <img src="?action=get_profile_picture&id=${c.id}" class="rounded-circle" style="width: 32px; height: 32px; object-fit: cover;">
                          <div>
                            <div class="d-flex align-items-center gap-2">
                              <span class="badge bg-dark border border-secondary text-secondary" style="font-size: 0.75rem;">ID: ${c.id}</span>
                              <strong class="text-white">${escapeHTML(c.artist)}</strong>
                            </div>
                            <div class="small text-secondary" style="font-size: 0.75rem; margin-top: 2px;">${escapeHTML(c.email || '')}</div>
                          </div>
                        </div>
                        <button class="btn btn-sm btn-outline-danger song-collab-remove-btn" data-id="${c.id}"><i class="bi bi-x-lg"></i></button>
                      </div>
                    `).join('');
                  }
                }
              };

              let collabSearchTimeout;
              collabInput.oninput = (e) => {
                clearTimeout(collabSearchTimeout);
                selectedCollabUserId = null;
                const q = e.target.value.trim();
                if (q === '') {
                  collabDropdown.classList.add('d-none');
                  return;
                }
                collabSearchTimeout = setTimeout(async () => {
                  const res = await fetchData('?action=manage_song_collaborators', {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({ song_id: songId, collab_action: 'search', query: q })
                  });
                  if (res && res.status === 'success') {
                    if (res.users.length > 0) {
                      collabDropdown.innerHTML = res.users.map(u => `
                        <div class="search-dropdown-item song-collab-user-item" data-id="${u.id}" data-artist="${escapeHTML(u.artist)}">
                          <img src="?action=get_profile_picture&id=${u.id}" class="search-dropdown-img rounded-circle">
                          <div class="search-dropdown-text">
                            <div class="search-dropdown-title">${escapeHTML(u.artist)}</div>
                            <div class="search-dropdown-subtitle">ID: ${u.id}</div>
                          </div>
                        </div>
                      `).join('');
                      collabDropdown.classList.remove('d-none');
                    } else {
                      collabDropdown.innerHTML = '<div class="p-3 text-secondary text-center small">No users found</div>';
                      collabDropdown.classList.remove('d-none');
                    }
                  }
                }, 300);
              };

              collabDropdown.onclick = (e) => {
                const item = e.target.closest('.song-collab-user-item');
                if (item) {
                  selectedCollabUserId = item.dataset.id;
                  collabInput.value = item.dataset.artist;
                  collabDropdown.classList.add('d-none');
                }
              };

              document.addEventListener('click', (e) => {
                if (collabDropdown && !collabDropdown.contains(e.target) && e.target !== collabInput) {
                  collabDropdown.classList.add('d-none');
                }
              });

              document.getElementById('song-collab-add-btn').onclick = async () => {
                const target = collabInput.value.trim();
                if (!target && !selectedCollabUserId) return;
                
                const reqBody = { song_id: songId, collab_action: 'add' };
                if (selectedCollabUserId) reqBody.target_id = selectedCollabUserId;
                else reqBody.target = target;
                
                const res = await fetchData('?action=manage_song_collaborators', {
                  method: 'POST', headers: {'Content-Type': 'application/json'},
                  body: JSON.stringify(reqBody)
                });
                if (res) { 
                  showToast(res.message, res.status); 
                  if (res.status === 'success') {
                    loadCollabs(); 
                    collabInput.value = '';
                    selectedCollabUserId = null;
                  }
                }
              };

              const expireSelect = document.getElementById('song-collab-expire-select');
              const customExpireInput = document.getElementById('song-collab-custom-expire');
              if (expireSelect && customExpireInput) {
                expireSelect.onchange = (e) => {
                  if (e.target.value === 'custom') customExpireInput.classList.remove('d-none');
                  else customExpireInput.classList.add('d-none');
                };
              }

              const copyLinkBtn = document.getElementById('song-collab-copy-link-btn');
              if (copyLinkBtn) {
                const newCopyBtn = copyLinkBtn.cloneNode(true);
                copyLinkBtn.parentNode.replaceChild(newCopyBtn, copyLinkBtn);
                
                newCopyBtn.addEventListener('click', async () => {
                  let expireVal = expireSelect ? expireSelect.value : '1440';
                  if (expireVal === 'custom') {
                    expireVal = customExpireInput.value.trim();
                    if (!expireVal || isNaN(expireVal) || parseInt(expireVal) <= 0) {
                      return showToast('Please enter a valid number of minutes.', 'error');
                    }
                  } else if (expireVal === 'forever') {
                    expireVal = null;
                  }
                  
                  newCopyBtn.disabled = true;
                  newCopyBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Generating...';

                  const res = await fetchData('?action=manage_song_collaborators', {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({ song_id: songId, collab_action: 'generate_link', expire: expireVal })
                  });

                  if (res && res.status === 'success') {
                    const inviteUrl = window.location.origin + window.location.pathname + '?song_invite=' + res.token;
                    const onSuccess = () => {
                      newCopyBtn.innerHTML = '<i class="bi bi-check-lg"></i> Link Copied!';
                      newCopyBtn.classList.replace('btn-outline-light', 'btn-success');
                      setTimeout(() => {
                        newCopyBtn.innerHTML = '<i class="bi bi-link-45deg"></i> Generate & Copy Link';
                        newCopyBtn.classList.replace('btn-success', 'btn-outline-light');
                      }, 2000);
                    };
                    const onError = () => showToast('Failed to copy link.', 'error');

                    if (navigator.clipboard && window.isSecureContext) {
                      navigator.clipboard.writeText(inviteUrl).then(onSuccess).catch(onError);
                    } else {
                      const textArea = document.createElement("textarea");
                      textArea.value = inviteUrl;
                      textArea.style.position = "fixed";
                      textArea.style.opacity = "0";
                      document.body.appendChild(textArea);
                      textArea.focus();
                      textArea.select();
                      try {
                        if (document.execCommand('copy')) onSuccess();
                        else onError();
                      } catch (err) { onError(); }
                      document.body.removeChild(textArea);
                    }
                  } else {
                    showToast(res?.message || 'Error generating link', 'error');
                    newCopyBtn.innerHTML = '<i class="bi bi-link-45deg"></i> Generate & Copy Link';
                  }
                  newCopyBtn.disabled = false;
                });
              }
              
              songCollabModalEl.onclick = async (evt) => {
                const removeBtn = evt.target.closest('.song-collab-remove-btn');
                if (removeBtn) {
                  if (!confirm('Remove this collaborator?')) return;
                  const res = await fetchData('?action=manage_song_collaborators', {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({ song_id: songId, collab_action: 'remove', collab_user_id: removeBtn.dataset.id })
                  });
                  if (res) { showToast(res.message, res.status); loadCollabs(); }
                }
              };

              songCollabModal.show();
              loadCollabs();
            }
          });
        }

        if (editMetadataForm) {
          editMetadataForm.addEventListener('submit', async e => {
            e.preventDefault();
            
            const submitBtn = document.getElementById('edit-metadata-submit-btn');
            const progContainer = document.getElementById('metadata-progress-container');
            const progBar = document.getElementById('metadata-progress');
            
            submitBtn.disabled = true;
            progContainer.classList.remove('d-none');
            progBar.style.width = '0%';
            progBar.textContent = '0%';

            const formData = new FormData();
            formData.append('id', document.getElementById('edit-metadata-id').value);
            formData.append('title', document.getElementById('edit-metadata-title').value);
            formData.append('artist', document.getElementById('edit-metadata-artist').value);
            formData.append('album', document.getElementById('edit-metadata-album').value);
            formData.append('genre', document.getElementById('edit-metadata-genre').value);
            formData.append('lyrics', document.getElementById('edit-metadata-lyrics').value);
            formData.append('is_private', document.getElementById('edit-metadata-is-private').checked ? 1 : 0);
            formData.append('is_collaborative', document.getElementById('edit-metadata-is-collaborative').checked ? 1 : 0);

            const doMetadataUpload = () => {
              const xhr = new XMLHttpRequest();
              xhr.upload.onprogress = (evt) => {
                if (evt.lengthComputable) {
                  const pct = Math.round((evt.loaded / evt.total) * 100);
                  progBar.style.width = pct + '%';
                  progBar.textContent = pct + '%';
                }
              };
              xhr.open('POST', '?action=edit_metadata', true);
              xhr.onload = () => {
                submitBtn.disabled = false;
                progContainer.classList.add('d-none');
                if (xhr.status === 200) {
                  try {
                    const result = JSON.parse(xhr.responseText);
                    if (result && result.status === 'success') {
                      showToast(result.message, 'success');
                      if (metadataCropper) { metadataCropper.destroy(); metadataCropper = null; }
                      if (editMetadataModal) editMetadataModal.hide();
                      loadView(currentView);
                    } else {
                      showToast(result.message || 'Upload failed', 'error');
                    }
                  } catch(err) {
                    showToast('Invalid server response.', 'error');
                  }
                } else {
                  showToast('Upload error', 'error');
                }
              };
              xhr.onerror = () => {
                submitBtn.disabled = false;
                progContainer.classList.add('d-none');
                showToast('Network error during upload', 'error');
              };
              xhr.send(formData);
            };

            if (metadataCropper) {
              metadataCropper.getCroppedCanvas({ width: 600, height: 600 }).toBlob(blob => {
                formData.append('cover_image', blob, 'cover.jpg');
                doMetadataUpload();
              }, 'image/jpeg', 0.85);
            } else {
              const coverInput = document.getElementById('edit-metadata-cover');
              if (coverInput && coverInput.files.length > 0) {
                formData.append('cover_image', coverInput.files[0]);
              }
              doMetadataUpload();
            }
          });

          const coverInput = document.getElementById('edit-metadata-cover');
          if (coverInput) {
            coverInput.addEventListener('change', function(e) {
              if (this.files && this.files[0]) {
                const reader = new FileReader();
                reader.onload = e => {
                  const preview = document.getElementById('edit-metadata-cover-preview');
                  preview.src = e.target.result;
                  if (metadataCropper) metadataCropper.destroy();
                  metadataCropper = new Cropper(preview, {
                    aspectRatio: 1,
                    viewMode: 1,
                    autoCropArea: 1,
                    dragMode: 'move',
                    background: false
                  });
                };
                reader.readAsDataURL(this.files[0]);
              }
            });
          }
        }
        
        const sasVolSlider = document.getElementById('sas-vol-slider');
        const sasVolVal = document.getElementById('sas-vol-val');
        
        if (sasVolSlider) {
          sasVolSlider.addEventListener('input', e => {
            sasVolVal.textContent = e.target.value + 'x';
            const activeId = document.getElementById('sas-song-id').value;
            if (currentSong && currentSong.id == activeId && perSongGain) {
                perSongGain.gain.setTargetAtTime(parseFloat(e.target.value), audioCtx.currentTime, 0.1);
            }
          });
        }
        
        document.querySelectorAll('.sas-eq-band').forEach(slider => {
          slider.addEventListener('input', e => {
            document.getElementById('sas-eq-preset-select').value = 'Custom';
            const activeId = document.getElementById('sas-song-id').value;
            if (currentSong && currentSong.id == activeId && audioCtx) {
              const bandIndex = parseInt(e.target.dataset.band);
              eqBands[bandIndex].gain.setTargetAtTime(parseFloat(e.target.value), audioCtx.currentTime, 0.1);
            }
          });
        });

        const sasEqPresetSelect = document.getElementById('sas-eq-preset-select');
        if (sasEqPresetSelect) {
          sasEqPresetSelect.addEventListener('change', (e) => {
            if (e.target.value === 'Custom') return;
            const preset = EQ_PRESETS[e.target.value];
            if (preset) {
              const sasEqBands = document.querySelectorAll('.sas-eq-band');
              preset.forEach((val, i) => { 
                if (sasEqBands[i]) sasEqBands[i].value = val; 
              });
              const activeId = document.getElementById('sas-song-id').value;
              if (currentSong && currentSong.id == activeId && audioCtx) {
                preset.forEach((val, i) => {
                  eqBands[i].gain.setTargetAtTime(val, audioCtx.currentTime, 0.1);
                });
              }
            }
          });
        }

        const sasSaveBtn = document.getElementById('sas-save-btn');
        if (sasSaveBtn) {
          sasSaveBtn.addEventListener('click', async () => {
            const songId = document.getElementById('sas-song-id').value;
            const vol = parseFloat(document.getElementById('sas-vol-slider').value);
            const eqs = Array.from(document.querySelectorAll('.sas-eq-band')).map(s => parseFloat(s.value));
            
            const result = await fetchData('?action=save_song_settings', {
              method: 'POST', headers: {'Content-Type': 'application/json'},
              body: JSON.stringify({ song_id: songId, volume: vol, eq: eqs })
            });

            if (result && result.status === 'success') {
              showToast('Song audio settings saved to database', 'success');
              
              if (globalSongCache[songId]) {
                 globalSongCache[songId].volume_multiplier = vol;
                 globalSongCache[songId].eq_bands = eqs;
              }
              if (currentSong && currentSong.id == songId) {
                 currentSong.volume_multiplier = vol;
                 currentSong.eq_bands = eqs;
                 applyAudioSettings();
              }
              
              bootstrap.Modal.getOrCreateInstance(document.getElementById('song-audio-settings-modal')).hide();
            }
          });
        }

        const sasResetBtn = document.getElementById('sas-reset-btn');
        if (sasResetBtn) {
          sasResetBtn.addEventListener('click', async () => {
            const songId = document.getElementById('sas-song-id').value;
            
            const result = await fetchData('?action=reset_song_settings', {
              method: 'POST', headers: {'Content-Type': 'application/json'},
              body: JSON.stringify({ song_id: songId })
            });

            if (result && result.status === 'success') {
              showToast('Song audio settings reset to global default', 'success');
              
              if (globalSongCache[songId]) {
                 globalSongCache[songId].volume_multiplier = null;
                 globalSongCache[songId].eq_bands = null;
              }
              if (currentSong && currentSong.id == songId) {
                 currentSong.volume_multiplier = null;
                 currentSong.eq_bands = null;
                 applyAudioSettings();
              }

              bootstrap.Modal.getOrCreateInstance(document.getElementById('song-audio-settings-modal')).hide();
            }
          });
        }

        const handleLogout = async (e) => {
          if (e) e.preventDefault(); // Stop browser from adding '#' to URL and breaking the view
          await fetchData('?action=logout');
          currentUser = null;
          cachedExploreData = null;
          updateAppFavicon('?action=get_app_icon');
          updateUIForAuthState();
          
          const authRequiredViews = ['user_profile', 'get_user_stats', 'get_offline_songs', 'get_favorites', 'get_listen_later', 'get_notes', 'get_community', 'get_history', 'get_following', 'get_recommendations', 'get_user_playlists', 'get_collab_playlists'];
          
          if (authRequiredViews.includes(currentView.type)) {
            loadView({ type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' });
          } else {
            loadView(currentView);
          }
        };
        
        document.getElementById('profile-dropdown-logout-desktop').addEventListener('click', handleLogout);
        document.getElementById('profile-dropdown-logout-mobile').addEventListener('click', handleLogout);
        document.getElementById('profile-dropdown-stats-desktop').addEventListener('click', (e) => { e.preventDefault(); loadView({type: 'get_user_stats'}); });
        document.getElementById('profile-dropdown-stats-mobile').addEventListener('click', (e) => { e.preventDefault(); loadView({type: 'get_user_stats'}); });
        
        const sleepTimerBubble = document.getElementById('sleep-timer-bubble');
        const sleepTimerCountdown = document.getElementById('sleep-timer-countdown');
        const sleepTimerCancelBtn = document.getElementById('sleep-timer-cancel-btn');
        const sleepTimerWakeBtn = document.getElementById('sleep-timer-wake-btn');

        let noSleep = new NoSleep();

        const releaseWakeLock = () => {
          if (sleepTimerKeepAwake) {
            noSleep.disable();
            sleepTimerKeepAwake = false;
            if (sleepTimerWakeBtn) {
              sleepTimerWakeBtn.classList.remove('active');
              sleepTimerWakeBtn.innerHTML = '<i class="bi bi-display"></i>';
            }
          }
        };

        const toggleWakeLock = async (e) => {
          if (e) e.stopPropagation();
          
          if (sleepTimerKeepAwake) {
            releaseWakeLock();
            showToast('Screen wake lock disabled.', 'info');
          } else {
            try {
              noSleep.enable();
              sleepTimerKeepAwake = true;
              if (sleepTimerWakeBtn) {
                sleepTimerWakeBtn.classList.add('active');
                sleepTimerWakeBtn.innerHTML = '<i class="bi bi-display-fill"></i>';
              }
              showToast('Screen will stay awake.', 'success');
            } catch (err) {
              showToast("Failed to acquire screen wake lock.", "error");
            }
          }
        };

        if (sleepTimerWakeBtn) {
          sleepTimerWakeBtn.addEventListener('click', toggleWakeLock);
        }

        const cancelSleepTimer = () => {
          if (sleepTimerInterval) clearInterval(sleepTimerInterval);
          sleepTimerInterval = null;
          sleepTimerBubble.classList.add('d-none');
          releaseWakeLock();
          showToast('Sleep timer canceled.', 'info');
        };

        sleepTimerCancelBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          cancelSleepTimer();
        });

        const handleSleepTimer = (e) => {
          if (e) e.preventDefault();
          if (sleepTimerInterval) {
            if (confirm(`Sleep timer is active. Cancel it?`)) {
              cancelSleepTimer();
            }
            return;
          }
          const mins = prompt("Stop playing after how many minutes?", "30");
          if (mins && !isNaN(mins) && parseInt(mins) > 0) {
            releaseWakeLock();

            const ms = parseInt(mins) * 60000;
            sleepTimerEndTime = Date.now() + ms;
            
            const updateTimer = () => {
              const now = Date.now();
              const remaining = sleepTimerEndTime - now;
              if (remaining <= 0) {
                clearInterval(sleepTimerInterval);
                sleepTimerInterval = null;
                sleepTimerBubble.classList.add('d-none');
                releaseWakeLock();
                if (isPlaying) togglePlayPause();
                showToast('Sleep timer reached. Playback paused.', 'info');
                return;
              }
              const totalSeconds = Math.floor(remaining / 1000);
              const m = Math.floor(totalSeconds / 60);
              const s = (totalSeconds % 60).toString().padStart(2, '0');
              sleepTimerCountdown.textContent = `${m}:${s}`;
            };
            
            updateTimer();
            sleepTimerInterval = setInterval(updateTimer, 1000);
            sleepTimerBubble.classList.remove('d-none');
            showToast(`Sleep timer set for ${mins} minutes.`, 'success');
          }
        };

        // Sleep Timer Bubble Dragging Logic
        let isDraggingBubble = false;
        let bubbleOffsetX, bubbleOffsetY;

        const startDragBubble = (e) => {
          if (e.target.closest('.action-btn')) return;
          isDraggingBubble = true;
          const clientX = e.touches ? e.touches[0].clientX : e.clientX;
          const clientY = e.touches ? e.touches[0].clientY : e.clientY;
          const rect = sleepTimerBubble.getBoundingClientRect();
          bubbleOffsetX = clientX - rect.left;
          bubbleOffsetY = clientY - rect.top;
          sleepTimerBubble.style.cursor = 'grabbing';
        };

        const moveDragBubble = (e) => {
          if (!isDraggingBubble) return;
          e.preventDefault(); // Prevents screen scrolling while dragging
          const clientX = e.touches ? e.touches[0].clientX : e.clientX;
          const clientY = e.touches ? e.touches[0].clientY : e.clientY;
          
          let newLeft = clientX - bubbleOffsetX;
          let newTop = clientY - bubbleOffsetY;
          
          const maxX = window.innerWidth - sleepTimerBubble.offsetWidth;
          const maxY = window.innerHeight - sleepTimerBubble.offsetHeight;
          newLeft = Math.max(0, Math.min(newLeft, maxX));
          newTop = Math.max(0, Math.min(newTop, maxY));
          
          sleepTimerBubble.style.left = `${newLeft}px`;
          sleepTimerBubble.style.top = `${newTop}px`;
          sleepTimerBubble.style.right = 'auto'; // Disable initial right constraint
        };

        const stopDragBubble = () => {
          if (isDraggingBubble) {
            isDraggingBubble = false;
            sleepTimerBubble.style.cursor = 'grab';
          }
        };

        sleepTimerBubble.addEventListener('mousedown', startDragBubble);
        sleepTimerBubble.addEventListener('touchstart', startDragBubble, {passive: false});
        document.addEventListener('mousemove', moveDragBubble, {passive: false});
        document.addEventListener('touchmove', moveDragBubble, {passive: false});
        document.addEventListener('mouseup', stopDragBubble);
        document.addEventListener('touchend', stopDragBubble);

        document.getElementById('sleep-timer-btn-desktop').addEventListener('click', handleSleepTimer);
        document.getElementById('sleep-timer-btn-mobile').addEventListener('click', handleSleepTimer);

        let profileBgCropper = null;
        const profileBgInput = document.getElementById('profile-bg-input');
        const profileBgPreview = document.getElementById('profile-bg-preview');
        const profileBgPreviewContainer = document.getElementById('profile-bg-preview-container');

        if (profileBgInput) {
          profileBgInput.addEventListener('change', function(e) {
            if (this.files && this.files[0]) {
              const reader = new FileReader();
              reader.onload = ev => {
                profileBgPreviewContainer.style.display = 'block';
                profileBgPreview.src = ev.target.result;
                if (profileBgCropper) profileBgCropper.destroy();
                profileBgCropper = new Cropper(profileBgPreview, {
                  aspectRatio: 3 / 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
              };
              reader.readAsDataURL(this.files[0]);
            }
          });
        }

        const profileBgForm = document.getElementById('profile-bg-form');
        const bioForm = document.getElementById('bio-form');

        if (profileBgForm) {
          profileBgForm.addEventListener('submit', async e => {
            e.preventDefault();
            if (profileBgInput.files.length === 0 && !profileBgCropper) {
              showToast('Please select an image file.', 'error');
              return;
            }
            const submitBtn = document.getElementById('profile-bg-submit-btn');
            submitBtn.disabled = true;
            submitBtn.textContent = 'Uploading...';

            const doBgUpload = async (blob) => {
              const formData = new FormData();
              formData.append('profile_background', blob, 'background.jpg');
              
              try {
                const res = await fetch('?action=upload_profile_background', { method: 'POST', body: formData });
                const result = await res.json();
                showToast(result.message, result.status);
                if (result.status === 'success') {
                   if (profileBgCropper) { profileBgCropper.destroy(); profileBgCropper = null; }
                   profileBgPreviewContainer.style.display = 'none';
                   profileBgInput.value = '';
                   await checkSession();
                   if (currentView.type === 'user_profile') loadView(currentView);
                }
              } catch (err) {
                showToast('Upload failed', 'error');
              }
              submitBtn.disabled = false;
              submitBtn.textContent = 'Save Uploaded Background';
            };

            if (profileBgCropper) {
              profileBgCropper.getCroppedCanvas({ width: 1200, height: 400 }).toBlob(blob => {
                doBgUpload(blob);
              }, 'image/jpeg', 0.85);
            } else {
              doBgUpload(profileBgInput.files[0]);
            }
          });
        }

        // --- BACKGROUND GENERATOR LOGIC ---
        const bgCanvas = document.getElementById('bg-gen-canvas');
        if (bgCanvas) {
          const bgCtx = bgCanvas.getContext('2d');
          const bgState = { pattern: 'blobs', hue: Math.floor(Math.random()*360), saturation: 70, complexity: 5, scale: 100, angle: 0, drawStyle: 'fill', seed: Math.random() };
          let bgRng = null;

          function bgMulberry32(a) {
            return function() {
              var t = a += 0x6D2B79F5; t = Math.imul(t ^ t >>> 15, t | 1);
              t ^= t + Math.imul(t ^ t >>> 7, t | 61); return ((t ^ t >>> 14) >>> 0) / 4294967296;
            }
          }
          function bgGetHsl(h, s, l, a = 1) { return `hsla(${h}, ${s}%, ${l}%, ${a})`; }
          function bgGetPalette() {
            const h = bgState.hue; const s = bgState.saturation;
            return [
                bgGetHsl(h, s, 40), bgGetHsl(h, s*0.6, 30), bgGetHsl((h + 40) % 360, s*0.8, 40), 
                bgGetHsl((h - 40 + 360) % 360, s*0.8, 40), bgGetHsl(h, s, 80, 0.7)
            ];
          }
          function bgApplyStyle(color) {
            bgCtx.fillStyle = color; bgCtx.strokeStyle = color;
            bgCtx.lineWidth = Math.max(1, (bgState.scale / 100) * 15 / (bgState.complexity * 0.5));
            bgCtx.lineCap = 'round'; bgCtx.lineJoin = 'round';
          }
          function bgDrawPath() {
            if (bgState.drawStyle === 'fill') bgCtx.fill();
            else if (bgState.drawStyle === 'stroke') bgCtx.stroke();
            else { if (bgRng() > 0.5) bgCtx.fill(); else bgCtx.stroke(); }
          }

          const bgDrawFns = {
            blobs: (b, pal) => {
              const count = bgState.complexity * 3; const baseSize = (b.w * (bgState.scale / 100)) / 4;
              for (let i = 0; i < count; i++) {
                const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; const size = baseSize * (0.5 + bgRng());
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]);
                bgCtx.beginPath(); const points = 5 + Math.floor(bgRng() * 3); let angle = 0;
                for(let j=0; j<=points; j++) {
                  const r = size * (0.6 + bgRng() * 0.4); const x = cx + Math.cos(angle) * r; const y = cy + Math.sin(angle) * r;
                  if (j === 0) bgCtx.moveTo(x, y); else {
                      const cp1x = cx + Math.cos(angle - Math.PI/points) * size; const cp1y = cy + Math.sin(angle - Math.PI/points) * size;
                      bgCtx.quadraticCurveTo(cp1x, cp1y, x, y);
                  }
                  angle += (Math.PI * 2) / points;
                }
                bgDrawPath();
              }
            },
            geometric: (b, pal) => {
              const count = bgState.complexity * 5; const baseSize = (b.w * (bgState.scale / 100)) / 6;
              for (let i = 0; i < count; i++) {
                  const x = b.x + bgRng() * b.w; const y = b.y + bgRng() * b.h; const size = baseSize * (0.2 + bgRng());
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]);
                  const type = Math.floor(bgRng() * 3);
                  bgCtx.save(); bgCtx.translate(x, y); bgCtx.rotate(bgRng() * Math.PI * 2); bgCtx.beginPath();
                  if (type === 0) bgCtx.arc(0, 0, size, 0, Math.PI * 2); else if (type === 1) bgCtx.arc(0, 0, size, 0, Math.PI);
                  else { const rw = size * 2; const rh = size * 0.5; bgCtx.roundRect(-rw/2, -rh/2, rw, rh, rh/2); }
                  bgDrawPath(); bgCtx.restore();
              }
            },
            mesh: (b, pal) => {
              const count = bgState.complexity * 2; const baseSize = b.w * (bgState.scale / 100) * 0.8;
              for (let i = 0; i < count; i++) {
                  const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; const size = baseSize * (0.5 + bgRng());
                  const cBase = pal[Math.floor(bgRng() * pal.length)];
                  const grad = bgCtx.createRadialGradient(cx, cy, 0, cx, cy, size);
                  grad.addColorStop(0, cBase.replace(/[\d\.]+\)$/, '1)')); grad.addColorStop(1, cBase.replace(/[\d\.]+\)$/, '0)'));
                  bgCtx.fillStyle = grad; bgCtx.globalCompositeOperation = 'screen';
                  bgCtx.fillRect(cx - size, cy - size, size * 2, size * 2); bgCtx.globalCompositeOperation = 'source-over';
              }
            },
            waves: (b, pal) => {
              const count = bgState.complexity * 3; const sp = b.h / count; const amp = (bgState.scale / 100) * 200;
              for (let i = 0; i <= count; i++) {
                  bgApplyStyle(pal[i % pal.length]); bgCtx.beginPath(); bgCtx.moveTo(b.x, b.y + b.h); bgCtx.lineTo(b.x, b.y + i * sp + (bgRng() * 50));
                  const pts = 5; const step = b.w / pts; let cx = b.x; let cy = b.y + i * sp;
                  for(let j=0; j<pts; j++) {
                      const nX = cx + step; const nY = cy + (bgRng() > 0.5 ? 1 : -1) * amp * bgRng();
                      bgCtx.bezierCurveTo(cx + step/2, cy, nX - step/2, nY, nX, nY); cx = nX; cy = nY;
                  }
                  bgCtx.lineTo(b.x + b.w, b.y + b.h); bgDrawPath();
              }
            },
            stripes: (b, pal) => {
              const w = (bgState.scale / 100) * 100; const gap = w * (10 / bgState.complexity);
              for(let x = b.x; x < b.x + b.w * 2; x += (w + gap)) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x - b.w, b.y, w, b.h); bgDrawPath(); }
            },
            dots: (b, pal) => {
              const sp = (bgState.scale / 100) * 100 + 20; const rad = sp * (bgState.complexity / 20);
              for(let y = b.y; y < b.y + b.h; y += sp) { for(let x = b.x; x < b.x + b.w; x += sp) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.arc(x + (bgRng()*sp*0.2), y + (bgRng()*sp*0.2), rad * (0.5+bgRng()), 0, Math.PI*2); bgDrawPath(); } }
            },
            particles: (b, pal) => {
              const count = bgState.complexity * 10; const pts = []; for(let i=0; i<count; i++) pts.push({ x: b.x + bgRng()*b.w, y: b.y + bgRng()*b.h, c: pal[Math.floor(bgRng()*pal.length)] });
              const cDist = (bgState.scale / 100) * 300; bgCtx.lineWidth = 2;
              for(let i=0; i<pts.length; i++) {
                  for(let j=i+1; j<pts.length; j++) {
                      const d = Math.hypot(pts[i].x - pts[j].x, pts[i].y - pts[j].y);
                      if (d < cDist) { bgCtx.strokeStyle = pts[i].c; bgCtx.globalAlpha = 1 - (d/cDist); bgCtx.beginPath(); bgCtx.moveTo(pts[i].x, pts[i].y); bgCtx.lineTo(pts[j].x, pts[j].y); bgCtx.stroke(); bgCtx.globalAlpha = 1; }
                  }
                  bgApplyStyle(pts[i].c); bgCtx.beginPath(); bgCtx.arc(pts[i].x, pts[i].y, 5 + bgRng()*10, 0, Math.PI*2); bgDrawPath();
              }
            },
            triangles: (b, pal) => {
              const step = (bgState.scale / 100) * 150 + 20;
              for(let y = b.y; y < b.y + b.h; y += step) { for(let x = b.x; x < b.x + b.w; x += step) { if (bgRng() > bgState.complexity/10) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.moveTo(x + bgRng()*step, y + bgRng()*step); bgCtx.lineTo(x + step + bgRng()*step, y + bgRng()*step); bgCtx.lineTo(x + bgRng()*step, y + step + bgRng()*step); bgCtx.closePath(); bgDrawPath(); } }
            },
            rays: (b, pal) => {
              const count = bgState.complexity * 8; const rad = b.w; 
              for(let i=0; i<count; i++) { bgApplyStyle(pal[i % pal.length]); const a1 = (i / count) * Math.PI * 2; const a2 = ((i + (bgRng()*0.5 + 0.5)) / count) * Math.PI * 2; bgCtx.beginPath(); bgCtx.moveTo(0, 0); bgCtx.lineTo(Math.cos(a1) * rad, Math.sin(a1) * rad); bgCtx.lineTo(Math.cos(a2) * rad, Math.sin(a2) * rad); bgCtx.closePath(); bgDrawPath(); }
            },
            squares: (b, pal) => {
              const count = bgState.complexity * 5; for (let i = 0; i < count; i++) { const s = (bgState.scale / 100) * 200 * (0.2 + bgRng()); const x = b.x + bgRng() * b.w; const y = b.y + bgRng() * b.h; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x-s/2, y-s/2, s, s); bgDrawPath(); }
            },
            hexagons: (b, pal) => {
              const r = (bgState.scale / 100) * 50 + 10; const dx = r * Math.sqrt(3); const dy = r * 1.5; let row = 0;
              for(let y = b.y; y < b.y + b.h + r; y += dy) { let offset = (row % 2 === 0) ? 0 : dx / 2; for(let x = b.x; x < b.x + b.w + r; x += dx) { if (bgRng() > (bgState.complexity / 10)) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); for (let i = 0; i < 6; i++) { const angle = i * Math.PI / 3 + Math.PI/6; const px = x + offset + r * Math.cos(angle); const py = y + r * Math.sin(angle); if (i === 0) bgCtx.moveTo(px, py); else bgCtx.lineTo(px, py); } bgCtx.closePath(); bgDrawPath(); } row++; }
            },
            concentric: (b, pal) => {
              const count = bgState.complexity * 2; const maxR = (bgState.scale / 100) * 300;
              for(let i=0; i<count; i++) { const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; const rings = 3 + Math.floor(bgRng()*5); for(let r=rings; r>0; r--) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.arc(cx, cy, (r/rings)*maxR, 0, Math.PI*2); bgDrawPath(); } }
            },
            noise: (b, pal) => {
              const size = Math.max(5, (bgState.scale / 100) * 30); const den = bgState.complexity * 0.08; 
              for(let y = b.y; y < b.y + b.h; y += size) { for(let x = b.x; x < b.x + b.w; x += size) { if (bgRng() < den) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x, y, size, size); bgDrawPath(); } } }
            },
            scribble: (b, pal) => {
              const count = bgState.complexity * 3; for(let i=0; i<count; i++) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); let cx = b.x + bgRng() * b.w; let cy = b.y + bgRng() * b.h; bgCtx.moveTo(cx, cy); const segs = 20 + bgRng() * 50; const jump = (bgState.scale / 100) * 100; for(let j=0; j<segs; j++) { cx += (bgRng() - 0.5) * jump; cy += (bgRng() - 0.5) * jump; bgCtx.lineTo(cx, cy); } bgCtx.stroke(); }
            },
            diamonds: (b, pal) => {
              const size = (bgState.scale / 100) * 60 + 10; for(let y = b.y; y < b.y + b.h; y += size) { for(let x = b.x; x < b.x + b.w; x += size) { if (bgRng() > (bgState.complexity / 10)) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save(); bgCtx.translate(x, y); bgCtx.rotate(Math.PI/4); bgCtx.beginPath(); bgCtx.rect(-size/2, -size/2, size, size); bgDrawPath(); bgCtx.restore(); } }
            },
            checkers: (b, pal) => {
              const size = (bgState.scale / 100) * 60 + 10; for(let y = b.y; y < b.y + b.h; y += size) { for(let x = b.x; x < b.x + b.w; x += size) { if (bgRng() > (bgState.complexity / 10)) continue; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); bgCtx.rect(x, y, size, size); bgDrawPath(); } }
            },
            maze: (b, pal) => {
              const step = (bgState.scale / 100) * 40 + 10; bgCtx.lineWidth = step * (bgState.complexity / 20) + 2; bgCtx.lineCap = 'round';
              for(let y = b.y; y < b.y + b.h; y += step) { for(let x = b.x; x < b.x + b.w; x += step) { bgCtx.strokeStyle = pal[Math.floor(bgRng() * pal.length)]; bgCtx.beginPath(); if (bgRng() > 0.5) { bgCtx.moveTo(x, y); bgCtx.lineTo(x + step, y + step); } else { bgCtx.moveTo(x + step, y); bgCtx.lineTo(x, y + step); } bgCtx.stroke(); } }
            },
            lines: (b, pal) => {
              const count = bgState.complexity * 10; const len = (bgState.scale / 100) * 300; for(let i=0; i<count; i++) { bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); const x = b.x + bgRng() * b.w; const y = b.y + bgRng() * b.h; bgCtx.moveTo(x, y); if (bgRng() > 0.5) bgCtx.lineTo(x + len * (bgRng()>0.5?1:-1), y); else bgCtx.lineTo(x, y + len * (bgRng()>0.5?1:-1)); bgCtx.stroke(); }
            },
            crosses: (b, pal) => {
              const step = (bgState.scale / 100) * 80 + 20; const size = step * (bgState.complexity / 15); bgCtx.lineWidth = size * 0.3;
              for(let y = b.y; y < b.y + b.h; y += step) { for(let x = b.x; x < b.x + b.w; x += step) { if (bgRng() > 0.8) continue; bgCtx.strokeStyle = pal[Math.floor(bgRng() * pal.length)]; bgCtx.beginPath(); bgCtx.moveTo(x - size/2, y); bgCtx.lineTo(x + size/2, y); bgCtx.moveTo(x, y - size/2); bgCtx.lineTo(x, y + size/2); bgCtx.stroke(); } }
            },
            spirals: (b, pal) => {
              const count = bgState.complexity * 2; const maxR = (bgState.scale / 100) * 150; for(let i=0; i<count; i++) { const cx = b.x + bgRng() * b.w; const cy = b.y + bgRng() * b.h; bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.beginPath(); let loops = 2 + bgRng() * 4; for(let a=0; a<Math.PI * 2 * loops; a+=0.1) { const r = (a / (Math.PI*2)) * (maxR / loops); const x = cx + Math.cos(a) * r; const y = cy + Math.sin(a) * r; if (a===0) bgCtx.moveTo(x,y); else bgCtx.lineTo(x,y); } bgDrawPath(); }
            }
          };

          const bgShapes = {
            circle: (s) => { bgCtx.arc(0, 0, s, 0, Math.PI*2); },
            square: (s) => { bgCtx.rect(-s/2, -s/2, s, s); },
            diamond: (s) => { bgCtx.moveTo(0, -s); bgCtx.lineTo(s, 0); bgCtx.lineTo(0, s); bgCtx.lineTo(-s, 0); bgCtx.closePath(); },
            triangle: (s) => { bgCtx.moveTo(0, -s*0.8); bgCtx.lineTo(s*0.866, s*0.6); bgCtx.lineTo(-s*0.866, s*0.6); bgCtx.closePath(); },
            star: (s) => { for(let i=0;i<10;i++){ const r = i%2===0?s:s/2; const a = i*Math.PI/5 - Math.PI/2; if (i===0)bgCtx.moveTo(Math.cos(a)*r,Math.sin(a)*r); else bgCtx.lineTo(Math.cos(a)*r,Math.sin(a)*r); } bgCtx.closePath(); },
            cross: (s) => { const q=s/3; bgCtx.moveTo(-s,-q); bgCtx.lineTo(-q,-q); bgCtx.lineTo(-q,-s); bgCtx.lineTo(q,-s); bgCtx.lineTo(q,-q); bgCtx.lineTo(s,-q); bgCtx.lineTo(s,q); bgCtx.lineTo(q,q); bgCtx.lineTo(q,s); bgCtx.lineTo(-q,s); bgCtx.lineTo(-q,q); bgCtx.lineTo(-s,q); bgCtx.closePath(); },
            hexagon: (s) => { for(let i=0;i<6;i++){ const a = i*Math.PI/3; if (i===0)bgCtx.moveTo(s*Math.cos(a),s*Math.sin(a)); else bgCtx.lineTo(s*Math.cos(a),s*Math.sin(a)); } bgCtx.closePath(); },
            pentagon: (s) => { for(let i=0;i<5;i++){ const a = i*Math.PI*2/5 - Math.PI/2; if (i===0)bgCtx.moveTo(s*Math.cos(a),s*Math.sin(a)); else bgCtx.lineTo(s*Math.cos(a),s*Math.sin(a)); } bgCtx.closePath(); },
            octagon: (s) => { for(let i=0;i<8;i++){ const a = i*Math.PI/4 - Math.PI/8; if (i===0)bgCtx.moveTo(s*Math.cos(a),s*Math.sin(a)); else bgCtx.lineTo(s*Math.cos(a),s*Math.sin(a)); } bgCtx.closePath(); },
            ring: (s) => { bgCtx.arc(0, 0, s, 0, Math.PI*2); bgCtx.moveTo(s*0.7,0); bgCtx.arc(0, 0, s*0.7, 0, Math.PI*2, true); },
            heart: (s) => { const x=0, y=0; bgCtx.moveTo(x, y+s/3); bgCtx.bezierCurveTo(x, y-s/2, x-s, y-s/2, x-s, y); bgCtx.bezierCurveTo(x-s, y+s/2, x, y+s*0.8, x, y+s); bgCtx.bezierCurveTo(x, y+s*0.8, x+s, y+s/2, x+s, y); bgCtx.bezierCurveTo(x+s, y-s/2, x, y-s/2, x, y+s/3); },
            moon: (s) => { bgCtx.arc(0, 0, s, 0, Math.PI*2); bgCtx.arc(s*0.3, -s*0.3, s*0.8, 0, Math.PI*2, true); },
            spade: (s) => { bgCtx.moveTo(0, s*0.2); bgCtx.bezierCurveTo(s, s*0.2, s, -s, 0, -s); bgCtx.bezierCurveTo(-s, -s, -s, s*0.2, 0, s*0.2); bgCtx.moveTo(0, 0); bgCtx.lineTo(-s*0.3, s); bgCtx.lineTo(s*0.3, s); bgCtx.closePath(); },
            club: (s) => { bgCtx.arc(0, -s*0.5, s*0.4, 0, Math.PI*2); bgCtx.arc(-s*0.4, s*0.2, s*0.4, 0, Math.PI*2); bgCtx.arc(s*0.4, s*0.2, s*0.4, 0, Math.PI*2); bgCtx.moveTo(0, 0); bgCtx.lineTo(-s*0.2, s); bgCtx.lineTo(s*0.2, s); bgCtx.closePath(); },
            leaf: (s) => { bgCtx.moveTo(0, -s); bgCtx.quadraticCurveTo(s, 0, 0, s); bgCtx.quadraticCurveTo(-s, 0, 0, -s); },
            shield: (s) => { bgCtx.moveTo(-s, -s*0.8); bgCtx.lineTo(s, -s*0.8); bgCtx.quadraticCurveTo(s, s*0.5, 0, s); bgCtx.quadraticCurveTo(-s, s*0.5, -s, -s*0.8); },
            gem: (s) => { bgCtx.moveTo(-s*0.6, -s); bgCtx.lineTo(s*0.6, -s); bgCtx.lineTo(s, -s*0.2); bgCtx.lineTo(0, s); bgCtx.lineTo(-s, -s*0.2); bgCtx.closePath(); },
            droplet: (s) => { bgCtx.moveTo(0, -s); bgCtx.quadraticCurveTo(s, 0, s, s*0.4); bgCtx.arc(0, s*0.4, s, 0, Math.PI); bgCtx.quadraticCurveTo(-s, 0, 0, -s); },
            burst: (s) => { for(let i=0;i<16;i++){ const r = i%2===0?s:s*0.3; const a = i*Math.PI/8; if (i===0)bgCtx.moveTo(Math.cos(a)*r,Math.sin(a)*r); else bgCtx.lineTo(Math.cos(a)*r,Math.sin(a)*r); } bgCtx.closePath(); },
            sparkle: (s) => { for(let i=0;i<8;i++){ const r = i%2===0?s:s*0.1; const a = i*Math.PI/4; if (i===0)bgCtx.moveTo(Math.cos(a)*r,Math.sin(a)*r); else bgCtx.lineTo(Math.cos(a)*r,Math.sin(a)*r); } bgCtx.closePath(); },
            clover: (s) => { for(let i=0; i<4; i++){ const a=i*Math.PI/2; bgCtx.arc(Math.cos(a)*s*0.5, Math.sin(a)*s*0.5, s*0.5, 0, Math.PI*2); } },
            flower: (s) => { for(let i=0; i<6; i++){ const a=i*Math.PI/3; bgCtx.arc(Math.cos(a)*s*0.6, Math.sin(a)*s*0.6, s*0.4, 0, Math.PI*2); } bgCtx.arc(0,0,s*0.3,0,Math.PI*2); }
          };

          const bgLayouts = {
            scatter: (b, pal, shapeFn) => {
              const count = bgState.complexity * 12; const baseSize = (b.w * (bgState.scale / 100)) / 15;
              for(let i=0;i<count;i++){ 
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(b.x+bgRng()*b.w, b.y+bgRng()*b.h); bgCtx.rotate(bgRng()*Math.PI*2);
                bgCtx.beginPath(); shapeFn(baseSize * (0.3+bgRng())); bgDrawPath(); bgCtx.restore();
              }
            },
            grid: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 80 + 20; const size = step * (bgState.complexity / 20);
              for(let y=b.y; y<b.y+b.h; y+=step) { for(let x=b.x; x<b.x+b.w; x+=step) {
                if (bgRng() > 0.9) continue;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(x, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
              }}
            },
            isometric: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 80 + 20; const size = step * (bgState.complexity / 20); let row=0;
              for(let y=b.y; y<b.y+b.h; y+=step*0.866) { let off=(row%2===0)?0:step/2; for(let x=b.x; x<b.x+b.w; x+=step) {
                if (bgRng() > 0.9) continue;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(x+off, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
              } row++;}
            },
            concentric: (b, pal, shapeFn) => {
              const count = bgState.complexity * 3; const maxR = (bgState.scale / 100) * 150;
              for(let i=0;i<count;i++){ 
                const cx=b.x+bgRng()*b.w; const cy=b.y+bgRng()*b.h; const rings=3+Math.floor(bgRng()*5);
                for(let r=rings; r>0; r--) {
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(cx, cy); bgCtx.beginPath(); shapeFn(maxR*(r/rings)); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            radial: (b, pal, shapeFn) => {
              const count = bgState.complexity * 12; const maxR = b.w; const cx=0, cy=0;
              for(let i=0;i<count;i++){ 
                const a = (i/count)*Math.PI*2; const r = bgRng()*maxR;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(cx+Math.cos(a)*r, cy+Math.sin(a)*r); bgCtx.rotate(a + Math.PI/2);
                bgCtx.beginPath(); shapeFn((bgState.scale/100)*40 * (0.5+bgRng())); bgDrawPath(); bgCtx.restore();
              }
            },
            spiral: (b, pal, shapeFn) => {
              const count = bgState.complexity * 15; const maxR = b.w; const cx = b.x + b.w/2; const cy = b.y + b.h/2;
              for(let i=0; i<count; i++) {
                const a = i * 0.5; const r = (i/count) * maxR;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(cx + Math.cos(a)*r, cy + Math.sin(a)*r); bgCtx.rotate(a);
                bgCtx.beginPath(); shapeFn((bgState.scale/100) * 20 * (1 + bgRng())); bgDrawPath(); bgCtx.restore();
              }
            },
            waveGrid: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 60 + 20; const size = step * (bgState.complexity / 20);
              for(let x=b.x; x<b.x+b.w; x+=step) {
                let yOffset = Math.sin(x * 0.05) * 100;
                for(let y=b.y; y<b.y+b.h; y+=step) {
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(x, y + yOffset); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            zigzag: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 60 + 20; const size = step * (bgState.complexity / 20);
              let flip = false;
              for(let y=b.y; y<b.y+b.h; y+=step) {
                flip = !flip;
                for(let x=b.x; x<b.x+b.w; x+=step) {
                  let px = x + (flip ? step/2 : 0);
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(px, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            orbit: (b, pal, shapeFn) => {
              const cx = b.x + b.w/2; const cy = b.y + b.h/2; const rings = bgState.complexity; const maxR = b.w;
              for(let r=1; r<=rings; r++) {
                const rad = (r/rings) * maxR; const items = r * 6;
                for(let i=0; i<items; i++) {
                  const a = (i/items) * Math.PI * 2 + (bgRng()*0.5);
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(cx + Math.cos(a)*rad, cy + Math.sin(a)*rad); bgCtx.rotate(a);
                  bgCtx.beginPath(); shapeFn((bgState.scale/100) * 30); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            pyramid: (b, pal, shapeFn) => {
              const step = (bgState.scale / 100) * 60 + 20; const size = step * (bgState.complexity / 20);
              const rows = Math.floor(b.h / step);
              for(let r=0; r<rows; r++) {
                const cols = r + 1; const startX = (b.x + b.w/2) - (cols * step)/2;
                const y = b.y + r * step;
                for(let c=0; c<cols; c++) {
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(startX + c * step, y); bgCtx.beginPath(); shapeFn(size); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            waterfall: (b, pal, shapeFn) => {
              const cols = bgState.complexity * 5; const stepX = b.w / cols;
              for(let c=0; c<cols; c++) {
                const x = b.x + c * stepX;
                const offset = bgRng() * 1000;
                for(let y=b.y; y<b.y+b.h; y+= (bgState.scale/100)*40) {
                  const px = x + Math.sin((y+offset)*0.02) * 30;
                  bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                  bgCtx.translate(px, y); bgCtx.beginPath(); shapeFn((bgState.scale/100) * 15); bgDrawPath(); bgCtx.restore();
                }
              }
            },
            vortex: (b, pal, shapeFn) => {
              const count = bgState.complexity * 12; const maxR = b.w; const cx = b.x + b.w/2; const cy = b.y + b.h/2;
              for(let i=count; i>0; i--) {
                const a = Math.pow(i, 1.1) * 0.2; const r = (i/count) * maxR;
                bgApplyStyle(pal[Math.floor(bgRng() * pal.length)]); bgCtx.save();
                bgCtx.translate(cx + Math.cos(a)*r, cy + Math.sin(a)*r); bgCtx.rotate(a + Math.PI/4);
                bgCtx.beginPath(); shapeFn((bgState.scale/100) * 40 * (i/count)); bgDrawPath(); bgCtx.restore();
              }
            }
          };

          // Compile all combinatoric variants and merge them into the master drawing function map
          Object.keys(bgLayouts).forEach(layout => {
            Object.keys(bgShapes).forEach(shape => {
              bgDrawFns[`${layout}_${shape}`] = (b, pal) => bgLayouts[layout](b, pal, bgShapes[shape]);
            });
          });

          const drawWallpaper = () => {
            bgRng = bgMulberry32(Math.floor(bgState.seed * 100000));
            const w = 1200; const h = 400;
            bgCanvas.width = w; bgCanvas.height = h;

            bgCtx.fillStyle = bgGetHsl(bgState.hue, bgState.saturation * 0.3, 10);
            bgCtx.fillRect(0, 0, w, h);

            bgCtx.save();
            bgCtx.translate(w/2, h/2);
            bgCtx.rotate(bgState.angle * Math.PI / 180);
            
            const diag = Math.sqrt(w*w + h*h);
            const b = { x: -diag/2, y: -diag/2, w: diag, h: diag };

            if (bgDrawFns[bgState.pattern]) bgDrawFns[bgState.pattern](b, bgGetPalette());
            bgCtx.restore();
          };

          const settingsModalEl = document.getElementById('settings-modal');
          if (settingsModalEl) {
            settingsModalEl.addEventListener('show.bs.modal', () => {
              document.getElementById('bg-gen-hue').value = bgState.hue;
              drawWallpaper();
            });
          }

          document.getElementById('bg-gen-pattern').addEventListener('change', e => { bgState.pattern = e.target.value; drawWallpaper(); });
          document.getElementById('bg-gen-style').addEventListener('change', e => { bgState.drawStyle = e.target.value; drawWallpaper(); });
          document.getElementById('bg-gen-hue').addEventListener('input', e => { bgState.hue = parseInt(e.target.value); drawWallpaper(); });
          
          document.getElementById('bg-gen-random-btn').addEventListener('click', () => {
            bgState.seed = Math.random();
            bgState.hue = Math.floor(Math.random() * 360);
            document.getElementById('bg-gen-hue').value = bgState.hue;
            
            const patterns = Object.keys(bgDrawFns);
            bgState.pattern = patterns[Math.floor(Math.random() * patterns.length)];
            document.getElementById('bg-gen-pattern').value = bgState.pattern;
            
            const styles = ['fill', 'stroke', 'mixed'];
            bgState.drawStyle = styles[Math.floor(Math.random() * styles.length)];
            document.getElementById('bg-gen-style').value = bgState.drawStyle;

            drawWallpaper();
          });

          document.getElementById('bg-gen-save-btn').addEventListener('click', () => {
            bgCanvas.toBlob(async (blob) => {
              const submitBtn = document.getElementById('bg-gen-save-btn');
              submitBtn.disabled = true;
              submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Saving...';
              const formData = new FormData();
              formData.append('profile_background', blob, 'generated_bg.jpg');
              
              try {
                const res = await fetch('?action=upload_profile_background', { method: 'POST', body: formData });
                const result = await res.json();
                showToast(result.message, result.status);
                if (result.status === 'success') {
                   await checkSession();
                   if (currentView.type === 'user_profile') loadView(currentView);
                }
              } catch (err) {
                showToast('Upload failed', 'error');
              }
              submitBtn.disabled = false;
              submitBtn.innerHTML = 'Set Background';
            }, 'image/jpeg', 0.9);
          });
        }

        if (bioForm) {
          bioForm.addEventListener('submit', async e => {
            e.preventDefault();
            const bio = document.getElementById('settings-bio').value;
            const res = await fetchData('?action=save_bio', { method: 'POST', body: JSON.stringify({ bio }) });
            if (res && res.status === 'success') {
              showToast(res.message, 'success');
              await checkSession();
              if (currentView.type === 'user_profile') loadView(currentView);
            }
          });
        }

        changeNameForm.addEventListener('submit', async e => {
          e.preventDefault();
          const new_name = document.getElementById('new-name').value;
          const data = await fetchData('?action=change_name', {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ new_name })
          });
          if (data && data.status === 'success') {
            bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
            changeNameForm.reset();
            showToast(data.message, 'success');
            await checkSession();
            if (currentView.type === 'user_profile') loadView(currentView);
          }
        });

        changePwForm.addEventListener('submit', async e => {
          e.preventDefault();
          const new_password = document.getElementById('new-password').value;
          const data = await fetchData('?action=change_password', {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ new_password })
          });
          if (data && data.status === 'success') {
            bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
            changePwForm.reset();
            showToast(data.message, 'success');
          }
        });
        
        let profileCropper = null;
        let groupCropper = null;
        const profilePicInput = document.getElementById('profile-picture-input');
        const profilePicPreview = document.getElementById('profile-picture-preview');
        const presetContainer = document.getElementById('preset-avatar-container');
        const refreshPresetsBtn = document.getElementById('refresh-presets-btn');
        const groupPicInput = document.getElementById('group-manage-image');
        const groupPicPreview = document.getElementById('group-manage-image-preview');
        const groupPresetContainer = document.getElementById('group-preset-avatar-container');

        const loadPresets = (targetContainer, isGroup = false) => {
          if (!targetContainer || typeof multiavatar === 'undefined') return;
          targetContainer.innerHTML = '';
          for (let i = 0; i < 6; i++) {
            const seed = Math.random().toString(36).substring(2, 8);
            const svgCode = multiavatar(seed);
            const blob = new Blob([svgCode], {type: 'image/svg+xml'});
            const url = URL.createObjectURL(blob);
            
            const img = document.createElement('img');
            img.src = url;
            img.className = 'rounded-circle shadow-sm';
            img.style.width = '55px';
            img.style.height = '55px';
            img.style.cursor = 'pointer';
            img.style.border = '2px solid transparent';
            img.style.transition = 'transform 0.2s, border-color 0.2s';
            img.style.flexShrink = '0';
            
            img.addEventListener('mouseover', () => img.style.transform = 'scale(1.1)');
            img.addEventListener('mouseout', () => img.style.transform = 'scale(1)');
            
            img.addEventListener('click', () => {
              if (isGroup) {
                groupPicPreview.src = url;
                groupPicPreview.style.display = 'block';
                if (groupCropper) groupCropper.destroy();
                groupCropper = new Cropper(groupPicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
                if (groupPicInput) groupPicInput.value = '';
              } else {
                profilePicPreview.src = url;
                if (profileCropper) profileCropper.destroy();
                profileCropper = new Cropper(profilePicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
                if (profilePicInput) profilePicInput.value = '';
              }
            });
            
            targetContainer.appendChild(img);
          }
        };

        if (refreshPresetsBtn) {
          refreshPresetsBtn.addEventListener('click', () => loadPresets(presetContainer, false));
        }

        const settingsModalEl = document.getElementById('settings-modal');
        if (settingsModalEl) {
          settingsModalEl.addEventListener('show.bs.modal', () => loadPresets(presetContainer, false));
        }

        const groupManageModalEl = document.getElementById('group-manage-modal');
        if (groupManageModalEl) {
          groupManageModalEl.addEventListener('show.bs.modal', () => {
            loadPresets(groupPresetContainer, true);
            if (!document.getElementById('group-manage-id').value) {
               groupPicPreview.src = 'data:image/gif;base64,R0lGODlhAQABAAD/ACwAAAAAAQABAAACADs=';
               groupPicPreview.style.display = 'none';
               if (groupCropper) { groupCropper.destroy(); groupCropper = null; }
               if (groupPicInput) groupPicInput.value = '';
            }
          });
          groupManageModalEl.addEventListener('hidden.bs.modal', () => {
            if (groupCropper) { groupCropper.destroy(); groupCropper = null; }
          });
        }
        
        if (profilePicInput) {
          profilePicInput.addEventListener('change', function(e) {
            if (this.files && this.files[0]) {
              const reader = new FileReader();
              reader.onload = ev => {
                profilePicPreview.src = ev.target.result;
                if (profileCropper) profileCropper.destroy();
                profileCropper = new Cropper(profilePicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
              };
              reader.readAsDataURL(this.files[0]);
            }
          });
        }
        
        if (groupPicInput) {
          groupPicInput.addEventListener('change', function(e) {
            if (this.files && this.files[0]) {
              const reader = new FileReader();
              reader.onload = ev => {
                groupPicPreview.src = ev.target.result;
                groupPicPreview.style.display = 'block';
                if (groupCropper) groupCropper.destroy();
                groupCropper = new Cropper(groupPicPreview, {
                  aspectRatio: 1, viewMode: 1, autoCropArea: 1, dragMode: 'move', background: false
                });
              };
              reader.readAsDataURL(this.files[0]);
            }
          });
        }

        profilePicForm.addEventListener('submit', async e => {
          e.preventDefault();
          if (profilePicInput.files.length === 0 && !profileCropper) {
            showToast('Please select an image file.', 'error');
            return;
          }

          const submitBtn = document.getElementById('profile-picture-submit-btn');
          const progContainer = document.getElementById('profile-pic-progress-container');
          const progBar = document.getElementById('profile-pic-progress');
          
          submitBtn.disabled = true;
          progContainer.classList.remove('d-none');
          progBar.style.width = '0%';
          progBar.textContent = '0%';

          const doUpload = (blob) => {
            const formData = new FormData();
            formData.append('profile_picture', blob, 'profile.jpg');

            const xhr = new XMLHttpRequest();
            xhr.upload.onprogress = (evt) => {
              if (evt.lengthComputable) {
                const pct = Math.round((evt.loaded / evt.total) * 100);
                progBar.style.width = pct + '%';
                progBar.textContent = pct + '%';
              }
            };
            xhr.open('POST', '?action=upload_profile_picture', true);
            xhr.onload = async () => {
              submitBtn.disabled = false;
              progContainer.classList.add('d-none');
              if (xhr.status === 200) {
                try {
                  const result = JSON.parse(xhr.responseText);
                  if (result.status === 'success') {
                    showToast(result.message, 'success');
                    if (profileCropper) { profileCropper.destroy(); profileCropper = null; }
                    await checkSession();
                    bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
                  } else {
                    showToast(result.message || 'Upload failed', 'error');
                  }
                } catch(err) {
                  showToast('Invalid server response.', 'error');
                }
              } else {
                showToast('Upload error', 'error');
              }
            };
            xhr.onerror = () => {
              submitBtn.disabled = false;
              progContainer.classList.add('d-none');
              showToast('Network error during upload', 'error');
            };
            xhr.send(formData);
          };

          if (profileCropper) {
            profileCropper.getCroppedCanvas({ width: 500, height: 500 }).toBlob(blob => {
              doUpload(blob);
            }, 'image/jpeg', 0.85);
          } else {
             doUpload(profilePicInput.files[0]);
          }
        });

        document.getElementById('toggle-normalization').addEventListener('change', (e) => {
          enableNormalization = e.target.checked;
          toggleAudioEnhancements();
        });

        document.getElementById('toggle-eq').addEventListener('change', (e) => {
          isEQEnabled = e.target.checked;
          document.getElementById('eq-sliders').classList.toggle('d-none', !isEQEnabled);
          toggleAudioEnhancements();
        });

        if (btnDeleteKeep) {
          btnDeleteKeep.addEventListener('click', async () => {
            if (!confirm('Are you sure you want to delete your account but keep the data? A backup key will be downloaded.')) return;
            const data = await fetchData('?action=delete_account_keep_data');
            if (data && data.status === 'success') {
              const blob = new Blob([data.backup_key], { type: 'text/plain' });
              const a = document.createElement('a');
              a.href = URL.createObjectURL(blob);
              a.download = 'backup.txt';
              document.body.appendChild(a);
              a.click();
              document.body.removeChild(a);
              showToast('Account deleted. Backup key downloaded.', 'success');
              bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
              await checkSession();
              
              const authRequiredViews = ['user_profile', 'get_user_stats', 'get_offline_songs', 'get_favorites', 'get_listen_later', 'get_notes', 'get_community', 'get_history', 'get_following', 'get_recommendations', 'get_user_playlists', 'get_collab_playlists'];
              if (authRequiredViews.includes(currentView.type)) {
                loadView({ type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' });
              } else {
                loadView(currentView);
              }
            }
          });
        }

        if (btnDeleteAll) {
          btnDeleteAll.addEventListener('click', async () => {
            if (!confirm('Are you sure you want to permanently delete your account and ALL your data? This cannot be undone!')) return;
            const data = await fetchData('?action=delete_account_all');
            if (data && data.status === 'success') {
              showToast('Account and data permanently deleted.', 'success');
              bootstrap.Modal.getInstance(document.getElementById('settings-modal')).hide();
              await checkSession();
              
              const authRequiredViews = ['user_profile', 'get_user_stats', 'get_offline_songs', 'get_favorites', 'get_listen_later', 'get_notes', 'get_community', 'get_history', 'get_following', 'get_recommendations', 'get_user_playlists', 'get_collab_playlists'];
              if (authRequiredViews.includes(currentView.type)) {
                loadView({ type: 'get_songs', param: '', sort: 'random', filter_user_id: '', artist_name: '' });
              } else {
                loadView(currentView);
              }
            }
          });
        }

        const btnExportUserData = document.getElementById('btn-export-user-data');
        if (btnExportUserData) {
          btnExportUserData.addEventListener('click', (e) => {
            e.preventDefault();
            window.exportData('?action=export_user_data', `phpmusic_backup_${Date.now()}.json`);
          });
        }

        const btnImportUserDataTrigger = document.getElementById('btn-import-user-data-trigger');
        const fileImportUserData = document.getElementById('import-user-data-file');
        if (btnImportUserDataTrigger && fileImportUserData) {
          btnImportUserDataTrigger.addEventListener('click', (e) => {
            e.preventDefault();
            fileImportUserData.click();
          });

          fileImportUserData.addEventListener('change', (e) => {
            const file = e.target.files[0];
            if (!file) return;
            
            const originalText = btnImportUserDataTrigger.innerHTML;
            btnImportUserDataTrigger.disabled = true;
            
            // Inject Progress Bar Dynamically
            let progContainer = document.getElementById('import-user-data-progress-container');
            if (!progContainer) {
              progContainer = document.createElement('div');
              progContainer.id = 'import-user-data-progress-container';
              progContainer.className = 'progress mt-3';
              progContainer.style.height = '15px';
              progContainer.innerHTML = '<div id="import-user-data-progress" class="progress-bar progress-bar-striped progress-bar-animated bg-info" role="progressbar" style="width: 0%;">0%</div>';
              btnImportUserDataTrigger.parentElement.parentElement.appendChild(progContainer);
            } else {
              progContainer.classList.remove('d-none');
            }
            
            const progBar = document.getElementById('import-user-data-progress');
            progBar.style.width = '0%';
            progBar.textContent = 'Checking data... 0%';
            progBar.classList.remove('bg-success', 'bg-danger', 'bg-warning');
            progBar.classList.add('bg-info');
            btnImportUserDataTrigger.innerHTML = '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span> Checking data...';

            const reader = new FileReader();

            // Track local file reading progress (Validation Phase)
            reader.onprogress = (evt) => {
              if (evt.lengthComputable) {
                const pct = Math.round((evt.loaded / evt.total) * 100);
                progBar.style.width = pct + '%';
                progBar.textContent = 'Checking data... ' + pct + '%';
              }
            };

            reader.onload = (event) => {
              try {
                // Validate JSON formatting client-side before uploading
                progBar.style.width = '100%';
                progBar.textContent = 'Validating JSON...';
                const parsedData = JSON.parse(event.target.result);
                
                if (parsedData.version === undefined || !parsedData.date) {
                  if (!confirm("Data structure doesn't fully match standard backup. Do you want to add new data anyway?")) {
                    btnImportUserDataTrigger.disabled = false;
                    btnImportUserDataTrigger.innerHTML = originalText;
                    progContainer.classList.add('d-none');
                    fileImportUserData.value = '';
                    return;
                  }
                }
                
                // Switch to Upload Phase
                progBar.style.width = '0%';
                progBar.textContent = 'Uploading... 0%';
                btnImportUserDataTrigger.innerHTML = '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span> Uploading...';
                
                const xhr = new XMLHttpRequest();
                
                // Track precise network upload percentage
                xhr.upload.onprogress = (evt) => {
                  if (evt.lengthComputable) {
                    const pct = Math.round((evt.loaded / evt.total) * 100);
                    progBar.style.width = pct + '%';
                    progBar.textContent = 'Uploading... ' + pct + '%';
                    if (pct >= 100) {
                      progBar.classList.replace('bg-info', 'bg-warning');
                      progBar.textContent = 'Processing DB...';
                      btnImportUserDataTrigger.innerHTML = '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span> Processing...';
                    }
                  }
                };

                xhr.open('POST', '?action=import_user_data', true);
                xhr.setRequestHeader('Content-Type', 'application/json');
                
                xhr.onload = () => {
                  btnImportUserDataTrigger.disabled = false;
                  btnImportUserDataTrigger.innerHTML = originalText;
                  
                  if (xhr.status === 200) {
                    try {
                      const result = JSON.parse(xhr.responseText);
                      if (result && result.status === 'success') {
                        progBar.classList.replace('bg-warning', 'bg-success');
                        progBar.classList.replace('bg-info', 'bg-success');
                        progBar.textContent = 'Complete!';
                        showToast(result.message, 'success');
                        setTimeout(() => progContainer.classList.add('d-none'), 4000);
                        loadView(currentView);
                      } else {
                        progBar.classList.replace('bg-warning', 'bg-danger');
                        progBar.classList.replace('bg-info', 'bg-danger');
                        progBar.textContent = 'Failed';
                        showToast(result.message || 'Import failed', 'error');
                        setTimeout(() => progContainer.classList.add('d-none'), 5000);
                      }
                    } catch(err) {
                      progBar.classList.replace('bg-warning', 'bg-danger');
                      progBar.classList.replace('bg-info', 'bg-danger');
                      progBar.textContent = 'Error';
                      showToast('Invalid server response.', 'error');
                    }
                  } else {
                    progBar.classList.replace('bg-warning', 'bg-danger');
                    progBar.classList.replace('bg-info', 'bg-danger');
                    progBar.textContent = 'Error';
                    showToast('Network error during import. Payload might be too large.', 'error');
                  }
                  fileImportUserData.value = '';
                };

                xhr.onerror = () => {
                  btnImportUserDataTrigger.disabled = false;
                  btnImportUserDataTrigger.innerHTML = originalText;
                  progBar.classList.replace('bg-warning', 'bg-danger');
                  progBar.classList.replace('bg-info', 'bg-danger');
                  progBar.textContent = 'Network Error';
                  showToast('Network error during import. Connection failed.', 'error');
                  fileImportUserData.value = '';
                };

                // Send the raw file directly to bypass RAM stringification exhaustion on XHR
                xhr.send(file);
                
              } catch (err) {
                showToast('Failed to parse JSON. File might be corrupted.', 'error');
                btnImportUserDataTrigger.disabled = false;
                btnImportUserDataTrigger.innerHTML = '<i class="bi bi-box-arrow-in-down me-2"></i>Import';
                progBar.classList.replace('bg-info', 'bg-danger');
                progBar.textContent = 'Validation Failed';
                setTimeout(() => progContainer.classList.add('d-none'), 4000);
                fileImportUserData.value = '';
              }
            };
            reader.readAsText(file);
          });
        }

        const uploadLimitText = document.getElementById('upload-limit-text');
        const uploadRemainingText = document.getElementById('upload-remaining-text');
        const songFilesInput = document.getElementById('song-files');
        const songArtistInput = document.getElementById('song-artist');
        const songGenreInput = document.getElementById('song-genre');
        const startUploadBtn = document.getElementById('start-upload-btn');
        const uploadProgressArea = document.getElementById('upload-progress-area');
        const songIsCollaborativeUpload = document.getElementById('song-is-collaborative');
        const uploadCollabContainer = document.getElementById('upload-collaborator-container');
        const uploadCollabInput = document.getElementById('upload-collab-search-input');
        const uploadCollabDropdown = document.getElementById('upload-collab-search-dropdown');
        const uploadCollabList = document.getElementById('upload-collab-list');
        let selectedUploadCollabs = [];
        let filesToUpload = [];

        const renderUploadCollabs = () => {
          if (uploadCollabList) {
            if (selectedUploadCollabs.length === 0) {
              uploadCollabList.innerHTML = '<p class="text-secondary small mt-2">No collaborators yet.</p>';
            } else {
              uploadCollabList.innerHTML = selectedUploadCollabs.map(c => `
                <div class="list-group-item bg-transparent text-white d-flex justify-content-between align-items-center border-secondary px-0">
                  <div class="d-flex align-items-center gap-3">
                    <img src="?action=get_profile_picture&id=${c.id}" onerror="this.outerHTML='<i class=\\'bi bi-person-circle fs-3 text-secondary\\'></i>'" class="rounded-circle" style="width: 32px; height: 32px; object-fit: cover;">
                    <div>
                      <div>${escapeHTML(c.artist)}</div>
                      <div class="small text-secondary" style="font-size: 0.75rem;">ID: ${c.id}</div>
                    </div>
                  </div>
                  <button type="button" class="btn btn-sm btn-outline-danger remove-upload-collab-btn" data-id="${c.id}"><i class="bi bi-x-lg"></i></button>
                </div>
              `).join('');
            }
          }
          if (songArtistInput) {
            songArtistInput.value = selectedUploadCollabs.map(c => c.id).join(',');
          }
        };

        if (songIsCollaborativeUpload && uploadCollabContainer) {
          songIsCollaborativeUpload.addEventListener('change', (e) => {
            uploadCollabContainer.style.display = e.target.checked ? 'block' : 'none';
          });
          uploadCollabContainer.style.display = songIsCollaborativeUpload.checked ? 'block' : 'none';
          setTimeout(renderUploadCollabs, 100);
        }

        if (uploadCollabInput) {
          let uploadCollabSearchTimeout;
          let uploadCollabSelectedFromDropdown = null;
          
          uploadCollabInput.addEventListener('input', (e) => {
            clearTimeout(uploadCollabSearchTimeout);
            uploadCollabSelectedFromDropdown = null;
            const q = e.target.value.trim();
            if (q === '') {
              uploadCollabDropdown.classList.add('d-none');
              return;
            }
            uploadCollabSearchTimeout = setTimeout(async () => {
              const res = await fetchData('?action=manage_song_collaborators', {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({ song_id: 0, collab_action: 'search', query: q })
              });
              if (res && res.status === 'success') {
                if (res.users.length > 0) {
                  uploadCollabDropdown.innerHTML = res.users.map(u => `
                    <div class="search-dropdown-item upload-collab-user-item" data-id="${u.id}" data-artist="${escapeHTML(u.artist)}">
                      <img src="?action=get_profile_picture&id=${u.id}" class="search-dropdown-img rounded-circle">
                      <div class="search-dropdown-text">
                        <div class="search-dropdown-title">${escapeHTML(u.artist)}</div>
                        <div class="search-dropdown-subtitle">ID: ${u.id}</div>
                      </div>
                    </div>
                  `).join('');
                  uploadCollabDropdown.classList.remove('d-none');
                } else {
                  uploadCollabDropdown.innerHTML = '<div class="p-3 text-secondary text-center small">No users found</div>';
                  uploadCollabDropdown.classList.remove('d-none');
                }
              }
            }, 300);
          });

          uploadCollabDropdown.addEventListener('click', (e) => {
            const item = e.target.closest('.upload-collab-user-item');
            if (item) {
              uploadCollabSelectedFromDropdown = {
                id: item.dataset.id,
                artist: item.dataset.artist
              };
              uploadCollabInput.value = item.dataset.artist;
              uploadCollabDropdown.classList.add('d-none');
            }
          });
          
          const uploadCollabAddBtn = document.getElementById('upload-collab-add-btn');
          if (uploadCollabAddBtn) {
            uploadCollabAddBtn.addEventListener('click', () => {
              const target = uploadCollabInput.value.trim();
              if (!target && !uploadCollabSelectedFromDropdown) return;
              
              const collabToAdd = uploadCollabSelectedFromDropdown || { id: target, artist: target };
              
              if (!selectedUploadCollabs.find(c => c.id === collabToAdd.id)) {
                selectedUploadCollabs.push(collabToAdd);
                renderUploadCollabs();
              }
              uploadCollabInput.value = '';
              uploadCollabSelectedFromDropdown = null;
            });
          }
          
          document.addEventListener('click', (e) => {
            if (uploadCollabDropdown && !uploadCollabDropdown.contains(e.target) && e.target !== uploadCollabInput) {
              uploadCollabDropdown.classList.add('d-none');
            }
          });
          
          uploadCollabList.addEventListener('click', (e) => {
            const removeBtn = e.target.closest('.remove-upload-collab-btn');
            if (removeBtn) {
              selectedUploadCollabs = selectedUploadCollabs.filter(c => c.id !== removeBtn.dataset.id);
              renderUploadCollabs();
            }
          });
        }

        songFilesInput.addEventListener('change', () => { filesToUpload = Array.from(songFilesInput.files); });
        
        startUploadBtn.addEventListener('click', async () => {
          if (filesToUpload.length === 0) {
            showToast('Please select files to upload.', 'error'); return;
          }
          startUploadBtn.disabled = true;
          uploadProgressArea.innerHTML = '';

          for (let i = 0; i < filesToUpload.length; i++) {
            const file = filesToUpload[i];
            const progressId = `upload-prog-${Date.now()}-${i}`;
            
            uploadProgressArea.insertAdjacentHTML('beforeend', `
              <div class="mb-3 p-3 rounded" style="background-color: var(--ytm-surface-2); border: 1px solid #404040;">
                <div class="d-flex justify-content-between align-items-center mb-2">
                  <small class="text-white text-truncate fw-bold" style="max-width: 80%;">${escapeHTML(file.name)}</small>
                  <small class="text-secondary fw-bold" id="${progressId}-text">0%</small>
                </div>
                <div class="progress" style="height: 8px; background-color: #000;">
                  <div id="${progressId}" class="progress-bar bg-danger" role="progressbar" style="width: 0%; transition: width 0.1s linear;"></div>
                </div>
              </div>`);

            const formData = new FormData();
            formData.append('song', file);
            formData.append('artist', songArtistInput.value);
            formData.append('genre', songGenreInput.value);
            formData.append('is_private', document.getElementById('song-is-private').checked ? 1 : 0);
            formData.append('is_collaborative', document.getElementById('song-is-collaborative').checked ? 1 : 0);

            const xhr = new XMLHttpRequest();
            
            xhr.upload.onprogress = (e) => {
              if (e.lengthComputable) {
                const percentComplete = Math.round((e.loaded / e.total) * 100);
                const progressBar = document.getElementById(progressId);
                const progressText = document.getElementById(`${progressId}-text`);
                if (progressBar) progressBar.style.width = `${percentComplete}%`;
                if (progressText) progressText.textContent = `${percentComplete}%`;
              }
            };
            
            xhr.open('POST', '?action=upload_song', true);
            
            await new Promise(resolve => {
              xhr.onload = () => {
                const progressBar = document.getElementById(progressId);
                const progressText = document.getElementById(`${progressId}-text`);
                if (xhr.status === 200) {
                  if (progressBar) progressBar.classList.replace('bg-danger', 'bg-success');
                  if (progressText) progressText.classList.replace('text-secondary', 'text-success');
                } else {
                  if (progressBar) progressBar.classList.replace('bg-danger', 'bg-warning');
                  if (progressText) {
                    progressText.classList.replace('text-secondary', 'text-warning');
                    progressText.textContent = 'Failed';
                  }
                  try {
                    showToast(`Upload failed for ${file.name}: ${JSON.parse(xhr.responseText).message}`, 'error');
                  } catch (e) {
                    showToast(`Upload failed for ${file.name}: Server error.`, 'error');
                  }
                }
                resolve();
              };
              xhr.onerror = () => {
                const progressBar = document.getElementById(progressId);
                const progressText = document.getElementById(`${progressId}-text`);
                if (progressBar) progressBar.classList.replace('bg-danger', 'bg-warning');
                if (progressText) {
                  progressText.classList.replace('text-secondary', 'text-warning');
                  progressText.textContent = 'Network Error';
                }
                showToast(`A network error occurred during upload of ${file.name}.`, 'error');
                resolve();
              };
              xhr.send(formData);
            });
          }
          startUploadBtn.disabled = false;
          showToast('All uploads complete.', 'success');
          await checkSession();
          loadView(currentView);
          filesToUpload = [];
          songFilesInput.value = '';
          songArtistInput.value = '';
          songGenreInput.value = '';
          if (typeof selectedUploadCollabs !== 'undefined') {
            selectedUploadCollabs = [];
            if (typeof renderUploadCollabs === 'function') renderUploadCollabs();
          }
        });

        if (copyShareUrlBtn) {
          copyShareUrlBtn.addEventListener('click', () => {
            const onSuccess = () => {
              copyShareUrlBtn.textContent = 'Copied!';
              copyShareUrlBtn.disabled = true;
              setTimeout(() => {
                copyShareUrlBtn.textContent = 'Copy';
                copyShareUrlBtn.disabled = false;
              }, 2000);
            };
            const onError = () => showToast('Failed to copy link.', 'error');

            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(shareUrlInput.value).then(onSuccess).catch(onError);
            } else {
              const textArea = document.createElement("textarea");
              textArea.value = shareUrlInput.value;
              textArea.style.position = "fixed";
              textArea.style.top = "0";
              textArea.style.left = "0";
              textArea.style.opacity = "0";
              document.body.appendChild(textArea);
              textArea.focus();
              textArea.select();
              try {
                const successful = document.execCommand('copy');
                if (successful) onSuccess();
                else onError();
              } catch (err) {
                onError();
              }
              document.body.removeChild(textArea);
            }
          });
        }

        const embedModalElGlobal = document.getElementById('embed-modal');
        if (embedModalElGlobal) {
          embedModalElGlobal.addEventListener('hidden.bs.modal', () => {
            const previewContainer = document.getElementById('embed-preview-container');
            if (previewContainer) previewContainer.innerHTML = '';
          });
        }

        const copyEmbedCodeBtn = document.getElementById('copy-embed-code-btn');
        if (copyEmbedCodeBtn) {
          copyEmbedCodeBtn.addEventListener('click', () => {
            const embedInput = document.getElementById('embed-code-input');
            const onSuccess = () => {
              copyEmbedCodeBtn.innerHTML = '<i class="bi bi-check-lg"></i> Copied!';
              copyEmbedCodeBtn.classList.replace('btn-danger', 'btn-success');
              copyEmbedCodeBtn.disabled = true;
              setTimeout(() => {
                copyEmbedCodeBtn.innerHTML = '<i class="bi bi-clipboard"></i> Copy';
                copyEmbedCodeBtn.classList.replace('btn-success', 'btn-danger');
                copyEmbedCodeBtn.disabled = false;
              }, 2000);
            };
            const onError = () => showToast('Failed to copy embed code.', 'error');

            if (navigator.clipboard && window.isSecureContext) {
              navigator.clipboard.writeText(embedInput.value).then(onSuccess).catch(onError);
            } else {
              const textArea = document.createElement("textarea");
              textArea.value = embedInput.value;
              textArea.style.position = "fixed";
              textArea.style.opacity = "0";
              document.body.appendChild(textArea);
              textArea.focus();
              textArea.select();
              try {
                if (document.execCommand('copy')) onSuccess();
                else onError();
              } catch (err) {
                onError();
              }
              document.body.removeChild(textArea);
            }
          });
        }

        let pdAllSongs = [];
        let pdCurrentPage = 1;
        const pdItemsPerPage = 50;
        let pdIsDownloading = false;
        let pdStopRequested = false;

        const pdPlaylistIdInput = document.getElementById('pd-playlist-id');
        const pdSongIdInput = document.getElementById('pd-song-id');
        const pdLoadForm = document.getElementById('pd-load-form');
        const pdDownloadSingleBtn = document.getElementById('pd-download-single');
        const pdResultsCard = document.getElementById('pd-results-card');
        const pdPlaylistTitle = document.getElementById('pd-playlist-title');
        const pdStartAutoBtn = document.getElementById('pd-start-auto');
        const pdLogArea = document.getElementById('pd-log');
        const pdClearLogBtn = document.getElementById('pd-clear-log');
        const pdSongRows = document.getElementById('pd-song-rows');

        const pdEscapeHtml = (str) => {
          if (!str) return '';
          return str.replace(/[&<>'"]/g, m => ({'&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;'}[m] || m))
                    .replace(/[\uD800-\uDBFF][\uDC00-\uDFFF]/g, c => c);
        };
        const pdTruncate = (str, len = 50) => str.length > len ? str.substring(0, len) + '…' : str;

        const pdLog = (message, isError = false) => {
          const time = new Date().toLocaleTimeString();
          const div = document.createElement('div');
          div.className = 'log-line';
          div.style.color = isError ? '#ff8888' : '#aaaaaa';
          div.style.borderBottom = '1px solid #404040';
          div.style.padding = '0.25rem 0';
          div.innerHTML = `[${time}] ${message}`;
          pdLogArea.appendChild(div);
          div.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        };

        const pdDownloadSong = async (song, isAuto = false, index = null, total = null) => {
          const safeTitle = (song.title + ' - ' + (song.artist || 'Unknown')).replace(/[^a-zA-Z0-9\s\.\-\(\)\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]/g, '_');
          const url = `?action=download_song&id=${encodeURIComponent(song.id)}`;
          if (isAuto) {
            pdLog(`Downloading ${index+1}/${total}: ${song.title} - ${song.artist || 'Unknown'}`);
          } else {
            pdLog(`Manual download: ${song.title} - ${song.artist || 'Unknown'}`);
          }
          const a = document.createElement('a');
          a.href = url;
          a.download = safeTitle + '.mp3';
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          await new Promise(r => setTimeout(r, 1200));
        };

        const handleManualDl = async (e) => {
          e.preventDefault();
          const songId = parseInt(e.currentTarget.dataset.id);
          const song = pdAllSongs.find(s => s.id === songId);
          if (song) await pdDownloadSong(song, false);
        };

        const pdRenderSongRows = () => {
          pdSongRows.innerHTML = '';
          const start = 0;
          const end = pdItemsPerPage;
          const pageSongs = pdAllSongs.slice(start, end);
          
          const rowsHtml = pageSongs.map((song, idx) => {
            const globalIdx = start + idx;
            return `
              <div class="song-item pd-song-row" style="color: #ffffff !important;">
                <div class="text-secondary small d-flex align-items-center" style="color: #ffffff !important;">
                  <input class="form-check-input pd-song-checkbox me-2" type="checkbox" data-id="${song.id}" ${song.pdSelected !== false ? 'checked' : ''}>
                  <span class="d-none d-md-inline">${globalIdx + 1}</span>
                </div>
                <div class="title-col text-truncate" title="${pdEscapeHtml(song.title)}" style="color: #ffffff !important;">${pdEscapeHtml(pdTruncate(song.title, 60))}</div>
                <div class="artist-col text-truncate d-none d-md-block" title="${pdEscapeHtml(song.artist)}" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
                <div class="duration-col d-none d-md-block" style="color: #ffffff !important;">${formatTime(song.duration)}</div>
                <div class="download-col"><button class="btn btn-sm btn-outline-light pd-manual-dl" data-id="${song.id}" style="color: #ffffff !important; border-color: #ffffff !important;"><i class="bi bi-download"></i></button></div>
                <div class="pd-mobile-artist d-md-none text-truncate" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
              </div>
            `;
          }).join('');
          
          pdSongRows.innerHTML = rowsHtml;
          
          document.querySelectorAll('.pd-manual-dl').forEach(btn => {
            btn.removeEventListener('click', handleManualDl);
            btn.addEventListener('click', handleManualDl);
          });
          document.querySelectorAll('.pd-song-checkbox').forEach(chk => {
            chk.addEventListener('change', (e) => {
              const s = pdAllSongs.find(song => song.id === parseInt(e.target.dataset.id));
              if (s) s.pdSelected = e.target.checked;
              updatePdSelectAllState();
            });
          });
        };

        const updatePdSelectAllState = () => {
          const selectAllChk = document.getElementById('pd-select-all');
          if (selectAllChk) {
            const allSelected = pdAllSongs.every(s => s.pdSelected !== false);
            selectAllChk.checked = allSelected;
          }
        };

        const selectAllChk = document.getElementById('pd-select-all');
        if (selectAllChk) {
          selectAllChk.addEventListener('change', (e) => {
            const isChecked = e.target.checked;
            pdAllSongs.forEach(s => s.pdSelected = isChecked);
            pdRenderSongRows();
            const pdModalBody = document.querySelector('#playlist-downloader-modal .modal-body');
            if (pdModalBody) pdModalBody.dispatchEvent(new Event('scroll'));
          });
        }

        const pdStopAutoDownload = () => {
          if (!pdIsDownloading) return;
          pdStopRequested = true;
          pdLog('⏹️ Stopping download process...', false);
          pdStartAutoBtn.disabled = true;
          pdStartAutoBtn.innerHTML = '<i class="bi bi-stop-fill" style="color: #ffffff !important;"></i> Stopping...';
        };

        const pdStartAutoDownload = async () => {
          if (pdIsDownloading) return;
          pdIsDownloading = true;
          pdStopRequested = false;
          
          pdStartAutoBtn.removeEventListener('click', pdStartAutoDownload);
          pdStartAutoBtn.addEventListener('click', pdStopAutoDownload);
          pdStartAutoBtn.classList.replace('btn-danger', 'btn-warning');
          pdStartAutoBtn.innerHTML = '<i class="bi bi-stop-fill" style="color: #ffffff !important;"></i> Stop Download';
          pdStartAutoBtn.disabled = false;
          
          const songsToDownload = pdAllSongs.filter(s => s.pdSelected !== false);
          pdLog(`🚀 Starting sequential download of ${songsToDownload.length} selected songs. Click "Stop Download" to cancel.`);
          
          for (let i = 0; i < songsToDownload.length; i++) {
            if (pdStopRequested) {
              pdLog(`⏹️ Download stopped by user after ${i}/${songsToDownload.length} songs.`);
              break;
            }
            await pdDownloadSong(songsToDownload[i], true, i, songsToDownload.length);
          }
          
          pdStartAutoBtn.removeEventListener('click', pdStopAutoDownload);
          pdStartAutoBtn.addEventListener('click', pdStartAutoDownload);
          pdStartAutoBtn.classList.replace('btn-warning', 'btn-danger');
          pdStartAutoBtn.innerHTML = '<i class="bi bi-play-fill" style="color: #ffffff !important;"></i> Download Selected Songs (Sequential)';
          pdStartAutoBtn.disabled = false;
          
          if (!pdStopRequested) pdLog(`✅ All ${songsToDownload.length} selected songs have been sent for download!`);
          pdIsDownloading = false;
          pdStopRequested = false;
        };

        pdLoadForm.addEventListener('submit', async (e) => {
          e.preventDefault();
          const publicId = pdPlaylistIdInput.value.trim();
          if (!publicId) return;
          
          pdLogArea.innerHTML = '';
          pdLog(`Fetching playlist details for: ${publicId}`);
          
          try {
            const data = await fetchData(`?action=get_playlist_songs&public_id=${publicId}&sort=manual_order&all=1`);
            if (data && data.length > 0) {
              pdAllSongs = data.map(s => ({...s, pdSelected: true}));
              pdCurrentPage = 1;
              
              let totalSizeBytes = pdAllSongs.reduce((sum, song) => sum + ((song.duration || 0) * (song.bitrate || 128000) / 8), 0);
              const formatBytes = (bytes) => {
                if (bytes === 0) return '0 Bytes';
                const k = 1024;
                const sizes = ['Bytes', 'KB', 'MB', 'GB'];
                const i = Math.floor(Math.log(bytes) / Math.log(k));
                return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
              };
              
              pdResultsCard.classList.remove('d-none');
              pdPlaylistTitle.innerHTML = `<i class="bi bi-music-note-beamed" style="color: #ffffff !important;"></i> Playlist loaded <span class="badge bg-secondary ms-2">${pdAllSongs.length} songs</span> <span class="badge bg-info ms-2">~${formatBytes(totalSizeBytes)}</span>`;
              pdLog(`✅ Successfully loaded ${pdAllSongs.length} songs (~${formatBytes(totalSizeBytes)}).`);
              pdRenderSongRows();
              const loader = document.getElementById('pd-infinite-scroll-loader');
              if (loader) {
                if (pdCurrentPage * pdItemsPerPage < pdAllSongs.length) {
                  loader.classList.remove('d-none');
                } else {
                  loader.classList.add('d-none');
                }
              }
            } else {
              showToast('Playlist not found or empty', 'error');
              pdLog('❌ Failed to load playlist or it is empty.', true);
            }
          } catch (err) {
            showToast('Error fetching playlist', 'error');
          }
        });

        pdDownloadSingleBtn.addEventListener('click', async () => {
          const songId = parseInt(pdSongIdInput.value);
          if (isNaN(songId) || songId <= 0) {
            showToast('Enter a valid song ID', 'error');
            return;
          }
          try {
            const song = await fetchData(`?action=get_song_data&id=${songId}`);
            if (song && song.id) {
              await pdDownloadSong(song, false);
            } else {
              showToast('Song not found', 'error');
            }
          } catch (err) {
            showToast('Error fetching song', 'error');
          }
        });

        pdStartAutoBtn.addEventListener('click', pdStartAutoDownload);
        pdClearLogBtn.addEventListener('click', () => { pdLogArea.innerHTML = ''; pdLog('Log cleared.'); });

        const pdModalBody = document.querySelector('#playlist-downloader-modal .modal-body');
        if (pdModalBody) {
          pdModalBody.addEventListener('scroll', () => {
            if (pdResultsCard.classList.contains('d-none') || pdAllSongs.length === 0) return;
            const scrollBottom = pdModalBody.scrollHeight - pdModalBody.scrollTop - pdModalBody.clientHeight;
            if (scrollBottom < 200 && pdCurrentPage * pdItemsPerPage < pdAllSongs.length) {
              const start = pdCurrentPage * pdItemsPerPage;
              pdCurrentPage++;
              const end = pdCurrentPage * pdItemsPerPage;
              const pageSongs = pdAllSongs.slice(start, end);
              
              const rowsHtml = pageSongs.map((song, idx) => {
                const globalIdx = start + idx;
                return `
                  <div class="song-item pd-song-row" style="color: #ffffff !important;">
                    <div class="text-secondary small d-flex align-items-center" style="color: #ffffff !important;">
                      <input class="form-check-input pd-song-checkbox me-2" type="checkbox" data-id="${song.id}" ${song.pdSelected !== false ? 'checked' : ''}>
                      <span class="d-none d-md-inline">${globalIdx + 1}</span>
                    </div>
                    <div class="title-col text-truncate" title="${pdEscapeHtml(song.title)}" style="color: #ffffff !important;">${pdEscapeHtml(pdTruncate(song.title, 60))}</div>
                    <div class="artist-col text-truncate d-none d-md-block" title="${pdEscapeHtml(song.artist)}" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
                    <div class="duration-col d-none d-md-block" style="color: #ffffff !important;">${formatTime(song.duration)}</div>
                    <div class="download-col"><button class="btn btn-sm btn-outline-light pd-manual-dl" data-id="${song.id}" style="color: #ffffff !important; border-color: #ffffff !important;"><i class="bi bi-download"></i></button></div>
                    <div class="pd-mobile-artist d-md-none text-truncate" style="color: #ffffff !important;">${pdEscapeHtml(song.artist ? pdTruncate(song.artist, 40) : 'Unknown')}</div>
                  </div>
                `;
              }).join('');
              pdSongRows.insertAdjacentHTML('beforeend', rowsHtml);
              document.querySelectorAll('.pd-manual-dl').forEach(btn => {
                btn.removeEventListener('click', handleManualDl);
                btn.addEventListener('click', handleManualDl);
              });
              document.querySelectorAll('.pd-song-checkbox').forEach(chk => {
                chk.addEventListener('change', (e) => {
                  const s = pdAllSongs.find(song => song.id === parseInt(e.target.dataset.id));
                  if (s) s.pdSelected = e.target.checked;
                  updatePdSelectAllState();
                });
              });
              const loader = document.getElementById('pd-infinite-scroll-loader');
              if (loader) {
                if (pdCurrentPage * pdItemsPerPage >= pdAllSongs.length) {
                  loader.classList.add('d-none');
                }
              }
            }
          });
        }

        let lastNotifiedMsgId = localStorage.getItem('ytm_lastMsgId') || 0;

        const requestNotificationPermission = async () => {
          if (!('Notification' in window)) return;
          if (Notification.permission === 'default') {
            try { await Notification.requestPermission(); } catch (e) {}
          }
        };

        const showNativeNotification = (title, body) => {
          if (!('Notification' in window) || Notification.permission !== 'granted') return;
          
          const opts = {
            body: body,
            icon: '?action=get_app_icon&size=192',
            badge: '?action=get_app_icon&size=192',
            vibrate: [200, 100, 200]
          };

          if ('serviceWorker' in navigator && navigator.serviceWorker.ready) {
            navigator.serviceWorker.ready.then(reg => {
              reg.showNotification(title, opts);
            });
          } else {
            const n = new Notification(title, opts);
            n.onclick = () => { window.focus(); };
          }
        };

        const updateNotifBadge = async () => {
          if (!currentUser) return;
          const data = await fetchData('?action=get_unread_notif_count', {}, true);
          const badges = document.querySelectorAll('.notif-badge');
          const dots = document.querySelectorAll('.notif-dot');
          if (data && typeof data.count === 'number') {
            if (data.count > 0) {
              const displayCount = data.count > 99 ? '99+' : data.count;
              badges.forEach(b => { b.textContent = displayCount; b.classList.remove('d-none'); });
              dots.forEach(d => d.classList.remove('d-none'));
            } else {
              badges.forEach(b => b.classList.add('d-none'));
              dots.forEach(d => d.classList.add('d-none'));
            }
          }

          // Check Unread Inbox Badges only if viewing inbox or if inbox badges exist
          const inboxBadges = document.querySelectorAll('.inbox-badge');
          if (inboxBadges.length > 0 && currentView.type === 'get_inbox') {
            const inboxData = await fetchData('?action=get_inbox', {}, true);
            let totalUnread = 0;
            let highestMsgId = parseInt(lastNotifiedMsgId);

            if (Array.isArray(inboxData) && inboxData.length > 0) {
              inboxData.forEach(m => {
                totalUnread += m.unread_count;
                if (m.unread_count > 0 && m.id > highestMsgId && m.sender_id != currentUser.id) {
                  highestMsgId = m.id;
                  let previewText = window.getPreviewText(m.content);
                  if (m.has_image) {
                    if (m.media_type && m.media_type.startsWith('video/')) previewText = '📹 Video';
                    else if (m.media_type && m.media_type.startsWith('audio/')) previewText = '🎵 Audio';
                    else previewText = '📷 Photo';
                  }
                  showNativeNotification(`New message from ${m.name}`, previewText);
                }
              });
            }

            if (highestMsgId > parseInt(lastNotifiedMsgId)) {
              lastNotifiedMsgId = highestMsgId;
              localStorage.setItem('ytm_lastMsgId', highestMsgId);
            }

            if (totalUnread > 0) {
              inboxBadges.forEach(b => { b.textContent = totalUnread; b.classList.remove('d-none'); });
            } else {
              inboxBadges.forEach(b => b.classList.add('d-none'));
            }
          }
        };
        
        // Background Real-Time Notification Poller
        // This ensures you get notifications even if the tab is minimized!
        setInterval(() => {
          if (currentUser && document.visibilityState !== 'visible') {
            updateNotifBadge();
          }
        }, 5000);

        function updateUIForAuthState() {
          const isLoggedIn = !!currentUser;
          document.body.classList.toggle('logged-in', isLoggedIn);
          document.body.classList.toggle('logged-out', !isLoggedIn);
          if (isLoggedIn) {
            document.body.classList.toggle('user-verified', currentUser.verified === 'yes');
            const picUrl = navigator.onLine 
              ? currentUser.profile_picture_url + '&t=' + new Date().getTime() 
              : `?action=get_profile_picture&id=${currentUser.id}`;
            profilePictureHeaderDesktop.src = picUrl;
            profilePictureHeaderMobile.src = picUrl;
            profilePicturePreview.src = picUrl;
            
            const bgUrl = navigator.onLine
              ? `?action=get_profile_background&id=${currentUser.id}&v=${Date.now()}`
              : `?action=get_profile_background&id=${currentUser.id}`;
            document.querySelectorAll('.phpmusic-profile-bg-placeholder').forEach(el => el.style.backgroundImage = `url('${bgUrl}')`);
            
            const bgPreviewEl = document.getElementById('profile-bg-preview');
            const bgPreviewContainer = document.getElementById('profile-bg-preview-container');
            if (bgPreviewEl && bgPreviewContainer) {
              bgPreviewContainer.style.display = 'block';
              bgPreviewEl.src = bgUrl;
              if (typeof profileBgCropper !== 'undefined' && profileBgCropper) {
                profileBgCropper.destroy();
                profileBgCropper = null;
              }
            }
            document.querySelectorAll('.phpmusic-profile-img-placeholder').forEach(img => img.src = picUrl);
            document.querySelectorAll('.phpmusic-profile-name').forEach(el => el.textContent = currentUser.artist);
            document.querySelectorAll('.phpmusic-profile-subtext').forEach(el => el.textContent = currentUser.email || 'Verified Artist');

            const scanAllBtn = document.getElementById('nav-scan-all');
            const adminPanelBtn = document.getElementById('nav-admin-panel');
            const coverScanBtn = document.getElementById('nav-cover-scan');
            const isSuperAdmin = currentUser.email && currentUser.email.toLowerCase() === 'musiclibrary@mail.com';
            const isAdmin = currentUser.is_admin == 1 || isSuperAdmin;
            
            // Scan All is now globally visible for emergencies.
            
            if (adminPanelBtn) {
              if (isAdmin) {
                adminPanelBtn.style.setProperty('display', 'flex', 'important');
                const scanAllBtn = document.getElementById('nav-scan-all');
                if (scanAllBtn) scanAllBtn.style.setProperty('display', 'flex', 'important');
                const chartScanBtn = document.getElementById('nav-chart-scan');
                if (chartScanBtn) chartScanBtn.style.setProperty('display', 'flex', 'important');
                const chartConfigBtn = document.getElementById('nav-chart-config');
                if (chartConfigBtn) chartConfigBtn.style.setProperty('display', 'flex', 'important');
                if (coverScanBtn) coverScanBtn.style.setProperty('display', 'flex', 'important');
              } else {
                adminPanelBtn.style.setProperty('display', 'none', 'important');
                const scanAllBtn = document.getElementById('nav-scan-all');
                if (scanAllBtn) scanAllBtn.style.setProperty('display', 'none', 'important');
                const chartScanBtn = document.getElementById('nav-chart-scan');
                if (chartScanBtn) chartScanBtn.style.setProperty('display', 'none', 'important');
                const chartConfigBtn = document.getElementById('nav-chart-config');
                if (chartConfigBtn) chartConfigBtn.style.setProperty('display', 'none', 'important');
                if (coverScanBtn) coverScanBtn.style.setProperty('display', 'none', 'important');
              }
            }
          } else {
            document.body.classList.remove('user-verified');
          }
        }

        async function checkSession() {
          const data = await fetchData('?action=get_session', {}, true);
          if (data && data.status === 'loggedin') {
            currentUser = data.user;
            try { 
              localStorage.setItem('ytm_currentUser', JSON.stringify(currentUser)); 
              if ('caches' in window) {
                caches.open('php-music-offline').then(cache => {
                  cache.add(`?action=get_profile_picture&id=${currentUser.id}`).catch(()=>{});
                  cache.add(`?action=get_profile_background&id=${currentUser.id}`).catch(()=>{});
                });
              }
            } catch(e) {}
            if (currentUser.settings) {
              try {
                // Highly robust JSON extraction for settings
                const s = typeof currentUser.settings === 'string' ? JSON.parse(currentUser.settings) : currentUser.settings;
                
                enableNormalization = s.enableNormalization !== undefined ? s.enableNormalization : true;
                isEQEnabled = s.isEQEnabled !== undefined ? s.isEQEnabled : false;
                isSpatialEnabled = s.isSpatialEnabled !== undefined ? s.isSpatialEnabled : false;
                globalVolumeMultiplier = s.globalVolumeMultiplier !== undefined ? parseFloat(s.globalVolumeMultiplier) : 1.0;
                globalEQBands = Array.isArray(s.globalEQBands) ? s.globalEQBands.map(b => parseFloat(b)) : [0, 0, 0, 0, 0];
                crossfadeDuration = s.crossfadeDuration !== undefined ? parseFloat(s.crossfadeDuration) : 3.0;
                
                // Propagate to UI DOM
                const normEl = document.getElementById('toggle-normalization');
                if (normEl) normEl.checked = enableNormalization;
                
                const crossEl = document.getElementById('crossfade-slider');
                if (crossEl) {
                   crossEl.value = crossfadeDuration;
                   document.getElementById('crossfade-val').textContent = crossfadeDuration + 's';
                }
                
                const eqToggleEl = document.getElementById('toggle-eq');
                if (eqToggleEl) eqToggleEl.checked = isEQEnabled;
                
                const spatialToggleEl = document.getElementById('toggle-spatial');
                if (spatialToggleEl) spatialToggleEl.checked = isSpatialEnabled;
                
                const eqSlidersContainer = document.getElementById('eq-sliders');
                if (eqSlidersContainer) eqSlidersContainer.classList.toggle('d-none', !isEQEnabled);
                
                const volSliderEl = document.getElementById('global-vol-slider');
                if (volSliderEl) {
                   volSliderEl.value = globalVolumeMultiplier;
                   document.getElementById('global-vol-val').textContent = globalVolumeMultiplier + 'x';
                }
                
                const eqSliders = document.querySelectorAll('#eq-sliders .eq-band');
                globalEQBands.forEach((val, i) => { if (eqSliders[i]) eqSliders[i].value = val; });
                
                // Immediately apply audio processing if active
                if (audioCtx) {
                   applyAudioSettings();
                   toggleAudioEnhancements();
                }
              } catch(e) { 
                console.error("Error parsing settings JSON during checkSession:", e); 
              }
            }
            
            const newNameInput = document.getElementById('new-name');
            if (newNameInput) newNameInput.value = currentUser.artist;
            const bioInput = document.getElementById('settings-bio');
            if (bioInput) bioInput.value = currentUser.bio || '';
            if (uploadLimitText) uploadLimitText.textContent = data.upload_limit;
            if (uploadRemainingText) {
              uploadRemainingText.textContent = `Today's remaining uploads: ${currentUser.uploads_remaining}`;
            }
          } else if (data && data.status === 'loggedout') {
            currentUser = null;
            try { localStorage.removeItem('ytm_currentUser'); } catch(e) {}
          } else {
            // OFFLINE FALLBACK: Restore persistent session identity to bypass Auth locks when network fails
            try {
              const cachedUser = localStorage.getItem('ytm_currentUser');
              if (cachedUser) currentUser = JSON.parse(cachedUser);
              else currentUser = null;
            } catch(e) { currentUser = null; }
          }
          updateUIForAuthState();
        }

        window.noteCategories = [];
        window.taskCategories = [];
        window.blogCategories = [];
        window.noteViewerStates = {}; // Holds markdown state
        
        window.getCategoryName = (id, type = 'note') => {
          const arr = type === 'task' ? window.taskCategories : (type === 'blog' ? window.blogCategories : window.noteCategories);
          if (!arr) return 'Uncategorized';
          const c = arr.find(c => c.id === id);
          return c ? c.name : 'Uncategorized';
        };

        window.renderNoteCategories = () => {
          const catSelect = document.getElementById('editorCategorySelect');
          if (catSelect) {
            catSelect.innerHTML = '<option value="all" style="background: var(--ytm-surface-2);">Uncategorized</option>';
            window.noteCategories.forEach(c => {
              const opt = document.createElement('option');
              opt.value = c.id; opt.innerText = c.name;
              opt.style.background = 'var(--ytm-surface-2)';
              catSelect.appendChild(opt);
            });
          }

          const taskCatSelect = document.getElementById('taskEditorCategorySelect');
          if (taskCatSelect) {
            taskCatSelect.innerHTML = '<option value="all" style="background: var(--ytm-surface-2);">Uncategorized</option>';
            window.taskCategories.forEach(c => {
              const opt = document.createElement('option');
              opt.value = c.id; opt.innerText = c.name;
              opt.style.background = 'var(--ytm-surface-2)';
              taskCatSelect.appendChild(opt);
            });
          }

          const blogCatSelect = document.getElementById('blogEditorCategorySelect');
          if (blogCatSelect) {
            blogCatSelect.innerHTML = '<option value="all" style="background: var(--ytm-surface-2);">Uncategorized</option>';
            (window.blogCategories || []).forEach(c => {
              const opt = document.createElement('option');
              opt.value = c.id; opt.innerText = c.name;
              opt.style.background = 'var(--ytm-surface-2)';
              blogCatSelect.appendChild(opt);
            });
          }
        };

        const updateNoteSelectionUI = () => {
          document.getElementById('selectionCountNotes').innerText = window.selectedNoteIds.size;
          document.querySelectorAll('.note-card-item, .task-card-wrapper').forEach(card => {
            if (window.selectedNoteIds.has(card.dataset.id)) card.classList.add('selected');
            else card.classList.remove('selected');
          });
          const bar = document.getElementById('selectionBarNotes');
          const dlBtn = document.getElementById('bulkDownloadNotesBtn');
          dlBtn.classList.remove('d-none');
          
          if (window.multiSelectNoteMode) bar.classList.add('active');
          else bar.classList.remove('active');
        };

        const toggleNoteMultiSelect = (id) => {
          if (!window.multiSelectNoteMode) {
            window.multiSelectNoteMode = true;
          }
          if (window.selectedNoteIds.has(id)) window.selectedNoteIds.delete(id);
          else window.selectedNoteIds.add(id);
          
          if (window.selectedNoteIds.size === 0) window.multiSelectNoteMode = false;
          updateNoteSelectionUI();
        };

        const updateBlogSelectionUI = () => {
          document.getElementById('selectionCountBlogs').innerText = window.selectedBlogIds.size;
          document.querySelectorAll('.blog-card-owner').forEach(card => {
            if (window.selectedBlogIds.has(card.dataset.id)) card.classList.add('selected');
            else card.classList.remove('selected');
          });
          const bar = document.getElementById('selectionBarBlogs');
          if (window.multiSelectBlogMode) bar.classList.add('active');
          else bar.classList.remove('active');
        };

        const toggleBlogMultiSelect = (id) => {
          if (!window.multiSelectBlogMode) {
            window.multiSelectBlogMode = true;
          }
          if (window.selectedBlogIds.has(id)) window.selectedBlogIds.delete(id);
          else window.selectedBlogIds.add(id);
          
          if (window.selectedBlogIds.size === 0) window.multiSelectBlogMode = false;
          updateBlogSelectionUI();
        };

        window.bindBlogCardEvents = (container) => {
          container.querySelectorAll('.blog-card-owner:not(.bound)').forEach(card => {
            card.classList.add('bound');
            let pressTimer;
            let startX = 0, startY = 0;

            const doToggle = () => {
              const now = Date.now();
              if (card.dataset.lastToggle && now - parseInt(card.dataset.lastToggle) < 800) return; 
              card.dataset.lastToggle = now;
              toggleBlogMultiSelect(card.dataset.id);
            };
            
            const startTouch = (e) => { 
              if (e.touches && e.touches.length > 0) {
                startX = e.touches[0].clientX; startY = e.touches[0].clientY;
              }
              pressTimer = setTimeout(() => { doToggle(); if (navigator.vibrate) navigator.vibrate(50); }, 400); 
            };
            const cancelTouch = () => clearTimeout(pressTimer);
            const moveTouch = (e) => {
              if (!e.touches) return;
              const dx = Math.abs(e.touches[0].clientX - startX);
              const dy = Math.abs(e.touches[0].clientY - startY);
              if (dx > 10 || dy > 10) clearTimeout(pressTimer);
            };
            
            card.addEventListener('touchstart', startTouch, { passive: true });
            card.addEventListener('touchend', cancelTouch);
            card.addEventListener('touchcancel', cancelTouch);
            card.addEventListener('touchmove', moveTouch, { passive: true });
            card.addEventListener('contextmenu', (e) => { e.preventDefault(); doToggle(); });
          });
        };

        let blogWordCountTimeout = null;
        const updateBlogEditorWordCount = () => {
          const text = document.getElementById('blogEditorContent').value;
          document.getElementById('blogEditorCharCount').innerText = `${new Intl.NumberFormat().format(text.length)} chars`;
          
          clearTimeout(blogWordCountTimeout);
          blogWordCountTimeout = setTimeout(() => {
            let words = 0;
            if (text.length > 500000) {
              document.getElementById('blogEditorWordCount').innerText = `Massive Document`;
            } else if (text.trim()) {
              const matches = text.match(/\S+/g);
              words = matches ? matches.length : 0;
              document.getElementById('blogEditorWordCount').innerText = `${new Intl.NumberFormat().format(words)} words`;
            } else {
              document.getElementById('blogEditorWordCount').innerText = `0 words`;
            }
          }, 600);
        };

        document.getElementById('toggleSelectAllBlogsBtn')?.addEventListener('click', () => {
          const allSelected = window.currentBlogsList && window.currentBlogsList.length > 0 && window.currentBlogsList.every(b => window.selectedBlogIds.has(b.public_id));
          if (allSelected) {
            window.currentBlogsList.forEach(b => window.selectedBlogIds.delete(b.public_id));
            if (window.selectedBlogIds.size === 0) window.multiSelectBlogMode = false;
          } else {
            window.currentBlogsList.forEach(b => window.selectedBlogIds.add(b.public_id));
          }
          updateBlogSelectionUI();
        });

        document.getElementById('cancelSelectBlogsBtn')?.addEventListener('click', () => {
          window.multiSelectBlogMode = false; 
          window.selectedBlogIds.clear();
          updateBlogSelectionUI();
        });

        document.getElementById('bulkDownloadBlogsBtn')?.addEventListener('click', async () => {
          const zip = new JSZip();
          window.selectedBlogIds.forEach(public_id => {
            const b = window.currentBlogsList.find(x => x.public_id === public_id);
            if (b) {
              const cleanContent = (b.content || '').replace(/<[^>]*>?/gm, '');
              const displayTitle = (b.title && b.title.trim()) ? decodeHTML(b.title) : 'blog_post';
              zip.file(`${displayTitle.replace(/[^\w\s-]/gi, '_')}.txt`, decodeHTML(b.content) || '');
            }
          });
          const blob = await zip.generateAsync({ type: 'blob' });
          const a = document.createElement('a');
          a.href = URL.createObjectURL(blob);
          a.download = `Blogs_Selection_${Date.now()}.zip`;
          a.click();
          
          window.selectedBlogIds.clear();
          window.multiSelectBlogMode = false;
          updateBlogSelectionUI();
        }); 

        document.getElementById('bulkDeleteBlogsBtn')?.addEventListener('click', async () => {
          if (confirm(`Delete ${window.selectedBlogIds.size} blogs permanently?`)) {
            for (let public_id of window.selectedBlogIds) {
              const b = window.currentBlogsList.find(x => x.public_id === public_id);
              if (b && b.id) {
                await fetchData('?action=delete_blog', { method:'POST', body: JSON.stringify({id: b.id}) }, true);
              }
            }
            window.selectedBlogIds.clear(); 
            window.multiSelectBlogMode = false;
            updateBlogSelectionUI();
            loadView(currentView);
          }
        });

        window.openDocumentPip = async (containerEl, width = 1200, height = 700, onCloseCallback = null) => {
          if (!('documentPictureInPicture' in window)) {
            showToast('Picture-in-Picture is not supported in this browser.', 'error');
            return null;
          }
          try {
            const parentEl = containerEl.parentElement;
            const nextSibling = containerEl.nextSibling;
            
            const pipWin = await window.documentPictureInPicture.requestWindow({ width, height });

            [...document.styleSheets].forEach(styleSheet => {
              try {
                const cssRules = [...styleSheet.cssRules].map(rule => rule.cssText).join('');
                const style = document.createElement('style');
                style.textContent = cssRules;
                pipWin.document.head.appendChild(style);
              } catch (e) {
                if (styleSheet.href) {
                  const link = document.createElement('link');
                  link.rel = 'stylesheet';
                  link.href = styleSheet.href;
                  pipWin.document.head.appendChild(link);
                }
              }
            });

            const iconLink = document.createElement('link');
            iconLink.rel = 'stylesheet';
            iconLink.href = 'https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.min.css';
            pipWin.document.head.appendChild(iconLink);

            pipWin.document.body.style.background = 'var(--ytm-bg)';
            pipWin.document.body.style.margin = '0';
            pipWin.document.body.style.height = '100vh';
            pipWin.document.body.appendChild(containerEl);

            pipWin.addEventListener('pagehide', () => {
              if (parentEl) {
                if (nextSibling) parentEl.insertBefore(containerEl, nextSibling);
                else parentEl.appendChild(containerEl);
              }
              if (typeof onCloseCallback === 'function') onCloseCallback();
            });

            return pipWin;
          } catch (err) {
            console.error('PiP Error:', err);
            showToast('Failed to open Picture-in-Picture window.', 'error');
            return null;
          }
        };

        let notePipWin = null;
        document.getElementById('editorPipBtn')?.addEventListener('click', async () => {
          if (notePipWin) { notePipWin.close(); return; }
          const overlay = document.getElementById('editorOverlay');
          notePipWin = await window.openDocumentPip(overlay, 1200, 700, () => { notePipWin = null; });
        });

        let taskPipWin = null;
        document.getElementById('taskEditorPipBtn')?.addEventListener('click', async () => {
          if (taskPipWin) { taskPipWin.close(); return; }
          const overlay = document.getElementById('taskEditorOverlay');
          taskPipWin = await window.openDocumentPip(overlay, 1200, 700, () => { taskPipWin = null; });
        });

        let blogPipWin = null;
        document.getElementById('blogEditorPipBtn')?.addEventListener('click', async () => {
          if (blogPipWin) { blogPipWin.close(); return; }
          const overlay = document.getElementById('blogEditorOverlay');
          blogPipWin = await window.openDocumentPip(overlay, 1200, 700, () => { blogPipWin = null; });
        });

        let noteTextHistory = [];
        let noteHistoryIdx = -1;
        let noteSaveTimeout = null;
        let noteHistoryTimeout = null;
        let activeEditorNote = null;
        let isMarkdownPreview = false;
        let presenceSyncInterval = null;
        let lastSyncContentTime = null;

        const startPresenceSync = (itemId, itemType) => {
          if (presenceSyncInterval) clearInterval(presenceSyncInterval);
          const avContainer = document.getElementById(itemType === 'task' ? 'taskFloatingPresence' : (itemType === 'blog' ? 'blogFloatingPresence' : 'editorFloatingPresence'));
          
          presenceSyncInterval = setInterval(async () => {
            if (!itemId) return;
            const res = await fetchData('?action=sync_presence', {
              method: 'POST', body: JSON.stringify({ item_id: itemId, item_type: itemType })
            }, true);
            
            if (res && res.active_users) {
              if (res.active_users.length > 0) {
                avContainer.innerHTML = res.active_users.map(u => `
                  <div class="floating-avatar">
                    <img src="?action=get_profile_picture&id=${u.id}" alt="Avatar">
                    <span>${escapeHTML(u.artist)} is editing...</span>
                  </div>
                `).join('');
              } else {
                avContainer.innerHTML = '';
              }
              
              if (res.latest_update && lastSyncContentTime && res.latest_update !== lastSyncContentTime) {
                lastSyncContentTime = res.latest_update;
                
                const safeUpdateField = (el, newText) => {
                  if (!el || !newText) return;
                  const decodedText = decodeHTML(newText);
                  if (el.value === decodedText) return;
                  
                  if (document.activeElement === el) {
                    // Preserve cursor position during live collaborative injection
                    const start = el.selectionStart;
                    const end = el.selectionEnd;
                    const oldLen = el.value.length;
                    el.value = decodedText;
                    const diff = decodedText.length - oldLen;
                    el.setSelectionRange(start + diff, end + diff);
                  } else {
                    el.value = decodedText;
                  }
                };

                let statusIndicator = null;

                if (itemType === 'note') {
                   safeUpdateField(document.getElementById('editorTitle'), res.item_data.title);
                   safeUpdateField(document.getElementById('editorContent'), res.item_data.content);
                   statusIndicator = document.getElementById('noteSaveStatus');
                } else if (itemType === 'blog') {
                   safeUpdateField(document.getElementById('blogEditorTitle'), res.item_data.title);
                   safeUpdateField(document.getElementById('blogEditorContent'), res.item_data.content);
                   statusIndicator = document.getElementById('blogSaveStatus');
                } else if (itemType === 'task') {
                   safeUpdateField(document.getElementById('taskEditorTitle'), res.item_data.title);
                   
                   const isUserTyping = ['TEXTAREA', 'INPUT'].includes(document.activeElement?.tagName);
                   if (!isUserTyping && res.item_data && res.item_data.items) {
                     try {
                       window.currentTaskItems = JSON.parse(res.item_data.items);
                       window.renderTaskItems();
                     } catch(e) {}
                   }
                   statusIndicator = document.getElementById('taskSaveStatus');
                }

                if (statusIndicator) {
                   statusIndicator.innerHTML = '<span class="text-success"><i class="bi bi-cloud-download"></i> Live Sync</span>';
                   setTimeout(() => { if (statusIndicator.textContent.includes('Sync')) statusIndicator.textContent = ""; }, 2000);
                }
              }
              lastSyncContentTime = res.latest_update || lastSyncContentTime;
            }
          }, 500);
        };
        
        const stopPresenceSync = () => {
          if (presenceSyncInterval) clearInterval(presenceSyncInterval);
          presenceSyncInterval = null;
          lastSyncContentTime = null;
          const noteAv = document.getElementById('editorFloatingPresence');
          const taskAv = document.getElementById('taskFloatingPresence');
          const blogAv = document.getElementById('blogFloatingPresence');
          if (noteAv) noteAv.innerHTML = '';
          if (taskAv) taskAv.innerHTML = '';
          if (blogAv) blogAv.innerHTML = '';
        };

        const populateProjectMoveSelect = async (type) => {
          const select = document.getElementById('project-move-select');
          select.innerHTML = '<option value="">🏠 Personal (Private)</option>';
          const projs = await fetchData(`?action=get_projects&filter=${type}`);
          if (projs && projs.length > 0) {
            projs.forEach(p => {
              select.insertAdjacentHTML('beforeend', `<option value="${p.id}">📁 Project: ${escapeHTML(p.name)}</option>`);
            });
          }
        };

        document.getElementById('confirm-move-project-btn')?.addEventListener('click', async () => {
          const destProjId = document.getElementById('project-move-select').value;
          if (destProjId === "") {
            if (!confirm("Moving this to your Personal workspace will instantly revoke access for all current project collaborators. Proceed?")) return;
          }
          
          let itemId, itemType;
          
          if (document.getElementById('editorOverlay').classList.contains('active')) {
            itemId = document.getElementById('editorNoteId').value;
            itemType = 'note';
          } else if (document.getElementById('blogEditorOverlay').classList.contains('active')) {
            itemId = document.getElementById('blogEditorId').value;
            itemType = 'blog';
          } else {
            itemId = document.getElementById('taskEditorId').value;
            itemType = 'task';
          }
          
          if (!itemId) return showToast("Save the item first before moving it.", "error");
          
          const res = await fetchData('?action=manage_project', {
            method: 'POST', body: JSON.stringify({ action_type: 'move_item', item_id: itemId, item_type: itemType, project_id: destProjId })
          });
          
          if (res && res.status === 'success') {
            showToast('Moved successfully!', 'success');
            bootstrap.Modal.getInstance(document.getElementById('project-move-modal')).hide();
          }
        });

        document.getElementById('editorMoveProjectBtn')?.addEventListener('click', () => { 
          document.getElementById('editorMoreMenu')?.classList.remove('active'); 
          populateProjectMoveSelect('note'); 
        });
        
        document.getElementById('taskMoveProjectBtn')?.addEventListener('click', () => { 
          document.getElementById('taskEditorMoreMenu')?.classList.remove('active'); 
          populateProjectMoveSelect('task'); 
        });
        
        document.getElementById('blogEditorMoveProjectBtn')?.addEventListener('click', () => { 
          document.getElementById('blogEditorMoreMenu')?.classList.remove('active'); 
          populateProjectMoveSelect('blog'); 
        });
        
        window.activeBlogPublicId = null;
        let currentBlogCommentsPage = 1;

        window.refreshBlogComments = async (reset = false) => {
          if (!window.activeBlogPublicId) return;
          if (reset === true || typeof reset !== 'boolean') currentBlogCommentsPage = 1;
          const sortVal = document.getElementById('blog-comments-sort-select') ? document.getElementById('blog-comments-sort-select').value : 'newest';

          const data = await fetchData(`?action=get_blog_comments&blog_id=${window.activeBlogPublicId}&page=${currentBlogCommentsPage}&sort=${sortVal}`);
          if (!data) return;
          
          const totalCountEl = document.getElementById('total-blog-comments-count');
          if (totalCountEl) totalCountEl.textContent = data.total_comments || 0;

          const lCount = document.getElementById('blog-like-count');
          const dCount = document.getElementById('blog-dislike-count');
          if (lCount) lCount.textContent = data.reactions.like || 0;
          if (dCount) dCount.textContent = data.reactions.dislike || 0;

          const lBtn = document.getElementById('blog-like-btn');
          const dBtn = document.getElementById('blog-dislike-btn');
          if (lBtn) {
            const lIcon = lBtn.querySelector('i');
            if (lIcon) lIcon.className = `bi bi-hand-thumbs-up${data.my_reaction === 'like' ? '-fill' : ''} fs-5`;
            lBtn.classList.toggle('active', data.my_reaction === 'like');
            lBtn.classList.toggle('text-info', data.my_reaction === 'like');
          }
          if (dBtn) {
            const dIcon = dBtn.querySelector('i');
            if (dIcon) dIcon.className = `bi bi-hand-thumbs-down${data.my_reaction === 'dislike' ? '-fill' : ''} fs-5`;
            dBtn.classList.toggle('active', data.my_reaction === 'dislike');
            dBtn.classList.toggle('text-danger', data.my_reaction === 'dislike');
          }

          const buildTree = (comments, parent = null) => {
            const children = comments.filter(c => c.parent_id == parent);
            if (children.length === 0) return '';
            
            const renderContent = (raw) => {
              let decoded = decodeHTML(raw || '');
              let parsed = parseUserText(decoded);
              if (typeof marked !== 'undefined') {
                try { parsed = marked.parse(parsed); } catch(e) {}
              }
              return `<div class="rich-comment-box" style="font-size: 0.95rem; line-height: 1.6; word-break: break-word; color: #f1f1f1;">${parsed}</div>`;
            };

            const styleInjection = parent === null ? `
              <style>
