                              data-userid="${c.u_id}" 
                              data-artist="${encodeURIComponent(c.artist)}" 
                              style="font-size: 1rem; cursor:${c.is_disabled ? 'default' : 'pointer'}; letter-spacing: 0.3px; text-shadow: 0 2px 4px rgba(0,0,0,0.8);"
                              onmouseover="this.style.textDecoration='underline'"
                              onmouseout="this.style.textDecoration='none'">
                          ${escapeHTML(c.artist)}
                        </span>
                        <span class="text-secondary d-flex align-items-center gap-1 fw-medium" style="font-size: 0.75rem; opacity: 0.8; background: rgba(255,255,255,0.05); padding: 2px 8px; border-radius: 50px;">
                          <i class="bi bi-clock"></i> ${timeAgo(c.created_at)}
                        </span>
                      </div>
                      ${(currentUser && (currentUser.id == c.u_id || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `
                        <div class="position-relative flex-shrink-0 ms-2 custom-opt-dropdown">
                          <button class="btn btn-link text-secondary p-0 border-0 custom-opt-toggle" type="button"><i class="bi bi-three-dots-vertical fs-5"></i></button>
                          <ul class="dropdown-menu dropdown-menu-dark shadow-lg border-secondary custom-opt-menu" style="position: absolute; right: 0; top: 100%; display: none; z-index: 1060; min-width: 150px;">
                            <li><button class="dropdown-item edit-blog-comment-btn" data-id="${c.id}" data-content="${escapeHTML(c.content)}"><i class="bi bi-pencil"></i> Edit</button></li>
                            <li><button class="dropdown-item text-danger delete-blog-comment-btn" data-id="${c.id}"><i class="bi bi-trash"></i> Delete</button></li>
                          </ul>
                        </div>
                      ` : ''}
                    </div>
                    
                    <div class="p-3 mb-3 rounded-4">
                      ${renderContent(c.content)}
                    </div>
                    
                    ${currentUser ? `
                    <div class="d-flex align-items-center flex-wrap gap-2 mt-1">
                      <button class="phpmusic-comments-action-btn blog-comment-react-btn ${c.my_reaction === 'like' ? 'active-like' : ''}" data-id="${c.id}" data-reaction="like" title="Like">
                        <i class="bi ${c.my_reaction === 'like' ? 'bi-hand-thumbs-up-fill' : 'bi-hand-thumbs-up'} fs-5"></i>
                        <span>${c.like_count || 0}</span>
                      </button>
                      
                      <button class="phpmusic-comments-action-btn blog-comment-react-btn ${c.my_reaction === 'dislike' ? 'active-dislike' : ''}" data-id="${c.id}" data-reaction="dislike" title="Dislike">
                        <i class="bi ${c.my_reaction === 'dislike' ? 'bi-hand-thumbs-down-fill' : 'bi-hand-thumbs-down'} fs-5"></i>
                        <span>${c.dislike_count || 0}</span>
                      </button>
                      
                      <button class="phpmusic-comments-action-btn blog-reply-btn" data-id="${c.id}" data-root-id="${c.id}" data-username="${escapeHTML(c.artist)}" data-content="${escapeHTML(c.content)}" title="Reply to ${escapeHTML(c.artist)}">
                        <i class="bi bi-chat-left-text fs-5"></i> Reply ${children.filter(ch => ch.parent_id == c.id).length > 0 ? `(${children.filter(ch => ch.parent_id == c.id).length})` : ''}
                      </button>
                    </div>
                    ` : `
                    <div class="d-flex align-items-center gap-3 text-secondary fw-bold" style="font-size: 0.9rem;">
                      <span class="d-flex align-items-center gap-2 bg-dark px-3 py-1 rounded-pill border border-secondary shadow-sm"><i class="bi bi-hand-thumbs-up-fill text-info fs-5"></i> ${c.like_count || 0}</span>
                      <span class="d-flex align-items-center gap-2 bg-dark px-3 py-1 rounded-pill border border-secondary shadow-sm"><i class="bi bi-hand-thumbs-down-fill text-danger fs-5"></i> ${c.dislike_count || 0}</span>
                    </div>
                    `}
                    <div class="mt-4">${buildTree(comments, c.id)}</div>
                  </div>
                </div>
              `).join('');
            } else {
              const repliesHtml = children.map(c => `
                <div class="d-flex gap-3 mb-3 position-relative border-start border-top border-dark border-2 rounded-4 p-2" style="animation: slideFadeIn 0.3s ease forwards; --bs-border-opacity: .5;">
                  <div class="d-flex flex-column align-items-center" style="width: 36px; flex-shrink: 0;">
                    <img src="?action=get_profile_picture&id=${c.u_id}" 
                         class="rounded-circle shadow-sm ${c.is_disabled ? '' : 'user-profile-link'}" 
                         data-userid="${c.u_id}" 
                         data-artist="${encodeURIComponent(c.artist)}" 
                         style="width:36px; height:36px; object-fit:cover; cursor:${c.is_disabled ? 'default' : 'pointer'}; border: 1px solid rgba(255,255,255,0.15); transition: transform 0.3s;"
                         onmouseover="this.style.transform='scale(1.15)'"
                         onmouseout="this.style.transform='scale(1)'">
                    ${children.filter(ch => ch.parent_id == c.id).length > 0 ? `<div class="mt-2" style="width: 2px; flex-grow: 1; background: linear-gradient(to bottom, rgba(255,255,255,0.1), transparent); border-radius: 2px;"></div>` : ''}
                  </div>
                  
                  <div class="flex-grow-1" style="min-width: 0;">
                    <div class="d-flex justify-content-between align-items-start mb-1">
                      <div class="d-flex align-items-center flex-wrap gap-2">
                        <span class="fw-bold text-white ${c.is_disabled ? '' : 'user-profile-link'}" 
                              data-userid="${c.u_id}" 
                              data-artist="${encodeURIComponent(c.artist)}" 
                              style="font-size: 0.85rem; cursor:${c.is_disabled ? 'default' : 'pointer'}; text-shadow: 0 1px 2px rgba(0,0,0,0.5);"
                              onmouseover="this.style.textDecoration='underline'"
                              onmouseout="this.style.textDecoration='none'">
                          ${escapeHTML(c.artist)}
                        </span>
                        <span class="text-secondary d-flex align-items-center gap-1 fw-medium" style="font-size: 0.7rem; opacity: 0.7;">
                          <i class="bi bi-clock"></i> ${timeAgo(c.created_at)}
                        </span>
                      </div>
                      ${(currentUser && (currentUser.id == c.u_id || currentUser.email === 'musiclibrary@mail.com' || currentUser.is_admin == 1)) ? `
                        <div class="position-relative flex-shrink-0 ms-2 custom-opt-dropdown">
                          <button class="btn btn-link text-secondary p-0 border-0 custom-opt-toggle" type="button"><i class="bi bi-three-dots-vertical fs-5"></i></button>
                          <ul class="dropdown-menu dropdown-menu-dark shadow-lg border-secondary custom-opt-menu" style="position: absolute; right: 0; top: 100%; display: none; z-index: 1060; min-width: 150px;">
                            <li><button class="dropdown-item edit-blog-comment-btn" data-id="${c.id}" data-content="${escapeHTML(c.content)}"><i class="bi bi-pencil"></i> Edit</button></li>
                            <li><button class="dropdown-item text-danger delete-blog-comment-btn" data-id="${c.id}"><i class="bi bi-trash"></i> Delete</button></li>
                          </ul>
                        </div>
                      ` : ''}
                    </div>
                    
                    <div class="p-2 mb-2">
                      ${renderContent(c.content)}
                    </div>
                    
                    ${currentUser ? `
                    <div class="d-flex align-items-center flex-wrap gap-2 mt-1">
                      <button class="phpmusic-comments-action-btn blog-comment-react-btn ${c.my_reaction === 'like' ? 'active-like' : ''}" data-id="${c.id}" data-reaction="like" style="padding: 4px 12px; font-size: 0.85rem;">
                        <i class="bi ${c.my_reaction === 'like' ? 'bi-hand-thumbs-up-fill' : 'bi-hand-thumbs-up'}"></i>
                        <span>${c.like_count || 0}</span>
                      </button>
                      
                      <button class="phpmusic-comments-action-btn blog-comment-react-btn ${c.my_reaction === 'dislike' ? 'active-dislike' : ''}" data-id="${c.id}" data-reaction="dislike" style="padding: 4px 12px; font-size: 0.85rem;">
                        <i class="bi ${c.my_reaction === 'dislike' ? 'bi-hand-thumbs-down-fill' : 'bi-hand-thumbs-down'}"></i>
                        <span>${c.dislike_count || 0}</span>
                      </button>
                      
                      <button class="phpmusic-comments-action-btn blog-reply-btn" data-id="${c.id}" data-root-id="${parent}" data-username="${escapeHTML(c.artist)}" data-content="${escapeHTML(c.content)}" style="padding: 4px 12px; font-size: 0.85rem;">
                        <i class="bi bi-chat-left-text"></i> Reply ${children.filter(ch => ch.parent_id == c.id).length > 0 ? `(${children.filter(ch => ch.parent_id == c.id).length})` : ''}
                      </button>
                    </div>
                    ` : `
                    <div class="d-flex align-items-center gap-3 text-secondary fw-bold" style="font-size: 0.8rem;">
                      <span class="d-flex align-items-center gap-1 bg-dark px-2 py-1 rounded-pill border border-secondary shadow-sm"><i class="bi bi-hand-thumbs-up-fill text-info"></i> ${c.like_count || 0}</span>
                      <span class="d-flex align-items-center gap-1 bg-dark px-2 py-1 rounded-pill border border-secondary shadow-sm"><i class="bi bi-hand-thumbs-down-fill text-danger"></i> ${c.dislike_count || 0}</span>
                    </div>
                    `}
                    <div class="mt-2">${buildTree(comments, c.id)}</div>
                  </div>
                </div>
              `).join('');

              return `
                <div class="ps-3 ms-2 position-relative mt-2" style="border-left: 2px solid rgba(255,255,255,0.1); border-radius: 0 0 0 12px;">
                  <button class="btn btn-link text-info text-decoration-none fw-bold d-inline-flex align-items-center gap-2 toggle-replies-btn mb-3 p-0" data-target="blog-comment-reply-container-${parent}" style="font-size: 0.95rem; transition: 0.2s;" onmouseover="this.style.textShadow='0 0 12px rgba(0, 188, 212, 0.6)'" onmouseout="this.style.textShadow='none'">
                    <div class="d-flex align-items-center justify-content-center bg-info text-dark rounded-circle shadow-sm" style="width: 24px; height: 24px;">
                      <i class="bi bi-chevron-down" style="font-size: 0.85rem;"></i>
                    </div>
                    View ${children.length} ${children.length === 1 ? 'reply' : 'replies'}
                  </button>
                  <div id="blog-comment-reply-container-${parent}" class="d-none mt-2 pt-2">
                    ${repliesHtml}
                  </div>
                </div>
              `;
            }
          };

          const commentsList = document.getElementById('blog-comments-list');
          if (commentsList) {
            const newHtml = buildTree(data.comments) || (reset ? '<p class="text-secondary text-center mt-3">No comments yet. Be the first to comment!</p>' : '');
            if (reset) preserveReplyState(newHtml, 'blog-comments-list');
            else commentsList.insertAdjacentHTML('beforeend', newHtml);

            const btnContainer = document.getElementById('load-more-blog-comments-container');
            if (btnContainer) {
              const rootCount = data.comments.filter(c => c.parent_id == null).length;
              if (rootCount >= 25) btnContainer.classList.remove('d-none');
              else btnContainer.classList.add('d-none');
            }
            window.checkMediaCache();
          }
        };

        // Attach listeners for blog view comments & reactions
        document.addEventListener('click', async (e) => {
          const blogLikeBtn = e.target.closest('#blog-like-btn');
          if (blogLikeBtn) {
            if (!currentUser) return showToast('Please login', 'error');
            const iconEl = blogLikeBtn.querySelector('i');
            const countEl = blogLikeBtn.querySelector('span');
            let count = parseInt(countEl.textContent) || 0;
            if (iconEl.classList.contains('bi-hand-thumbs-up-fill')) {
               iconEl.className = 'bi bi-hand-thumbs-up fs-5';
               countEl.textContent = Math.max(0, count - 1);
            } else {
               const sib = document.getElementById('blog-dislike-btn');
               if (sib && sib.querySelector('i').classList.contains('bi-hand-thumbs-down-fill')) {
                 sib.querySelector('i').className = 'bi bi-hand-thumbs-down fs-5';
                 sib.querySelector('span').textContent = Math.max(0, (parseInt(sib.querySelector('span').textContent) || 0) - 1);
               }
               iconEl.className = 'bi bi-hand-thumbs-up-fill fs-5';
               countEl.textContent = count + 1;
            }
            fetchData('?action=toggle_blog_reaction', { method: 'POST', body: JSON.stringify({ blog_id: window.activeBlogPublicId, reaction: 'like' }) });
            return;
          }
          const blogDislikeBtn = e.target.closest('#blog-dislike-btn');
          if (blogDislikeBtn) {
            if (!currentUser) return showToast('Please login', 'error');
            const iconEl = blogDislikeBtn.querySelector('i');
            const countEl = blogDislikeBtn.querySelector('span');
            let count = parseInt(countEl.textContent) || 0;
            if (iconEl.classList.contains('bi-hand-thumbs-down-fill')) {
               iconEl.className = 'bi bi-hand-thumbs-down fs-5';
               countEl.textContent = Math.max(0, count - 1);
            } else {
               const sib = document.getElementById('blog-like-btn');
               if (sib && sib.querySelector('i').classList.contains('bi-hand-thumbs-up-fill')) {
                 sib.querySelector('i').className = 'bi bi-hand-thumbs-up fs-5';
                 sib.querySelector('span').textContent = Math.max(0, (parseInt(sib.querySelector('span').textContent) || 0) - 1);
               }
               iconEl.className = 'bi bi-hand-thumbs-down-fill fs-5';
               countEl.textContent = count + 1;
            }
            fetchData('?action=toggle_blog_reaction', { method: 'POST', body: JSON.stringify({ blog_id: window.activeBlogPublicId, reaction: 'dislike' }) });
            return;
          }
          const blogReplyBtn = e.target.closest('.blog-reply-btn');
          if (blogReplyBtn) {
            document.getElementById('reply-blog-comment-parent-id').value = blogReplyBtn.dataset.rootId || blogReplyBtn.dataset.id;
            const input = document.getElementById('reply-blog-comment-input');
            const preview = document.getElementById('reply-blog-comment-preview');
            const username = blogReplyBtn.dataset.username;
            const content = blogReplyBtn.dataset.content || '';
            if (preview) {
              preview.innerHTML = `<strong class="text-white">Replying to ${escapeHTML(username)}:</strong><br><span class="text-secondary text-truncate d-block">${escapeHTML(content).replace(/<[^>]*>?/gm, '')}</span>`;
            }
            if (username) {
              input.value = `@${username.replace(/\s+/g, '')} `;
            } else {
              input.value = '';
            }
            bootstrap.Modal.getOrCreateInstance(document.getElementById('reply-blog-comment-modal')).show();
            setTimeout(() => input.focus(), 500);
            return;
          }
          const communityReplyBtn = e.target.closest('.community-reply-btn');
          if (communityReplyBtn) {
            e.stopPropagation();
            document.getElementById('reply-community-post-parent-id').value = communityReplyBtn.dataset.id;
            const input = document.getElementById('reply-community-post-input');
            const preview = document.getElementById('reply-community-post-preview');
            const username = communityReplyBtn.dataset.username;
            const content = communityReplyBtn.dataset.content || '';
            if (preview) {
              preview.innerHTML = `<strong class="text-white">Replying to ${escapeHTML(username)}:</strong><br><span class="text-secondary text-truncate d-block">${escapeHTML(content).replace(/<[^>]*>?/gm, '')}</span>`;
            }
            if (username) {
              input.value = `@${username.replace(/\s+/g, '')} `;
            } else {
              input.value = '';
            }
            bootstrap.Modal.getOrCreateInstance(document.getElementById('reply-community-post-modal')).show();
            setTimeout(() => input.focus(), 500);
            return;
          }
          const blogCommentReactBtn = e.target.closest('.blog-comment-react-btn');
          if (blogCommentReactBtn) {
            e.stopPropagation();
            if (!currentUser) return showToast('Please login', 'error');
            const reaction = blogCommentReactBtn.dataset.reaction;
            const iconEl = blogCommentReactBtn.querySelector('i');
            const spanEl = blogCommentReactBtn.querySelector('span');
            let count = parseInt(spanEl.textContent) || 0;
            const isFilled = iconEl.classList.contains('bi-hand-thumbs-up-fill') || iconEl.classList.contains('bi-hand-thumbs-down-fill');
            
            if (isFilled) {
              iconEl.className = `bi bi-hand-thumbs-${reaction === 'like' ? 'up' : 'down'} fs-5`;
              spanEl.textContent = Math.max(0, count - 1);
            } else {
              const sibling = blogCommentReactBtn.parentElement.querySelector(`[data-reaction="${reaction === 'like' ? 'dislike' : 'like'}"]`);
              if (sibling) {
                const sibIcon = sibling.querySelector('i');
                if (sibIcon.classList.contains('bi-hand-thumbs-up-fill') || sibIcon.classList.contains('bi-hand-thumbs-down-fill')) {
                  sibIcon.className = `bi bi-hand-thumbs-${reaction === 'like' ? 'down' : 'up'} fs-5`;
                  const sibSpan = sibling.querySelector('span');
                  sibSpan.textContent = Math.max(0, (parseInt(sibSpan.textContent) || 0) - 1);
                }
              }
              iconEl.className = `bi bi-hand-thumbs-${reaction === 'like' ? 'up' : 'down'}-fill fs-5`;
              spanEl.textContent = count + 1;
            }
            
            fetchData('?action=toggle_blog_comment_reaction', { method: 'POST', body: JSON.stringify({ comment_id: blogCommentReactBtn.dataset.id, reaction: reaction }) });
            return;
          }
          const editBlogCommentBtn = e.target.closest('.edit-blog-comment-btn');
          if (editBlogCommentBtn) {
            document.getElementById('edit-blog-comment-id').value = editBlogCommentBtn.dataset.id;
            document.getElementById('edit-blog-comment-input').value = decodeHTML(editBlogCommentBtn.dataset.content);
            bootstrap.Modal.getOrCreateInstance(document.getElementById('edit-blog-comment-modal')).show();
            return;
          }
          const deleteBlogCommentBtn = e.target.closest('.delete-blog-comment-btn');
          if (deleteBlogCommentBtn) {
            if (confirm('Delete this comment?')) {
              await fetchData('?action=delete_blog_comment', { method: 'POST', body: JSON.stringify({ comment_id: deleteBlogCommentBtn.dataset.id }) });
              window.refreshBlogComments(true);
            }
            return;
          }
        });

        document.addEventListener('submit', async (e) => {
          if (e.target.id === 'blog-comment-form') {
            e.preventDefault();
            if (!currentUser) return showToast('Please login', 'error');
            const input = document.getElementById('blog-comment-input');
            const parentId = document.getElementById('blog-comment-parent-id').value;
            await fetchData('?action=add_blog_comment', { method: 'POST', body: JSON.stringify({ blog_id: window.activeBlogPublicId, parent_id: parentId || null, content: input.value }) });
            input.value = '';
            document.getElementById('blog-comment-parent-id').value = '';
            input.placeholder = "Add a comment... (use @ to mention)";
            window.refreshBlogComments(true);
          }
        });

        let findBlogMatches = [];
        let currentBlogMatchIdx = -1;

        const executeBlogFind = (fromInput = true) => {
          const text = document.getElementById('blogEditorContent').value;
          const query = document.getElementById('blogFindInput').value;
          findBlogMatches = [];
          if (!query) { updateBlogFindUI(-1, false); return; }

          const regex = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
          let match;
          while ((match = regex.exec(text)) !== null) {
            findBlogMatches.push({ index: match.index, length: match[0].length });
          }
          
          if (findBlogMatches.length > 0) {
            if (fromInput) {
              if (currentBlogMatchIdx < 0 || currentBlogMatchIdx >= findBlogMatches.length) currentBlogMatchIdx = 0;
              updateBlogFindUI(currentBlogMatchIdx, false);
            } else {
              currentBlogMatchIdx = 0;
              updateBlogFindUI(currentBlogMatchIdx, true);
            }
          } else {
            updateBlogFindUI(-1, false);
          }
        };

        const updateBlogFindUI = (idx, doFocusJump = true) => {
          currentBlogMatchIdx = idx;
          const counter = document.getElementById('blogFindCounter');
          if (findBlogMatches.length === 0 || idx < 0) {
            counter.innerText = '0/0'; return;
          }
          counter.innerText = `${idx + 1}/${findBlogMatches.length}`;
          
          if (doFocusJump) {
            const ta = document.getElementById('blogEditorContent');
            const match = findBlogMatches[idx];
            ta.focus({ preventScroll: true });
            ta.setSelectionRange(match.index, match.index + match.length);
          }
        };

        document.getElementById('blogEditorFindBtn')?.addEventListener('click', () => {
          if (isBlogMarkdownPreview) return;
          const p = document.getElementById('blogFindReplacePanel');
          p.classList.toggle('active');
          if (p.classList.contains('active')) {
            document.getElementById('blogFindInput').focus();
            executeBlogFind();
          } else {
            document.getElementById('blogEditorContent').focus();
          }
        });

        document.getElementById('closeBlogFindBtn')?.addEventListener('click', () => document.getElementById('blogFindReplacePanel').classList.remove('active'));
        document.getElementById('blogFindInput')?.addEventListener('input', executeBlogFind);

        document.getElementById('blogFindNextBtn')?.addEventListener('click', () => {
          if (findBlogMatches.length === 0) return;
          let next = currentBlogMatchIdx + 1;
          if (next >= findBlogMatches.length) next = 0;
          updateBlogFindUI(next, true);
        });

        document.getElementById('blogFindPrevBtn')?.addEventListener('click', () => {
          if (findBlogMatches.length === 0) return;
          let next = currentBlogMatchIdx - 1;
          if (next < 0) next = findBlogMatches.length - 1;
          updateBlogFindUI(next, true);
        });

        document.getElementById('blogReplaceBtn')?.addEventListener('click', () => {
          if (currentBlogMatchIdx < 0 || findBlogMatches.length === 0) return;
          const rep = document.getElementById('blogReplaceInput').value;
          const ta = document.getElementById('blogEditorContent');
          const match = findBlogMatches[currentBlogMatchIdx];
          ta.value = ta.value.substring(0, match.index) + rep + ta.value.substring(match.index + match.length);
          ta.dispatchEvent(new Event('input'));
          executeBlogFind(false);
        });

        document.getElementById('blogReplaceAllBtn')?.addEventListener('click', () => {
          const query = document.getElementById('blogFindInput').value;
          if (!query) return;
          const rep = document.getElementById('blogReplaceInput').value;
          const ta = document.getElementById('blogEditorContent');
          const regex = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
          ta.value = ta.value.replace(regex, rep);
          ta.dispatchEvent(new Event('input'));
          executeBlogFind(false);
        });
        
        window.openEditorNote = (note) => {
          activeEditorNote = note;
          const isOwner = !note.id || note.user_id == (currentUser ? currentUser.id : null);
          
          const catSelect = document.getElementById('editorCategorySelect');
          if (catSelect) {
            catSelect.disabled = !isOwner;
            catSelect.style.opacity = isOwner ? '1' : '0.6';
            catSelect.style.cursor = isOwner ? 'pointer' : 'default';
            if (note.category) catSelect.value = note.category;
          }
          
          const moveBtn = document.getElementById('editorMoveProjectBtn');
          if (moveBtn) moveBtn.style.display = isOwner ? 'flex' : 'none';
          
          const delBtn = document.getElementById('editorDeleteBtn');
          if (delBtn) delBtn.style.display = isOwner ? 'flex' : 'none';
          
          const noteIdEl = document.getElementById('editorNoteId');
          if (noteIdEl) noteIdEl.value = note.id || '';
          
          const noteTypeEl = document.getElementById('editorNoteType');
          if (noteTypeEl) noteTypeEl.value = note.note_type || 'note';
          
          const titleEl = document.getElementById('editorTitle');
          if (titleEl) titleEl.value = note.title ? decodeHTML(note.title) : '';
          
          const contentEl = document.getElementById('editorContent');
          if (contentEl) contentEl.value = note.content ? decodeHTML(note.content) : '';
          
          const dateEl = document.getElementById('editorDate');
          if (dateEl) dateEl.innerText = note.updated_at ? new Date(note.updated_at.replace(' ', 'T') + 'Z').toLocaleDateString() : new Date().toLocaleDateString();
          
          // History state implementation for back/forth
          if (!history.state || history.state.overlay !== 'note_' + note.id) {
            history.pushState({ viewConfig: currentView, overlay: 'note_' + note.id }, '', window.location.pathname);
          }

          isMarkdownPreview = false;
          const mdBtn = document.getElementById('editorMarkdownBtn');
          if (mdBtn) {
            const mdIcon = mdBtn.querySelector('i');
            // Persist Markdown state if the user previously toggled it for this note
            if (window.noteViewerStates[note.id] === 'markdown') {
              mdBtn.click();
            } else {
              if (mdIcon) mdIcon.className = 'bi bi-markdown';
              if (contentEl) contentEl.classList.remove('d-none');
              const previewEl = document.getElementById('editorMarkdownPreview');
              if (previewEl) previewEl.classList.add('d-none');
            }
          }
          
          if (contentEl) noteTextHistory = [contentEl.value];
          noteHistoryIdx = 0;
          
          const starIcon = document.getElementById('editorStarIcon');
          if (starIcon) {
            starIcon.className = note.starred == 1 ? 'bi bi-star-fill text-warning' : 'bi bi-star';
          }
          
          updateEditorWordCount();
          const findPanel = document.getElementById('findReplacePanel');
          if (findPanel) findPanel.classList.remove('active');
          
          const moreMenu = document.getElementById('editorMoreMenu');
          if (moreMenu) moreMenu.classList.remove('active');
          
          const overlay = document.getElementById('editorOverlay');
          if (overlay) overlay.classList.add('active');
          
          if (note.id) {
            lastSyncContentTime = note.updated_at;
            startPresenceSync(note.id, 'note');
          }
        };

        const saveCurrentEditorNote = async (force = false) => {
          const statusIndicator = document.getElementById('noteSaveStatus');
          if (statusIndicator) statusIndicator.textContent = "Saving...";
          const idInput = document.getElementById('editorNoteId');
          const id = idInput.value;
          const title = document.getElementById('editorTitle').value.trim();
          const content = document.getElementById('editorContent').value;
          const category = document.getElementById('editorCategorySelect').value;
          const noteType = document.getElementById('editorNoteType').value || 'note';
          const isStarred = document.getElementById('editorStarIcon').classList.contains('bi-star-fill') ? 1 : 0;
          
          if (!title && !content) return; // don't save empty notes automatically
          
          // CONDITIONAL SAVE: Do not auto-save a brand new note unless the user explicitly hits Save/Close
          if (!id && !force) return;
          
          let projId = null;
          if (currentView.filter && currentView.filter.startsWith('proj_')) {
            projId = currentView.filter.replace('proj_', '');
          }
          const res = await fetchData('?action=save_note', { 
            method: 'POST', body: JSON.stringify({id: id || null, title, content, category, starred: isStarred, note_type: noteType, project_id: projId}) 
          }, true);

          if (res && res.status === 'success' && res.id && !id) {
            idInput.value = res.id;
          }
          if (statusIndicator && res && res.status === 'success') {
            statusIndicator.textContent = "Saved";
            setTimeout(() => { if (statusIndicator.textContent === "Saved") statusIndicator.textContent = ""; }, 2000);
          }
        };

        document.getElementById('editorMarkdownBtn').addEventListener('click', () => {
          isMarkdownPreview = !isMarkdownPreview;
          const idInput = document.getElementById('editorNoteId').value;
          if (idInput) window.noteViewerStates[idInput] = isMarkdownPreview ? 'markdown' : 'editor';
          
          const contentArea = document.getElementById('editorContent');
          const previewArea = document.getElementById('editorMarkdownPreview');
          const icon = document.getElementById('editorMarkdownBtn').querySelector('i');
          
          if (isMarkdownPreview) {
            icon.className = 'bi bi-pencil-square';
            contentArea.classList.add('d-none');
            previewArea.classList.remove('d-none');
            
            document.getElementById('findReplacePanel').classList.remove('active');
            document.getElementById('editorFindBtn').disabled = true;
            document.getElementById('editorFindBtn').style.opacity = '0.5';
            
            // Render markdown using Marked.js (with Github Flavored Markdown for Tasks)
            if (typeof marked !== 'undefined') {
              marked.use({ gfm: true });
              previewArea.innerHTML = marked.parse(contentArea.value);
               
              // Notion-style live checkboxes inside the preview
              previewArea.querySelectorAll('input[type="checkbox"]').forEach(cb => {
                cb.addEventListener('change', (e) => {
                  const isChecked = e.target.checked;
                  const regex = new RegExp(`\\[[ xX]\\]`, 'g');
                  let matchCount = 0;
                  let cbIndex = Array.from(previewArea.querySelectorAll('input[type="checkbox"]')).indexOf(e.target);
                   
                  contentArea.value = contentArea.value.replace(regex, (match) => {
                    if (matchCount === cbIndex) {
                      matchCount++;
                      return isChecked ? `[x]` : `[ ]`;
                    }
                    matchCount++;
                    return match;
                  });
                  saveCurrentEditorNote(false);
                });
              });
            } else {
              previewArea.innerHTML = '<p class="text-secondary text-center p-5">Markdown renderer is loading or unavailable.</p>';
            }
          } else {
            icon.className = 'bi bi-markdown';
            previewArea.classList.add('d-none');
            contentArea.classList.remove('d-none');
            contentArea.focus();
            
            document.getElementById('editorFindBtn').disabled = false;
            document.getElementById('editorFindBtn').style.opacity = '1';
          }
        });

        let wordCountTimeout = null;
        const updateEditorWordCount = () => {
          const text = document.getElementById('editorContent').value;
          document.getElementById('editorCharCount').innerText = `${new Intl.NumberFormat().format(text.length)} chars`;
          
          clearTimeout(wordCountTimeout);
          wordCountTimeout = setTimeout(() => {
            let words = 0;
            // ADVANCED RENDERING: Prevent browser freeze by bypassing regex on documents over 500k chars
            if (text.length > 500000) {
              document.getElementById('editorWordCount').innerText = `Massive Document`;
            } else if (text.trim()) {
              const matches = text.match(/\S+/g);
              words = matches ? matches.length : 0;
              document.getElementById('editorWordCount').innerText = `${new Intl.NumberFormat().format(words)} words`;
            } else {
              document.getElementById('editorWordCount').innerText = `0 words`;
            }
          }, 600);
        };

        document.getElementById('editorCopyBtn')?.addEventListener('click', () => {
          document.getElementById('editorMoreMenu').classList.remove('active');
          const text = document.getElementById('editorContent').value;
          if (navigator.clipboard && window.isSecureContext) {
            navigator.clipboard.writeText(text).then(() => showToast('Copied to clipboard!', 'success'));
          }
        });

        document.addEventListener('click', (e) => {
          const btn = e.target.closest('button[data-md]');
          if (!btn) return;
          e.preventDefault();
          const md = btn.dataset.md;
          let ta;
          const container = btn.closest('.rich-input-container');
          
          if (container) {
            ta = document.getElementById(container.dataset.targetId);
          } else if (btn.closest('#blogEditorToolbar')) {
            ta = document.getElementById('blogEditorContent');
          } else if (btn.closest('.editor-toolbar')) {
            ta = document.getElementById('editorContent');
          }
          if (!ta) return;

          const start = ta.selectionStart;
          const end = ta.selectionEnd;
          const selectedText = ta.value.substring(start, end);
          let pre = '', suf = '', def = '';

          switch(md) {
            case 'bold': pre = '**'; suf = '**'; def = 'bold text'; break;
            case 'italic': pre = '*'; suf = '*'; def = 'italic text'; break;
            case 'heading': pre = '### '; def = 'Heading'; break;
            case 'strikethrough': pre = '~~'; suf = '~~'; def = 'strikethrough'; break;
            case 'ul': pre = '- '; def = 'List item'; break;
            case 'ol': pre = '1. '; def = 'List item'; break;
            case 'task': pre = '- [ ] '; def = 'Task'; break;
            case 'quote': pre = '> '; def = 'Quote'; break;
            case 'code': pre = '```\n'; suf = '\n```'; def = 'code block'; break;
            case 'table': pre = '| Header | Header |\n| --- | --- |\n| Cell | Cell |'; break;
            case 'align-left': pre = '<div style="text-align: left;">\n'; suf = '\n</div>'; def = 'Left aligned text'; break;
            case 'align-center': pre = '<div style="text-align: center;">\n'; suf = '\n</div>'; def = 'Center aligned text'; break;
            case 'align-right': pre = '<div style="text-align: right;">\n'; suf = '\n</div>'; def = 'Right aligned text'; break;
            case 'link': pre = '['; suf = '](url)'; def = 'link text'; break;
            case 'image': 
              const imgUrl = prompt("Enter image URL:", "https://example.com/image.jpg");
              if (imgUrl) {
                const imgWidth = prompt("Enter width (e.g. 100%, 300px, auto):", "100%");
                const imgHeight = prompt("Enter height (e.g. auto, 300px):", "auto");
                pre = `<img src="${imgUrl}" width="${imgWidth || '100%'}" height="${imgHeight || 'auto'}" alt="`;
                suf = '">';
                def = 'image description';
              } else {
                return; // Cancelled
              }
              break;
            case 'video':
              const vidUrl = prompt("Enter Video or YouTube URL:", "https://www.youtube.com/watch?v=...");
              if (vidUrl) {
                const ytMatch = vidUrl.match(/(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=)|youtu\.be\/)([^"&?\/\s]{11})/i);
                if (ytMatch && ytMatch[1]) {
                  pre = `\n<iframe src="https://www.youtube.com/embed/${ytMatch[1]}" title="YouTube video player" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen></iframe>\n`;
                } else {
                  pre = `\n<video src="${vidUrl}" controls style="background: #000;"></video>\n`;
                }
                suf = '';
                def = '';
              } else {
                return; // Cancelled
              }
              break;
          }

          const insertText = selectedText || def;
          const finalInsert = md === 'table' ? pre : pre + insertText + suf;
          
          ta.value = ta.value.substring(0, start) + finalInsert + ta.value.substring(end);
          ta.focus();
          
          if (md === 'table') {
            ta.setSelectionRange(start + 2, start + 8);
          } else if (selectedText) {
             ta.setSelectionRange(start, start + finalInsert.length);
          } else {
             ta.setSelectionRange(start + pre.length, start + pre.length + def.length);
          }
          
          ta.dispatchEvent(new Event('input'));
          ta.style.height = ''; ta.style.height = ta.scrollHeight + 'px';
        });

        let taskSaveTimeout = null;

        window.openTaskEditor = (task) => {
          const isOwner = !task.id || task.user_id == (currentUser ? currentUser.id : null);
          
          const catSelect = document.getElementById('taskEditorCategorySelect');
          if (catSelect) {
            catSelect.disabled = !isOwner;
            catSelect.style.opacity = isOwner ? '1' : '0.6';
            catSelect.style.cursor = isOwner ? 'pointer' : 'default';
            if (task.category) catSelect.value = task.category;
          }
          
          const moveBtn = document.getElementById('taskMoveProjectBtn');
          if (moveBtn) moveBtn.style.display = isOwner ? 'flex' : 'none';
          
          const delBtn = document.getElementById('taskEditorDeleteBtn');
          if (delBtn) delBtn.style.display = isOwner ? 'flex' : 'none';
          
          if (!history.state || history.state.overlay !== 'task_' + task.id) {
            history.pushState({ viewConfig: currentView, overlay: 'task_' + task.id }, '', window.location.pathname);
          }
          
          const idEl = document.getElementById('taskEditorId');
          if (idEl) idEl.value = task.id || '';
          
          const titleEl = document.getElementById('taskEditorTitle');
          if (titleEl) titleEl.value = task.title ? decodeHTML(task.title) : '';
          
          const dateEl = document.getElementById('taskEditorDate');
          if (dateEl) dateEl.innerText = task.updated_at ? new Date(task.updated_at.replace(' ', 'T') + 'Z').toLocaleDateString() : new Date().toLocaleDateString();
          
          const starIcon = document.getElementById('taskEditorStarIcon');
          if (starIcon) starIcon.className = task.starred == 1 ? 'bi bi-star-fill text-warning' : 'bi bi-star';

          let items = [];
          try { items = task.items ? JSON.parse(task.items) : []; } catch(e) {}
          window.currentTaskItems = items;
          
          window.renderTaskItems();

          const findPanel = document.getElementById('taskFindReplacePanel');
          if (findPanel) findPanel.classList.remove('active');
          
          const moreMenu = document.getElementById('taskEditorMoreMenu');
          if (moreMenu) moreMenu.classList.remove('active');
          
          const overlay = document.getElementById('taskEditorOverlay');
          if (overlay) overlay.classList.add('active');
          
          if (task.id) {
            lastSyncContentTime = task.updated_at;
            startPresenceSync(task.id, 'task');
          }
        };

        window.renderTaskItems = () => {
          const container = document.getElementById('taskItemsContainer');
          if (!container) return;
          const autoResizeTaskInput = (el) => {
            el.style.height = 'auto';
            el.style.height = (el.scrollHeight) + 'px';
          };

          container.innerHTML = window.currentTaskItems.map((item, idx) => `
            <div class="task-item-row">
              <input type="checkbox" class="task-item-checkbox" data-idx="${idx}" ${item.completed ? 'checked' : ''}>
              <textarea class="task-item-input ${item.completed ? 'completed' : ''}" data-idx="${idx}" placeholder="Task description..." rows="1" style="resize: none; overflow: hidden; padding-top: 4px;">${escapeHTML(item.text)}</textarea>
              <button class="task-item-del" data-idx="${idx}"><i class="bi bi-x-lg"></i></button>
            </div>
          `).join('');

          container.querySelectorAll('.task-item-input').forEach(input => {
            autoResizeTaskInput(input);
            input.addEventListener('input', (e) => {
              autoResizeTaskInput(e.target);
              window.currentTaskItems[e.target.dataset.idx].text = e.target.value;
              if (document.getElementById('taskFindReplacePanel').classList.contains('active')) executeTaskFind();
              clearTimeout(taskSaveTimeout);
              taskSaveTimeout = setTimeout(() => window.saveCurrentTask(false), 300);
            });
            input.addEventListener('keydown', (e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                const idx = parseInt(e.target.dataset.idx);
                window.currentTaskItems.splice(idx + 1, 0, { text: '', completed: false });
                window.renderTaskItems();
                const inputs = document.querySelectorAll('.task-item-input');
                if (inputs.length > idx + 1) inputs[idx + 1].focus();
                window.saveCurrentTask(false);
              } else if (e.key === 'Backspace' && e.target.value === '') {
                e.preventDefault();
                const idx = parseInt(e.target.dataset.idx);
                if (idx > 0) {
                  window.currentTaskItems.splice(idx, 1);
                  window.renderTaskItems();
                  const inputs = document.querySelectorAll('.task-item-input');
                  if (inputs.length > idx - 1) {
                    inputs[idx - 1].focus();
                    // Instantly move the cursor to the end of the previous line
                    const val = inputs[idx - 1].value;
                    inputs[idx - 1].value = '';
                    inputs[idx - 1].value = val;
                  }
                  window.saveCurrentTask(false);
                }
              }
            });
          });

          container.querySelectorAll('.task-item-checkbox').forEach(chk => {
            chk.addEventListener('change', (e) => {
              const idx = e.target.dataset.idx;
              const isChecked = e.target.checked;
              window.currentTaskItems[idx].completed = isChecked;
                
              // ADVANCED DOM RENDERING: Bypass full array re-rendering to prevent UI lag on massive lists
              const row = e.target.closest('.task-item-row');
              if (row) {
                const inputField = row.querySelector('.task-item-input');
                if (inputField) {
                  if (isChecked) inputField.classList.add('completed');
                  else inputField.classList.remove('completed');
                }
              }
              window.saveCurrentTask(false);
            });
          });

          container.querySelectorAll('.task-item-del').forEach(btn => {
            btn.addEventListener('click', (e) => {
              window.currentTaskItems.splice(e.currentTarget.dataset.idx, 1);
              window.renderTaskItems();
              window.saveCurrentTask(false);
            });
          });
        };

        window.saveCurrentTask = async (force = false) => {
          const statusIndicator = document.getElementById('taskSaveStatus');
          if (statusIndicator) statusIndicator.textContent = "Saving...";
          const idInput = document.getElementById('taskEditorId');
          const id = idInput.value;
          const title = document.getElementById('taskEditorTitle').value.trim();
          const category = document.getElementById('taskEditorCategorySelect').value;
          const isStarred = document.getElementById('taskEditorStarIcon').classList.contains('bi-star-fill') ? 1 : 0;
          const items = JSON.stringify(window.currentTaskItems);
          
          if (!title && window.currentTaskItems.length === 0) return;
          
          // CONDITIONAL SAVE: Do not auto-save a brand new task list unless explicitly requested
          if (!id && !force) return;
          
          let projId = null;
          if (currentView.filter && currentView.filter.startsWith('proj_')) {
            projId = currentView.filter.replace('proj_', '');
          }
          const res = await fetchData('?action=save_task', { 
            method: 'POST', body: JSON.stringify({id: id || null, title, items, category, starred: isStarred, project_id: projId}) 
          }, true);

          if (res && res.status === 'success' && res.id && !id) {
            idInput.value = res.id;
          }
          if (statusIndicator && res && res.status === 'success') {
            statusIndicator.textContent = "Saved";
            setTimeout(() => { if (statusIndicator.textContent === "Saved") statusIndicator.textContent = ""; }, 2000);
          }
        };

        document.getElementById('addTaskItemBtn')?.addEventListener('click', () => {
          window.currentTaskItems.push({ text: '', completed: false });
          window.renderTaskItems();
          const inputs = document.querySelectorAll('.task-item-input');
          if (inputs.length > 0) inputs[inputs.length - 1].focus();
        });

        document.getElementById('taskEditorTitle')?.addEventListener('input', () => {
          clearTimeout(taskSaveTimeout);
          taskSaveTimeout = setTimeout(() => window.saveCurrentTask(false), 300);
        });

        document.getElementById('taskEditorCategorySelect')?.addEventListener('change', () => window.saveCurrentTask(false));

        document.getElementById('closeTaskEditorBtn')?.addEventListener('click', async () => {
          if (taskPipWin) { taskPipWin.close(); taskPipWin = null; }
          await window.saveCurrentTask(true);
          stopPresenceSync();
          document.getElementById('taskFindReplacePanel')?.classList.remove('active');
          document.getElementById('taskEditorOverlay').classList.remove('active');
          if (currentView.type === 'get_tasks') loadView(currentView);
        });

        document.getElementById('taskEditorStarBtn')?.addEventListener('click', () => {
          const starIcon = document.getElementById('taskEditorStarIcon');
          starIcon.className = starIcon.classList.contains('bi-star-fill') ? 'bi bi-star' : 'bi bi-star-fill text-warning';
          window.saveCurrentTask(true);
        });

        document.getElementById('taskEditorMoreBtn')?.addEventListener('click', (e) => {
          e.stopPropagation();
          document.getElementById('taskEditorMoreMenu').classList.toggle('active');
        });

        document.getElementById('taskEditorForceSaveBtn')?.addEventListener('click', async () => {
          await window.saveCurrentTask(true);
          showToast('Tasks saved!', 'success');
          document.getElementById('taskEditorMoreMenu').classList.remove('active');
        });

        document.getElementById('taskEditorCopyBtn')?.addEventListener('click', () => {
          document.getElementById('taskEditorMoreMenu').classList.remove('active');
          const text = window.currentTaskItems.map(t => (t.completed ? '[x] ' : '[ ] ') + t.text).join('\n');
          if (navigator.clipboard && window.isSecureContext) {
            navigator.clipboard.writeText(text).then(() => showToast('Copied to clipboard!', 'success'));
          }
        });

        document.getElementById('taskEditorDeleteBtn')?.addEventListener('click', async () => {
          if (taskPipWin) { taskPipWin.close(); taskPipWin = null; }
          document.getElementById('taskEditorMoreMenu').classList.remove('active');
          const id = document.getElementById('taskEditorId').value;
          if (!id) {
            document.getElementById('taskEditorOverlay').classList.remove('active');
            showToast('Discarded unsaved task list.', 'info');
            return;
          }
          if (confirm('Delete this task list?')) {
            await fetchData('?action=delete_task', { method:'POST', body: JSON.stringify({id}) });
            document.getElementById('taskEditorOverlay').classList.remove('active');
            if (currentView.type === 'get_tasks') loadView(currentView);
          }
        });

        document.getElementById('editorContent').addEventListener('input', (e) => {
          clearTimeout(noteSaveTimeout);
          clearTimeout(noteHistoryTimeout);
          updateEditorWordCount();
          if (document.getElementById('findReplacePanel').classList.contains('active')) executeNoteFind();
          noteSaveTimeout = setTimeout(() => saveCurrentEditorNote(false), 300);
          noteHistoryTimeout = setTimeout(() => {
            if (noteTextHistory[noteHistoryIdx] === e.target.value) return;
            noteTextHistory = noteTextHistory.slice(0, noteHistoryIdx + 1);
            noteTextHistory.push(e.target.value);
            
            // ADVANCED MEMORY MGMT: Cap history dynamically to prevent RAM crashes on massive documents
            const maxHistory = e.target.value.length > 200000 ? 5 : 50; 
            if (noteTextHistory.length > maxHistory) noteTextHistory.shift();
            else noteHistoryIdx++;
          }, 600);
        });

        document.getElementById('editorTitle').addEventListener('input', () => {
          clearTimeout(noteSaveTimeout);
          noteSaveTimeout = setTimeout(() => saveCurrentEditorNote(false), 300);
        });
        
        document.getElementById('editorCategorySelect').addEventListener('change', () => saveCurrentEditorNote(false));

        document.getElementById('closeEditorBtn').addEventListener('click', async () => {
          if (notePipWin) { notePipWin.close(); notePipWin = null; }
          await saveCurrentEditorNote(true);
          stopPresenceSync();
          document.getElementById('editorOverlay').classList.remove('active');
          activeEditorNote = null;
          if (currentView.type === 'get_notes') loadView(currentView);
        });

        let blogSaveTimeout = null;
        let blogHistoryTimeout = null;
        let blogTextHistory = [];
        let blogHistoryIdx = -1;
        let isBlogMarkdownPreview = false;

        window.openBlogEditor = (blog) => {
          const isOwner = !blog.id || blog.user_id == (currentUser ? currentUser.id : null);
          
