          async openArtistDetail(artistName) {
            this.activeArtistDetailName = artistName;

            // Cache current state to survive page reloads
            localStorage.setItem("rg_active_artist", artistName);
            localStorage.setItem("rg_active_tab", "artistDetail");

            // 2. Determine if the artist is a registered user to fetch overall stats
            let sampleSong = { id: 0 };

            const uStmt = await fetchData(
              `?action=get_view_data&type=artist&name=${encodeURIComponent(artistName)}`,
              {},
              true
            );
            let artistUserId = null;
            let isUser = false;

            if (uStmt && uStmt.details) {
              if (uStmt.details.is_user) {
                artistUserId = uStmt.details.user_id;
                isUser = true;
              }
              if (uStmt.songs && uStmt.songs.length > 0) {
                sampleSong = uStmt.songs[0];
              }
            }

            let totalScore = 0;
            let artistScores = [];
            let displayRank = "F";
            let rankColor = "#555";

            const activePlayerId = typeof currentUser !== "undefined" && currentUser ? currentUser.id : null;

            if (isUser && artistUserId) {
              // Fetch the artist's personal overall play history of ALL songs they played
              artistScores =
                (await fetchData(`?action=get_user_rhythm_scores&target_user_id=${artistUserId}&page=1`, {}, true)) ||
                [];

              let totalPerfect = 0,
                totalGreat = 0,
                totalGood = 0,
                totalBad = 0,
                totalMiss = 0;
              artistScores.forEach((s) => {
                totalScore += parseInt(s.score || 0);
                totalPerfect += parseInt(s.perfect || 0);
                totalGreat += parseInt(s.great || 0);
                totalGood += parseInt(s.good || 0);
                totalBad += parseInt(s.bad || 0);
                totalMiss += parseInt(s.miss || 0);
              });

              const rankInfo = this.getRankFromStats(totalPerfect, totalGreat, totalGood, totalBad, totalMiss);
              displayRank = artistScores.length > 0 ? rankInfo.rank : "F";
              rankColor = artistScores.length > 0 ? rankInfo.color : "#555";
            }

            // Render Header with statistical metrics & dynamic Share Button
            const headerContainer = document.getElementById("rg-artist-detail-header");
            if (isUser && artistUserId) {
              headerContainer.innerHTML = `
                <img src="?action=get_image&id=${sampleSong.id}&size=small" onerror="this.onerror=null; this.src='?action=get_app_icon';" class="rounded-circle shadow-lg border border-secondary" style="width: 72px; height: 72px; object-fit: cover; flex-shrink: 0;">
                <div class="d-flex flex-column justify-content-center flex-grow-1" style="min-width: 0; text-align: left;">
                  <h4 class="text-white fw-bold mb-1 text-truncate" style="font-size: 1.4rem;">${escapeHTML(artistName)}</h4>
                  <div class="d-flex flex-column align-items-start text-secondary small gap-1" style="font-weight: 500;">
                    <div class="d-flex align-items-center gap-3 flex-wrap">
                      <span>Played: <b class="text-white">${artistScores.length}</b> times</span>
                      <span>Score: <b class="text-white">${totalScore.toLocaleString()}</b></span>
                    </div>
                    <button class="btn btn-outline-light btn-sm rounded-pill px-3 fw-bold border-secondary text-secondary mt-1" id="rg-btn-share-artist" style="font-size: 0.7rem; height: 24px; padding: 0 10px; display: inline-flex; align-items: center; gap: 4px; transition: 0.2s;"><i class="bi bi-share-fill"></i> Share</button>
                  </div>
                </div>
                <div class="d-flex flex-column align-items-end flex-shrink-0">
                  <span class="badge d-flex align-items-center justify-content-center" style="font-family: 'Arial Black', sans-serif; font-size: 1.1rem; font-weight: 900; background-color: ${rankColor}; color: #000; height: 42px; min-width: 48px; border-radius: 8px; box-shadow: 0 4px 12px ${rankColor}40;" title="AVERAGE RANK">${displayRank}</span>
                </div>
              `;

              document.getElementById("rg-btn-share-artist").onclick = (e) => {
                e.stopPropagation();
                showShareModal("game", "", artistName, artistUserId, artistName);
              };
            } else {
              headerContainer.innerHTML = `
                <img src="?action=get_image&id=${sampleSong.id}&size=small" onerror="this.onerror=null; this.src='?action=get_app_icon';" class="rounded-circle shadow-lg border border-secondary" style="width: 72px; height: 72px; object-fit: cover; flex-shrink: 0;">
                <div class="d-flex flex-column justify-content-center flex-grow-1" style="min-width: 0; text-align: left;">
                  <h4 class="text-white fw-bold mb-1 text-truncate" style="font-size: 1.4rem;">${escapeHTML(artistName)}</h4>
                  <div class="d-flex flex-column align-items-start text-secondary small gap-1" style="font-weight: 500;">
                    <span class="badge bg-dark border border-secondary text-secondary">Guest Artist</span>
                    <button class="btn btn-outline-light btn-sm rounded-pill px-3 fw-bold border-secondary text-secondary mt-1" id="rg-btn-share-artist" style="font-size: 0.7rem; height: 24px; padding: 0 10px; display: inline-flex; align-items: center; gap: 4px; transition: 0.2s;"><i class="bi bi-share-fill"></i> Share</button>
                  </div>
                </div>
              `;

              document.getElementById("rg-btn-share-artist").onclick = (e) => {
                e.stopPropagation();
                showShareModal("game", "", artistName, "", artistName); // No User ID for guest artists
              };
            }

            // Render History list for this artist's personal plays
            const histContainer = document.getElementById("rg-list-artist-history");
            if (!isUser) {
              histContainer.innerHTML = `<div class="text-center p-5 text-secondary"><i class="bi bi-person-x-fill d-block fs-1 mb-2"></i>Only registered artist user accounts have an active play history.</div>`;
            } else if (artistScores.length === 0) {
              histContainer.innerHTML = `<div class="text-center p-5 text-secondary"><i class="bi bi-controller d-block fs-1 mb-2"></i>This user hasn't played any tracks yet.</div>`;
            } else {
              const diffColors = {
                easy: "#22d3ee",
                medium: "#34d399",
                hard: "#fb923c",
                expert: "#f43f5e",
                master: "#a78bfa",
                demon: "#7f1d1d",
              };
              const diffLabels = {
                easy: "EZ",
                medium: "ND",
                hard: "HD",
                expert: "EX",
                master: "MS",
                demon: "DM",
              };

              histContainer.innerHTML = artistScores
                .map((s) => {
                  const jud = this.getRankFromStats(s.perfect, s.great, s.good, s.bad, s.miss);
                  const diffColor = diffColors[s.difficulty] || "#aaa";
                  const diffLabel = diffLabels[s.difficulty] || "UN";
                  const lvlText = s.level ? `Lv.${s.level}` : "Lv.--";
                  const coverSvg = getSvgPlaceholder(s.title);
                  const playedAt = s.played_at
                    ? new Date(s.played_at.replace(" ", "T") + "Z").toLocaleDateString()
                    : "Unknown";
                  const totalHits =
                    parseInt(s.perfect || 0) +
                    parseInt(s.great || 0) +
                    parseInt(s.good || 0) +
                    parseInt(s.bad || 0) +
                    parseInt(s.miss || 0);
                  const suspicious =
                    (jud.acc === "100.00" && totalHits > 50) || (s.max_combo > 500 && s.miss == 0)
                      ? '<span class="badge bg-danger ms-2" style="font-size: 0.6rem;" title="Perfect Play / Bot Suspected"><i class="bi bi-exclamation-triangle-fill"></i> SUS</span>'
                      : "";

                  return `
                  <div class="rg-list-item" style="background: linear-gradient(135deg, rgba(255,255,255,0.02) 0%, rgba(255,255,255,0.01) 100%); border: 1px solid rgba(255,255,255,0.05); border-left: 4px solid ${diffColor}; border-radius: 12px; padding: 12px 16px; display: flex; flex-direction: column; gap: 8px; cursor: default;">
                    <div class="d-flex align-items-center justify-content-between gap-3" style="min-width: 0; width: 100%;">
                      <div class="d-flex align-items-center gap-3" style="min-width: 0; flex: 1;">
                        <img src="?action=get_image&id=${s.song_id}&v=${s.last_modified}" onerror="this.onerror=null; this.src='${coverSvg}'" style="width: 44px; height: 44px; border-radius: 8px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.4); flex-shrink: 0;">
                        <div class="text-truncate text-start" style="min-width: 0; flex: 1;">
                          <div class="text-white fw-bold text-truncate" style="font-size: 0.95rem;">${escapeHTML(s.title)}</div>
                          <div class="text-secondary small mt-1" style="font-size: 0.75rem;">by ${escapeHTML(s.artist)}</div>
                        </div>
                      </div>
                      <div class="d-flex align-items-center gap-1" style="flex-shrink: 0;">
                        ${suspicious}
                        <span class="badge d-flex align-items-center justify-content-center" style="font-family: monospace; font-size: 0.65rem; font-weight: 800; background-color: ${diffColor}; color: ${s.difficulty === "demon" ? "#fff" : "#000"}; padding: 2px 6px; border-radius: 4px;">${diffLabel} ${lvlText}</span>
                        <span class="badge d-flex align-items-center justify-content-center" style="font-family: monospace; font-size: 0.65rem; font-weight: 800; background-color: ${jud.color}; color: #000;">${jud.rank}</span>
                      </div>
                    </div>
                    
                    <div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 6px; width: 100%; border-top: 1px solid rgba(255,255,255,0.03); padding-top: 8px; margin-top: 4px; text-align: center;">
                      <div style="grid-column: span 2; display: flex; justify-content: space-between; align-items: center; background-color: rgba(255,255,255,0.01); border: 1px solid rgba(255,255,255,0.02); padding: 4px 10px; border-radius: 6px; text-align: left;">
                        <span style="font-size: 0.65rem; font-weight: 700; color: #888; text-transform: uppercase;">Score</span>
                        <span style="font-size: 0.9rem; font-weight: 900; font-family: monospace; color: var(--rg-primary);">${parseInt(s.score).toLocaleString()}</span>
                      </div>
                      <div style="grid-column: span 2; display: flex; justify-content: space-between; align-items: center; background-color: rgba(255,255,255,0.01); border: 1px solid rgba(255,255,255,0.02); padding: 4px 10px; border-radius: 6px; text-align: left;">
                        <span style="font-size: 0.65rem; font-weight: 700; color: #888; text-transform: uppercase;">Combo</span>
                        <span style="font-size: 0.9rem; font-weight: 900; font-family: monospace; color: #fff;">${s.max_combo}x</span>
                      </div>
                    </div>
                  </div>
                `;
                })
                .join("");
            }

            this.activeArtistDetailId = artistUserId;

            // Render Playlists list for this artist
            const playContainer = document.getElementById("rg-list-artist-playlists");
            if (playContainer) {
              if (uStmt && uStmt.details && uStmt.details.playlists && uStmt.details.playlists.length > 0) {
                playContainer.innerHTML = uStmt.details.playlists.slice(0, 25).map(p => `
                  <div class="rg-list-item rg-artist-playlist-item" data-id="${p.public_id}" data-name="${escapeHTML(p.name).replace(/"/g, '&quot;')}" style="background: linear-gradient(135deg, rgba(255,255,255,0.02) 0%, rgba(255,255,255,0.01) 100%); border: 1px solid rgba(255,255,255,0.05); border-left: 4px solid var(--rg-primary); border-radius: 12px; padding: 12px 16px; display: flex; align-items: center; gap: 12px; cursor: pointer; transition: transform 0.2s;" onmouseover="this.style.transform='scale(1.02)'" onmouseout="this.style.transform='scale(1)'">
                    <img src="?action=get_image&id=${p.image_id || 0}&v=${p.image_v || 0}&size=small" style="width: 50px; height: 50px; border-radius: 8px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.4); flex-shrink: 0;">
                    <div class="text-truncate flex-grow-1" style="min-width: 0;">
                      <div class="text-white fw-bold text-truncate" style="font-size: 1rem;">${p.is_private == 1 ? '<i class="bi bi-lock-fill text-warning me-1"></i>' : ''}${escapeHTML(p.name)}</div>
                      <div class="text-secondary small mt-1" style="font-size: 0.75rem;"><i class="bi bi-music-note-list text-danger"></i> ${p.song_count} Tracks</div>
                    </div>
                    <i class="bi bi-chevron-right text-secondary fs-5" style="flex-shrink: 0;"></i>
                  </div>
                `).join("");

                // Securely bind click events natively
                playContainer.querySelectorAll('.rg-artist-playlist-item').forEach(item => {
                  item.addEventListener('click', () => {
                    this.loadRgPlaylistSongs(item.dataset.id, item.dataset.name);
                  });
                });
              } else {
                playContainer.innerHTML = `<div class="text-center p-5 text-secondary"><i class="bi bi-music-note-list d-block fs-1 mb-2"></i>No playlists found.</div>`;
              }
            }

            // Render Favorites list for this artist
            if (isUser && artistUserId) {
              const favsSearchInput = document.getElementById("rg-search-artist-favs");
              if (favsSearchInput) favsSearchInput.value = "";
              this.loadArtistFavorites(artistUserId);
              this.loadArtistFollowing(artistUserId);
            } else {
              const favsContainer = document.getElementById("rg-list-artist-favs");
              if (favsContainer) {
                favsContainer.innerHTML = `<div class="text-center p-5 text-secondary"><i class="bi bi-heart-break-fill d-block fs-1 mb-2"></i>Only registered users can have favorites.</div>`;
              }
              const folContainer = document.getElementById("rg-list-artist-following");
              if (folContainer) {
                folContainer.innerHTML = `<div class="text-center p-5 text-secondary"><i class="bi bi-person-x-fill d-block fs-1 mb-2"></i>Only registered users can follow others.</div>`;
              }
            }

            document.getElementById("rg-search-artist-songs").value = "";

            // Hide ALL active tabs first to prevent vertical overlapping conflicts
            Object.values(this.tabs).forEach((t) => {
              if (t) t.classList.add("rg-hidden");
            });

            // Show only the artist detail view
            if (this.tabs.artistDetail) {
              this.tabs.artistDetail.classList.remove("rg-hidden");
            }

            // Sync bottom navigation highlight conditionally (Profile vs Artists)
            const isMyOwnProfile =
              typeof currentUser !== "undefined" &&
              currentUser &&
              artistName.toLowerCase() === currentUser.artist.toLowerCase();
            document.querySelectorAll(".rg-nav-item").forEach((n) => {
              if (isMyOwnProfile) {
                n.classList.toggle("active", n.id === "rg-nav-my-profile");
              } else {
                n.classList.toggle("active", n.getAttribute("data-target") === "artists");
              }
            });

            // Default to correct sub-tab based on device size
            if (window.innerWidth >= 992) {
              const artTabHistory = document.getElementById("rg-art-tab-history");
              if (artTabHistory) artTabHistory.click();
            } else {
              const artTabTracks = document.getElementById("rg-art-tab-tracks");
              if (artTabTracks) artTabTracks.click();
            }

            this.loadArtistSongs(artistName);
          }

          openArtistChoiceDialog(artistsList) {
            const body = document.getElementById("artists-modal-body");
            if (!body) return;

            const modalEl = document.getElementById("artists-modal");
            const modal = bootstrap.Modal.getOrCreateInstance(modalEl);

            const modalTitle = modalEl.querySelector(".modal-title");
            if (modalTitle) modalTitle.textContent = "Artists";

            body.innerHTML = `
              <div class="list-group list-group-flush rounded">
                ${artistsList
                  .map(
                    (a) => `
                  <button type="button" class="list-group-item list-group-item-action bg-transparent text-white border-secondary rhythm-artist-modal-item py-3 text-start px-4" style="border-left: none; border-right: none;" data-artist="${encodeURIComponent(a)}">
                    ${a}
                  </button>
                `
                  )
                  .join("")}
              </div>
            `;

            // Re-bind clicks directly to open the selected artist profile
            body.querySelectorAll(".rhythm-artist-modal-item").forEach((btn) => {
              btn.addEventListener("click", () => {
                modal.hide();
                this.openArtistDetail(decodeURIComponent(btn.dataset.artist));
              });
            });

            modal.show();
          }

          async endGame(failed = false) {
            this.isPlaying = false;
            if (this.audioPlayback) this.audioPlayback.pause();

            if (this.autoplayWakeLocked) {
              if (typeof noSleep !== "undefined") noSleep.disable();
              this.autoplayWakeLocked = false;
            }

            this.switchScreen("result");

            // Inject dynamic blurred cover background to results screen
            const resultScreen = document.getElementById("rg-screen-result");
            if (resultScreen) {
              resultScreen.style.backgroundColor = "transparent";
              let resultBg = document.getElementById("rg-result-bg");
              if (!resultBg) {
                resultBg = document.createElement("div");
                resultBg.id = "rg-result-bg";
                resultBg.style.cssText = "position:absolute; top:-40px; left:-40px; right:-40px; bottom:-40px; background-size:cover; background-position:center; filter:blur(40px) brightness(0.35); z-index:0; pointer-events:none; transition: background-image 0.5s ease;";
                resultScreen.insertBefore(resultBg, resultScreen.firstChild);
              }
              if (this.selectedSong) {
                resultBg.style.backgroundImage = `url('?action=get_image&id=${this.selectedSong.id}&v=${this.selectedSong.last_modified || 0}')`;
              }
            }

            const resultWarningId = "rg-offline-result-warning";
            let resultWarningEl = document.getElementById(resultWarningId);
            if (resultWarningEl) resultWarningEl.remove();

            if (!navigator.onLine && !failed && !this.isAutoplay) {
              const resultButtonContainer = document.getElementById("rg-btn-result-share").parentNode;
              resultButtonContainer.insertAdjacentHTML("beforebegin", `
                <div id="${resultWarningId}" class="alert border-danger text-danger small mb-3 text-center rounded-3 w-100" style="background: rgba(255,59,48,0.1); line-height: 1.4; font-weight: bold; border-style: dashed;">
                  <i class="bi bi-shield-slash-fill me-2"></i>Score Not Saved: Played while offline. This score will NOT be synced to the database.
                </div>
              `);
            }

            const titleEl = document.querySelector("#rg-screen-result h2");
            if (titleEl) {
              titleEl.textContent = failed ? "STAGE FAILED" : "STAGE CLEARED";
              titleEl.style.color = failed ? "#ff5f56" : "var(--rg-primary)";
            }
            const shareBtn = document.getElementById("rg-btn-result-share");
            if (shareBtn) {
              shareBtn.style.display = failed ? "none" : "block";
            }

            let rank = "F";
            let rankColor = "#7f1d1d";
            const accVal = parseFloat(this.accuracy);

            if (accVal >= 98.0) {
              rank = "SS";
              rankColor = "#ff0055";
            } else if (accVal >= 95.0) {
              rank = "S";
              rankColor = "#ffbd2e";
            } else if (accVal >= 90.0) {
              rank = "A";
              rankColor = "#a78bfa";
            } else if (accVal >= 80.0) {
              rank = "B";
              rankColor = "#60a5fa";
            } else if (accVal >= 70.0) {
              rank = "C";
              rankColor = "#34d399";
            } else if (accVal >= 60.0) {
              rank = "D";
              rankColor = "#fb923c";
            } else if (accVal >= 50.0) {
              rank = "E";
              rankColor = "#9ca3af";
            }

            if (failed) {
              rank = "F";
              rankColor = "#ff5f56";
            }

            const rankEl = document.getElementById("rg-res-rank");
            if (rankEl) {
              rankEl.textContent = rank;
              rankEl.style.color = rankColor;
            }

            const accEl = document.getElementById("rg-res-acc");
            if (accEl) {
              accEl.textContent = this.accuracy + "%";
            }

            let maxScore = 0;
            this.chartNotes.forEach(n => {
               if (n.isLong) {
                  maxScore += n.hitEndSwipe ? 350 : 110; 
               } else {
                  maxScore += n.isSwipe ? 150 : 100;
               }
            });
            if (maxScore === 0) maxScore = 1;
            const pct = Math.min(100, Math.max(0, (this.curScore / maxScore) * 100));
            const scoreBar = document.getElementById("rg-res-score-bar");
            if (scoreBar) {
              scoreBar.style.width = "0%";
              setTimeout(() => {
                scoreBar.style.width = pct + "%";
              }, 100);
            }

            document.getElementById("rg-res-score").textContent = String(this.curScore).padStart(9, "0");
            document.getElementById("rg-res-max-combo").textContent = this.maxCombo;
            document.getElementById("rg-res-perfect").textContent = this.stats.perfect;
            document.getElementById("rg-res-great").textContent = this.stats.great;
            document.getElementById("rg-res-good").textContent = this.stats.good;
            document.getElementById("rg-res-bad").textContent = this.stats.bad;
            document.getElementById("rg-res-miss").textContent = this.stats.miss;

            const resTitle = document.querySelector("#rg-screen-result h2");
            if (this.isAutoplay && resTitle) {
              resTitle.textContent = "AUTOPLAY (UNRANKED)";
              resTitle.style.color = "#00bcd4";
            }

            if (!failed && this.curScore > 0 && this.selectedSong && !this.isAutoplay) {
              await fetchData("?action=save_rhythm_score", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  song_id: this.selectedSong.id,
                  score: this.curScore,
                  max_combo: this.maxCombo,
                  perfect: this.stats.perfect,
                  great: this.stats.great,
                  good: this.stats.good,
                  bad: this.stats.bad,
                  miss: this.stats.miss,
                  difficulty: this.selectedDiff,
                  hit_deltas: this.hitDeltas,
                }),
              });
              this.loadLeaderboard();
            }
          }
        }
        
        // --- Photo Editor Engine ---
        class EditorEngine {
          constructor() {
            this.layers = [];
            this.activeLayer = null;
            this.bgColor = '#0A0A0A';
            this.canvasW = 800;
            this.canvasH = 800;
            this.isDragging = false;
            this.dragType = null;
            this.dragStart = { x: 0, y: 0 };
            this.layerStart = {};
            this.history = [];
            this.historyIndex = -1;
            this.isDrawMode = false;
            this.currentPath = null;
            this.brushColor = '#FF0000';
            this.brushSize = 5;
            this.loadState();
          }

          initDOM() {
            this.canvas = document.getElementById('pe-main-canvas');
            if (!this.canvas) return; // Prevent crashes if not mounted
            this.ctx = this.canvas.getContext('2d');
            this.overlay = document.getElementById('pe-overlay-canvas');
            this.overlayCtx = this.overlay.getContext('2d');
            this.workspace = document.getElementById('pe-workspace');
            this.textEditor = document.getElementById('pe-text-editor');
            this.panel = document.getElementById('pe-properties-panel');
            this.panelContent = document.getElementById('pe-panel-content');
            this.propBtn = document.getElementById('pe-btn-properties');

            this.resizeCanvas();
            window.removeEventListener('resize', this._resizeHandler);
            this._resizeHandler = () => this.resizeCanvas();
            window.addEventListener('resize', this._resizeHandler);

            document.getElementById('pe-upload-img').addEventListener('change', (e) => this.handleImageUpload(e));
            document.getElementById('pe-btn-add-text').addEventListener('click', () => { this.isDrawMode = false; this.updateDrawBtn(); this.addText(); });
            document.getElementById('pe-btn-add-shape').addEventListener('click', () => { this.isDrawMode = false; this.updateDrawBtn(); this.addShape(); });
            
            const btnDraw = document.getElementById('pe-btn-draw');
            if (btnDraw) btnDraw.addEventListener('click', () => {
              this.isDrawMode = !this.isDrawMode;
              this.activeLayer = null;
              this.closePanel();
              this.updateDrawBtn();
              this.render();
            });
            
            const btnUndo = document.getElementById('pe-btn-undo');
            if (btnUndo) btnUndo.addEventListener('click', () => this.undo());
            
            const btnRedo = document.getElementById('pe-btn-redo');
            if (btnRedo) btnRedo.addEventListener('click', () => this.redo());

            const btnReset = document.getElementById('pe-btn-reset');
            if (btnReset) btnReset.addEventListener('click', () => {
              if (confirm('Are you sure you want to reset the canvas? All unsaved progress will be lost.')) {
                this.layers = [];
                this.activeLayer = null;
                this.bgColor = '#0A0A0A';
                this.canvasW = 800;
                this.canvasH = 800;
                this.history = [];
                this.historyIndex = -1;
                this.resizeCanvas();
                this.saveState();
                this.closePanel();
              }
            });
            
            this.propBtn.addEventListener('click', () => {
              this.isDrawMode = false;
              this.updateDrawBtn();
              if (this.panel.classList.contains('open')) {
                this.closePanel();
              } else {
                if (this.activeLayer) {
                  this.buildProperties();
                } else {
                  this.showCanvasSettings();
                }
                this.panel.classList.add('open');
                this.propBtn.classList.add('active');
                setTimeout(() => this.resizeCanvas(), 50); // FIX: Recalculate canvas after panel expands
              }
            });
            
            document.getElementById('pe-btn-close-panel').addEventListener('click', () => this.closePanel());
            
            // FIXED: Bind event listeners to both the desktop and mobile buttons
            const dExport = document.getElementById('pe-btn-export-desktop');
            const mExport = document.getElementById('pe-btn-export-mobile');
            if (dExport) dExport.addEventListener('click', () => this.exportImage());
            if (mExport) mExport.addEventListener('click', () => this.exportImage());

            this.bindEvents();
            this.render();
          }

          updateDrawBtn() {
            const btn = document.getElementById('pe-btn-draw');
            if (btn) btn.classList.toggle('active', this.isDrawMode);
          }

          undo() {
            if (this.historyIndex > 0) {
              this.historyIndex--;
              this.restoreFromState(this.history[this.historyIndex]);
            }
          }

          redo() {
            if (this.historyIndex < this.history.length - 1) {
              this.historyIndex++;
              this.restoreFromState(this.history[this.historyIndex]);
            }
          }

          restoreFromState(stateStr) {
            try {
              const state = JSON.parse(stateStr);
              this.bgColor = state.bgColor;
              this.canvasW = state.canvasW;
              this.canvasH = state.canvasH;
              this.layers = [];
              let pendingImages = 0;
              state.layers.forEach(l => {
                if (l.type === 'image' && l.imgSrc) {
                  pendingImages++;
                  const img = new Image();
                  img.onload = () => {
                    l.img = img;
                    this.layers.push(l);
                    pendingImages--;
                    if (pendingImages === 0 && this.ctx) {
                      this.layers.sort((a,b) => a.id - b.id);
                      this.activeLayer = null;
                      this.render();
                    }
                  };
                  img.onerror = () => pendingImages--;
                  img.src = l.imgSrc;
                } else {
                  this.layers.push(l);
                }
              });
              if (pendingImages === 0) {
                this.activeLayer = null;
                this.render();
              }
            } catch (e) {}
          }

          saveState() {
            let safeLayers = this.layers.map(l => {
              const clone = { ...l };
              if (l.type === 'image' && l.img) {
                // Downscale massively large images for localStorage safety
                if (l.img.src.length > 2000000) {
                   const tmpCanvas = document.createElement('canvas');
                   const tCtx = tmpCanvas.getContext('2d');
                   tmpCanvas.width = l.img.width > 1200 ? 1200 : l.img.width;
                   tmpCanvas.height = l.img.height * (tmpCanvas.width / l.img.width);
                   tCtx.drawImage(l.img, 0, 0, tmpCanvas.width, tmpCanvas.height);
                   clone.imgSrc = tmpCanvas.toDataURL('image/jpeg', 0.8);
                } else {
                   clone.imgSrc = l.img.src;
                }
              }
              delete clone.img;
              return clone;
            });
            const state = { bgColor: this.bgColor, canvasW: this.canvasW, canvasH: this.canvasH, layers: safeLayers };
            const stateStr = JSON.stringify(state);
            
            // Push to history array for Undo/Redo
            if (this.historyIndex === -1 || this.history[this.historyIndex] !== stateStr) {
              this.history = this.history.slice(0, this.historyIndex + 1);
              this.history.push(stateStr);
              if (this.history.length > 20) this.history.shift(); // Max 20 states
              else this.historyIndex++;
            }
            
            try {
              localStorage.setItem('phpMusic_photoEditorState', stateStr);
            } catch (e) {
              console.warn('Could not save photo editor state (Quota exceeded).');
            }
          }

          loadState() {
            try {
              const saved = localStorage.getItem('phpMusic_photoEditorState');
              if (saved) {
                this.history.push(saved);
                this.historyIndex = 0;
                const state = JSON.parse(saved);
                this.bgColor = state.bgColor || '#0A0A0A';
                this.canvasW = state.canvasW || 800;
                this.canvasH = state.canvasH || 800;
                this.layers = [];
                
                let pendingImages = 0;
                state.layers.forEach(l => {
                  if (l.type === 'image' && l.imgSrc) {
                    pendingImages++;
                    const img = new Image();
                    img.onload = () => {
                      l.img = img;
                      this.layers.push(l);
                      pendingImages--;
                      if (pendingImages === 0 && this.ctx) {
                        this.layers.sort((a,b) => a.id - b.id);
                        this.render();
                      }
                    };
                    img.onerror = () => pendingImages--;
                    img.src = l.imgSrc;
                  } else {
                    this.layers.push(l);
                  }
                });
              }
            } catch (e) { console.warn('Failed to load photo editor state', e); }
          }

          resizeCanvas() {
            if (!this.workspace) return;
            // FIX: Prevent negative or 0 dimension calculations causing CSS collapse
            const maxWidth = Math.max(10, this.workspace.clientWidth - 40);
            const maxHeight = Math.max(10, this.workspace.clientHeight - 40);
            const ratio = Math.min(maxWidth / this.canvasW, maxHeight / this.canvasH);
            const finalW = Math.max(10, this.canvasW * ratio);
            const finalH = Math.max(10, this.canvasH * ratio);
            
            this.canvas.width = this.canvasW;
            this.canvas.height = this.canvasH;
            this.canvas.style.width = `${finalW}px`;
            this.canvas.style.height = `${finalH}px`;
            
            this.overlay.width = this.canvasW;
            this.overlay.height = this.canvasH;
            this.overlay.style.width = `${finalW}px`;
            this.overlay.style.height = `${finalH}px`;

            this.render();
          }

          bindEvents() {
            const ov = this.overlay;
            ov.addEventListener('pointerdown', (e) => this.onPointerDown(e));
            window.addEventListener('pointermove', (e) => this.onPointerMove(e));
            window.addEventListener('pointerup', (e) => this.onPointerUp(e));

            let lastTap = 0;
            ov.addEventListener('pointerdown', (e) => {
              const now = Date.now();
              if (now - lastTap < 300) this.onDoubleClick(e);
              lastTap = now;
            });

            this.textEditor.addEventListener('blur', () => this.commitTextEdit());
            this.textEditor.addEventListener('keydown', (e) => {
              if (e.key === 'Enter' && !e.shiftKey) { 
                e.preventDefault(); 
                this.commitTextEdit(); 
              }
            });
          }

          getCoords(e) {
            const rect = this.overlay.getBoundingClientRect();
            const scaleX = this.canvasW / rect.width;
            const scaleY = this.canvasH / rect.height;
            return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
          }

          hitTest(x, y) {
            if (this.activeLayer) {
              const handle = this.hitTestHandles(x, y, this.activeLayer);
              if (handle) return { layer: this.activeLayer, type: handle };
            }
            for (let i = this.layers.length - 1; i >= 0; i--) {
              const l = this.layers[i];
              const cx = l.x + l.w / 2;
              const cy = l.y + l.h / 2;
              const dx = x - cx;
              const dy = y - cy;
              const rad = -l.rotation * Math.PI / 180;
              const rx = dx * Math.cos(rad) - dy * Math.sin(rad);
              const ry = dx * Math.sin(rad) + dy * Math.cos(rad);

              if (rx >= -l.w/2 && rx <= l.w/2 && ry >= -l.h/2 && ry <= l.h/2) {
                return { layer: l, type: 'move' };
              }
            }
            return null;
          }

          hitTestHandles(x, y, l) {
            const hs = 30;
            const cx = l.x + l.w / 2;
            const cy = l.y + l.h / 2;
            const dx = x - cx;
            const dy = y - cy;
            const rad = -l.rotation * Math.PI / 180;
            const rx = dx * Math.cos(rad) - dy * Math.sin(rad);
            const ry = dx * Math.sin(rad) + dy * Math.cos(rad);

            if (Math.abs(rx - l.w/2) < hs && Math.abs(ry - l.h/2) < hs) return 'resize';
            if (Math.abs(rx) < hs && Math.abs(ry + l.h/2 + 40) < hs) return 'rotate';
            return null;
          }

          onPointerDown(e) {
            if (e.target === this.textEditor) return;
            const pos = this.getCoords(e);
            
            if (this.isDrawMode) {
              this.isDragging = true;
              this.currentPath = {
                id: Date.now(), type: 'path', x: 0, y: 0, w: this.canvasW, h: this.canvasH,
                rotation: 0, opacity: 1, flipX: false, flipY: false,
                color: this.brushColor, size: this.brushSize,
                points: [{ x: pos.x, y: pos.y }]
              };
              return;
            }

            const hit = this.hitTest(pos.x, pos.y);

            if (hit) {
              this.activeLayer = hit.layer;
              this.isDragging = true;
              this.dragType = hit.type;
              this.dragStart = pos;
              this.layerStart = { x: hit.layer.x, y: hit.layer.y, w: hit.layer.w, h: hit.layer.h, r: hit.layer.rotation };
              if (this.panel.classList.contains('open')) this.buildProperties();
            } else {
              this.activeLayer = null;
              if (this.panel.classList.contains('open')) this.showCanvasSettings();
            }
            this.render();
          }

          onPointerMove(e) {
            if (!this.isDragging) return;
            const pos = this.getCoords(e);
            
            if (this.isDrawMode && this.currentPath) {
              this.currentPath.points.push({ x: pos.x, y: pos.y });
              
              // Draw the active stroke overlay for smooth realtime preview without triggering full canvas re-render
              this.overlayCtx.clearRect(0, 0, this.canvasW, this.canvasH);
              this.overlayCtx.strokeStyle = this.currentPath.color;
              this.overlayCtx.lineWidth = this.currentPath.size;
              this.overlayCtx.lineCap = 'round';
              this.overlayCtx.lineJoin = 'round';
              this.overlayCtx.beginPath();
              this.currentPath.points.forEach((pt, i) => {
                if (i === 0) this.overlayCtx.moveTo(pt.x, pt.y);
                else this.overlayCtx.lineTo(pt.x, pt.y);
              });
              this.overlayCtx.stroke();
              return;
            }

            if (!this.activeLayer) return;
            const dx = pos.x - this.dragStart.x;
            const dy = pos.y - this.dragStart.y;
            const l = this.activeLayer;

            if (this.dragType === 'move') {
              l.x = this.layerStart.x + dx;
              l.y = this.layerStart.y + dy;
            } else if (this.dragType === 'resize') {
              const rad = l.rotation * Math.PI / 180;
              const rdx = dx * Math.cos(-rad) - dy * Math.sin(-rad);
              const rdy = dx * Math.sin(-rad) + dy * Math.cos(-rad);
              l.w = Math.max(20, this.layerStart.w + rdx);
              l.h = Math.max(20, this.layerStart.h + rdy);
            } else if (this.dragType === 'rotate') {
              const cx = l.x + l.w / 2;
              const cy = l.y + l.h / 2;
              const angle = Math.atan2(pos.y - cy, pos.x - cx) + Math.PI / 2;
              l.rotation = angle * 180 / Math.PI;
            }
            if (this.panel.classList.contains('open')) this.updateInputsIfOpen();
            this.render();
          }

          onPointerUp(e) {
            if (this.isDragging) {
              this.isDragging = false;
              
              if (this.isDrawMode && this.currentPath) {
                if (this.currentPath.points.length > 0) {
                  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
                  this.currentPath.points.forEach(p => {
                    if (p.x < minX) minX = p.x; if (p.y < minY) minY = p.y;
                    if (p.x > maxX) maxX = p.x; if (p.y > maxY) maxY = p.y;
                  });
                  
                  // Adjust points relative to layer center
                  const cx = (minX + maxX) / 2;
                  const cy = (minY + maxY) / 2;
                  this.currentPath.points.forEach(p => { p.x -= cx; p.y -= cy; });
                  
                  this.currentPath.x = cx - (maxX - minX) / 2;
                  this.currentPath.y = cy - (maxY - minY) / 2;
                  this.currentPath.w = Math.max(10, maxX - minX);
                  this.currentPath.h = Math.max(10, maxY - minY);
                  
                  this.layers.push(this.currentPath);
                }
                this.currentPath = null;
                this.overlayCtx.clearRect(0, 0, this.canvasW, this.canvasH);
                this.render();
              }
              
              this.saveState();
            }
          }

          onDoubleClick(e) {
            if (!this.activeLayer || this.activeLayer.type !== 'text') return;
            const l = this.activeLayer;
            const rect = this.overlay.getBoundingClientRect();
            const scaleX = rect.width / this.canvasW;
            const scaleY = rect.height / this.canvasH;
            
            this.textEditor.style.display = 'block';
            this.textEditor.value = l.text;
            
            // Recalculate formatting immediately to ensure sizing is perfect before extracting
            this.render();

            // Canva-style: Lock the physical width to match bounding box and enforce word-wrap
            this.textEditor.style.width = (l.w * scaleX) + 'px';
            this.textEditor.style.height = (l.h * scaleY) + 'px';
            this.textEditor.style.whiteSpace = 'pre-wrap';
            this.textEditor.style.wordBreak = 'break-word';
            this.textEditor.style.overflow = 'hidden';
            
            // Use .oninput to prevent duplicate listeners attaching on multiple clicks
            this.textEditor.oninput = () => {
              this.textEditor.style.height = 'auto';
              this.textEditor.style.height = this.textEditor.scrollHeight + 'px';
              // Sync content live so the red Canvas bounding box scales around it as you type
              l.text = this.textEditor.value;
              this.render();
            };
            
            const screenX = rect.left + l.x * scaleX;
            const screenY = rect.top + l.y * scaleY;
            
            this.textEditor.style.left = `${screenX}px`;
            this.textEditor.style.top = `${screenY}px`;
            this.textEditor.style.fontSize = `${l.fontSize * scaleY}px`;
            this.textEditor.style.color = l.color;
            this.textEditor.style.transform = `rotate(${l.rotation}deg)`;
            
            l.isEditing = true;
            this.render();
            this.textEditor.focus();
            this.textEditor.select();
          }

          commitTextEdit() {
            if (this.textEditor.style.display === 'none') return;
            if (this.activeLayer && this.activeLayer.type === 'text') {
              this.activeLayer.text = this.textEditor.value || 'Text';
              this.activeLayer.isEditing = false;
            }
            this.textEditor.style.display = 'none';
            if (this.panel.classList.contains('open')) this.buildProperties();
            this.render();
            this.saveState();
          }

          createLayer(type) {
            return {
              id: Date.now(), type, x: this.canvasW / 2 - 100, y: this.canvasH / 2 - 100,
              w: 200, h: 200, rotation: 0, opacity: 1, flipX: false, flipY: false,
              cornerRadius: 0, brightness: 100, contrast: 100, grayscale: 0, isEditing: false
            };
          }

          handleImageUpload(e) {
            const files = e.target.files;
            if (!files) return;
            Array.from(files).forEach(file => {
              const reader = new FileReader();
              reader.onload = (ev) => {
                const img = new Image();
                img.onload = () => {
                  const layer = this.createLayer('image');
                  layer.img = img;
                  const ratio = img.height / img.width;
                  
                  // Scale nicely within the current custom canvas bounds
                  if (this.canvasW / this.canvasH > 1) { 
                    layer.h = this.canvasH * 0.6;
                    layer.w = layer.h / ratio;
                  } else {
                    layer.w = this.canvasW * 0.6;
                    layer.h = layer.w * ratio;
                  }
                  
                  layer.x = (this.canvasW - layer.w) / 2;
                  layer.y = (this.canvasH - layer.h) / 2;
                  this.layers.push(layer);
                  this.activeLayer = layer;
                  if (this.panel.classList.contains('open')) this.buildProperties();
                  this.render();
                  this.saveState();
                };
                img.src = ev.target.result;
              };
              reader.readAsDataURL(file);
            });
            e.target.value = '';
          }

          addText() {
            const layer = this.createLayer('text');
            layer.text = 'Double Tap to Edit';
            layer.fontSize = Math.max(24, this.canvasH * 0.08); // Responsive font scale
            layer.color = '#FFFFFF';
            layer.w = this.canvasW * 0.6; 
            layer.h = layer.fontSize * 1.2;
            layer.x = (this.canvasW - layer.w) / 2;
            layer.y = (this.canvasH - layer.h) / 2;
            this.layers.push(layer);
            this.activeLayer = layer;
            if (this.panel.classList.contains('open')) this.buildProperties();
            this.render();
            this.saveState();
          }

          addShape() {
            const layer = this.createLayer('shape');
            layer.shapeType = 'rect';
            layer.color = '#FF0000';
            layer.cornerRadius = 16;
            layer.w = Math.min(this.canvasW, this.canvasH) * 0.3; // Responsive shape scale
            layer.h = layer.w;
            layer.x = (this.canvasW - layer.w) / 2;
            layer.y = (this.canvasH - layer.h) / 2;
            this.layers.push(layer);
            this.activeLayer = layer;
            if (this.panel.classList.contains('open')) this.buildProperties();
            this.render();
            this.saveState();
          }

          showCanvasSettings() {
            document.getElementById('pe-panel-title').innerText = 'Canvas Settings';
            this.panelContent.innerHTML = `
              <div class="pe-control-group">
                <label>Background Color</label>
                <input type="color" value="${this.bgColor}" id="pe-inp-bg">
              </div>
              <div class="pe-grid-2 mt-4">
                <div class="pe-control-group">
                  <label>Brush Color</label>
                  <input type="color" value="${this.brushColor}" id="pe-inp-brush-col">
                </div>
                <div class="pe-control-group pe-slider-group">
                  <div class="pe-control-header">
                    <label>Brush Size</label>
                    <span id="pe-val-brush-size">${this.brushSize}</span>
                  </div>
                  <input type="range" id="pe-inp-brush-size" min="1" max="100" value="${this.brushSize}">
                </div>
              </div>
              <hr style="border-color: var(--pe-sys-color-outline); margin: 24px 0;">
              <div class="pe-control-group" style="margin-bottom: 16px;">
                <label>Canvas Presets</label>
                <select id="pe-inp-ratio" style="margin-top: 8px;">
                  <option value="custom">Custom / Free Form</option>
                  <optgroup label="Lock Aspect Ratio">
                    <option value="ratio_1">1:1 (Square)</option>
                    <option value="ratio_1.7777">16:9 (Landscape)</option>
                    <option value="ratio_0.5625">9:16 (Portrait)</option>
                    <option value="ratio_1.3333">4:3 (Standard)</option>
                    <option value="ratio_3">3:1 (Banner)</option>
                  </optgroup>
                  <optgroup label="Device & Social Sizes">
                    <option value="size_1920_1080">1920 x 1080 (FHD 1080p)</option>
                    <option value="size_1080_1920">1080 x 1920 (Story / Reel)</option>
                    <option value="size_1280_720">1280 x 720 (HD 720p)</option>
                    <option value="size_1080_1080">1080 x 1080 (Social Post)</option>
                    <option value="size_1170_2532">1170 x 2532 (iPhone Pro)</option>
                    <option value="size_3840_2160">3840 x 2160 (4K UHD)</option>
                  </optgroup>
                </select>
              </div>
              <div class="pe-grid-2">
                <div class="pe-control-group">
                  <label>Canvas Width</label>
                  <input type="number" value="${this.canvasW}" id="pe-inp-cw">
                </div>
                <div class="pe-control-group">
                  <label>Canvas Height</label>
                  <input type="number" value="${this.canvasH}" id="pe-inp-ch">
                </div>
              </div>
            `;
            
            document.getElementById('pe-inp-bg').addEventListener('input', (e) => { 
              this.bgColor = e.target.value; 
              this.render(); 
              this.saveState();
            });
            
            document.getElementById('pe-inp-brush-col').addEventListener('input', (e) => { 
              this.brushColor = e.target.value; 
            });
            
            document.getElementById('pe-inp-brush-size').addEventListener('input', (e) => { 
              this.brushSize = parseFloat(e.target.value); 
              document.getElementById('pe-val-brush-size').innerText = Math.round(this.brushSize);
            });

            const ratioSel = document.getElementById('pe-inp-ratio');
            const cwInp = document.getElementById('pe-inp-cw');
            const chInp = document.getElementById('pe-inp-ch');

            const currentRatio = this.canvasW / this.canvasH;
            Array.from(ratioSel.options).forEach(opt => {
              if (opt.value.startsWith('ratio_') && Math.abs(parseFloat(opt.value.replace('ratio_', '')) - currentRatio) < 0.01) {
                ratioSel.value = opt.value;
              }
            });

            ratioSel.addEventListener('change', () => {
              const val = ratioSel.value;
              if (val.startsWith('size_')) {
                const parts = val.replace('size_', '').split('_');
                this.canvasW = parseInt(parts[0]);
                this.canvasH = parseInt(parts[1]);
                cwInp.value = this.canvasW;
                chInp.value = this.canvasH;
                this.resizeCanvas();
                this.saveState();
                ratioSel.value = 'custom'; // Revert to custom so users can freely edit the size afterward
              } else if (val.startsWith('ratio_')) {
                const ratio = parseFloat(val.replace('ratio_', ''));
                const newH = Math.round(this.canvasW / ratio);
                chInp.value = newH;
                this.canvasH = newH;
                this.resizeCanvas();
                this.saveState();
              }
            });
            
            const resize = (isWidthChange) => {
              this.canvasW = parseInt(cwInp.value) || 800;
              const val = ratioSel.value;
              if (val.startsWith('ratio_')) {
                const ratio = parseFloat(val.replace('ratio_', ''));
                if (isWidthChange) {
                  this.canvasH = Math.round(this.canvasW / ratio);
                  chInp.value = this.canvasH;
                } else {
                  this.canvasH = parseInt(chInp.value) || 600;
                  this.canvasW = Math.round(this.canvasH * ratio);
                  cwInp.value = this.canvasW;
                }
              } else {
                this.canvasH = parseInt(chInp.value) || 600;
              }
              this.resizeCanvas();
              this.saveState();
            };
            
            cwInp.addEventListener('change', () => resize(true));
            chInp.addEventListener('change', () => resize(false));
          }

          buildProperties() {
            if (!this.activeLayer) return;
            const l = this.activeLayer;
            document.getElementById('pe-panel-title').innerText = l.type.charAt(0).toUpperCase() + l.type.slice(1) + ' Edit';
            
            const makeSlider = (id, label, min, max, val) => `
              <div class="pe-control-group pe-slider-group">
                <div class="pe-control-header">
                  <label>${label}</label>
                  <span id="pe-val-${id}">${Math.round(val)}</span>
                </div>
                <input type="range" id="pe-${id}" min="${min}" max="${max}" value="${val}">
              </div>
            `;

            let html = `
              <div class="pe-grid-2">
                <div class="pe-control-group"><label>X Position</label><input type="number" id="pe-prop-x" value="${Math.round(l.x)}"></div>
                <div class="pe-control-group"><label>Y Position</label><input type="number" id="pe-prop-y" value="${Math.round(l.y)}"></div>
                <div class="pe-control-group"><label>Width</label><input type="number" id="pe-prop-w" value="${Math.round(l.w)}"></div>
                <div class="pe-control-group"><label>Height</label><input type="number" id="pe-prop-h" value="${Math.round(l.h)}"></div>
              </div>
              
              ${makeSlider('prop-rot', 'Rotation', -180, 180, l.rotation)}
              ${makeSlider('prop-op', 'Opacity', 0, 100, l.opacity * 100)}
            `;

            if (l.type === 'shape') {
              html += `
                <div class="pe-control-group" style="margin-bottom: 24px;">
                  <label>Shape</label>
                  <select id="pe-prop-stype" style="margin-top: 8px;">
                    <option value="rect" ${l.shapeType === 'rect' ? 'selected' : ''}>Rectangle</option>
                    <option value="circle" ${l.shapeType === 'circle' ? 'selected' : ''}>Ellipse</option>
                  </select>
                </div>
                <div class="pe-control-group">
                  <label>Color</label>
                  <input type="color" id="pe-prop-col" value="${l.color}">
                </div>
              `;
              if (l.shapeType === 'rect') html += makeSlider('prop-rad', 'Corner Radius', 0, 200, l.cornerRadius);
            }

            if (l.type === 'image') {
              html += makeSlider('prop-rad', 'Corner Radius', 0, 200, l.cornerRadius);
              html += makeSlider('prop-bri', 'Brightness', 0, 200, l.brightness);
              html += makeSlider('prop-con', 'Contrast', 0, 200, l.contrast);
              html += makeSlider('prop-gray', 'Grayscale', 0, 100, l.grayscale);
            }

            if (l.type === 'text') {
              html += `
                <div class="pe-control-group">
                  <label>Color</label>
                  <input type="color" id="pe-prop-col" value="${l.color}">
                </div>
              `;
              html += makeSlider('prop-fs', 'Font Size', 10, 300, l.fontSize);
            }

            if (l.type === 'path') {
              html += `
                <div class="pe-control-group">
                  <label>Color</label>
                  <input type="color" id="pe-prop-col" value="${l.color}">
                </div>
              `;
              html += makeSlider('prop-size', 'Brush Size', 1, 100, l.size);
            }

            html += `
              <div class="pe-action-buttons">
                ${(l.type === 'image' || l.type === 'shape') ? `
                <div class="pe-btn-row">
                  <button class="pe-btn" id="pe-btn-flip-h">Flip Horizontal</button>
                  <button class="pe-btn" id="pe-btn-flip-v">Flip Vertical</button>
                </div>` : ''}
                <div class="pe-btn-row">
                  <button class="pe-btn" id="pe-btn-up">Bring Forward</button>
                  <button class="pe-btn" id="pe-btn-down">Send Back</button>
                </div>
                <div class="pe-btn-row">
                  <button class="pe-btn" id="pe-btn-dup">Duplicate Layer</button>
                  <button class="pe-btn error" id="pe-btn-del">Delete Item</button>
                </div>
              </div>
            `;

            this.panelContent.innerHTML = html;

            const bind = (id, key, parser, cb) => {
              const el = document.getElementById('pe-' + id);
              const valEl = document.getElementById('pe-val-' + id);
              if (el) {
                el.addEventListener('input', (e) => { 
                  if (valEl) valEl.innerText = Math.round(e.target.value);
                  l[key] = parser(e.target.value); 
                  if (cb) cb(); 
                  this.render(); 
                  this.saveState();
                });
              }
            };
            
            bind('prop-x', 'x', parseFloat); 
            bind('prop-y', 'y', parseFloat);
            bind('prop-w', 'w', parseFloat); 
            bind('prop-h', 'h', parseFloat);
            bind('prop-rot', 'rotation', parseFloat);
            bind('prop-op', 'opacity', (v) => parseFloat(v)/100);
            bind('prop-rad', 'cornerRadius', parseFloat);
            bind('prop-col', 'color', String);
            
            const stype = document.getElementById('pe-prop-stype');
            if (stype) {
              stype.addEventListener('input', (e) => {
                l.shapeType = e.target.value;
                this.buildProperties(); 
                this.saveState();
              });
            }
            
            bind('prop-fs', 'fontSize', parseFloat);
            
            bind('prop-size', 'size', parseFloat);

            bind('prop-bri', 'brightness', parseFloat);
            bind('prop-con', 'contrast', parseFloat);
            bind('prop-gray', 'grayscale', parseFloat);

            const flipH = document.getElementById('pe-btn-flip-h');
            if (flipH) flipH.addEventListener('click', () => { l.flipX = !l.flipX; this.render(); this.saveState(); });
            
            const flipV = document.getElementById('pe-btn-flip-v');
            if (flipV) flipV.addEventListener('click', () => { l.flipY = !l.flipY; this.render(); this.saveState(); });

            document.getElementById('pe-btn-up').addEventListener('click', () => this.reorder(1));
            document.getElementById('pe-btn-down').addEventListener('click', () => this.reorder(-1));
            document.getElementById('pe-btn-del').addEventListener('click', () => this.deleteActive());
            document.getElementById('pe-btn-dup').addEventListener('click', () => this.duplicateActive());
          }

          updateInputsIfOpen() {
            if (!this.activeLayer) return;
            const setVal = (id, val) => { 
              const el = document.getElementById('pe-' + id); 
              if (el) el.value = Math.round(val); 
              const valEl = document.getElementById('pe-val-' + id);
              if (valEl) valEl.innerText = Math.round(val);
            };
            setVal('prop-x', this.activeLayer.x);
            setVal('prop-y', this.activeLayer.y);
            setVal('prop-w', this.activeLayer.w);
            setVal('prop-h', this.activeLayer.h);
            setVal('prop-rot', this.activeLayer.rotation);
          }

          reorder(dir) {
            const idx = this.layers.indexOf(this.activeLayer);
            if (idx < 0) return;
            const newIdx = idx + dir;
            if (newIdx >= 0 && newIdx < this.layers.length) {
              const temp = this.layers[newIdx];
              this.layers[newIdx] = this.layers[idx];
              this.layers[idx] = temp;
              this.render();
              this.saveState();
            }
          }

          deleteActive() {
            this.layers = this.layers.filter(l => l !== this.activeLayer);
            this.activeLayer = null;
            this.closePanel();
            this.render();
            this.saveState();
          }

          duplicateActive() {
            const clone = JSON.parse(JSON.stringify(this.activeLayer));
            clone.id = Date.now();
            clone.x += 20; clone.y += 20;
            if (clone.type === 'image') clone.img = this.activeLayer.img;
            this.layers.push(clone);
            this.activeLayer = clone;
            if (this.panel.classList.contains('open')) this.buildProperties();
            this.render();
            this.saveState();
          }

          closePanel() {
            this.panel.classList.remove('open');
            this.propBtn.classList.remove('active');
            setTimeout(() => this.resizeCanvas(), 50); // FIX: Restore canvas size when workspace regains space
          }

          render() {
            if (!this.ctx) return;
            this.ctx.clearRect(0, 0, this.canvasW, this.canvasH);
            this.ctx.fillStyle = this.bgColor;
            this.ctx.fillRect(0, 0, this.canvasW, this.canvasH);

            this.layers.forEach(l => {
              // Pre-calculate line wrapping and exact bounding box height before coordinate translation
              if (l.type === 'text' && l.text) {
                this.ctx.font = `bold ${l.fontSize}px sans-serif`;
                const paragraphs = l.text.split('\n');
                l.lines = [];
                paragraphs.forEach(p => {
                  const words = p.split(' ');
                  let currentLine = words[0] || '';
                  for (let i = 1; i < words.length; i++) {
                    const word = words[i];
                    const width = this.ctx.measureText(currentLine + ' ' + word).width;
                    if (width <= l.w) {
                      currentLine += ' ' + word;
                    } else {
                      l.lines.push(currentLine);
                      currentLine = word;
                    }
                  }
                  l.lines.push(currentLine);
                });
                l.h = Math.max(l.fontSize * 1.2, l.lines.length * (l.fontSize * 1.2));
              }

              this.ctx.save();
              this.ctx.globalAlpha = l.opacity;
              this.ctx.translate(l.x + l.w/2, l.y + l.h/2);
              this.ctx.rotate(l.rotation * Math.PI / 180);
              this.ctx.scale(l.flipX ? -1 : 1, l.flipY ? -1 : 1);
              
              this.ctx.filter = `brightness(${l.brightness}%) contrast(${l.contrast}%) grayscale(${l.grayscale}%)`;

              if (l.type === 'image') {
                if (l.cornerRadius > 0) {
                  this.ctx.beginPath();
                  this.ctx.roundRect(-l.w/2, -l.h/2, l.w, l.h, l.cornerRadius);
                  this.ctx.clip();
                }
                this.ctx.drawImage(l.img, -l.w/2, -l.h/2, l.w, l.h);
              } 
              else if (l.type === 'shape') {
                this.ctx.fillStyle = l.color;
                this.ctx.beginPath();
                if (l.shapeType === 'rect') {
                  this.ctx.roundRect(-l.w/2, -l.h/2, l.w, l.h, l.cornerRadius || 0);
                } else {
                  this.ctx.ellipse(0, 0, l.w/2, l.h/2, 0, 0, Math.PI * 2);
                }
                this.ctx.fill();
              }
              else if (l.type === 'text') {
                if (l.text && !l.isEditing) {
                  this.ctx.font = `bold ${l.fontSize}px sans-serif`;
                  this.ctx.fillStyle = l.color;
                  this.ctx.textBaseline = 'top';
                  
                  if (l.lines) {
                    l.lines.forEach((line, i) => {
                      this.ctx.fillText(line, -l.w/2, -l.h/2 + (i * (l.fontSize * 1.2)));
                    });
                  }
                }
              }
              else if (l.type === 'path') {
                this.ctx.strokeStyle = l.color;
                this.ctx.lineWidth = l.size;
                this.ctx.lineCap = 'round';
                this.ctx.lineJoin = 'round';
                this.ctx.beginPath();
                l.points.forEach((pt, i) => {
                  if (i === 0) this.ctx.moveTo(pt.x, pt.y);
                  else this.ctx.lineTo(pt.x, pt.y);
                });
                this.ctx.stroke();
              }
              this.ctx.restore();
            });

            this.renderOverlay();
          }

          renderOverlay() {
            this.overlayCtx.clearRect(0, 0, this.canvasW, this.canvasH);
            if (!this.activeLayer) return;
            const l = this.activeLayer;
            const ctx = this.overlayCtx;
            
            ctx.save();
            ctx.translate(l.x + l.w/2, l.y + l.h/2);
            ctx.rotate(l.rotation * Math.PI / 180);
            
            ctx.strokeStyle = '#FF0000';
            ctx.lineWidth = 2;
            ctx.strokeRect(-l.w/2, -l.h/2, l.w, l.h);
            
            ctx.fillStyle = '#4A0000';
            ctx.strokeStyle = '#FFFFFF';
            
            ctx.beginPath(); ctx.arc(l.w/2, l.h/2, 10, 0, Math.PI*2); ctx.fill(); ctx.stroke();
            ctx.beginPath(); ctx.arc(0, -l.h/2 - 30, 10, 0, Math.PI*2); ctx.fill(); ctx.stroke();
            
            ctx.beginPath(); ctx.moveTo(0, -l.h/2); ctx.lineTo(0, -l.h/2 - 20); ctx.stroke();
            ctx.restore();
          }

          exportImage() {
            this.activeLayer = null;
            this.render();
            const link = document.createElement('a');
            link.download = `pro-edit-${Date.now()}.png`;
            link.href = this.canvas.toDataURL('image/png');
            link.click();
          }
        }

        init();
      });
    </script>
  </body>
</html>